# v4.14.2 stage 4: internal cheat-sheet directory. Hidden+system on
# Windows (set during install). Files here are AI-consumed metadata
# users shouldn't edit — see IDEAS "Tired Market AI as system steward
# — full architecture" (Phase 1 — authored layer foundation).
INTERNAL_DIR = USER_DATA_DIR / "internal"
PROVIDER_SIGNUP_SPECS_PATH = INTERNAL_DIR / "provider_signup_specs.json"


_provider_signup_specs_cache: dict | None = None


def _load_provider_signup_specs() -> dict:
    """v4.14.2 stage 4: lazy-cached read of the cheat-sheet artifact
    at data/internal/provider_signup_specs.json. Returns the raw
    dict (excluding the underscore-prefixed metadata keys) keyed by
    profile id (e.g. 'fred'). Empty dict on missing file or parse
    failure — callers handle gracefully (Settings UI just shows the
    profile without the upfront signup blurb)."""
    global _provider_signup_specs_cache
    if _provider_signup_specs_cache is not None:
        return _provider_signup_specs_cache
    try:
        import json as _json
        if not PROVIDER_SIGNUP_SPECS_PATH.exists():
            _provider_signup_specs_cache = {}
            return _provider_signup_specs_cache
        with open(PROVIDER_SIGNUP_SPECS_PATH, 'r',
                   encoding='utf-8') as f:
            raw = _json.load(f)
        if not isinstance(raw, dict):
            _provider_signup_specs_cache = {}
            return _provider_signup_specs_cache
        # Strip metadata keys (the schema reserves leading underscore
        # for non-provider entries like _schema_version).
        out = {k: v for k, v in raw.items() if not k.startswith('_')}
        _provider_signup_specs_cache = out
        return out
    except Exception:
        _provider_signup_specs_cache = {}
        return _provider_signup_specs_cache

