# ═══════════════════════════════════════════════════════════════════════════
# DATABASE — News and price caches only.
#
# Cleaned up 2026-04-27: removed predictions, learnings, model_performance,
# post_mortems, adaptive_weights tables — those belonged to the dead ML
# engine. The new system uses portfolio.json + signals.jsonl for analysis
# data; the database is just for caching news articles and price history
# so we don't re-fetch the same Yahoo data on every restart.
# ═══════════════════════════════════════════════════════════════════════════
class Database:
    """Thread-safe SQLite database. Just news + price caches now."""
    def __init__(self):
        self.db_path = DB_PATH
        self.conn = sqlite3.connect(str(self.db_path), check_same_thread=False, timeout=10)
        self.conn.execute("PRAGMA journal_mode=WAL")
        self.conn.execute("PRAGMA synchronous=NORMAL")
        self.conn.execute("PRAGMA temp_store=MEMORY")
        self.conn.execute("PRAGMA cache_size=10000")
        # v4.14.5.14-db-concurrency: RLock (reentrant) — `check_same_thread=
        # False` is set above so SQLite itself requires serialization across
        # threads; this lock now actually serializes ALL direct app.db.conn
        # users (bridge / queue runner / event triggers / shutdown). RLock
        # (not plain Lock) is belt-and-suspenders: if any of the 14+ caller
        # functions ever nests (one lock-holding helper calling another), a
        # plain Lock would deadlock; RLock recurses cleanly. The cost over a
        # plain Lock is negligible at this workload.
        self.lock = threading.RLock()
        self.cfg = None
        self._init()
        self._drop_dead_tables()
        self._init_source_weights()

    def set_config_ref(self, cfg):
        """Save reference to live config so query helpers can read it."""
        self.cfg = cfg

    def _exec(self, sql, params=()):
        with self.lock:
            self.conn.execute(sql, params)
            self.conn.commit()

    def _query(self, sql, params=()):
        with self.lock:
            cur = self.conn.execute(sql, params)
            return cur.fetchall()

    def _query_one(self, sql, params=()):
        with self.lock:
            cur = self.conn.execute(sql, params)
            return cur.fetchone()

    def _init(self):
        """Create the slim schema. Only news and price caches."""
        with self.lock:
            self.conn.executescript("""
                CREATE TABLE IF NOT EXISTS price_history (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    timestamp TEXT, ticker TEXT, price REAL, volume REAL,
                    change_pct REAL, sources TEXT
                );
                CREATE INDEX IF NOT EXISTS idx_ph ON price_history(ticker, timestamp);
                CREATE TABLE IF NOT EXISTS news_cache (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    timestamp TEXT, ticker TEXT,
                    headline TEXT, source TEXT,
                    sentiment_score REAL, raw_data TEXT
                );
                CREATE INDEX IF NOT EXISTS idx_nc ON news_cache(ticker, timestamp);
                CREATE TABLE IF NOT EXISTS news_scans (
                    ticker TEXT PRIMARY KEY,
                    last_scan TEXT,
                    total_headlines INTEGER,
                    avg_sentiment REAL,
                    top_headlines TEXT
                );
                CREATE TABLE IF NOT EXISTS source_weights (
                    source_id TEXT NOT NULL,
                    context_id TEXT NOT NULL,
                    ticker TEXT NOT NULL DEFAULT '__global__',
                    category_tier TEXT NOT NULL,
                    within_tier_score INTEGER NOT NULL DEFAULT 5,
                    state TEXT NOT NULL DEFAULT 'active',
                    sample_size INTEGER NOT NULL DEFAULT 0,
                    last_updated TEXT NOT NULL,
                    last_state_change TEXT,
                    confidence_band_low INTEGER,
                    confidence_band_high INTEGER,
                    PRIMARY KEY (source_id, context_id, ticker)
                );
                CREATE INDEX IF NOT EXISTS idx_sw_state
                    ON source_weights(state);
                CREATE TABLE IF NOT EXISTS recommend_queue (
                    pick_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    ticker TEXT NOT NULL,
                    path TEXT NOT NULL,
                    direction TEXT NOT NULL DEFAULT 'BUY',
                    target REAL,
                    stop REAL,
                    timeframe TEXT,
                    confidence TEXT,
                    conviction TEXT,
                    reasoning TEXT,
                    source_model TEXT,
                    source_provider_kind TEXT,
                    created_at TEXT NOT NULL,
                    last_seen_at TEXT NOT NULL,
                    status TEXT NOT NULL DEFAULT 'active',
                    verify_result_json TEXT,
                    invalidation_reason TEXT,
                    price_at_creation REAL
                );
                CREATE INDEX IF NOT EXISTS idx_rq_read
                    ON recommend_queue(status, path, last_seen_at DESC);
                CREATE INDEX IF NOT EXISTS idx_rq_ticker
                    ON recommend_queue(ticker, status);
                CREATE TABLE IF NOT EXISTS recommend_cache (
                    ticker TEXT NOT NULL,
                    path TEXT NOT NULL,
                    tier TEXT NOT NULL
                        CHECK (tier IN ('displayed', 'bench')),
                    rank_within_tier INTEGER NOT NULL,
                    filter_score REAL NOT NULL,
                    momentum_score REAL,
                    rel_volume_score REAL,
                    social_bonus REAL,
                    news_bonus REAL,
                    last_buy_confirmation_at INTEGER,
                    first_seen_at INTEGER NOT NULL,
                    last_refresh_at INTEGER NOT NULL,
                    PRIMARY KEY (ticker, path)
                );
                CREATE INDEX IF NOT EXISTS idx_recommend_cache_ptr
                    ON recommend_cache(path, tier, rank_within_tier);
                CREATE TABLE IF NOT EXISTS queue_runner_analysis_log (
                    ticker TEXT NOT NULL,
                    path TEXT NOT NULL,
                    last_analyzed_at INTEGER NOT NULL,
                    last_outcome TEXT,
                    PRIMARY KEY (ticker, path)
                );
                CREATE INDEX IF NOT EXISTS idx_qral_path_time
                    ON queue_runner_analysis_log(path, last_analyzed_at);
                CREATE TABLE IF NOT EXISTS trigger_fire_log (
                    ticker TEXT NOT NULL,
                    path TEXT NOT NULL,
                    trigger_kind TEXT NOT NULL,
                    fired_at INTEGER NOT NULL,
                    signal_context TEXT,
                    PRIMARY KEY (ticker, path, trigger_kind, fired_at)
                );
                CREATE INDEX IF NOT EXISTS idx_tfl_ticker_path_time
                    ON trigger_fire_log(ticker, path, fired_at DESC);
            """)
            self.conn.commit()
            # v4.14.6.21-news-identity: news_cache gains `url` + `published_at`
            # so the event detector can recognise genuinely-new headlines by
            # identity instead of raw-count bounce, and so the AI prompt's
            # NEWS block sees real publisher dates. Idempotent ADD COLUMN
            # pattern matches tm_cache.py:307-313. New columns append at the
            # end so the one positional reader (get_news_scan reads
            # news_scans, not news_cache; news_cache reads in this module
            # use explicit column lists) is unaffected. Old rows keep
            # NULL url/published_at — the detector anchors on the existing
            # `timestamp` column for those.
            existing_nc = {row[1] for row in self.conn.execute(
                "PRAGMA table_info(news_cache)")}
            if 'url' not in existing_nc:
                self.conn.execute(
                    "ALTER TABLE news_cache ADD COLUMN url TEXT")
            if 'published_at' not in existing_nc:
                self.conn.execute(
                    "ALTER TABLE news_cache ADD COLUMN published_at TEXT")
            self.conn.execute(
                "CREATE INDEX IF NOT EXISTS idx_nc_ticker_url "
                "ON news_cache(ticker, url)")
            self.conn.commit()

    def _drop_dead_tables(self):
        """Drop tables left over from the old ML engine. Old data is junk
        now that the engine is gone — predictions referenced models that
        no longer exist, learnings are about a system we removed, etc.
        Idempotent: safe to run on fresh installs (no-op when nothing's there).
        """
        dead_tables = [
            "predictions", "learnings", "model_performance",
            "post_mortems", "adaptive_weights",
        ]
        for tbl in dead_tables:
            try:
                with self.lock:
                    self.conn.execute(f"DROP TABLE IF EXISTS {tbl}")
                    self.conn.commit()
            except Exception:
                pass
        # Reclaim space after big deletes
        try:
            with self.lock:
                self.conn.execute("VACUUM")
        except Exception:
            pass

    def _init_source_weights(self):
        """v4.14.2-stage6 — seed the source_weights table with every
        source from the registry at the mid-active default
        (within_tier=5, state='active'). Idempotent: existing rows are
        never overwritten, so any scores future stages have updated
        stay put."""
        try:
            import tm_source_weights
            with self.lock:
                tm_source_weights.initialize_source_weights(self.conn)
        except Exception:
            pass

    # ─── Price cache ───
    def save_price(self, ticker, price, volume, change_pct, sources=""):
        try:
            self._exec(
                "INSERT INTO price_history (timestamp, ticker, price, volume, change_pct, sources) "
                "VALUES (?, ?, ?, ?, ?, ?)",
                (datetime.now().isoformat(), ticker, price, volume, change_pct, sources)
            )
        except Exception:
            pass

    # ─── News cache ───
    def save_news_batch(self, ticker, items):
        """items: list of (headline, source, sentiment_score, url,
        published_at_iso) tuples. url/published_at may be '' or None when
        the source didn't supply them (e.g. Finviz HTML scrape).

        v4.14.6.21-news-identity: shape widened from 3-tuple to 5-tuple
        so the URL and publisher date survive into storage. The detector
        now reads `timestamp` (first-seen / ingestion time) as the
        anchor for "new since last check" — so this method dedups on
        (ticker, url) so a re-scan of the same URL keeps its ORIGINAL
        first-seen `timestamp`. Without the dedup the same URL would be
        re-inserted every 30 minutes and every "new" count would equal
        the merged feed size, exactly the bug we are fixing. Rows with
        no URL (Finviz) fall back to (ticker, headline) dedup to avoid
        runaway dupes from that source.

        Backwards compatibility: 3-tuples are still accepted (pad
        url/published_at to '' / None) so any in-flight callers that
        haven't been re-shaped don't crash.

        raw_data column is left NULL by THIS writer — but tm_news_bodies
        (v4.14.5.67+) actively uses it as the tier-2 article-body cache
        (reads + writes at tm_news_bodies.py:178/194/218). Don't
        repurpose it. v4.14.6.25 stale-comment fix: prior versions of
        this docstring claimed raw_data was "unused" / "always NULL" —
        that was true at write time here but has been wrong about the
        column overall since v4.14.5.67. The body-cache writer is the
        single source of truth for that column.

        Errors that escape the dedup+executemany log to
        data/data_fetch_errors.log instead of being silently swallowed.
        """
        if not items:
            return
        try:
            now = datetime.now().isoformat()
            # Normalise to 5-tuple shape. 3-tuple legacy callers get
            # padded with empty url + NULL published_at.
            norm = []
            for it in items:
                if len(it) == 3:
                    h, s, sc = it
                    u, pa = '', None
                elif len(it) == 5:
                    h, s, sc, u, pa = it
                else:
                    continue
                norm.append((h, s, float(sc), (u or ''), pa))
            if not norm:
                return
            with self.lock:
                # Per-URL dedup: skip rows whose (ticker, url) already
                # exist. For URL-less rows fall back to (ticker, headline).
                # Pre-loading the existing sets is cheaper than per-row
                # `INSERT ... WHERE NOT EXISTS` on a 1.8M-row table.
                urls = [r[3] for r in norm if r[3]]
                headlines_no_url = [r[0] for r in norm if not r[3]]
                seen_urls = set()
                seen_headlines = set()
                if urls:
                    qmarks = ','.join('?' for _ in urls)
                    rows = self.conn.execute(
                        f"SELECT url FROM news_cache "
                        f"WHERE ticker=? AND url IN ({qmarks})",
                        [ticker] + urls).fetchall()
                    seen_urls = {r[0] for r in rows}
                if headlines_no_url:
                    qmarks = ','.join('?' for _ in headlines_no_url)
                    rows = self.conn.execute(
                        f"SELECT headline FROM news_cache "
                        f"WHERE ticker=? AND (url IS NULL OR url='') "
                        f"AND headline IN ({qmarks})",
                        [ticker] + headlines_no_url).fetchall()
                    seen_headlines = {r[0] for r in rows}
                fresh = []
                for h, s, sc, u, pa in norm:
                    if u and u in seen_urls:
                        continue
                    if not u and h in seen_headlines:
                        continue
                    fresh.append((now, ticker, h, s, sc, u, pa))
                    # In-batch dedup too (the merged list shouldn't
                    # carry intra-batch dupes but be defensive).
                    if u:
                        seen_urls.add(u)
                    else:
                        seen_headlines.add(h)
                if fresh:
                    self.conn.executemany(
                        "INSERT INTO news_cache "
                        "(timestamp, ticker, headline, source, "
                        "sentiment_score, raw_data, url, published_at) "
                        "VALUES (?, ?, ?, ?, ?, NULL, ?, ?)",
                        fresh)
                self.conn.commit()
        except Exception as e:
            # Defer the import — _log_data_fetch_error is defined
            # later in the module. The Database class is imported by
            # plenty of other code that doesn't need news_cache.
            try:
                _log_data_fetch_error(
                    f"Database.save_news_batch ticker={ticker} "
                    f"items_count={len(items)}", e)
            except Exception:
                pass

    def save_news_scan(self, ticker, total, avg_sent, top_headlines):
        try:
            top_str = json.dumps(top_headlines) if isinstance(top_headlines, list) else str(top_headlines)
            self._exec(
                "INSERT OR REPLACE INTO news_scans (ticker, last_scan, total_headlines, avg_sentiment, top_headlines) "
                "VALUES (?, ?, ?, ?, ?)",
                (ticker, datetime.now().isoformat(), total, avg_sent, top_str)
            )
        except Exception:
            pass

    def get_news_scan(self, ticker):
        try:
            row = self._query_one("SELECT * FROM news_scans WHERE ticker=?", (ticker,))
            if not row:
                return None
            # row layout: ticker, last_scan, total_headlines, avg_sentiment, top_headlines
            return {
                'ticker': row[0],
                'last_scan': row[1],
                'total_headlines': row[2],
                'avg_sentiment': row[3],
                'top_headlines': json.loads(row[4]) if row[4] else [],
            }
        except Exception:
            return None

    def needs_news_scan(self, ticker, hours=5):
        """True if we don't have a recent scan for this ticker."""
        scan = self.get_news_scan(ticker)
        if not scan:
            return True
        try:
            last = datetime.fromisoformat(scan['last_scan'])
            return (datetime.now() - last).total_seconds() > hours * 3600
        except Exception:
            return True

    def get_recent_news(self, ticker, hours=24):
        """Return list of recent news articles for a ticker."""
        try:
            cutoff = (datetime.now() - timedelta(hours=hours)).isoformat()
            rows = self._query(
                "SELECT timestamp, headline, source, sentiment_score, raw_data "
                "FROM news_cache WHERE ticker=? AND timestamp > ? ORDER BY timestamp DESC",
                (ticker, cutoff)
            )
            return [
                {'timestamp': r[0], 'headline': r[1], 'source': r[2],
                 'sentiment_score': r[3], 'raw_data': r[4]}
                for r in rows
            ]
        except Exception:
            return []
# HTTP HELPERS
# ═══════════════════════════════════════════════════════════════════════════
_HDR = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
        "AppleWebKit/537.36 Chrome/124.0 Safari/537.36"}
_SSL = ssl.create_default_context()
_SSL.check_hostname = False
_SSL.verify_mode = ssl.CERT_NONE

# ── HTTP Response Cache — avoids repeat calls within 60 seconds ──
_http_cache = {}
_HTTP_CACHE_TTL = 60  # seconds


def _fetch(url, timeout=10):
    now = time.time()
    # Check cache
    if url in _http_cache:
        data, ts = _http_cache[url]
        if now - ts < _HTTP_CACHE_TTL:
            return data
    try:
        req = Request(url, headers=_HDR)
        with urlopen(req, timeout=timeout, context=_SSL) as r:
            result = r.read().decode("utf-8", errors="replace")
        _http_cache[url] = (result, now)
        # Prune old entries every 50 calls
        if len(_http_cache) > 200:
            cutoff = now - _HTTP_CACHE_TTL * 2
            for k in list(_http_cache):
                if _http_cache[k][1] < cutoff:
                    del _http_cache[k]
        return result
    except Exception:
        return None

def _fetch_json(url, timeout=10):
    raw = _fetch(url, timeout)
    if raw:
        try:
            return json.loads(raw)
        except Exception:
            pass
    return None


# ═══════════════════════════════════════════════════════════════════════════
# INTERNET CONNECTIVITY
# ═══════════════════════════════════════════════════════════════════════════
_internet_status = {'online': True, 'last_check': None, 'failures': 0}

def check_internet(force=False):
    """Check internet connectivity. Caches result for 30 seconds."""
    global _internet_status
    now = datetime.now()
    if (not force and _internet_status['last_check'] and
            (now - _internet_status['last_check']).seconds < 30):
        return _internet_status['online']

    # Try multiple endpoints — if any work, we're online
    test_urls = [
        ("https://www.google.com", 5),
        ("https://finance.yahoo.com", 5),
        ("https://1.1.1.1", 3),
    ]
    for url, timeout in test_urls:
        try:
            req = Request(url, headers=_HDR)
            with urlopen(req, timeout=timeout, context=_SSL) as r:
                if r.status == 200:
                    _internet_status = {'online': True, 'last_check': now, 'failures': 0}
                    return True
        except Exception:
            continue

    _internet_status['failures'] += 1
    _internet_status['online'] = False
    _internet_status['last_check'] = now
    return False


# ═══════════════════════════════════════════════════════════════════════════
# RESOURCE MANAGEMENT — release memory when idle
# ═══════════════════════════════════════════════════════════════════════════
def cleanup_resources(log_fn=None):
    """Release cached resources to free memory. Called when engine stops
    and periodically during long idle periods."""
    global _http_cache, _ticker_cache, _ticker_cache_time
    global _weekly_cache, _earnings_cache

    freed = 0

    # Clear HTTP response cache
    old_size = len(_http_cache)
    _http_cache.clear()
    freed += old_size

    # Clear yf.Ticker cache
    old_size = len(_ticker_cache)
    _ticker_cache.clear()
    _ticker_cache_time.clear()
    freed += old_size

    # Clear weekly trend cache
    old_size = len(_weekly_cache)
    _weekly_cache.clear()
    freed += old_size

    # Clear earnings cache
    old_size = len(_earnings_cache)
    _earnings_cache.clear()
    freed += old_size

    # Close any lingering matplotlib figures
    try:
        if _plt is not None:
            _plt.close('all')
            freed += 1
    except Exception:
        pass

    # Force garbage collection
    gc.collect()

    if log_fn and freed > 0:
        log_fn(f"Released {freed} cached resources", 'info')


def prune_caches():
    """Lightweight prune — remove only expired entries without clearing everything.
    Called between prediction rounds to keep memory bounded."""
    now = time.time()

    # Prune HTTP cache (keep entries < 60s old)
    expired = [k for k, (_, ts) in _http_cache.items() if now - ts > 60]
    for k in expired:
        del _http_cache[k]

    # Prune ticker cache (keep entries < 5 min old)
    expired = [k for k, ts in _ticker_cache_time.items() if now - ts > 300]
    for k in expired:
        _ticker_cache.pop(k, None)
        _ticker_cache_time.pop(k, None)

    # Prune weekly cache (keep entries < 1 hour old)
    expired = [k for k, (_, ts) in _weekly_cache.items() if now - ts > 3600]
    for k in expired:
        del _weekly_cache[k]

    # Prune earnings cache (keep entries < 12 hours old)
    cutoff = datetime.now() - timedelta(hours=12)
    expired = [k for k, (_, ts) in _earnings_cache.items()
               if isinstance(ts, datetime) and ts < cutoff]
    for k in expired:
        del _earnings_cache[k]


# ═══════════════════════════════════════════════════════════════════════════
# DATA SOURCES
# ═══════════════════════════════════════════════════════════════════════════

# --- Source 1: Yahoo Finance ---
_ticker_cache = {}
_ticker_cache_time = {}

def _get_yf_ticker(symbol):
    """Cached yf.Ticker — reuse same object for 5 minutes."""
    now = time.time()
    if symbol in _ticker_cache and now - _ticker_cache_time.get(symbol, 0) < 300:
        return _ticker_cache[symbol]
    t = yf.Ticker(symbol)
    _ticker_cache[symbol] = t
    _ticker_cache_time[symbol] = now
    return t

def yahoo_quote(ticker):
    """Fetch a current quote, with automatic fallback to Stooq if Yahoo
    fails or rate-limits us.

    v4.9.4: when Yahoo throttles, this used to return None and the caller
    had no quote at all. Now we transparently try Stooq as a backup.
    The returned dict's 'source' field will say either 'Yahoo' or 'Stooq'
    so callers can tell which pipe the data came from.

    Stooq covers most major US stocks but is spotty on penny stocks and
    very obscure tickers. Returns None only if BOTH sources fail.
    """
    # Try Yahoo first (this is the original behavior)
    try:
        t = _get_yf_ticker(ticker)
        info = t.fast_info
        price = info.get("lastPrice") or info.get("last_price", 0)
        prev = info.get("previousClose") or info.get("previous_close", 0)
        if price and price > 0:
            change = ((price - prev) / prev * 100) if prev else 0
            vol = info.get("lastVolume") or info.get("last_volume", 0)
            return {"source": "Yahoo", "ticker": ticker, "price": round(price, 2),
                    "change_pct": round(change, 2), "volume": vol,
                    "prev_close": round(prev, 2)}
    except Exception:
        pass  # Fall through to Stooq

    # Yahoo didn't work — try Stooq as a backup
    try:
        return stooq_quote(ticker)
    except Exception:
        return None

def _yahoo_price_in_cooldown() -> bool:
    """v4.14.5.43-price-spread (Move 2 Piece 2): True when Yahoo is currently
    recorded as rate-limit-cooled in the data Registry (Foundation B, v4.14.5.42,
    records it on a real YFRateLimitError). The price fill reads this to EASE
    OFF a throttled Yahoo and route to the real Stooq history adapter, instead
    of riding Yahoo past its cap into a stall / wasting futile calls.

    Reactive signal only (Yahoo's per-minute IP limit has no proactive near-cap
    counter — see DECISIONS 2026-05-31); the cooldown auto-clears (classify_429
    time-based), so Yahoo resumes the moment it recovers. Fail-safe FALSE: if
    the registry is unavailable or the check errors, run Yahoo exactly as before
    — never make the common (not-cooled) case worse."""
    try:
        import tm_data_providers as _tdp
        reg = _tdp.get_registry()
        if reg is None:
            return False
        return bool(reg.in_cooldown('yahoo'))
    except Exception:
        return False


def yahoo_history(ticker, period="1y"):
    """Fetch historical bars with 2-tier fallback:
       1. Direct Yahoo Finance via yfinance (SKIPPED while Yahoo is
          recorded-cooled — v4.14.5.43 ease-off; goes straight to Stooq)
       2. Stooq fallback (v4.9.4 — saves us when Yahoo throttles)

    Tier 2 covers most major US stocks but may be missing on penny stocks
    or very obscure tickers.

    v4.14.1.1: Removed never-defined references to a sync-client / server-
    client cache layer that was stubbed but never landed. Those references
    were silently raising NameError on every call, which _fetch_technicals
    swallowed — leaving the TECHNICALS prompt block empty for every
    ticker.

    v4.15.0: Side-effect cache write into tm_cache.daily_bars on each
    successful return. Tap is inside this function so both Yahoo and
    Stooq fallback paths fill the cache. Callers see no behavior change.
    """
    # ─── TIER 1: Direct Yahoo ───
    # v4.14.5.43-price-spread (Move 2 Piece 2): skip Tier-1 entirely while
    # Yahoo is recorded-cooled — ease off a rate-limited Yahoo straight to
    # Stooq (Tier 2) instead of wasting a futile call and riding Yahoo into a
    # stall. The common case (Yahoo NOT cooled) runs this block EXACTLY as
    # before, so a clean fill is byte-identical and no slower. The cooldown
    # auto-clears, so Yahoo resumes the instant it recovers.
    if not _yahoo_price_in_cooldown():
        try:
            # v4.14.5.79-daily-bars-incremental: per-ticker incremental
            # path. If this ticker is already cached with a known
            # have_to_date, fetch only the missing date range (a few
            # bars) instead of the full period. Already-up-to-date
            # tickers skip the fetch entirely. Returns are the same
            # shape downstream — DataFrame or None.
            _kind, _start, _end = _v415_resolve_incremental_range(ticker)
            if _kind == 'skip':
                # Already current — return the cached history shape
                # would be expensive; callers that NEED a DataFrame
                # treat the skip case as "no new data needed" and fall
                # through. The function's existing return-None paths
                # are well-tolerated by callers (they use the cache
                # side-effect, not the return value).
                return None
            if _kind == 'incremental':
                df = _get_yf_ticker(ticker).history(
                    start=_start, end=_end, interval="1d")
            else:
                df = _get_yf_ticker(ticker).history(
                    period=period, interval="1d")
            if df is not None and not df.empty:
                # v4.15.0: tap into cache. Side-effect only; existing callers see the same return value.
                try:
                    _v415_cache_write_bars(ticker, df)
                except Exception:
                    # Cache writes must never break the data path.
                    pass
                return df
            elif _kind == 'incremental':
                # Incremental fetch returned empty — valid "nothing
                # new" outcome (e.g. ticker is halted, or the data
                # provider hasn't published today's bar yet). Existing
                # bars and metadata are untouched; do NOT fall back to
                # a full pull. Next pass will retry the incremental
                # range naturally.
                return None
        except Exception as _yf_e:
            # v4.14.5.42-price-spread-foundations (Foundation B): if Yahoo
            # rate-limited, RECORD it in the data Registry so the cooldown
            # system SEES Yahoo is throttled on the price path — the signal
            # this slice (Piece 2) reads (above) to ease off Yahoo and shift to
            # Stooq. We still fall through to Stooq below and return data; the
            # fill itself stays correct, and router consumers skip a cooled
            # Yahoo exactly as the Yahoo fundamentals/earnings branches do.
            try:
                import tm_data_adapter_yahoo as _tday
                if _tday._is_yfinance_rate_limit(_yf_e):
                    import tm_data_providers as _tdp
                    _reg = _tdp.get_registry()
                    if _reg is not None:
                        _reg.record_failure(
                            'yahoo', error=f"rate_limit (history): {_yf_e}",
                            is_rate_limit=True)
            except Exception:
                pass
            # Fall through to Stooq.

    # ─── TIER 2: Stooq fallback (v4.9.4) ───
    # Map yfinance period strings to Stooq's days parameter
    try:
        period_to_days = {
            "1mo": 30, "3mo": 90, "6mo": 180,
            "1y": 365, "2y": 730, "5y": 1825,
            "10y": 3650, "max": 7300,
        }
        days = period_to_days.get(period, 365)
        df = stooq_history(ticker, days=days)
        if df is not None and not df.empty:
            # v4.15.0: tap into cache. Side-effect only; existing callers see the same return value.
            try:
                _v415_cache_write_bars(ticker, df)
            except Exception:
                # Cache writes must never break the data path.
                pass
            return df
    except Exception:
        pass

    return None


# v4.15.0 step 5: macro index tickers redirect into macro_indicators, not
# daily_bars. Yahoo's yahoo_history is called for these symbols by the macro
# lane fetcher; without the redirect they'd land in the wrong cache table.
_V415_MACRO_TICKERS = frozenset({
    '^TNX', '^FVX', '^IRX', '^TYX', '^VIX',
    # Defensive: index symbols not currently fetched but conventional macro
    # signals that may be added later. If a future fetcher pulls these via
    # yahoo_history they'll still land in macro_indicators.
    '^DJI', '^GSPC', '^IXIC', '^RUT', '^SPX',
})


# ─── v4.14.5.79-daily-bars-incremental: per-ticker incremental refetch ──
#
# Investigation found: when a daily_bars ticker is judged stale, the
# old refetch payload was a full `period="2y"` pull regardless of how
# far behind the ticker actually was. For Mike's typical Monday-
# morning restart with Friday-filled bars, that meant 2 years × 2,000+
# stale tickers when one bar would have sufficed. These helpers narrow
# the refetch to the missing date range when the ticker is already
# cached.
#
# Decision rule, per ticker:
#   - never-cached (no metadata / zero rows) → full period pull (unchanged)
#   - cached with have_to_date >= today    → already up-to-date, skip
#   - cached with have_to_date in past     → incremental: start=have_to_date+1, end=today+1
#   - cached but the gap is huge (> _INCREMENTAL_MAX_DAYS, default 365) →
#     full pull instead (incremental would equal it anyway)
#
# yfinance's `end` is EXCLUSIVE for the .history() and .download()
# APIs (well-documented gotcha). We pass `today + 1 day` so today's
# bar is included when present. The `start` is INCLUSIVE.
#
# Idempotency: the `tm_cache.upsert_daily_bars` chokepoint is INSERT-
# OR-REPLACE keyed on (ticker, date), so re-writing an overlapping
# day is harmless. The chunked-incremental batch below deliberately
# uses a single conservative `start` across all stale-in-batch
# tickers (the oldest have_to_date + 1d), which means some tickers
# in the batch re-download days they already had — that's fine, the
# upsert absorbs them and the total payload is still seconds-of-
# bars vs. years.

_INCREMENTAL_DAILY_BARS_ENABLED = True
_INCREMENTAL_MAX_GAP_DAYS = 365


def _set_incremental_daily_bars_enabled(enabled: bool) -> None:
    """Master toggle for the incremental refetch path. False reverts
    to the v4.14.5.78 baseline (full period pull on every stale
    ticker). Paired with `tm_cache.set_incremental_daily_bars_enabled`
    so a single App-init call drives both halves (cutoff date math
    AND refetch payload size)."""
    global _INCREMENTAL_DAILY_BARS_ENABLED
    _INCREMENTAL_DAILY_BARS_ENABLED = bool(enabled)


def _v415_resolve_incremental_range(ticker: str):
    """v4.14.5.79-daily-bars-incremental: per-ticker decision.

    Returns one of:
      ('incremental', start_iso, end_iso)
          → fetch only this date range; ticker is already cached and
            its known coverage ends before today
      ('full', None, None)
          → ticker is never-cached OR the gap exceeds
            _INCREMENTAL_MAX_GAP_DAYS; fall through to legacy period pull
      ('skip', None, None)
          → have_to_date is today or in the future; nothing to fetch

    Defensive: any cache read failure returns ('full', ...) so the
    legacy path runs (never miss a fill because metadata was unreadable).
    """
    if not _INCREMENTAL_DAILY_BARS_ENABLED:
        return ('full', None, None)
    try:
        from datetime import date as _date, timedelta as _td
        rows = tm_cache.get_cache_metadata(ticker, 'daily_bars')
    except Exception:
        return ('full', None, None)
    if not rows:
        return ('full', None, None)
    try:
        row = rows[0]
        keys = row.keys() if hasattr(row, 'keys') else []
        have_to = (row['have_to_date'] if 'have_to_date' in keys
                   else None)
    except Exception:
        return ('full', None, None)
    if not have_to:
        return ('full', None, None)
    try:
        # have_to_date is YYYY-MM-DD per upsert_daily_bars.
        have_to_date = _date.fromisoformat(str(have_to)[:10])
    except Exception:
        return ('full', None, None)
    today = _date.today()
    if have_to_date >= today:
        return ('skip', None, None)
    gap_days = (today - have_to_date).days
    if gap_days > _INCREMENTAL_MAX_GAP_DAYS:
        return ('full', None, None)
    start = have_to_date + _td(days=1)
    end = today + _td(days=1)  # yfinance end is EXCLUSIVE; +1 to include today
    return ('incremental', start.isoformat(), end.isoformat())


def _v415_resolve_batch_incremental(ticker_list):
    """v4.14.5.79-daily-bars-incremental: batch decision for the
    chunked-fetch path. Splits an input ticker list into three groups
    and computes ONE conservative start date for the incremental
    batch (the oldest have_to_date in the group + 1 day), so the whole
    incremental subset can be fetched in a SINGLE yfinance batch call.

    Returns: dict with keys:
      'full_tickers': list of tickers that need the legacy period pull
      'incremental_tickers': list of tickers that can be fetched
                              incrementally
      'skip_tickers': list of tickers already at today's have_to_date
                       (no fetch needed)
      'incremental_start': ISO start date for the incremental batch
                            (oldest have_to_date + 1; None if no
                            incremental tickers)
      'incremental_end': ISO end date (today + 1; None if no
                          incremental tickers)

    Idempotency note: tickers in the incremental batch that have
    `have_to_date` newer than `incremental_start` will re-download
    days they already have. The `upsert_daily_bars` chokepoint
    absorbs the overlap (INSERT-OR-REPLACE on the (ticker, date) key);
    overhead is tiny vs. the 2y-per-ticker we used to pull.
    """
    full: list = []
    incremental: list = []
    skip: list = []
    oldest_have_to = None
    for tk in ticker_list:
        kind, s, _e = _v415_resolve_incremental_range(tk)
        if kind == 'full':
            full.append(tk)
        elif kind == 'skip':
            skip.append(tk)
        else:  # 'incremental'
            incremental.append(tk)
            try:
                from datetime import date as _date
                # Recover have_to_date from the start (start = have_to + 1d)
                from datetime import timedelta as _td
                ht = _date.fromisoformat(s) - _td(days=1)
                if oldest_have_to is None or ht < oldest_have_to:
                    oldest_have_to = ht
            except Exception:
                pass
    inc_start_iso = None
    inc_end_iso = None
    if incremental and oldest_have_to is not None:
        from datetime import date as _date, timedelta as _td
        inc_start_iso = (oldest_have_to + _td(days=1)).isoformat()
        inc_end_iso = (_date.today() + _td(days=1)).isoformat()
    return {
        'full_tickers': full,
        'incremental_tickers': incremental,
        'skip_tickers': skip,
        'incremental_start': inc_start_iso,
        'incremental_end': inc_end_iso,
    }


# ─── v4.14.5.84-fetch-boundary-validation: OHLCV-response validator ──
#
# v.80 traced the garbage `('</script` / `(async()` date corruption to
# this writer's `str(idx)[:10]` fallback at line 1235 — when yfinance
# returns an HTML throttle/error page instead of OHLCV, the DataFrame
# index is string-typed (not a DatetimeIndex) and `idx.strftime` falls
# back to `str(idx)[:10]`, capturing literal JS body text as a "date."
# v.80 added a write-guard at the metadata storage layer; v.84 adds a
# REJECT-AT-FETCH-BOUNDARY validator so a bad response never reaches
# the parser. A rejected response is a TRANSIENT failure: leave
# cached bars + metadata intact, log once, retry next pass.
#
# Conservative by design: catches HTML/empty/wrong-shape responses
# while ACCEPTING legitimate minimal data (one valid row, OHLCV cols
# present). False-reject of real data is worse than the rare false-
# accept the v.80 write-guard already catches.

_FETCH_BOUNDARY_VALIDATION_ENABLED = True
_OHLCV_REJECT_LOG_DEDUP: dict = {}   # ticker -> last_log_epoch
_OHLCV_REJECT_LOG_INTERVAL_SECONDS = 60.0


def _set_fetch_boundary_validation_enabled(enabled: bool) -> None:
    """Master toggle. False → validator skipped, v.83 behavior exactly.
    Flipped from cfg['use_fetch_boundary_validation'] at App init."""
    global _FETCH_BOUNDARY_VALIDATION_ENABLED
    _FETCH_BOUNDARY_VALIDATION_ENABLED = bool(enabled)


def _v415_is_valid_ohlcv_response(df, ticker: str = '') -> bool:
    """Return True if `df` looks like a real OHLCV response and is
    safe to parse. False = transient-failure: do NOT parse, do NOT
    write, let the next pass retry.

    Conservative checks (in order, cheapest first):
      1. Not None.
      2. Has a `iterrows` and `index` (DataFrame-like, not a string
         blob or dict).
      3. Length > 0 (rows exist).
      4. The INDEX is datetime-typed — this is the load-bearing
         check. If it's a string-typed Index, the response is the
         HTML body from a Yahoo error/throttle page that yfinance
         couldn't parse normally. That's the exact corruption
         signature from v.80.
      5. At least ONE of the OHLCV column names (single or multi-
         index shape both supported) is present.

    When `_FETCH_BOUNDARY_VALIDATION_ENABLED` is False, returns True
    unconditionally — the v.80 write-guard remains as backstop and
    everything is exactly pre-v.84.
    """
    if not _FETCH_BOUNDARY_VALIDATION_ENABLED:
        return True
    # 1. Not None.
    if df is None:
        return False
    # 2. DataFrame-like — must have iterrows/columns/index.
    if not (hasattr(df, 'iterrows') and hasattr(df, 'index')
            and hasattr(df, 'columns')):
        return False
    # 3. Length > 0 (rows exist).
    try:
        if len(df) == 0:
            return False
    except Exception:
        return False
    # 4. Index is datetime-typed (the load-bearing check).
    try:
        idx = df.index
        # pandas DatetimeIndex has a `.is_all_dates` / `.dtype.kind`
        # signature. Most reliable check: dtype.kind == 'M' (datetime).
        idx_dtype = getattr(idx, 'dtype', None)
        kind = getattr(idx_dtype, 'kind', None)
        if kind != 'M':
            # Not datetime. Check if the first index value has
            # strftime (some pandas versions wrap a DatetimeIndex
            # whose dtype reads as 'object' but elements are real
            # Timestamps). If it does, accept.
            try:
                first = idx[0]
                if not hasattr(first, 'strftime'):
                    return False
            except Exception:
                return False
    except Exception:
        return False
    # 5. At least one OHLCV column present. yfinance returns both
    # single-level columns (single ticker) and multi-level (batch).
    try:
        cols = df.columns
        if hasattr(cols, 'levels'):
            # MultiIndex: check level-0 names (the OHLCV layer).
            level_vals = set()
            for lv in cols.levels:
                for v in lv:
                    level_vals.add(str(v))
            if not any(c in level_vals for c in
                       ('Open', 'High', 'Low', 'Close', 'Volume')):
                return False
        else:
            col_set = {str(c) for c in cols}
            if not any(c in col_set for c in
                       ('Open', 'High', 'Low', 'Close', 'Volume')):
                return False
    except Exception:
        return False
    return True


def _v415_log_ohlcv_reject(ticker: str, reason: str) -> None:
    """Rate-limited (60s per ticker) stderr log of a rejected fetch
    response. We use stderr because this module-level helper has no
    app-aware logger, and we don't want activity.log spam — the
    next-pass retry will succeed once the response normalizes."""
    import sys
    import time as _time
    now = _time.time()
    last = _OHLCV_REJECT_LOG_DEDUP.get(ticker, 0.0)
    if (now - last) < _OHLCV_REJECT_LOG_INTERVAL_SECONDS:
        return
    _OHLCV_REJECT_LOG_DEDUP[ticker] = now
    try:
        print(
            f"[fetch-boundary] OHLCV response REJECTED for "
            f"{ticker!r}: {reason} — leaving cached data intact, "
            f"will retry next pass.",
            file=sys.stderr)
    except Exception:
        pass


def _v415_cache_write_bars(ticker: str, df) -> None:
    """v4.15.0: Write a daily-bars DataFrame into tm_cache.

    No-op on empty/None input. Translates yfinance DataFrame shape into the
    daily_bars row dicts that tm_cache.upsert_daily_bars expects. Since
    yahoo_history uses auto_adjust=True by default, the DataFrame's Close
    column IS the adjusted close — we write adj_close = close to preserve
    the daily_bars schema without losing information.

    Also updates cache_metadata for the (ticker, 'daily_bars') lane with the
    date range we just cached and last_refresh_at = iso_now().

    v4.14.5.84-fetch-boundary-validation: validates the response is
    actually OHLCV BEFORE parsing anything from it. A bad response
    (HTML error page, throttle page, empty, wrong shape) is treated
    as a transient failure — existing cached bars/metadata are left
    intact and the next pass retries. Toggled by
    `_set_fetch_boundary_validation_enabled(False)` for rollback.

    Side-effect only. Callers of yahoo_history see no behavior change.
    """
    # v4.15.0 step 5: macro index tickers go to macro_indicators, not daily_bars.
    if ticker and ticker.upper() in _V415_MACRO_TICKERS:
        _v415_cache_write_macro_yahoo(ticker, df)
        return

    if df is None:
        return
    try:
        if len(df) == 0:
            return
    except Exception:
        return  # Not a DataFrame-like object; bail.

    # v4.14.5.84-fetch-boundary-validation: reject HTML/throttle/
    # wrong-shape responses BEFORE the loop below parses any dates.
    # This is the gate that stops a string-indexed Yahoo HTML body
    # from being mis-parsed via `str(idx)[:10]` into garbage like
    # "('</script". Transient-failure semantics: do not parse, do not
    # write, leave cached data intact, let next pass retry.
    if not _v415_is_valid_ohlcv_response(df, ticker):
        _v415_log_ohlcv_reject(
            ticker,
            "response failed OHLCV validation "
            "(likely HTML/throttle page; index not datetime or "
            "OHLCV columns missing)")
        return

    def _f(val):
        try:
            if val is None:
                return None
            fv = float(val)
            # Skip NaN (NaN != NaN).
            if fv != fv:
                return None
            return fv
        except (TypeError, ValueError):
            return None

    def _i(val):
        try:
            if val is None:
                return None
            fv = float(val)
            if fv != fv:
                return None
            return int(fv)
        except (TypeError, ValueError):
            return None

    rows = []
    earliest_date = None
    latest_date = None

    # yfinance and Stooq both use a DatetimeIndex with Open/High/Low/Close/Volume columns.
    for idx, row in df.iterrows():
        try:
            date_str = idx.strftime('%Y-%m-%d') if hasattr(idx, 'strftime') else str(idx)[:10]
        except Exception:
            continue  # Skip rows with unparseable dates.

        try:
            open_v = _f(row.get('Open') if hasattr(row, 'get') else row['Open'])
            high_v = _f(row.get('High') if hasattr(row, 'get') else row['High'])
            low_v = _f(row.get('Low') if hasattr(row, 'get') else row['Low'])
            close_v = _f(row.get('Close') if hasattr(row, 'get') else row['Close'])
            vol_v = _i(row.get('Volume') if hasattr(row, 'get') else row['Volume'])
        except Exception:
            continue  # Row missing expected columns; skip.

        rows.append({
            'ticker': ticker,
            'date': date_str,
            'open': open_v,
            'high': high_v,
            'low': low_v,
            'close': close_v,
            'adj_close': close_v,  # auto_adjust=True means Close IS adjusted.
            'volume': vol_v,
        })

        if earliest_date is None or date_str < earliest_date:
            earliest_date = date_str
        if latest_date is None or date_str > latest_date:
            latest_date = date_str

    if not rows:
        return

    # Write bars. tm_cache handles UPSERT — re-fetched bars overwrite cleanly.
    tm_cache.upsert_daily_bars(rows)

    # Extend cache_metadata coverage rather than overwrite, so the range reflects
    # everything we have for (ticker, daily_bars), not just this fetch's window.
    try:
        existing = tm_cache.get_cache_metadata(ticker, 'daily_bars')
        if existing:
            row = existing[0]
            keys = row.keys() if hasattr(row, 'keys') else []
            current_from = row['have_from_date'] if 'have_from_date' in keys else None
            current_to = row['have_to_date'] if 'have_to_date' in keys else None
            new_from = min(earliest_date, current_from) if current_from else earliest_date
            new_to = max(latest_date, current_to) if current_to else latest_date
        else:
            new_from = earliest_date
            new_to = latest_date

        tm_cache.upsert_cache_metadata(
            ticker, 'daily_bars',
            have_from_date=new_from,
            have_to_date=new_to,
            fill_source='direct',
        )
    except Exception:
        # Metadata update is best-effort; don't let it break the cache write.
        pass


def _v415_cache_read_technicals_df(ticker: str, months: int = 6):
    """v4.15.0: Try to assemble a technicals-ready DataFrame from cache.

    Returns a pandas DataFrame shaped like yahoo_history's output (capitalized
    OHLCV columns, DatetimeIndex) when the cache has fresh-enough coverage for
    the requested window. Returns None on cache miss, stale data, shallow
    coverage, or any error — callers fall through to a live fetch.

    Freshness rule: most recent bar must be within 4 calendar days of today
    (covers weekends and one-day holidays).
    Coverage rule: earliest bar must reach back at least `months` months.
    """
    try:
        import pandas as pd
        from datetime import datetime, timedelta, timezone

        md_rows = tm_cache.get_cache_metadata(ticker, 'daily_bars')
        if not md_rows:
            return None
        md = md_rows[0]
        keys = md.keys() if hasattr(md, 'keys') else []
        have_from = md['have_from_date'] if 'have_from_date' in keys else None
        have_to = md['have_to_date'] if 'have_to_date' in keys else None
        if not have_from or not have_to:
            return None

        today = datetime.now(timezone.utc).date()

        # Freshness check.
        try:
            have_to_dt = datetime.strptime(have_to, '%Y-%m-%d').date()
        except Exception:
            return None
        if (today - have_to_dt).days > 4:
            return None  # Stale.

        # Coverage check.
        try:
            have_from_dt = datetime.strptime(have_from, '%Y-%m-%d').date()
        except Exception:
            return None
        required_from = today - timedelta(days=months * 30 + 7)  # 7-day grace
        if have_from_dt > required_from:
            return None  # Too shallow.

        # Read the rows we need (slightly over-fetch start date to be safe).
        start_date_str = (today - timedelta(days=months * 31)).strftime('%Y-%m-%d')
        rows = tm_cache.get_daily_bars(ticker, start_date=start_date_str, end_date=None)
        if not rows or len(rows) < 20:
            # Need enough bars for technicals math (SMA20 etc.).
            return None

        df = pd.DataFrame(
            {
                'Open': [r['open'] for r in rows],
                'High': [r['high'] for r in rows],
                'Low': [r['low'] for r in rows],
                'Close': [r['close'] for r in rows],
                'Volume': [r['volume'] for r in rows],
            },
            index=pd.to_datetime([r['date'] for r in rows]),
        )
        # Ensure ascending order; compute_technicals expects oldest→newest.
        df = df.sort_index()
        return df
    except Exception:
        return None


def _v415_cache_write_news(ticker: str, merged_articles) -> None:
    """v4.15.0: Side-effect write of merged news articles into tm_cache.news_signals.

    `merged_articles` is the list produced by `_merge_news_articles(by_source)`
    — each item is a dict with keys: title, url, pub_date (mixed ISO/RFC-822
    string, may be empty), summary, sources (list[str]), sentiment (float in
    [-1, +1]).

    Dedup: skip rows whose (url, timestamp) pair already appears in the most
    recent 100 cached news_signals rows for this ticker. The scheduler re-runs
    deep_news_scan every ~30 min, so most articles repeat across refreshes —
    dedup keeps the table from ballooning.

    Also updates cache_metadata for the (ticker, 'news_signals') lane with the
    pub-date range of the just-cached articles. Best-effort: any failure inside
    the tap is silently swallowed so the data path is never disturbed.
    """
    if not merged_articles:
        return

    from datetime import datetime, timezone

    # Build a dedup set from the most recent 100 cached news rows.
    try:
        recent = tm_cache.get_news_signals(ticker, since=None, limit=100)
        existing_keys = set()
        for r in recent:
            try:
                keys = r.keys() if hasattr(r, 'keys') else []
                url = r['url'] if 'url' in keys else None
                ts = r['timestamp'] if 'timestamp' in keys else None
                existing_keys.add((url, ts))
            except Exception:
                continue
    except Exception:
        existing_keys = set()

    rows_to_insert = []
    earliest_date = None
    latest_date = None

    for art in merged_articles:
        try:
            if not isinstance(art, dict):
                continue
            title = art.get('title')
            if not title:
                continue
            url = art.get('url') or None
            pub_date = art.get('pub_date') or ''

            # Convert pub_date → ISO-8601 timestamp string.
            # _parse_news_date_to_epoch handles both ISO and RFC-822;
            # returns 0.0 if unparseable.
            iso_ts = None
            try:
                epoch = _parse_news_date_to_epoch(pub_date) if pub_date else 0.0
                if epoch and epoch > 0:
                    iso_ts = datetime.fromtimestamp(epoch, timezone.utc).strftime(
                        '%Y-%m-%dT%H:%M:%SZ')
            except Exception:
                iso_ts = None
            if iso_ts is None:
                # Fall back to ingest time so we have something monotonic.
                iso_ts = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')

            # Dedup check.
            key = (url, iso_ts)
            if key in existing_keys:
                continue
            existing_keys.add(key)  # In-batch dedup too.

            sources_list = art.get('sources') or []
            if isinstance(sources_list, (list, tuple, set)):
                source_str = ','.join(str(s) for s in sources_list) or 'unknown'
            else:
                source_str = str(sources_list) or 'unknown'

            sentiment = art.get('sentiment')
            try:
                sentiment_val = float(sentiment) if sentiment is not None else None
                if sentiment_val is not None and sentiment_val != sentiment_val:
                    sentiment_val = None  # NaN guard.
            except (TypeError, ValueError):
                sentiment_val = None

            rows_to_insert.append({
                'ticker': ticker,
                'timestamp': iso_ts,
                'source': source_str,
                'url': url,
                'title': title,
                'sentiment': sentiment_val,
                'topics': None,         # Future: AI-distilled.
                'entities': None,       # Future: AI-distilled.
                'summary': art.get('summary') or None,
                'ai_provider': None,    # Future: which AI did the distillation.
            })

            date_part = iso_ts[:10]  # 'YYYY-MM-DD'
            if earliest_date is None or date_part < earliest_date:
                earliest_date = date_part
            if latest_date is None or date_part > latest_date:
                latest_date = date_part
        except Exception:
            continue  # Skip malformed items.

    if not rows_to_insert:
        return

    try:
        tm_cache.insert_news_signals(rows_to_insert)
    except Exception:
        return

    # Extend cache_metadata coverage rather than overwrite.
    try:
        existing_md = tm_cache.get_cache_metadata(ticker, 'news_signals')
        if existing_md:
            md = existing_md[0]
            md_keys = md.keys() if hasattr(md, 'keys') else []
            current_from = md['have_from_date'] if 'have_from_date' in md_keys else None
            current_to = md['have_to_date'] if 'have_to_date' in md_keys else None
            new_from = min(earliest_date, current_from) if current_from else earliest_date
            new_to = max(latest_date, current_to) if current_to else latest_date
        else:
            new_from = earliest_date
            new_to = latest_date

        tm_cache.upsert_cache_metadata(
            ticker, 'news_signals',
            have_from_date=new_from,
            have_to_date=new_to,
            fill_source='direct',
        )
    except Exception:
        pass


def _v415_cache_write_macro_yahoo(ticker: str, df) -> None:
    """v4.15.0 step 5: Yahoo macro-index DataFrame → macro_indicators rows.

    Macro symbols (^TNX, ^VIX, etc.) are tracked by their daily close as a
    single indicator value per date. Schema is keyed by (series_id, date) so
    UPSERT means re-fetched values overwrite cleanly. No ticker column —
    series_id holds the symbol.

    v4.14.5.84-fetch-boundary-validation: same validator applies here
    (this writer has the identical `str(idx)[:10]` weak-spot the
    daily_bars writer had — line 1529 pre-patch). Reject HTML/error
    responses before parsing any dates.

    Side-effect only. Callers see no behavior change.
    """
    if df is None:
        return
    try:
        if len(df) == 0:
            return
    except Exception:
        return

    # v4.14.5.84-fetch-boundary-validation: reject before parsing.
    if not _v415_is_valid_ohlcv_response(df, ticker):
        _v415_log_ohlcv_reject(
            ticker,
            "macro response failed OHLCV validation "
            "(likely HTML/throttle page)")
        return

    series_id = (ticker or '').upper()
    if not series_id:
        return

    rows = []
    for idx, row in df.iterrows():
        try:
            date_str = idx.strftime('%Y-%m-%d') if hasattr(idx, 'strftime') else str(idx)[:10]
        except Exception:
            continue
        try:
            close = row.get('Close') if hasattr(row, 'get') else row['Close']
            if close is None:
                continue
            value = float(close)
            if value != value:  # NaN guard
                continue
        except (TypeError, ValueError, KeyError):
            continue
        rows.append({
            'series_id': series_id,
            'date': date_str,
            'value': value,
        })

    if not rows:
        return

    try:
        tm_cache.upsert_macro_indicators(rows)
    except Exception:
        return


def _v415_cache_write_fundamentals(ticker: str, data, source: str = 'yahoo') -> None:
    """v4.15.0 step 5: Yahoo / Finnhub fundamentals snapshot → fundamentals row.

    Both Yahoo and Finnhub return current-snapshot ratio dicts rather than
    quarterly financial-statement rows. The schema's fiscal_period_end column
    is therefore a synthetic '__current__' marker so successive snapshots
    UPSERT into one row per (ticker, source) pair. Most schema columns stay
    None — these sources don't expose revenue/net_income/total_assets etc.
    A future step that wires in proper quarterly fundamentals will populate
    real fiscal_period_end rows alongside this snapshot row.

    `data` shape varies by source:
      - yahoo: {marketCap, trailingPE, forwardPE, trailingEps, ...}
      - finnhub: {eps, pe_ratio, shares_outstanding, market_cap, ...}

    Side-effect only.
    """
    if not data or not isinstance(data, dict) or not ticker:
        return

    def _f(v):
        try:
            if v is None:
                return None
            fv = float(v)
            if fv != fv:
                return None
            return fv
        except (TypeError, ValueError):
            return None

    def _i(v):
        try:
            if v is None:
                return None
            fv = float(v)
            if fv != fv:
                return None
            return int(fv)
        except (TypeError, ValueError):
            return None

    src = (source or 'unknown').lower()
    if src == 'finnhub':
        eps = _f(data.get('eps'))
        shares = _i(data.get('shares_outstanding'))
    elif src == 'yahoo':
        eps = _f(data.get('trailingEps'))
        # yahoo_fundamentals doesn't extract shares_outstanding today.
        shares = None
    else:
        eps = _f(data.get('eps'))
        shares = _i(data.get('shares_outstanding'))

    # All other statement columns stay None for snapshot sources.
    row = {
        'ticker': ticker.upper(),
        'fiscal_period_end': '__current__',
        'revenue': None,
        'net_income': None,
        'eps': eps,
        'gross_margin': None,
        'operating_margin': None,
        'total_assets': None,
        'total_liabilities': None,
        'shares_outstanding': shares,
        'source': src,
    }

    try:
        tm_cache.upsert_fundamentals([row])
    except Exception:
        return

    try:
        today = tm_cache.iso_now()[:10]
        existing = tm_cache.get_cache_metadata(ticker.upper(), 'fundamentals')
        if existing:
            md = existing[0]
            md_keys = md.keys() if hasattr(md, 'keys') else []
            current_from = md['have_from_date'] if 'have_from_date' in md_keys else None
            current_to = md['have_to_date'] if 'have_to_date' in md_keys else None
            new_from = min(today, current_from) if current_from else today
            new_to = max(today, current_to) if current_to else today
        else:
            new_from = today
            new_to = today
        tm_cache.upsert_cache_metadata(
            ticker.upper(), 'fundamentals',
            have_from_date=new_from,
            have_to_date=new_to,
            fill_source='direct',
        )
    except Exception:
        pass


# ── v4.15.0 step 7: cache-read helpers for filings / fundamentals / macro ──
#
# Three helpers mirror Step 3's _v415_cache_read_technicals_df pattern:
# check cache.db for fresh-enough data, return in the shape consumers expect,
# return None on cache miss / stale / error so callers fall through to live
# fetch. The corresponding cache-write taps (Step 5) refill cache.db whenever
# the live path runs, so the next consumer call within the staleness window
# is a free read.


# Inverse mapping: cache rows for macro store rows keyed by canonical FRED
# series_id or Yahoo macro ticker; consumers want a friendly-key dict.
# Order in each list = preference (FRED preferred over Yahoo for overlapping
# keys, matching _fetch_macro's "FRED wins on overlaps" merge rule).
_V415_MACRO_FRIENDLY_FROM_SERIES = (
    # (friendly_key,            [series_ids in preference order])
    ('fed_funds',                ['DFF']),
    ('treasury_10y',             ['DGS10', '^TNX']),
    ('treasury_2y',              ['DGS2']),
    ('treasury_5y',              ['^FVX']),
    ('treasury_13w',             ['^IRX']),
    ('treasury_30y',             ['^TYX']),
    ('curve_spread_10y_2y',      ['T10Y2Y']),
    ('cpi',                      ['CPIAUCSL']),
    ('unemployment_pct',         ['UNRATE']),
    ('vix',                      ['VIXCLS', '^VIX']),
    ('gdp',                      ['GDP']),
)


def _v415_cache_read_filings(ticker: str, max_age_hours: int = 24):
    """v4.15.0 step 7: Try to assemble a filings payload from cache.

    Returns a dict shaped like the EDGAR adapter's _normalize_filings output
    so consumers downstream of `_fetch_filings` see no change. Returns None
    on cache miss, staleness past max_age_hours, or any error — callers fall
    through to a live EDGAR fetch.

    Cache rows store: accession_number, ticker, cik, filing_date,
    report_date, form_type, primary_document_url.
    Consumer shape: {filings: [{form, filing_date, accession_no,
    primary_document, description, url}], count, cik, company_name, as_of}.
    primary_document + description aren't stored in cache today — left as
    empty strings (consumer's _filings_block reads via .get() with empty
    fallback so this renders cleanly).
    """
    if not ticker:
        return None
    try:
        from datetime import datetime, timedelta, timezone

        md_rows = tm_cache.get_cache_metadata(ticker.upper(), 'filings')
        if not md_rows:
            return None
        md = md_rows[0]
        keys = md.keys() if hasattr(md, 'keys') else []
        last_refresh = md['last_refresh_at'] if 'last_refresh_at' in keys else None
        if not last_refresh:
            return None
        # cache_metadata.last_refresh_at is iso_now() format: 'YYYY-MM-DDTHH:MM:SSZ'
        try:
            last_dt = datetime.strptime(last_refresh, '%Y-%m-%dT%H:%M:%SZ')
        except (ValueError, TypeError):
            return None
        if (datetime.now(timezone.utc).replace(tzinfo=None) - last_dt) > timedelta(hours=max_age_hours):
            return None  # Stale.

        rows = tm_cache.get_filings(ticker.upper())
        if not rows:
            return None

        cik = None
        out_filings = []
        for r in rows:
            try:
                r_keys = r.keys() if hasattr(r, 'keys') else []
                if cik is None and 'cik' in r_keys:
                    cik = r['cik']
                out_filings.append({
                    'form': r['form_type'] if 'form_type' in r_keys else '',
                    'filing_date': r['filing_date'] if 'filing_date' in r_keys else '',
                    'accession_no': r['accession_number'] if 'accession_number' in r_keys else '',
                    'primary_document': '',
                    # v4.14.5.62-8k-descriptions: surface the persisted
                    # description (NULL on pre-existing date-only rows → '').
                    'description': (
                        (r['description'] if 'description' in r_keys else None)
                        or ''),
                    'url': r['primary_document_url'] if 'primary_document_url' in r_keys else '',
                })
            except Exception:
                continue

        if not out_filings:
            return None

        return {
            'filings': out_filings,
            'count': len(out_filings),
            'cik': cik or '',
            'company_name': '',
            'as_of': tm_cache.iso_now(),
        }
    except Exception:
        return None


def _v415_cache_read_fundamentals(ticker: str, max_age_days: int = 7):
    """v4.15.0 step 7: Try to assemble a fundamentals snapshot from cache.

    Returns a dict shaped like the Finnhub adapter's fundamentals output so
    consumers downstream of `_fetch_fundamentals` see no change. Returns
    None on cache miss / staleness / error.

    Prefers Finnhub rows over Yahoo when both exist for the same ticker
    (Finnhub exposes more fields in current code).

    The cache schema stores quarterly-statement columns (revenue,
    net_income, total_assets, ...) but Yahoo/Finnhub fundamentals fetchers
    today emit ratio/identity snapshots — most statement columns are None
    in cache rows. Consumer `_facts_block` reads fields via .get() and
    only renders lines for non-None values, so a thin row renders a
    thinner FACTS block (not a crash).
    """
    if not ticker:
        return None
    try:
        from datetime import datetime, timedelta, timezone

        md_rows = tm_cache.get_cache_metadata(ticker.upper(), 'fundamentals')
        if not md_rows:
            return None
        md = md_rows[0]
        keys = md.keys() if hasattr(md, 'keys') else []
        last_refresh = md['last_refresh_at'] if 'last_refresh_at' in keys else None
        if not last_refresh:
            return None
        try:
            last_dt = datetime.strptime(last_refresh, '%Y-%m-%dT%H:%M:%SZ')
        except (ValueError, TypeError):
            return None
        if (datetime.now(timezone.utc).replace(tzinfo=None) - last_dt) > timedelta(days=max_age_days):
            return None

        rows = tm_cache.get_fundamentals(ticker.upper())
        if not rows:
            return None

        # v4.15.0 Step 14: prefer deep sources (one row per fiscal period) over
        # snapshot sources (single '__current__' row per source). Within a
        # source, pick the most recent fiscal_period_end. Snapshot rows fall
        # through as last resort so a thin envelope still renders.
        # v4.15.0 Step 14 + v4.14.5.14-edgar-fundamentals: deep sources (one row
        # per fiscal period) preferred over snapshot rows; EDGAR (authoritative
        # SEC XBRL) is the top keyless deep source. We now MERGE at the FIELD
        # level across deep sources in priority order — the primary row supplies
        # most values, and any field it lacks falls back to the next source (so
        # EDGAR statements fill from yahoo_deep/finnhub_deep where EDGAR is
        # sparse, e.g. a company that omits GrossProfit in XBRL).
        source_priority = ('edgar', 'finnhub_deep', 'yahoo_deep',
                           'finnhub', 'yahoo')
        ordered = []   # best (most-recent) row per source, in priority order
        for preferred in source_priority:
            candidates = [r for r in rows
                          if (r['source'] if 'source' in r.keys() else None)
                          == preferred]
            if candidates:
                try:
                    candidates.sort(
                        key=lambda r: r['fiscal_period_end'] if 'fiscal_period_end' in r.keys() else '',
                        reverse=True,
                    )
                except Exception:
                    pass
                ordered.append(candidates[0])
        if not ordered:
            ordered = [rows[0]]
        primary = ordered[0]
        p_keys = primary.keys() if hasattr(primary, 'keys') else []

        def _mget(col):
            """First non-None value for `col` across the priority-ordered deep
            rows (field-level merge — EDGAR first, then the others)."""
            for r in ordered:
                try:
                    if col in r.keys() and r[col] is not None:
                        return r[col]
                except Exception:
                    continue
            return None

        # Map cache → consumer shape. Statement columns merge across deep
        # sources (EDGAR-first). Derived fields (company/sector/market_cap/pe/
        # beta/dividend) are NOT in the cache and are left None here — UNCHANGED
        # from prior behavior. Surfacing them alongside statements (a live
        # snapshot overlay) is a deliberate parked follow-up (see DECISIONS
        # 2026-05-26), not part of this patch.
        return {
            'company_name': None,
            'industry': None,
            'sector': None,
            'market_cap': None,
            'shares_outstanding': _mget('shares_outstanding'),
            'pe_ratio': None,
            'eps': _mget('eps'),
            'beta': None,
            'dividend_yield': None,
            'revenue': _mget('revenue'),
            'net_income': _mget('net_income'),
            'gross_margin': _mget('gross_margin'),
            'operating_margin': _mget('operating_margin'),
            'total_assets': _mget('total_assets'),
            'total_liabilities': _mget('total_liabilities'),
            'fiscal_period_end': (primary['fiscal_period_end']
                                  if 'fiscal_period_end' in p_keys else None),
            'as_of': tm_cache.iso_now(),
        }
    except Exception:
        return None


# Derived/market fields that the `fundamentals` cache table has NO columns for
# (the schema is statement-only), so _v415_cache_read_fundamentals always
# returns them None. They exist only in the LIVE router snapshot.
_V415_DERIVED_FUND_FIELDS = ('company_name', 'sector', 'industry', 'market_cap',
                             'pe_ratio', 'beta', 'dividend_yield')
# v4.14.5.62-analyst-facts: extra snapshot fields the overlay COPIES (when the
# live snapshot has them) but does NOT add to the short-circuit check above —
# analyst coverage is often absent, so including them in the "all present?"
# gate would force a re-fetch every render for uncovered tickers. Copying-only
# keeps the existing fetch cadence unchanged.
_V415_ANALYST_FUND_FIELDS = ('recommendation_key', 'target_mean_price')


def _v415_overlay_derived_fundamentals(ticker: str, stmt):
    """v4.14.5.14-derived-overlay: fill a deep-statement dict's missing
    derived/market fields from the live data-router snapshot.

    The `fundamentals` SQLite table stores statements only (revenue,
    net_income, eps, margins, assets, liabilities, shares) — it has no columns
    for company_name / sector / industry / market_cap / pe_ratio / beta /
    dividend_yield, so those are never persisted and _v415_cache_read_fundamentals
    hardcodes them None. A cache-reader overlay is therefore impossible without
    a schema migration; instead we overlay live here, onto whatever deep
    statement dict we're about to return.

    Only Nones are filled, so a real statement value always wins. Best-effort:
    any failure leaves `stmt` unchanged (no regression). The caller's result is
    memoized 6h by DataCacheLayer._get, so this costs ~one Yahoo `.info` call
    per ticker per 6h, not one per render.
    """
    try:
        if not isinstance(stmt, dict) or tm_data_router is None:
            return stmt
        # Nothing to fill -> skip the network call entirely.
        if all(stmt.get(f) is not None for f in _V415_DERIVED_FUND_FIELDS):
            return stmt
        env = tm_data_router.fetch('fundamentals', ticker=ticker)
        snap = env.get('result') if isinstance(env, dict) else None
        if isinstance(snap, dict):
            for f in (_V415_DERIVED_FUND_FIELDS + _V415_ANALYST_FUND_FIELDS):
                if stmt.get(f) is None and snap.get(f) is not None:
                    stmt[f] = snap[f]
    except Exception:
        pass
    return stmt


def _v415_fetch_financials_yfinance(ticker: str, freq: str = 'quarterly') -> list | None:
    """v4.15.0 Step 14: Yahoo fallback for deep fundamentals.

    Uses yfinance's quarterly_income_stmt / quarterly_balance_sheet (or the
    annual counterparts) DataFrames. Returns a list of period rows in the same
    cache-schema shape as the Finnhub deep fetcher, tagged source='yahoo_deep'.

    yfinance DataFrame shape: columns are period-end timestamps, rows are line
    items ('Total Revenue', 'Net Income', 'Total Assets', ...). Each column is
    one fiscal period. Line-item naming has shifted across yfinance versions;
    we try a couple of label variants and accept any None gracefully.

    Returns None on offline (Step 12 gate), empty/missing DataFrames, or any
    error producing zero usable rows. Side-effect cache write happens inline.
    """
    try:
        import tm_network as _tmn
        if not _tmn.is_online():
            return None
    except Exception:
        pass

    if not ticker:
        return None

    try:
        t = _get_yf_ticker(ticker)
        if freq == 'quarterly':
            ic = getattr(t, 'quarterly_income_stmt', None)
            bs = getattr(t, 'quarterly_balance_sheet', None)
        else:
            ic = getattr(t, 'income_stmt', None)
            bs = getattr(t, 'balance_sheet', None)

        if ic is None or bs is None:
            return None
        try:
            if len(ic.columns) == 0 or len(bs.columns) == 0:
                return None
        except Exception:
            return None

        output_rows = []
        for col_ts in ic.columns:
            try:
                period_end = (col_ts.strftime('%Y-%m-%d')
                               if hasattr(col_ts, 'strftime')
                               else str(col_ts)[:10])

                def _safe(df, row_label, _col=col_ts):
                    try:
                        if row_label not in df.index:
                            return None
                        value = df.loc[row_label, _col]
                        if value is None:
                            return None
                        fv = float(value)
                        if fv != fv:  # NaN
                            return None
                        return fv
                    except Exception:
                        return None

                revenue = _safe(ic, 'Total Revenue')
                net_income = _safe(ic, 'Net Income')
                eps = _safe(ic, 'Diluted EPS') or _safe(ic, 'Basic EPS')
                gross_profit = _safe(ic, 'Gross Profit')
                operating_income = _safe(ic, 'Operating Income')

                total_assets = _safe(bs, 'Total Assets')
                total_liabilities = (
                    _safe(bs, 'Total Liabilities Net Minority Interest')
                    or _safe(bs, 'Total Liabilities'))
                shares = (_safe(bs, 'Ordinary Shares Number')
                           or _safe(bs, 'Share Issued'))

                gross_margin = ((gross_profit / revenue)
                                 if (gross_profit is not None and revenue and revenue != 0)
                                 else None)
                operating_margin = ((operating_income / revenue)
                                     if (operating_income is not None and revenue and revenue != 0)
                                     else None)

                row = {
                    'ticker': ticker.upper(),
                    'fiscal_period_end': period_end,
                    'revenue': revenue,
                    'net_income': net_income,
                    'eps': eps,
                    'gross_margin': gross_margin,
                    'operating_margin': operating_margin,
                    'total_assets': total_assets,
                    'total_liabilities': total_liabilities,
                    'shares_outstanding': int(shares) if shares else None,
                    'source': 'yahoo_deep',
                }
                output_rows.append(row)
            except Exception:
                continue

        if not output_rows:
            return None

        try:
            _v415_cache_write_deep_fundamentals_local(
                ticker, output_rows, source='yahoo_deep')
        except Exception:
            pass

        return output_rows
    except Exception:
        return None


def _v415_cache_write_deep_fundamentals_local(ticker: str, rows: list,
                                                source: str = 'yahoo_deep') -> None:
    """v4.15.0 Step 14: module-local twin of the Finnhub adapter's write helper.

    Lives here (rather than calling into the Finnhub adapter) so the yfinance
    fallback doesn't depend on the Finnhub module's internals. Same UPSERT +
    cache_metadata widening behavior. Failures silently swallowed.
    """
    if not rows:
        return
    try:
        tm_cache.upsert_fundamentals(rows)
    except Exception:
        return
    try:
        period_dates = [r['fiscal_period_end'] for r in rows
                         if r.get('fiscal_period_end')]
        if not period_dates:
            return
        earliest = min(period_dates)
        latest = max(period_dates)
        existing_md = tm_cache.get_cache_metadata(ticker.upper(), 'fundamentals')
        if existing_md and len(existing_md) > 0:
            md = existing_md[0]
            md_keys = md.keys() if hasattr(md, 'keys') else []
            current_from = md['have_from_date'] if 'have_from_date' in md_keys else None
            current_to = md['have_to_date'] if 'have_to_date' in md_keys else None
            new_from = min(earliest, current_from) if current_from else earliest
            new_to = max(latest, current_to) if current_to else latest
        else:
            new_from = earliest
            new_to = latest
        tm_cache.upsert_cache_metadata(
            ticker.upper(), 'fundamentals',
            have_from_date=new_from,
            have_to_date=new_to,
            fill_source='direct',
        )
    except Exception:
        pass


def _v415_fetch_deep_fundamentals(ticker: str, max_age_days: int = 7,
                                  log_fn=None, with_overlay: bool = True):
    """v4.14.5.41-fill-fundamentals-chain: the SHARED EDGAR-first deep-
    fundamentals chain. Extracted verbatim from the analysis path
    (_build_holdings_state._fetch_fundamentals) so the startup fill and the
    analysis context use ONE chain instead of the fill's old EDGAR-less
    Finnhub-or-Yahoo fetcher (which left a fresh keyless install Yahoo-only
    for fundamentals — the stall Mike saw).

    Order (each deep source writes the `fundamentals` cache rows as a
    side-effect, then we re-read so the consumer sees the full thick
    envelope):
      cache-first (max_age_days)
        -> EDGAR XBRL deep   (keyless PRIMARY, authoritative SEC)
        -> Finnhub deep      (if a Finnhub key is configured + usable)
        -> Yahoo deep        (keyless fallback)
        -> data-router 'fundamentals' SNAPSHOT  (last resort only).

    IMPORTANT (the reason the first router-routing attempt was wrong): the
    deep quarterly STATEMENTS (revenue / net income / margins / assets) do
    NOT come from tm_data_router.fetch('fundamentals') — that data_type is
    the shallow derived-field `.info` snapshot. The deep rows come from the
    direct-adapter chain here; the router snapshot is only the final derived
    fallback. (See DECISIONS.md 2026-05-31.)

    Returns the derived-overlaid merged dict (the analysis path uses the
    return; the fill ignores it and relies on the side-effect cache writes).
    Returns None when nothing could be fetched. When the WHOLE chain yields
    nothing AND `log_fn` is provided, emits one honest 'all sources
    unavailable' line (amber) rather than failing silently — callers that
    need byte-identical silence (the analysis path) pass log_fn=None.

    v4.14.5.44-fundamentals-coldfill: `with_overlay` (default True) controls the
    derived-field overlay (_v415_overlay_derived_fundamentals), which makes a
    `tm_data_router.fetch('fundamentals')` call to fill company_name/sector/
    pe/etc. That router call routes to EDGAR (priority-1) and re-fetches it —
    THE COLD-FILL DOUBLE-FETCH (each ticker hit EDGAR twice). The FILL ignores
    this return value entirely (it relies on the side-effect cache writes), so
    the fill passes with_overlay=False → no overlay, no second EDGAR fetch, and
    warm fills read straight from cache. The ANALYSIS path keeps True (it
    displays the derived fields). Statements (what the fill caches) are
    unaffected either way.
    """
    def _ret(_cached):
        # Apply the derived-field overlay only when the caller wants it.
        return (_v415_overlay_derived_fundamentals(ticker, _cached)
                if with_overlay else _cached)
    try:
        # Cache-first read (staleness window).
        cached = _v415_cache_read_fundamentals(ticker, max_age_days=max_age_days)
        if cached is not None:
            return _ret(cached)

        # EDGAR XBRL CompanyFacts — keyless PRIMARY deep-statement source.
        try:
            import tm_data_adapter_edgar as _tde
            _erows = _tde.fetch_fundamentals(ticker)
            if _erows:
                _v415_cache_write_deep_fundamentals_local(
                    ticker, _erows, source='edgar')
                cached = _v415_cache_read_fundamentals(
                    ticker, max_age_days=max_age_days)
                if cached is not None:
                    return _ret(cached)
        except Exception:
            pass

        # Finnhub deep (keyed resilience).
        try:
            import tm_data_providers as _tdp
            import tm_data_adapter_finnhub as _tdf
            _reg = _tdp.get_registry()
            _prof = _reg.get('finnhub') if _reg else None
            if _prof and _prof.is_usable():
                _rows = _tdf.adapter(
                    _prof, 'financials_deep',
                    ticker=ticker, freq='quarterly')
                if _rows:
                    cached = _v415_cache_read_fundamentals(
                        ticker, max_age_days=max_age_days)
                    if cached is not None:
                        return _ret(cached)
        except Exception:
            pass

        # yfinance deep (keyless fallback — works whenever yfinance reaches Yahoo).
        try:
            _rows = _v415_fetch_financials_yfinance(ticker, freq='quarterly')
            if _rows:
                cached = _v415_cache_read_fundamentals(
                    ticker, max_age_days=max_age_days)
                if cached is not None:
                    return _ret(cached)
        except Exception:
            pass

        # Last resort — derived-field SNAPSHOT via the data router.
        if tm_data_router is not None:
            try:
                result = tm_data_router.fetch('fundamentals', ticker=ticker)
                if result:
                    # Unwrap router envelope: {'result': ..., 'source': ...}
                    return result.get('result')
            except Exception:
                pass

        # Whole chain yielded nothing — honest, NON-swallowed signal (only
        # when a logger is provided; the analysis path passes None to stay
        # silent/byte-identical).
        if log_fn is not None:
            try:
                log_fn(
                    f"[fundamentals] all sources unavailable for "
                    f"{str(ticker).upper()} (EDGAR/Finnhub/Yahoo) — "
                    f"will retry next cycle", 'amber')
            except Exception:
                pass
        return None
    except Exception:
        return None


def _v415_cache_read_macro(max_age_hours: int = 24):
    """v4.15.0 step 7: Try to assemble a macro snapshot from cache.

    Returns a dict shaped like `_fetch_macro`'s output (friendly keys like
    `fed_funds`, `treasury_10y`, `vix`, plus `series_dates`/`sources`/
    `as_of`). Returns None on empty cache, staleness, or error.

    Macro is universe-wide; cache_metadata isn't maintained for the lane
    (per Step 5's design — macro has no ticker key). Staleness is computed
    directly from the most recent `date` across all queried series.

    For each friendly key, picks the freshest row from the preferred series
    (FRED before Yahoo for overlapping keys, matching `_fetch_macro`'s
    merge rule).
    """
    try:
        from datetime import datetime, timedelta, timezone

        out: dict = {}
        series_dates: dict = {}
        sources_seen: set = set()
        latest_date_str = None

        for friendly_key, candidates in _V415_MACRO_FRIENDLY_FROM_SERIES:
            for sid in candidates:
                rows = tm_cache.get_macro_indicators(sid)
                if not rows:
                    continue
                # get_macro_indicators returns ASC by date; last is freshest.
                r = rows[-1]
                r_keys = r.keys() if hasattr(r, 'keys') else []
                value = r['value'] if 'value' in r_keys else None
                date_str = r['date'] if 'date' in r_keys else None
                if value is None or not date_str:
                    continue
                try:
                    fv = float(value)
                    if fv != fv:
                        continue
                except (TypeError, ValueError):
                    continue
                out[friendly_key] = fv
                series_dates[sid] = date_str
                sources_seen.add('fred' if not sid.startswith('^') else 'yahoo')
                if latest_date_str is None or date_str > latest_date_str:
                    latest_date_str = date_str
                break  # First (preferred) source wins for this friendly key.

        if not out or not latest_date_str:
            return None

        # Staleness: most recent row across all macro series must be within
        # max_age_hours of today.
        try:
            latest_dt = datetime.strptime(latest_date_str, '%Y-%m-%d')
        except (ValueError, TypeError):
            return None
        if (datetime.now(timezone.utc).replace(tzinfo=None) - latest_dt) > timedelta(hours=max_age_hours):
            return None

        # Derived spreads, matching _fetch_macro's behavior.
        if 'treasury_10y' in out and 'treasury_5y' in out:
            out['curve_spread_10y_5y'] = round(
                out['treasury_10y'] - out['treasury_5y'], 4)
        if 'treasury_10y' in out and 'treasury_13w' in out:
            out['curve_spread_10y_3m'] = round(
                out['treasury_10y'] - out['treasury_13w'], 4)

        out['series_dates'] = series_dates
        out['sources'] = sorted(sources_seen)
        out['as_of'] = tm_cache.iso_now()
        return out
    except Exception:
        return None


