# a ~1% BUY-rate, finite-pool path that reliably yields only a few picks. So
# its status dot never greened by count, and since the bar dismisses only when
# ALL dots green, lottery's never-greening dot held the bar open forever
# ("Speculative stuck at 6 / flashing"). DISPLAY-ONLY fix: green the lottery
# dot once it has at least this many displayed picks (OR the existing
# done-signal fires). The FILL still targets 10 unchanged; pick quality /
# BUY criteria are untouched — only this cosmetic dot threshold moves.
_LOTTERY_DOT_MIN = 2


def gui_phase_states(startup_complete, path_complete):
    """Return [(label, is_complete), ...] for the phase-dot row.
    `path_complete` is {path: bool}; the Startup phase uses
    `startup_complete`. Pure."""
    pc = path_complete or {}
    return [
        (label, bool(startup_complete) if path is None
                else bool(pc.get(path, False)))
        for label, path in _GUI_PHASE_DOTS
    ]


def gui_all_phases_complete(startup_complete, path_complete):
    """True when every phase dot (Startup + the 4 fill paths) is complete."""
    return all(done for _, done in
               gui_phase_states(startup_complete, path_complete))


def gui_activity_label(msg, base_state='Idle', *,
                       in_flight=False, msg_age=None, stale_after=10.0):
    """Map current activity to a short persistent-indicator label — HONESTLY.

    v4.14.5.14-indicator-honesty: the indicator must reflect what's happening
    NOW, not echo the most-recent log line forever. Inputs:
      - in_flight: True when a real AI call (consensus) is actually running —
        the strongest signal; always wins -> 'Analyzing'.
      - msg: the most-recent activity-log line (a passive RESULT, not state).
      - msg_age: seconds since that line was logged. When it exceeds
        `stale_after` (default 10s) the line is a finished echo and is ignored
        -> fall back to base_state. When None, the age gate is OFF (callers /
        tests that pass only msg+base get the recent-line mapping).
      - base_state: Idle/Running/Cooldown/Paused/Loading from the freshness
        check; the honest default when nothing recent/in-flight applies.

    NOTE (v4.14.5.56): retained as a pure helper for headless tests, but the
    RESTORED bar does NOT drive the corner indicator with it — `_state_icon_lbl`
    is owned solely by `_update_freshness_label` (the accurate Idle/Running/
    Paused/Cooldown state). Kept so the audit's behavior contract is preserved
    and a future caller can reuse it.

    'Filling …' / 'Checking …' only show while their dispatch/fetch line is
    RECENT. Pure, case-insensitive."""
    # Real AI call in flight beats everything (truth-table top priority).
    if in_flight:
        return 'Analyzing'
    m = (msg or '').lower()
    if not m:
        return base_state
    # Staleness gate: a log line older than `stale_after` is a finished
    # result, not current state — don't echo it as ongoing activity.
    if msg_age is not None and msg_age > stale_after:
        return base_state
    if '[fill-mode] dispatch' in m:
        for label, path in (('Conservative', 'slow_safe'),
                            ('Moderate', 'moderate'),
                            ('Aggressive', 'aggressive'),
                            ('Speculative', 'lottery')):
            if ('(%s)' % path) in m:
                return 'Filling ' + label
        return 'Filling'
    if '[event-driven] dispatch' in m:
        return 'Analyzing'
    if '[news]' in m or 'deep_news_scan' in m:
        return 'Checking news'
    if '[fundfile]' in m or 'fundamentals' in m:
        return 'Checking fundamentals'
    if 'earnings' in m:
        return 'Checking earnings'
    if 'filings' in m:
        return 'Checking filings'
    return base_state


def gui_path_complete_signal(line, recommend_counts, fill_targets):
    """Return the SET of fill-driven paths whose initial fill pass looks done,
    derived read-only from (a) a recent activity-log `line` and (b) current
    recommend_cache `recommend_counts` {path:(displayed,bench)} vs
    `fill_targets` {path:{displayed_target}}. A path counts complete when its
    displayed count reached target OR fill mode logged it has nothing left to
    analyze / no candidates this cycle. Pure; caller makes flags sticky.

    v4.14.5.56: lottery is NOW a fill-driven path (re-enabled in .55) — included
    here so its dot greens when its initial fill pass completes (it completes
    last, by yield)."""
    done = set()
    # v4.14.6.2-dropdown-fix: four band keys, cheapest -> priciest.
    fill_paths = ('lottery', 'band_5_10', 'band_10_50', 'band_50_up')
    counts = recommend_counts or {}
    targets = fill_targets or {}
    for p in fill_paths:
        d = (counts.get(p) or (0, 0))[0]
        if p == 'lottery':
            # v4.14.5.62-speculative-dot-fix: lottery's displayed_target (10)
            # is structurally unreachable, so green its dot at a REACHABLE
            # floor (_LOTTERY_DOT_MIN, ≥2 picks) — OR via the done-signal
            # below. DISPLAY-ONLY: the fill still targets 10; only the dot
            # threshold changes. Other paths keep `displayed >= target`.
            if d >= _LOTTERY_DOT_MIN:
                done.add(p)
            continue
        t = int(((targets.get(p) or {}).get('displayed_target', 10)) or 10)
        if t > 0 and d >= t:
            done.add(p)
    lm = (line or '').lower()
    if '[fill-mode]' in lm and ('nothing to analyze' in lm
                                or 'no candidates' in lm):
        for p in fill_paths:
            if ('(%s)' % p) in lm:
                done.add(p)
    return done


# ── v4.14.5.14-gui-cleanup-d: Watchlist UI pure helpers ──────────────────
# The Watchlist backend (tm_discover.Watchlist) shipped v4.14.4.3; this
# phase adds the user-facing surface. These helpers do the display logic
# so the tk render code is a thin consumer (unit-testable headless).

def gui_watchlist_dot(direction):
    """Map a ticker's latest-verdict direction to a status-dot kind for the
    Watchlist row / ticker cell. Returns one of 'buy' (green), 'watch'
    (amber), 'avoid' (red), or 'none' (dim — no verdict on record yet).
    Pure, case-insensitive, None-safe."""
    d = (direction or '').strip().upper()
    if d in ('BUY', 'BUY MORE', 'BUYMORE', 'ADD'):
        return 'buy'
    if d in ('WATCH', 'HOLD'):
        return 'watch'
    if d in ('AVOID', 'SELL', 'TRIM'):
        return 'avoid'
    return 'none'


def gui_short_age(ts_iso, now=None):
    """Short human age from an ISO timestamp: '3m' / '2h' / '5d' / '3w'.
    Returns '' when the timestamp is missing or unparseable. Pure (pass
    `now` for deterministic tests)."""
    if not ts_iso:
        return ''
    try:
        ts = datetime.fromisoformat(str(ts_iso))
    except Exception:
        return ''
    now = now or datetime.now()
    secs = (now - ts).total_seconds()
    if secs < 0:
        secs = 0
    mins = secs / 60.0
    if mins < 1:
        return 'just now'
    if mins < 60:
        return f'{int(mins)}m'
    hours = mins / 60.0
    if hours < 24:
        return f'{int(hours)}h'
    days = hours / 24.0
    if days < 14:
        return f'{int(days)}d'
    return f'{int(days / 7)}w'


def gui_ticker_strip_sections(portfolio_tickers, watchlist_tickers):
    """Ordered [(label, [tickers]), ...] for the top ticker strip.
    PORTFOLIO is always present (label shows even when empty — holdings are
    the primary concept); WATCHED appears ONLY when the watchlist is
    non-empty (no orphan label). Pure."""
    sections = [('PORTFOLIO', list(portfolio_tickers or []))]
    wl = list(watchlist_tickers or [])
    if wl:
        sections.append(('WATCHED', wl))
    return sections


def gui_watch_consensus(records):
    """Aggregate recent per-model prediction records for ONE ticker into a
    consensus summary for the Watch card's expanded view (v4.14.5.14-gui-
    cleanup-h). `records` is newest-first (PredictionsLog.get_recent_for_ticker).
    ONE vote per canonical model (most-recent wins), so two providers serving
    the same model count once — matching the consensus engine's dedup. Returns
    {buy, watch, avoid, models, latest_direction, latest_ts, target, stop}.
    NO_CALL / unknown directions are not votes. Pure."""
    seen = set()
    buy = watch = avoid = 0
    latest_direction = latest_ts = target = stop = None
    for r in (records or []):
        if not isinstance(r, dict):
            continue
        cm = r.get('canonical_model') or r.get('model') or r.get('id')
        if cm in seen:
            continue
        seen.add(cm)
        d = (r.get('direction') or '').strip().upper()
        if latest_direction is None:
            # newest record overall (records are newest-first) → header/plan
            latest_direction = d or None
            latest_ts = r.get('timestamp')
            target = r.get('target')
            stop = r.get('stop')
        if d in ('BUY', 'BUY MORE', 'BUYMORE', 'ADD'):
            buy += 1
        elif d in ('WATCH', 'HOLD'):
            watch += 1
        elif d in ('AVOID', 'SELL', 'TRIM'):
            avoid += 1
        # NO_CALL / '' / unknown → not counted as a vote
    return {'buy': buy, 'watch': watch, 'avoid': avoid,
            'models': len(seen), 'latest_direction': latest_direction,
            'latest_ts': latest_ts, 'target': target, 'stop': stop}


# Price-tier presets that DRIVE the existing min/max filter (single
# source of truth = min/max; 0 = "no bound" per existing convention).
_RECO_PRICE_TIERS = [
    ("Any",          (0.0, 0.0)),
    ("Penny (< $1)", (0.0, 0.99)),
    ("$1-$10",       (1.00, 10.00)),
    ("$10-$50",      (10.00, 50.00)),
    ("$50+",         (50.01, 0.0)),
]


def _reco_tier_bounds(tier: str) -> tuple:
    """(min, max) for a price-tier label; ('Any'/unknown → (0.0,0.0))."""
    return dict(_RECO_PRICE_TIERS).get(tier, (0.0, 0.0))


# ── v4.14.5.14-recommend-widget-transparency helpers ─────────────────
# Pure, side-effect-free functions powering the Recommend dialog's
# filter transparency (Parts A/B/C). Kept at module scope so the audit
# can exercise them without standing up a Tk dialog.

def _reco_match_tier_or_custom(price_min, price_max) -> str:
    """Return the _RECO_PRICE_TIERS label whose bounds equal (min, max),
    else 'Custom'. (0.0, 0.0) → 'Any' (the existing no-bound
    convention). This is what the tier dropdown DISPLAYS — so 'Any'
    can no longer sit next to a real $10-$50 band (Part B)."""
    try:
        pmin = round(float(price_min or 0), 2)
        pmax = round(float(price_max or 0), 2)
    except (TypeError, ValueError):
        return "Custom"
    for name, (tmn, tmx) in _RECO_PRICE_TIERS:
        if round(float(tmn), 2) == pmin and round(float(tmx), 2) == pmax:
            return name
    return "Custom"


def _reco_format_band(price_min, price_max) -> str:
    """Human price-band string for labels/messages. 0 = no bound, so
    '$10-$50', '$10+', '≤$50', or 'any price'."""
    try:
        pmin = float(price_min or 0)
        pmax = float(price_max or 0)
    except (TypeError, ValueError):
        return "any price"
    has_min = pmin > 0
    has_max = pmax > 0
    if has_min and has_max:
        return f"${pmin:g}-${pmax:g}"
    if has_min:
        return f"${pmin:g}+"
    if has_max:
        return f"≤${pmax:g}"
    return "any price"


def _reco_resolve_entry_price(pick):
    """v4.14.5.54a-recs-gate-budgetaware-entryfix: resolve a pick's effective
    entry price, working for BOTH shapes that reach the shared filter predicate:

    - RENDER path: picks are already normalized by tm_recommend and carry a
      numeric 'entry'.
    - GATE path: `_read_recommend_cache_picks` returns RAW predictions-log
      records, which DON'T carry 'entry' — they carry buy_zone_low/high and
      current_price_at_prediction (the same fields tm_recommend._normalize_
      prediction derives 'entry' from). Without this, the gate priced every raw
      record at $0 → the price filter (.53) and the budget filter (.54) were
      both INERT on the real gate path (the render worked only because it
      normalizes first). Mirror _normalize_prediction's resolution so the GATE
      prices a pick EXACTLY as the RENDER does. Pure; never raises."""
    try:
        e = pick.get('entry')
        if e not in (None, '', 0, 0.0):
            return float(e)
    except (TypeError, ValueError):
        pass
    try:
        lo = float(pick.get('buy_zone_low') or 0)
    except (TypeError, ValueError):
        lo = 0.0
    try:
        hi = float(pick.get('buy_zone_high') or 0)
    except (TypeError, ValueError):
        hi = 0.0
    if lo > 0 and hi > 0:
        return (lo + hi) / 2.0
    if lo > 0:
        return lo
    if hi > 0:
        return hi
    try:
        return float(pick.get('current_price_at_prediction') or 0)
    except (TypeError, ValueError):
        return 0.0


def _reco_pick_user_filter_reason(pick, price_min, price_max, conviction,
                                  cash=None):
    """v4.14.5.53 / v4.14.5.54: return the USER-CLEARABLE filter that REJECTS
    this pick ('price', 'conviction', or 'budget'), or None if it passes.

    THE single shared implementation: the recs panel's _hard_filter calls this
    for its price/conviction stage (and tallies the reason for the survivor
    summary), AND the recs-gate predicates (_recs_path_has_visible_picks,
    _recs_visible_tickers) call it to count picks that would actually render —
    so the gate and the rendered "X of N survive filters" CANNOT diverge. The
    consensus quality gate is system-driven (not user-clearable) and stays
    render-only; it is NOT part of this user-filter predicate.

    v4.14.5.54-recs-gate-budgetaware: `cash` makes BUDGET one more user-clearable
    filter — a pick the user can't afford even one share of fails with reason
    'budget'. cash=None means "Any" (a brand-new user who hasn't set a budget) →
    budget never rejects, so a fresh user is never dead-ended. Render callers
    pass no cash (budget is applied by the cash sizer downstream); only the
    GATES pass the active cash, so the gate matches what the panel will show.
    Pure; never raises."""
    # v4.14.5.54a: resolve entry for BOTH normalized (render) and raw plog
    # (gate) shapes — raw records carry buy_zone/current_price, not 'entry'.
    entry = _reco_resolve_entry_price(pick)
    try:
        pmin = float(price_min or 0)
        pmax = float(price_max or 0)
    except (TypeError, ValueError):
        pmin = pmax = 0.0
    if (pmin > 0 and entry < pmin) or (pmax > 0 and entry > pmax):
        return 'price'
    pc = (pick.get('conviction', '') or '').lower()
    # v4.14.6.11-fix-empty-recs-render (2026-06-12): predictions written
    # by the Tier-1 scan carry `confidence` (LOW/MODERATE/HIGH from the
    # parser) but no `conviction` field — conviction was added later
    # for UI grouping and the queue's hydration path never backfilled
    # it. When `conviction` is absent, derive it from `confidence` so a
    # saved 'med_plus'/'high' filter rejects only the genuinely-low-
    # confidence picks. Pre-fix every BUY pick had pc='' (None), so a
    # 'med_plus' filter rejected EVERY pick in the band; the panel
    # renderer painted empty even though picks were present in the
    # cache. Mapping: HIGH→high, MODERATE/MEDIUM→medium, LOW→low,
    # anything else→'' (unchanged; treated as low). Treating an absent
    # value as the picks' nearest available signal is strictly safer
    # than silently dropping all of them.
    if not pc:
        _conf = (pick.get('confidence', '') or '').lower()
        pc = {'high': 'high',
              'moderate': 'medium', 'medium': 'medium',
              'low': 'low'}.get(_conf, '')
    conv = (conviction or 'all').lower()
    if conv == 'high' and pc != 'high':
        return 'conviction'
    if conv == 'med_plus' and pc not in ('high', 'medium', 'med'):
        return 'conviction'
    # v4.14.5.54: budget filter. None == "Any" (no constraint). A real budget
    # rejects any pick priced above it (can't afford a single share); an
    # explicit $0 budget rejects everything.
    if cash is not None:
        try:
            c = float(cash)
        except (TypeError, ValueError):
            c = None
        if c is not None and (c <= 0 or (entry > 0 and entry > c)):
            return 'budget'
    return None


def _reco_empty_column_text(eligible_count, drop_reasons, band_str) -> str:
    """v4.14.5.53: name WHY a deployment column is empty. If the user's own
    price/conviction filter hid all picks (eligible 0 + that reason tallied),
    name the real culprit instead of blaming the budget; only a genuine cash
    sizing failure (picks survive the filters but none fit the $ amount) says
    "no positions fit this budget". Pure; never raises."""
    try:
        x = int(eligible_count)
    except (TypeError, ValueError):
        x = 0
    dr = dict(drop_reasons or {})
    if x <= 0:
        if int(dr.get('price', 0) or 0) > 0:
            return f"(no picks match your {band_str} price filter — tap Show all)"
        if int(dr.get('conviction', 0) or 0) > 0:
            return "(no picks match your conviction filter — tap Show all)"
        if int(dr.get('consensus', 0) or 0) > 0:
            return "(no picks cleared the consensus check yet)"
    return "(no positions fit this budget)"


def _reco_survivor_summary(eligible, prefilter, drop_reasons, band_str):
    """Build the survivor-label text + colour key + whether to show the
    [Show all] escape hatch (Part A).

    - eligible: picks that passed the dialog's hard filter (the "X").
    - prefilter: picks before the hard filter (the "Y").
    - drop_reasons: {'price': n, 'conviction': m, 'consensus': k} —
      counts of WHY picks were dropped (first failing reason per pick).
    - band_str: active price band ('$10-$50' …) used to name the
      price filter so the user knows exactly what to relax.

    Returns (text, colour_key, show_clear). colour_key ∈
    {'green','amber','red'}. show_clear is False when nothing the user
    can clear was responsible (e.g. only the consensus gate dropped
    picks) — that drop is not user-fixable via [Show all]."""
    try:
        x = int(eligible)
        y = int(prefilter)
    except (TypeError, ValueError):
        x, y = 0, 0
    dr = dict(drop_reasons or {})
    price_n = int(dr.get('price', 0) or 0)
    conv_n = int(dr.get('conviction', 0) or 0)
    cons_n = int(dr.get('consensus', 0) or 0)
    total_dropped = max(0, y - x)

    # Nothing hidden by the dialog's own filter → legacy phrasing.
    if total_dropped <= 0 or y <= 0:
        colour = 'green' if x >= 3 else 'amber' if x >= 1 else 'red'
        return (f"{x} of {y} pick(s) survive filters", colour, False)

    colour = 'amber' if x >= 1 else 'red'
    # User-clearable reasons get named with their concrete filter; the
    # consensus gate is system-driven (not cleared by [Show all]).
    reasons = []
    if price_n > 0:
        reasons.append((price_n, f"{band_str} price filter"))
    if conv_n > 0:
        reasons.append((conv_n, "conviction filter"))
    if cons_n > 0:
        reasons.append((cons_n, "consensus check"))
    reasons.sort(reverse=True)
    show_clear = (price_n > 0 or conv_n > 0)

    lead = f"0 of {y}" if x == 0 else f"{x} of {y}"
    if not reasons:
        return (f"{lead} — {total_dropped} hidden by filters",
                colour, show_clear)
    top_n, top_label = reasons[0]
    if len(reasons) == 1:
        if x == 0:
            text = f"{lead} — hidden by your {top_label}"
        else:
            text = f"{lead} — {total_dropped} hidden by your {top_label}"
    elif top_n >= 0.8 * total_dropped:
        text = f"{lead} — {total_dropped} hidden (mostly {top_label})"
    else:
        parts = ", ".join(f"{lbl} dropped {n}" for n, lbl in reasons)
        text = f"{lead} — {total_dropped} hidden ({parts})"
    return (text, colour, show_clear)


def _reco_band_change_message(prev_min, prev_max, prev_label,
                              new_min, new_max, new_label):
    """Cue text shown when changing Trading style swaps the active price
    band (Part C). Returns None when the band is unchanged — so the cue
    only fires on a real swap, not on every style change."""
    try:
        pm = round(float(prev_min or 0), 2)
        px = round(float(prev_max or 0), 2)
        nm = round(float(new_min or 0), 2)
        nx = round(float(new_max or 0), 2)
    except (TypeError, ValueError):
        return None
    if pm == nm and px == nx:
        return None
    prev_b = _reco_format_band(pm, px)
    new_b = _reco_format_band(nm, nx)
    return (f"Price band changed to {new_b} (saved for {new_label}). "
            f"Was {prev_b} for {prev_label}. Adjust the filters, or "
            f"click Show all.")


def _v415_get_choices(cfg: dict) -> dict:
    """Read choices from config dict. Returns dict with normalized defaults
    on missing/invalid keys. Never raises."""
    price_ranges = cfg.get('v415_price_ranges')
    style = cfg.get('v415_style')

    valid_price_ids = {pid for (pid, _) in _V415_PRICE_RANGES}
    if not isinstance(price_ranges, list):
        price_ranges = list(_V415_DEFAULT_PRICE_RANGES)
    else:
        price_ranges = [p for p in price_ranges if p in valid_price_ids]
        if not price_ranges:
            price_ranges = list(_V415_DEFAULT_PRICE_RANGES)

    valid_style_ids = {sid for (sid, _) in _V415_STYLES}
    if style not in valid_style_ids:
        style = _V415_DEFAULT_STYLE

    return {'price_ranges': price_ranges, 'style': style}


def _v415_set_choices(cfg: dict, price_ranges: list, style: str) -> None:
    """Write choices to config dict. Does NOT save to disk — caller must
    trigger save_config(cfg) separately."""
    valid_price_ids = {pid for (pid, _) in _V415_PRICE_RANGES}
    valid_style_ids = {sid for (sid, _) in _V415_STYLES}

    cleaned_ranges = [p for p in (price_ranges or []) if p in valid_price_ids]
    if not cleaned_ranges:
        cleaned_ranges = list(_V415_DEFAULT_PRICE_RANGES)
    cleaned_style = style if style in valid_style_ids else _V415_DEFAULT_STYLE

    cfg['v415_price_ranges'] = cleaned_ranges
    cfg['v415_style'] = cleaned_style


def _v415_format_choices_summary(choices: dict) -> str:
    """Format choices as a one-line summary for the main window.
    Example: 'Looking for: $1–$10, $10–$50 · Moderate'"""
    short_range = {
        'penny': 'Penny',
        'low':   '$1–$10',
        'mid':   '$10–$50',
        'high':  '$50+',
    }
    short_style = {
        'conservative': 'Conservative',
        'moderate':     'Moderate',
        'aggressive':   'Aggressive',
        'day_trade':    'Day-trade timing',
    }
    range_labels = [short_range.get(pid, pid)
                     for pid in choices.get('price_ranges', [])]
    ranges_str = ', '.join(range_labels) if range_labels else '(no range)'
    style_str = short_style.get(choices.get('style', ''),
                                  choices.get('style', ''))
    return f"Looking for: {ranges_str} · {style_str}"


def _v415_check_choice_warning(price_ranges: list, style: str) -> str | None:
    """Return rule-based warning text if the combination is in the contradiction
    list, else None. Multi-select-aware: penny+conservative still flags even
    when other ranges are also selected (penny dominates the risk profile)."""
    key_set = frozenset(price_ranges or [])
    direct_key = (key_set, style)
    if direct_key in _V415_CHOICE_WARNINGS:
        return _V415_CHOICE_WARNINGS[direct_key]
    if 'penny' in key_set and style == 'conservative':
        return _V415_CHOICE_WARNINGS[(frozenset({'penny'}), 'conservative')]
    if 'high' in key_set and style == 'day_trade':
        return _V415_CHOICE_WARNINGS[(frozenset({'high'}), 'day_trade')]
    if 'penny' in key_set and style == 'day_trade':
        return _V415_CHOICE_WARNINGS[(frozenset({'penny'}), 'day_trade')]
    return None


def _v415_format_choices_for_prompt(cfg: dict) -> str:
    """v4.15.0 Step 16: Format the user's Choices as a one-line natural-language
    sentence for inclusion in AI prompts.

    Returns '' when choices match defaults exactly (no point spamming every
    prompt with what the AI already implicitly assumes) or when cfg is unset.

    Wired through PromptBuilder's user_preferences_fn so the same call site
    sees the latest choices when the user changes them mid-session.
    """
    # v4.14.5.14a.7: the Choices dialog was removed; user intent is now
    # set at view time in Portfolio Recommendations. This soft prompt
    # sentence (a near-no-op per the a.5 investigation) is retired —
    # always return '' so prompts carry no Choices preference line.
    # Body below kept as inert dead code to avoid orphaning refs in
    # this 19k-line unrunnable-here tkinter file (flagged in report).
    return ''
    try:
        choices = _v415_get_choices(cfg)
    except Exception:
        return ''

    price_ranges = choices.get('price_ranges') or []
    style = choices.get('style') or ''

    if (set(price_ranges) == set(_V415_DEFAULT_PRICE_RANGES)
            and style == _V415_DEFAULT_STYLE):
        return ''

    range_phrases = []
    for pid in price_ranges:
        if pid == 'penny':
            range_phrases.append('penny stocks (under $1)')
        elif pid == 'low':
            range_phrases.append('$1-$10')
        elif pid == 'mid':
            range_phrases.append('$10-$50')
        elif pid == 'high':
            range_phrases.append('$50+')

    if not range_phrases:
        ranges_str = 'any price range'
    elif len(range_phrases) == 1:
        ranges_str = range_phrases[0]
    elif len(range_phrases) == 2:
        ranges_str = f"{range_phrases[0]} and {range_phrases[1]}"
    else:
        ranges_str = ', '.join(range_phrases[:-1]) + f", and {range_phrases[-1]}"

    style_phrases = {
        'conservative': ('a conservative, long-hold style — capital '
                          'preservation and stable returns matter more than '
                          'upside'),
        'moderate':     'a moderate trading style',
        'aggressive':   ('an aggressive trading style — willing to accept '
                          'higher risk for higher potential return'),
        'day_trade':    ('a day-trade timing focus — short-term moves and '
                          'momentum matter (note: this app does not execute '
                          'intraday trades)'),
    }
    style_str = style_phrases.get(style, 'a moderate trading style')

    return f"User preferences: looking at {ranges_str} with {style_str}."


# ─── v4.15.0 Step 18: Fill-mode picker ───────────────────────────────────────

def _v415_apply_fill_mode_to_lanes(mode: str) -> None:
    """v4.15.0 Step 18: Apply the picker selection to lane_config for every
    bulk-fillable lane. mode must be one of FILL_MODE_BULK / FILL_MODE_SERVER /
    FILL_MODE_INCREMENTAL. Per-lane errors swallowed so a single failure
    doesn't abort the others."""
    for lane in tm_cache.BULK_FILLABLE_LANES:
        try:
            tm_cache.set_lane_config(lane, mode)
        except Exception:
            pass


# v4.15.0 Step 22a: Available universes for the picker dropdown.
# Tuple shape: (id, display_name, approx_size, tm_discover_source_key)
# The 4th field maps the user-facing ID to the actual key consumed by
# tm_discover.Universe.SOURCES (so 'sp500' → 'ivv', 'russell3000' → 'iwv',
# 'dow' → 'dow' (hardcoded), etc.).
_V415_UNIVERSES = (
    ('dow',         'Dow 30',                 '~30',     'dow'),
    ('nasdaq100',   'NASDAQ-100',             '~100',    'nasdaq100'),
    ('sp500',       'S&P 500',                '~500',    'ivv'),
    ('russell1000', 'Russell 1000',           '~1,000',  'iwb'),
    ('russell2000', 'Russell 2000',           '~2,000',  'iwm'),
    # v4.14.6.25: label updated — the iShares IWV holdings export currently
    # returns ~7,200 lines (one per security position, not per index name),
    # so the picker reflects the actual fetch size rather than the index's
    # nominal 3,000-name target.
    ('russell3000', 'Russell 3000 (IWV holdings ~7,200)', '~7,200', 'iwv'),
    ('itot',        'Everything — US Total Market (ITOT)',
                                                '~2,500',  'itot'),
)

_V415_DEFAULT_UNIVERSE = 'russell3000'  # v4.14.6.25: IWV holdings export ~7,200; was 'sp500' (~503). Russell 3000 (IWV) is the honest default.


def _v415_universe_source_for(universe_id: str) -> str:
    """Translate a v4.15.0 universe id (e.g. 'sp500') to the underlying
    tm_discover.Universe source key (e.g. 'ivv'). Falls back to the
    default-universe's source on unknown input."""
    for (uid, _name, _size, src) in _V415_UNIVERSES:
        if uid == universe_id:
            return src
    for (uid, _name, _size, src) in _V415_UNIVERSES:
        if uid == _V415_DEFAULT_UNIVERSE:
            return src
    return 'iwv'


def _v415_estimate_universe_size(universe_id: str, choices: dict) -> int:
    """v4.15.0 Step 22a: Rough estimate of how many tickers fall in scope for
    a universe + Choices combination. Used for picker time estimates only;
    the actual fill loop reads the real tickers list at runtime.

    The price-range fractions are coarse market-knowledge approximations —
    large-cap universes (S&P 500, NASDAQ-100, Dow 30) skew toward $10+; the
    Russell 2000 / ITOT include more sub-$10 names."""
    # v4.14.6.25: IWV holdings file ships ~7,200 positions (not 3,000) —
    # the prior 3000 here under-estimated fill-cycle budgets ~2.4×.
    # Other universes left at their nominal index-name sizes (the
    # subset filters keep them accurate).
    base_sizes = {
        'dow':         30,
        'nasdaq100':   100,
        'sp500':       500,
        'russell1000': 1000,
        'russell2000': 2000,
        'russell3000': 7200,
        'itot':        3500,
    }
    base = base_sizes.get(universe_id, 500)

    # Large-cap default — penny names rare.
    range_fractions = {
        'penny': 0.05,
        'low':   0.15,
        'mid':   0.40,
        'high':  0.40,
    }
    if universe_id in ('russell2000', 'itot'):
        range_fractions = {
            'penny': 0.15, 'low': 0.30, 'mid': 0.30, 'high': 0.25,
        }
    elif universe_id == 'russell3000':
        range_fractions = {
            'penny': 0.10, 'low': 0.25, 'mid': 0.35, 'high': 0.30,
        }

    price_ranges = (choices or {}).get('price_ranges') or []
    if not price_ranges:
        return base

    fraction = sum(range_fractions.get(r, 0.0) for r in price_ranges)
    return max(1, int(base * fraction))




_fundamentals_cache = {}  # {ticker: (data, timestamp)}

def yahoo_fundamentals(ticker):
    """Get fundamentals — uses fast_info for speed, full .info only once per hour."""
    now = time.time()
    cached = _fundamentals_cache.get(ticker)
    if cached and now - cached[1] < 3600:  # Cache 1 hour
        return cached[0]
    try:
        t = _get_yf_ticker(ticker)
        result = {}
        # fast_info is much faster (~0.3s vs ~2s)
        try:
            fi = t.fast_info
            if fi:
                result['marketCap'] = getattr(fi, 'market_cap', None)
                result['fiftyTwoWeekHigh'] = getattr(fi, 'year_high', None)
                result['fiftyTwoWeekLow'] = getattr(fi, 'year_low', None)
                result['averageVolume'] = getattr(fi, 'three_month_average_volume', None)
        except Exception:
            pass
        # Full .info only if we don't have cached fundamentals yet
        if not cached:
            try:
                info = t.info
                for k in ["trailingPE","forwardPE","trailingEps","dividendYield","beta",
                          "sector","shortRatio","targetMeanPrice","recommendationKey",
                          "profitMargins","revenueGrowth","debtToEquity"]:
                    v = info.get(k)
                    if v is not None:
                        result[k] = v
            except Exception:
                pass
        else:
            # Reuse old fundamentals, just update fast_info fields
            old = cached[0]
            for k, v in old.items():
                if k not in result:
                    result[k] = v
        result = {k: v for k, v in result.items() if v is not None}
        _fundamentals_cache[ticker] = (result, now)
        # v4.15.0 step 5: tap into cache.fundamentals. Side-effect only.
        try:
            _v415_cache_write_fundamentals(ticker, result, source='yahoo')
        except Exception:
            pass
        return result
    except Exception:
        return {}


# ── Earnings date detection ──
_earnings_cache = {}  # {ticker: (earnings_date, check_time)}

def check_earnings_date(ticker):
    """Check if a stock has earnings coming up within 14 days.
    Returns (days_until_earnings, date_str) or (None, None)."""
    now = datetime.now()
    # Cache for 12 hours
    if ticker in _earnings_cache:
        edate, check_time = _earnings_cache[ticker]
        if (now - check_time).total_seconds() < 43200:
            if edate:
                days = (edate - now.date()).days
                return (days, edate.isoformat()) if 0 <= days <= 14 else (None, None)
            return None, None
    try:
        t = _get_yf_ticker(ticker)
        cal = t.calendar
        if cal is not None and not cal.empty:
            # Calendar can be a DataFrame or dict depending on yfinance version
            if hasattr(cal, 'iloc'):
                edate = pd.Timestamp(cal.iloc[0, 0]).date()
            elif isinstance(cal, dict):
                ed = cal.get('Earnings Date', [None])
                edate = pd.Timestamp(ed[0]).date() if ed and ed[0] else None
            else:
                edate = None
        else:
            edate = None
        _earnings_cache[ticker] = (edate, now)
        if edate:
            days = (edate - now.date()).days
            if 0 <= days <= 14:
                return days, edate.isoformat()
    except Exception:
        _earnings_cache[ticker] = (None, now)
    return None, None


# --- Source 2: Stooq ---
def stooq_quote(ticker):
    raw = _fetch(f"https://stooq.com/q/l/?s={ticker.lower()}.us&f=sd2t2ohlcvn&h&e=csv")
    if not raw:
        return None
    try:
        lines = raw.strip().split("\n")
        if len(lines) < 2:
            return None
        h = lines[0].split(","); v = lines[1].split(",")
        d = dict(zip(h, v))
        price = float(d.get("Close", 0))
        opn = float(d.get("Open", 0))
        if price <= 0:
            return None
        return {"source": "Stooq", "ticker": ticker, "price": round(price, 2),
                "change_pct": round(((price - opn) / opn * 100) if opn else 0, 2),
                "volume": float(d.get("Volume", 0))}
    except Exception:
        return None

def stooq_history(ticker, days=180):
    raw = _fetch(f"https://stooq.com/q/d/l/?s={ticker.lower()}.us&i=d", timeout=15)
    if not raw or len(raw) < 50:
        return None
    try:
        df = pd.read_csv(StringIO(raw))
        if "Date" in df.columns:
            df["Date"] = pd.to_datetime(df["Date"])
            df = df.set_index("Date").sort_index()
        return df.tail(days) if len(df) > 0 else None
    except Exception:
        return None


def stooq_history_cached(ticker, period="1y"):
    """v4.14.5.42-price-spread-foundations (Move 2, Foundation A): Stooq
    daily-bars fetch + the SAME daily_bars cache tap yahoo_history's Stooq
    Tier-2 uses, so the data router's `stooq` 'history' adapter fills the
    cache identically to the Yahoo path (no schema difference whether a bar
    came from Yahoo or Stooq).

    Per-ticker by nature — Stooq has no batch API (this is NOT a faked batch).
    Maps yfinance-style period strings to Stooq's days param exactly as the
    yahoo_history Stooq tier does. Returns the DataFrame (or None). The cache
    write is a side-effect; callers that just want the frame get it.
    """
    period_to_days = {
        "1mo": 30, "3mo": 90, "6mo": 180,
        "1y": 365, "2y": 730, "5y": 1825,
        "10y": 3650, "max": 7300,
    }
    days = period_to_days.get(period, 365)
    df = stooq_history(ticker, days=days)
    if df is not None and not df.empty:
        try:
            _v415_cache_write_bars(ticker, df)
        except Exception:
            # Cache writes must never break the data path.
            pass
    return df


# --- Source 3: Google Finance ---
def google_quote(ticker):
    if not HAS_BS4:
        return None
    for exchange in ["NASDAQ", "NYSE"]:
        raw = _fetch(f"https://www.google.com/finance/quote/{ticker}:{exchange}")
        if not raw:
            continue
        try:
            soup = BeautifulSoup(raw, "html.parser")
            el = soup.find("div", {"data-last-price": True})
            if el:
                price = float(el["data-last-price"])
                pct = float(el.get("data-last-normal-market-change-percent", 0)) * 100
                return {"source": "Google", "ticker": ticker,
                        "price": round(price, 2), "change_pct": round(pct, 2)}
        except Exception:
            continue
    return None


