def _try_server_macro_cache():
    """Try to fetch the cached macro snapshot from our server.

    Returns a dict with FRED + CNN F&G + Treasury data if the server
    has it cached, else None. Falls through silently to direct
    fetching if the server is down or the endpoint isn't deployed.

    The point: at scale, 1000 users hitting FRED+CNN independently
    every analysis round wastes bandwidth and risks rate limits.
    The server fetches once per hour and serves the cached values
    to all clients. Total external API hits: 1 per hour instead of
    thousands per round.

    In-memory TTL cache: dedupe calls within a 60-second window so
    fred_macro_snapshot() and cnn_fear_greed() called back-to-back
    only do one server hit per round, not two.
    """
    global _macro_server_cache, _macro_server_cache_at
    now_t = time.time()
    if _macro_server_cache is not None and (now_t - _macro_server_cache_at) < 60:
        return _macro_server_cache  # may be a dict OR None, both valid

    try:
        import urllib.request
        import json as _json
        url = API_BASE_URL.rstrip('/') + '/api/macro/snapshot'
        req = urllib.request.Request(url, headers={
            'User-Agent': f'TiredMarket/{APP_VERSION}'
        })
        with urllib.request.urlopen(req, timeout=8) as resp:
            if resp.status == 200:
                raw = resp.read().decode('utf-8')
                data = _json.loads(raw)
                if isinstance(data, dict) and data:
                    _macro_server_cache = data
                    _macro_server_cache_at = now_t
                    return data
    except Exception:
        pass  # silent fallback - not a problem if server isn't deployed

    # Cache the negative result too, so we don't keep retrying
    # for the next 60 sec if the server is unreachable.
    _macro_server_cache = None
    _macro_server_cache_at = now_t
    return None


# Module-level TTL cache for the macro server lookup
_macro_server_cache = None
_macro_server_cache_at = 0.0


def fred_latest(series_id):
    end = datetime.now(); start = end - timedelta(days=60)
    url = (f"https://fred.stlouisfed.org/graph/fredgraph.csv?id={series_id}"
           f"&cosd={start:%Y-%m-%d}&coed={end:%Y-%m-%d}")
    raw = _fetch(url, timeout=12)
    if not raw or len(raw) < 30:
        return None
    try:
        df = pd.read_csv(StringIO(raw))
        df.columns = ["date", "value"]
        df["value"] = pd.to_numeric(df["value"], errors="coerce")
        df = df.dropna()
        if len(df) == 0:
            return None
        return round(float(df.iloc[-1]["value"]), 4)
    except Exception:
        return None

def fred_macro_snapshot():
    """Get FRED macro indicators (treasury yields, VIX, fed rate, unemployment).

    Tries the server's cached snapshot first (1 fast API call instead
    of 5 separate FRED hits). Falls back to direct FRED fetching if
    the server is unreachable or hasn't deployed the cache endpoint.
    """
    # Try server cache first - returns FRED data if available
    cached = _try_server_macro_cache()
    if cached and isinstance(cached.get('fred'), dict):
        snap = dict(cached['fred'])
        # Add yield spread if both present (server may not compute it)
        if 'treasury_10y' in snap and 'treasury_2y' in snap and 'yield_spread' not in snap:
            snap['yield_spread'] = round(snap['treasury_10y'] - snap['treasury_2y'], 4)
        return snap

    # Fallback: direct FRED fetch (the original behavior)
    snap = {}
    for name, sid in FRED_SERIES.items():
        val = fred_latest(sid)
        if val is not None:
            snap[name] = val
    # Yield spread
    if "treasury_10y" in snap and "treasury_2y" in snap:
        snap["yield_spread"] = round(snap["treasury_10y"] - snap["treasury_2y"], 4)
    return snap


# --- Source 5: CNN Fear & Greed ---
def cnn_fear_greed():
    """Get the CNN Fear & Greed index value (0-100) and rating.

    Tries the server's cached snapshot first. CNN F&G is the same
    value globally - 1000 users fetching it independently is wasteful.
    Server caches it for 5 minutes, refreshes once.
    """
    # Try server cache first
    cached = _try_server_macro_cache()
    if cached and isinstance(cached.get('fear_greed'), dict):
        fg = cached['fear_greed']
        if 'value' in fg:
            return {"value": fg['value'], "rating": fg.get('rating', 'Neutral')}

    # Fallback: direct CNN fetch (the original behavior)
    data = _fetch_json("https://production.dataviz.cnn.io/index/fearandgreed/graphdata")
    if data and "fear_and_greed" in data:
        fg = data["fear_and_greed"]
        return {"value": round(fg.get("score", 50), 1),
                "rating": fg.get("rating", "Neutral")}
    return None


# --- Source 6: Finviz ---
def finviz_data(ticker):
    if not HAS_BS4:
        return {}
    raw = _fetch(f"https://finviz.com/quote.ashx?t={ticker.upper()}&ty=c&p=d&b=1")
    if not raw:
        return {}
    try:
        soup = BeautifulSoup(raw, "html.parser")
        data = {}
        # Find the snapshot table
        for table in soup.find_all("table"):
            cells = table.find_all("td")
            if len(cells) > 20:
                for i in range(0, len(cells) - 1, 2):
                    key = cells[i].get_text(strip=True)
                    val = cells[i + 1].get_text(strip=True)
                    if key:
                        data[key] = val

        parsed = {}
        for raw_key, clean_key in [
            ("P/E", "pe"), ("RSI (14)", "rsi"), ("Rel Volume", "rel_vol"),
            ("Short Float", "short_float"), ("SMA20", "sma20_dist"),
            ("SMA50", "sma50_dist"), ("SMA200", "sma200_dist"),
            ("Perf Week", "perf_week"), ("Perf Month", "perf_month"),
            ("Beta", "beta"), ("Target Price", "target"), ("Volatility", "volatility"),
        ]:
            v = data.get(raw_key, "")
            if v and v != "-":
                try:
                    parsed[clean_key] = float(v.replace("%", "").replace(",", ""))
                except ValueError:
                    pass
        return parsed
    except Exception:
        return {}

def finviz_sentiment(ticker):
    if not HAS_BS4:
        return 0, []
    raw = _fetch(f"https://finviz.com/quote.ashx?t={ticker.upper()}")
    if not raw:
        return 0, []
    try:
        soup = BeautifulSoup(raw, "html.parser")
        table = soup.find("table", id="news-table")
        if not table:
            return 0, []
        headlines = []
        for row in table.find_all("tr")[:12]:
            link = row.find("a")
            if link:
                headlines.append(link.get_text(strip=True))

        # Use unified VADER-powered scorer (falls back to keywords if unavailable).
        # _score_headline returns -100..+100 per headline; we average for a
        # headline-count-normalized composite score.
        if not headlines:
            return 0, []
        scored = [_score_headline(h) for h in headlines]
        avg = sum(scored) / len(scored)
        # Scale to the same -50..+50 range this function used to return.
        normalized = round(avg / 2, 1)
        return normalized, headlines[:3]
    except Exception:
        return 0, []


# --- Source 7: RSS News ---
RSS_FEEDS = [
    "https://feeds.marketwatch.com/marketwatch/topstories/",
    "https://search.cnbc.com/rs/search/combinedcms/view.xml?partnerId=wrss01&id=100003114",
    "https://news.google.com/rss/search?q=stock+market&hl=en-US&gl=US&ceid=US:en",
]

def rss_sentiment(ticker):
    all_headlines = []
    for url in RSS_FEEDS:
        raw = _fetch(url, timeout=8)
        if not raw:
            continue
        try:
            root = ET.fromstring(raw)
            for item in root.iter("item"):
                title = item.findtext("title", "")
                if title:
                    all_headlines.append(title)
        except Exception:
            continue

    # Use unified VADER-powered scorer. Only score headlines that mention
    # this ticker — general market news isn't attributable to this stock.
    mentions = 0
    score_sum = 0
    relevant = []
    for h in all_headlines:
        if ticker.lower() in h.lower():
            mentions += 1
            relevant.append(h)
            # _score_headline returns -100..+100; scale to -50..+50 range
            score_sum += _score_headline(h) / 2
    avg = score_sum / max(mentions, 1)
    return round(avg, 1), mentions, relevant[:3]


# ═══════════════════════════════════════════════════════════════════════════
# DEEP NEWS ENGINE — Searches every 5 hours per ticker
# ═══════════════════════════════════════════════════════════════════════════
POS_WORDS = [
    "surge","jump","rally","gain","beat","upgrade","bullish","growth","soar",
    "rise","strong","buy","profit","record","outperform","positive","boom",
    "exceed","optimistic","momentum","breakout","upside","dividend","expand",
    "improve","recovery","innovation","partnership","launch","contract","deal",
    "acquire","revenue","earnings beat","raised guidance","price target raised",
    "initiated buy","overweight","accumulate","top pick"
]
NEG_WORDS = [
    "drop","fall","crash","decline","loss","miss","bearish","downgrade","sell",
    "weak","cut","fear","risk","plunge","sink","down","negative","concern",
    "warning","lawsuit","recall","investigation","probe","layoff","restructure",
    "debt","default","bankruptcy","fraud","scandal","underperform","reduce",
    "price target cut","earnings miss","lowered guidance","overvalued","bubble",
    "sell-off","correction","halt","delist","fine","penalty","underweight"
]

def _score_headline(headline):
    """Score a single headline from -100 to +100.

    Primary: VADER sentiment analyzer. VADER understands negation
    ("failed to drop" = positive), intensifiers ("absolutely terrible"),
    punctuation/caps emphasis, and is far more reliable than keyword lists.

    Fallback: if VADER is not installed or errors, use POS_WORDS/NEG_WORDS
    keyword scoring so the app still works.

    Financial tone boost: VADER was trained on social media, not finance.
    A small keyword-based boost adds back some domain awareness without
    replacing VADER's context sensitivity.
    """
    if not headline:
        return 0
    # --- Primary: VADER ---
    if HAS_VADER and _vader is not None:
        try:
            scores = _vader.polarity_scores(headline)
            # compound is in [-1, +1]; scale to [-100, +100]
            base = scores.get('compound', 0.0) * 100
            # Small finance-domain nudge: if strong finance-specific words
            # appear, lean the score slightly in that direction (max ±15).
            hl = headline.lower()
            finance_pos_hits = sum(1 for p in POS_WORDS if p in hl)
            finance_neg_hits = sum(1 for n in NEG_WORDS if n in hl)
            nudge = (finance_pos_hits - finance_neg_hits) * 3
            nudge = max(-15, min(15, nudge))
            return max(-100, min(100, base + nudge))
        except Exception:
            # Fall through to keyword scoring
            pass
    # --- Fallback: keyword scoring (original logic) ---
    hl = headline.lower()
    pos = sum(2 if phrase in hl else 0 for phrase in POS_WORDS)
    neg = sum(2 if phrase in hl else 0 for phrase in NEG_WORDS)
    raw = pos - neg
    return max(-100, min(100, raw * 10))

def _rss_extract_articles(raw_xml: str, source_id: str,
                            ticker_filter: str | None = None,
                            min_title_len: int = 10) -> list[dict]:
    """v4.14.2 stage 2: parse an RSS feed body into article dicts with
    title + url + pub_date + summary populated from the standard
    <item> fields. ticker_filter, when set, requires the ticker
    substring to appear in the title (case-insensitive) — used by
    feeds that are general-purpose (MarketWatch, CNBC, Benzinga,
    Investing) where we mine the firehose for ticker-specific
    mentions. Sentiment is scored locally via _score_headline and
    normalized to the [-1, +1] range that the merge layer expects.
    """
    out: list[dict] = []
    try:
        root = ET.fromstring(raw_xml)
    except Exception:
        return out
    tf = ticker_filter.lower() if ticker_filter else None
    for item in root.iter("item"):
        title = (item.findtext("title", "") or "").strip()
        if not title or len(title) <= min_title_len:
            continue
        if tf and tf not in title.lower():
            continue
        url = (item.findtext("link", "") or "").strip()
        pub_date = (item.findtext("pubDate", "") or "").strip()
        summary = (item.findtext("description", "") or "").strip()[:500]
        out.append({
            'title':     title,
            'url':       url,
            'pub_date':  pub_date,
            'summary':   summary,
            'source':    source_id,
            # _score_headline returns [-100, +100]; normalize to the
            # [-1, +1] range Finnhub/Yahoo use so the merge averages
            # comparable values.
            'sentiment': _score_headline(title) / 100.0,
        })
    return out


def _search_ticker_news(ticker, enabled_sources=None):
    """Deep search for ticker-specific news from enabled RSS sources.

    v4.14.2 stage 2: returns a list of article dicts (title, url,
    pub_date, summary, source, sentiment) instead of the prior
    (title, source, score) 3-tuples. URL extraction is the
    enabling change for the parallel-merge architecture in
    deep_news_scan — without URLs we can't dedup across sources.
    Within-source dedup uses the canonical URL; falls back to
    title-prefix matching for items missing a <link>.
    """
    articles: list[dict] = []
    enabled = enabled_sources or DEFAULT_SOURCES

    # v4.14.2 stage 3: Google News RSS was promoted out of this
    # bundle to its own top-level fetcher (_news_via_google_news)
    # for independent attribution + timeout. The "GoogleNews" key
    # in enabled_sources is now a no-op here — it's still recognized
    # for backward-compat but the Google News fetch happens upstream
    # in deep_news_scan's parallel-fire list.

    # Yahoo Finance RSS
    if "YahooNews" in enabled:
        url = (f"https://feeds.finance.yahoo.com/rss/2.0/headline?"
               f"s={ticker}&region=US&lang=en-US")
        raw = _fetch(url, timeout=8)
        if raw:
            articles.extend(_rss_extract_articles(raw, "yahoo_rss"))

    # Finviz news (HTML scrape — no URL/pubDate available; emit
    # title-only article dicts so they still flow through the merge.)
    if "Finviz" in enabled:
        try:
            fv_sent, fv_headlines = finviz_sentiment(ticker)
            for h in fv_headlines:
                articles.append({
                    'title':     h,
                    'url':       '',
                    'pub_date':  '',
                    'summary':   '',
                    'source':    'finviz',
                    'sentiment': _score_headline(h) / 100.0,
                })
        except Exception:
            pass

    # MarketWatch RSS — firehose, ticker substring filter
    if "MarketWatch" in enabled:
        raw = _fetch("https://feeds.marketwatch.com/marketwatch/topstories/",
                     timeout=6)
        if raw:
            articles.extend(_rss_extract_articles(
                raw, "marketwatch", ticker_filter=ticker))

    # CNBC — firehose, ticker substring filter
    if "CNBC" in enabled:
        raw = _fetch("https://search.cnbc.com/rs/search/combinedcms/"
                     "view.xml?partnerId=wrss01&id=100003114", timeout=6)
        if raw:
            articles.extend(_rss_extract_articles(
                raw, "cnbc", ticker_filter=ticker))

    # Seeking Alpha RSS — ticker-specific feed
    if "SeekingAlpha" in enabled:
        raw = _fetch(
            f"https://seekingalpha.com/api/sa/combined/{ticker}.xml",
            timeout=6)
        if raw:
            articles.extend(_rss_extract_articles(raw, "seekingalpha"))

    # Reuters via Google News
    if "Reuters" in enabled:
        raw = _fetch(
            f"https://news.google.com/rss/search?q={ticker}+reuters"
            f"&hl=en-US", timeout=6)
        if raw:
            articles.extend(_rss_extract_articles(raw, "reuters"))

    # Benzinga RSS — firehose, ticker substring filter
    if "Benzinga" in enabled:
        raw = _fetch("https://www.benzinga.com/feed", timeout=6)
        if raw:
            articles.extend(_rss_extract_articles(
                raw, "benzinga", ticker_filter=ticker))

    # Investing.com RSS — firehose, ticker substring filter
    if "Investing" in enabled:
        raw = _fetch("https://www.investing.com/rss/market_overview.rss",
                     timeout=6)
        if raw:
            articles.extend(_rss_extract_articles(
                raw, "investing", ticker_filter=ticker))

    # Within-RSS dedup: prefer URL match; fall back to title prefix.
    # Cross-source dedup happens in _merge_news_articles below.
    seen: set[str] = set()
    unique: list[dict] = []
    for art in articles:
        key = (_canon_news_url(art.get('url', ''))
                or art['title'][:50].lower().strip())
        if key in seen:
            continue
        seen.add(key)
        unique.append(art)
    return unique


# ─── v4.14.2 stage 2: news merge architecture ─────────────────────────
#
# deep_news_scan now fires every enabled news source in parallel
# (RSS bundle + Yahoo via direct adapter + Finnhub via direct adapter)
# and merges the results by canonical URL. Per-source timeout is
# bounded so one slow source doesn't block the merge. Source
# attribution is tracked through the merge for future surfaces;
# today's prompt block still consumes only the merged title list.
#
# Plumbing for future sources: extend the `fetchers` list in
# deep_news_scan with a new (source_id, callable) tuple. The
# callable returns a list of normalized article dicts. No changes
# to the merge function or downstream code needed.

_NEWS_PER_SOURCE_TIMEOUT_SEC = 10.0
_DATA_FETCH_ERROR_LOG = "data_fetch_errors.log"


def _log_data_fetch_error(context: str, exc) -> None:
    """v4.14.2 stage 2: append a structured entry to
    data/data_fetch_errors.log (the file v4.14.1.3 hot patch
    introduced for code-bug exceptions in _fetch_technicals). All
    write paths here are best-effort — never raise from inside a
    logger because the caller is already in an error path.
    """
    try:
        import traceback as _tb
        path = USER_DATA_DIR / _DATA_FETCH_ERROR_LOG
        with open(path, 'a', encoding='utf-8') as f:
            f.write(
                f"\n=== {datetime.now().isoformat()} {context} "
                f"{type(exc).__name__}: {exc} ===\n")
            f.write(_tb.format_exc())
    except Exception:
        pass


def _canon_news_url(url) -> str:
    """Lowercase + strip trailing slash. Sufficient for the
    common-case URL match across Finnhub / Yahoo / RSS where the
    same article tends to come back with the same canonical URL.
    Future fuzzy matching (strip utm_*, fbclid, host normalization)
    is deferred to a later stage."""
    if not url:
        return ''
    u = str(url).strip().lower()
    if u.endswith('/'):
        u = u[:-1]
    return u


def _normalize_news_article(raw, source_id: str) -> dict | None:
    """Convert an adapter-returned headline dict (Finnhub / Yahoo
    shape) into the common pre-merge article shape. Returns None for
    items missing a usable title."""
    if not isinstance(raw, dict):
        return None
    title = (raw.get('title') or '').strip()
    if not title or len(title) < 5:
        return None
    # Finnhub uses 'timestamp_iso'; Yahoo's adapter passes through
    # the same key. RSS uses 'pub_date'. Accept either.
    pub_date = (raw.get('pub_date')
                 or raw.get('timestamp_iso')
                 or '').strip()
    return {
        'title':     title,
        'url':       (raw.get('url') or '').strip(),
        'pub_date':  pub_date,
        'summary':   (raw.get('summary') or '').strip()[:500],
        'source':    source_id,
        'sentiment': float(raw.get('sentiment', 0.0) or 0.0),
    }


def _news_via_yahoo(ticker: str) -> list[dict]:
    """Direct-adapter call. Bypasses router priority so the merge
    sees Yahoo's results regardless of whether Finnhub is also
    serving."""
    try:
        import tm_data_providers as _tdp
        import tm_data_adapter_yahoo as _tda
        reg = _tdp.get_registry()
        if reg is None:
            return []
        prof = reg.get('yahoo')
        if not prof or not prof.is_usable():
            return []
        result = _tda.yahoo_adapter(prof, 'news', ticker=ticker)
        if not isinstance(result, dict):
            return []
        out = []
        for h in (result.get('headlines') or []):
            art = _normalize_news_article(h, 'yahoo')
            if art is not None:
                out.append(art)
        return out
    except Exception as e:
        _log_data_fetch_error(
            f"deep_news_scan source=yahoo ticker={ticker}", e)
        return []


def _news_via_finnhub(ticker: str) -> list[dict]:
    """Direct-adapter call. Returns [] if Finnhub is disabled or
    has no key."""
    try:
        import tm_data_providers as _tdp
        import tm_data_adapter_finnhub as _tdf
        reg = _tdp.get_registry()
        if reg is None:
            return []
        prof = reg.get('finnhub')
        if not prof or not prof.is_usable():
            return []
        result = _tdf.adapter(prof, 'news', ticker=ticker, days_back=7)
        if not isinstance(result, dict):
            return []
        out = []
        for h in (result.get('headlines') or []):
            art = _normalize_news_article(h, 'finnhub')
            if art is not None:
                out.append(art)
        return out
    except Exception as e:
        _log_data_fetch_error(
            f"deep_news_scan source=finnhub ticker={ticker}", e)
        return []


def _news_via_rss(ticker: str, enabled_sources=None) -> list[dict]:
    """Wrap _search_ticker_news for the parallel-fetch loop. Each
    article already carries its specific RSS source name (e.g.
    'yahoo_rss', 'finviz', 'reuters'), so the merge keeps that
    granular attribution rather than collapsing to a single 'rss' tag.

    v4.14.2 stage 3: Google News RSS was promoted out of this bundle
    to its own top-level fetcher (_news_via_google_news) so it gets
    independent attribution + an independent timeout slice. The
    GoogleNews branch of _search_ticker_news no longer fires.

    Errors here go to the data-fetch error log instead of bubbling
    so one bad RSS feed doesn't take down the whole batch."""
    try:
        return _search_ticker_news(ticker, enabled_sources) or []
    except Exception as e:
        _log_data_fetch_error(
            f"deep_news_scan source=rss ticker={ticker}", e)
        return []


def _news_via_google_news(ticker: str) -> list[dict]:
    """v4.14.2 stage 3: Google News RSS as a top-level keyless news
    source. Promoted out of the _search_ticker_news RSS bundle so it
    gets its own attribution slot in the by_source counts and its own
    timeout slice in the parallel fetch.

    Endpoint: https://news.google.com/rss/search?q=<TICKER>+stock&...
    No API key required. Returns standard RSS 2.0 XML which
    _rss_extract_articles can parse directly. Articles tagged
    'google_news' so the merge keeps the granular attribution.

    Wrinkle: Google News links are redirector URLs of the form
    https://news.google.com/rss/articles/<base64> rather than
    publisher-canonical URLs. Cross-source URL dedup against
    Yahoo's finance.yahoo.com URLs and Finnhub's finnhub.io
    redirector URLs will continue to find zero matches — same
    URL-format-divergence pattern stage 2 documented. Within-source
    dedup still works (same Google News article won't appear twice).
    Future fuzzy-title matching is the path to cross-source dedup.

    Rate limits: Google News doesn't publish hard limits but throttles
    aggressively on heavy use. One ticker-specific request per news
    fetch cycle is well within polite-use territory.

    Errors go to the data-fetch error log; returns [] on parse
    failure or unexpected exception so the merge proceeds with
    whatever else returned."""
    # v4.15.0 Step 12: offline short-circuit.
    try:
        import tm_network as _tmn
        if not _tmn.is_online():
            return []
    except Exception:
        pass
    try:
        url = (f"https://news.google.com/rss/search?q={ticker}+stock"
               f"&hl=en-US&gl=US&ceid=US:en")
        raw = _fetch(url, timeout=8)
        if not raw:
            return []
        return _rss_extract_articles(raw, "google_news") or []
    except Exception as e:
        _log_data_fetch_error(
            f"deep_news_scan source=google_news ticker={ticker}", e)
        return []


def _parse_news_date_to_epoch(s) -> float:
    """v4.14.2 stage 2 polish: parse a pub_date string into epoch
    seconds for sortable comparison.

    News sources mix date formats: Finnhub writes naive ISO 8601
    ('2026-05-09T03:25:11', leading '2'), RSS feeds write RFC 822
    ('Thu, 08 May 2026 14:23:00 GMT', leading 'T'). Lexicographic
    string compare puts all RFC-822 strings above all ISO strings
    in desc sort, regardless of which is actually newer — RSS would
    always crowd Finnhub off the top of the merged list.

    Converting both formats to epoch float gives the merge a single
    comparable scale. Returns 0.0 for unparseable / empty strings so
    they sort to the bottom of a 'newest first' desc sort.
    """
    if not s:
        return 0.0
    s = str(s).strip()
    # RFC 822 first — most common RSS shape.
    try:
        from email.utils import parsedate_to_datetime
        dt = parsedate_to_datetime(s)
        if dt is not None:
            from datetime import timezone as _tz
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=_tz.utc)
            return dt.timestamp()
    except (TypeError, ValueError):
        pass
    # ISO 8601 fallback — Finnhub adapter, future Yahoo entries.
    try:
        iso = s
        # datetime.fromisoformat in Python < 3.11 doesn't accept
        # trailing 'Z'; normalize to +00:00.
        if iso.endswith('Z'):
            iso = iso[:-1] + '+00:00'
        dt = datetime.fromisoformat(iso)
        from datetime import timezone as _tz
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=_tz.utc)
        return dt.timestamp()
    except (TypeError, ValueError):
        return 0.0


# v4.14.6.22-entity-filter: STRICT company-entity matching on the
# collision-prone RSS-firehose feeds. Replaces the v4.14.6.21 keyword
# whitelist (`_FINANCE_RELEVANCE_TERMS` + `_is_finance_relevant`,
# retired). The keyword approach could always be defeated by a new
# ambiguous word — e.g. "shares" admitting "Drake's baby mama shares
# photos" — and adding finance bigrams ("shares of", "shares surge")
# was an arms race against headline writers. Entity matching is the
# closure: admit only if the title references THIS company by its
# (normalized) legal name, an alias, the ticker as cashtag/parens, or
# (for non-common-word tickers) the ticker as a word-boundary token.
#
# The per-ticker API adapters (yahoo, finnhub) are provider-curated and
# BYPASS this filter — that bypass is preserved verbatim at the
# `_keep` call site below.
_FINANCE_RELEVANCE_COLLISION_SOURCES = frozenset({
    'yahoo_rss', 'google_news', 'marketwatch', 'cnbc',
    'benzinga', 'investing', 'reuters', 'finviz',
})

# Curated alias map. SMALL and observation-grown — only entries where
# publishers commonly refer to the company by a brand or former name
# that the normalized legal name won't catch. Add an entry only when
# Mike (or a smoke test) surfaces a real held/traded ticker whose
# legit news is missing because of an alias gap. Not a fundamentals
# table; a hand-maintained source list.
_TICKER_ALIASES: dict[str, list[str]] = {
    'MAMA':  ['mamamancini', 'mamamancinis'],
    'GOOG':  ['google'],
    'GOOGL': ['google'],
    'META':  ['facebook'],
    'FUN':   ['cedar fair'],
    'WORK':  ['slack'],
    'SLV':   ['ishares silver', 'silver trust'],
}

# Tickers whose symbol is itself an English word — the
# word-boundary `\bTICKER\b` rule is DISABLED for these to avoid
# admitting unrelated articles ("now is the time", "mind the gap").
# Legit news for these tickers still admits via rules 1/2/3/5
# (normalized company name, cashtag/parens, alias). Observation-grown.
_COMMON_WORD_TICKERS = frozenset({
    'NOW', 'GAP', 'TWO', 'FUN', 'WORK', 'ZIP', 'CAKE', 'BIRD', 'BUD',
    'GAP', 'GME', 'NEW', 'HOOD', 'WIN', 'YOU', 'WE', 'ALL', 'LIFE',
    'BAR', 'FOX', 'CAR', 'EAR', 'EAT', 'ICE', 'OIL', 'TAP', 'KEY',
    'AIR', 'SEA', 'BIG', 'BAD', 'LOW', 'HIGH', 'FAST', 'FAT',
    'COOL', 'WARM', 'GO', 'IT', 'AI',
})

# Gossip-guard: reject overrides. If a title contains any of these
# bigrams the article is dropped even if it otherwise admitted —
# captures the "X's mama shares Y" / "Lil Mama" pattern that the
# `\bMAMA\b` word-boundary rule would otherwise admit. Observation-
# grown; extend when a new pattern surfaces.
_GOSSIP_GUARD = (
    'baby mama', 'lil mama', 'tot mama', 'mama mountain',
    'stroke mama', "'s mama", '’s mama',  # straight + curly apostrophe
)

# Corporate suffixes stripped during name normalization. Order
# matters: longer / multi-word suffixes first so "incorporated" is
# matched before "in" (no), and "sa/nv" before "sa".
_NAME_SUFFIXES = (
    'incorporated', 'corporation', 'sa/nv',
    'inc.', 'inc', 'corp.', 'corp', 'ltd.', 'ltd', 'plc', 'llc',
    'holdings', 'group', 'company', 'co.', 'co',
    'n.v.', 'nv', 's.a.', 's.a', 'ag', 'se',
    'limited', 'trust', 'fund',
)


def _normalize_name(name: str) -> str:
    """Normalize a company name OR headline title for substring
    matching. Lowercase; strip both straight (U+0027) and curly
    (U+2019) apostrophes; strip punctuation; strip leading 'the ';
    strip trailing corporate suffixes (iteratively, up to 3 layers).
    Collapse whitespace.
    """
    if not name:
        return ''
    n = name.lower()
    # Apostrophes — straight AND curly. The curly one is the dominant
    # form in real RSS headlines and was the single biggest cause of
    # the 44% raw-match miss in the recon (Mama's vs Mama’s).
    n = n.replace('’', '').replace("'", '')
    # Punctuation / brackets / quotes — convert to space so adjacent
    # tokens don't run together.
    for ch in ',.()"&':
        n = n.replace(ch, ' ')
    n = ' '.join(n.split())
    if n.startswith('the '):
        n = n[4:]
    # Strip trailing suffixes iteratively (handles "Inc Corp" tails).
    for _ in range(3):
        prev = n
        for suf in _NAME_SUFFIXES:
            if n.endswith(' ' + suf) or n == suf:
                n = n[:-(len(suf) + 1)].rstrip() if n != suf else ''
                break
        if n == prev:
            break
    return n.strip()


# v4.14.6.25-sec-name-bootstrap: in-process memo for the per-ticker
# company-name lookup. Stores (name, fetched_ts). `name=None` = real
# orphan (we know SEC + yfinance both have nothing). The rate-limited
# sentinel `__RATE_LIMITED__` is stored as None HERE (so the entity
# filter falls through to graceful degradation in-session) but is
# kept distinct in the DB so the cross-session retry logic can tell
# "yfinance failed, try later" from "genuinely no name." The memo's
# fetched_ts is consulted by the 24h retry path so a stale __RATE_LIMITED__
# eventually re-probes mid-session too.
_NAME_CACHE: dict[str, tuple[str | None, float]] = {}
_NAME_CACHE_LOCK = None  # lazy-init in _get_company_name
_NAME_RATE_LIMITED_SENTINEL = '__RATE_LIMITED__'
_NAME_RETRY_AFTER_SECONDS = 24 * 60 * 60  # 24h


def _is_real_company_name(value) -> bool:
    """True iff the value is a usable company name (not None, empty,
    or the rate-limited sentinel). Used by the entity filter and any
    other consumer so the sentinel never leaks into matching logic
    or UI as if it were a real name."""
    if value is None:
        return False
    s = str(value).strip()
    if not s:
        return False
    if s == _NAME_RATE_LIMITED_SENTINEL:
        return False
    return True


def _bulk_bootstrap_names_from_sec(app, log_fn=None) -> dict:
    """v4.14.6.25-sec-name-bootstrap: one-shot fetch of SEC's
    `company_tickers.json` (10,414 entries: ticker, title, cik). Bulk
    UPDATE-fills cache.db.tickers.name for any universe ticker whose
    name is currently NULL / empty / __RATE_LIMITED__. Also populates
    `cik` for matching rows when that column exists and is empty.

    Trigger: called from startup if marker `_v414625_sec_names_last_run`
    is absent or > 7 days old. Marker is set ONLY on success — on any
    network / parse / DB failure we leave it unset so the next eligible
    startup retries. This means an offline laptop is COMPLETELY
    unaffected: the function returns a stat dict, logs once, and the
    app continues normally with whatever names were already populated.

    Why SEC instead of yfinance: yfinance rate-limits the per-ticker
    probe hard, so the pre-v4.14.6.25 lazy-bootstrap path left 89.5%
    of tickers with NULL/empty name. SEC ships 10,414 (ticker, title)
    pairs in one free request (no API key; just the SEC-required
    User-Agent header). One-shot, broad, reliable — exactly what the
    bulk fill needs. yfinance stays the per-ticker fallback for the
    non-SEC ~5% (preferreds AHT-PD, warrants ASTLW, units AACBU,
    foreign ADRs, ETFs).

    Returns {'fetched': int, 'matched': int, 'updated': int,
             'cik_updated': int, 'error': str | None}. Never raises.
    """
    import urllib.request as _ur
    stat = {'fetched': 0, 'matched': 0, 'updated': 0,
            'cik_updated': 0, 'error': None}
    # The SEC requires a contact-bearing User-Agent for automated access
    # (fair-use rule: name + contact). This is a placeholder; users
    # deploying the app can configure cfg['sec_user_agent'] for a
    # custom string.
    try:
        cfg = getattr(app, 'cfg', None) or {}
        ua = str(cfg.get(
            'sec_user_agent',
            'TiredMarket research contact: tiredofitall@example.com')
        ).strip()
    except Exception:
        ua = ('TiredMarket research contact: '
              'tiredofitall@example.com')
    if not ua:
        ua = 'TiredMarket research contact: tiredofitall@example.com'
    try:
        req = _ur.Request(
            'https://www.sec.gov/files/company_tickers.json',
            headers={'User-Agent': ua,
                     'Accept': 'application/json'})
        with _ur.urlopen(req, timeout=10) as resp:
            if getattr(resp, 'status', 200) != 200:
                stat['error'] = f'HTTP {resp.status}'
                if log_fn:
                    try: log_fn(
                        f"[sec-names] fetch returned HTTP "
                        f"{resp.status} — skipping (will retry next "
                        f"eligible startup).", 'amber')
                    except Exception: pass
                return stat
            import json as _json
            data = _json.loads(resp.read())
    except Exception as e:
        stat['error'] = f'{type(e).__name__}: {e}'
        if log_fn:
            try: log_fn(
                f"[sec-names] fetch unavailable "
                f"({type(e).__name__}); app continues normally, "
                f"will retry on next eligible startup.",
                'amber')
            except Exception: pass
        return stat
    # Build {ticker -> (title, cik)} from SEC payload.
    if not isinstance(data, dict):
        stat['error'] = 'unexpected SEC payload shape'
        return stat
    sec_map: dict[str, tuple[str, str]] = {}
    for v in data.values():
        if not isinstance(v, dict):
            continue
        tk = str(v.get('ticker') or '').strip().upper()
        title = str(v.get('title') or '').strip()
        cik_raw = v.get('cik_str')
        cik = str(cik_raw) if cik_raw not in (None, '') else ''
        if tk and title:
            sec_map[tk] = (title, cik)
    stat['fetched'] = len(sec_map)
    if not sec_map:
        stat['error'] = 'SEC payload had zero usable entries'
        return stat
    # Open cache.db, find empty-name rows, UPDATE the intersection.
    try:
        import tm_cache as _tmc
        conn = _tmc.get_connection()
    except Exception as e:
        stat['error'] = f'cache.db open failed: {type(e).__name__}'
        return stat
    try:
        # Schema probe — does cik column exist?
        _cols = {row[1] for row in conn.execute(
            "PRAGMA table_info(tickers)")}
        _has_cik = 'cik' in _cols
        # Pull the empty-name tickers as a set.
        try:
            empty_tickers = {
                str(r[0]).upper() for r in conn.execute(
                    "SELECT ticker FROM tickers "
                    "WHERE name IS NULL OR name = '' "
                    "   OR name = ?",
                    (_NAME_RATE_LIMITED_SENTINEL,)
                ).fetchall()
            }
        except Exception as e:
            stat['error'] = f'tickers SELECT failed: {type(e).__name__}'
            return stat
        if not empty_tickers:
            return stat
        targets = empty_tickers & set(sec_map.keys())
        stat['matched'] = len(targets)
        if not targets:
            return stat
        now_iso = datetime.now().isoformat()
        with conn:
            for tk in targets:
                title, cik = sec_map[tk]
                try:
                    conn.execute(
                        "UPDATE tickers SET name=?, last_updated=? "
                        "WHERE ticker=? AND (name IS NULL "
                        "   OR name='' OR name=?)",
                        (title, now_iso, tk,
                         _NAME_RATE_LIMITED_SENTINEL))
                    stat['updated'] += 1
                    if _has_cik and cik:
                        try:
                            conn.execute(
                                "UPDATE tickers SET cik=? "
                                "WHERE ticker=? "
                                "  AND (cik IS NULL OR cik='')",
                                (cik, tk))
                            stat['cik_updated'] += 1
                        except Exception:
                            pass  # cik update is best-effort
                except Exception:
                    pass  # per-ticker failure stays scoped
    finally:
        try:
            conn.close()
        except Exception:
            pass
    return stat


def _get_company_name(ticker: str) -> str | None:
    """Resolve the canonical company name for `ticker`.

    v4.14.6.25-sec-name-bootstrap: the bulk SEC bootstrap
    `_bulk_bootstrap_names_from_sec` runs at eligible startups and
    pre-populates cache.db.tickers.name for the ~95% of the universe
    SEC covers (common stock filers). This per-ticker path now:

      1. In-process memo. Sentinel `__RATE_LIMITED__` results are
         memoized as None (so the entity filter degrades gracefully
         in-session) but with the original fetched_ts so a later
         in-session call after 24h triggers a fresh probe.
      2. cache.db.tickers.name — return when it's a real name. Empty
         string (legacy "we tried, no result") falls through to
         step 3 like before. __RATE_LIMITED__ falls through ONLY if
         the row's last_updated is older than 24h; otherwise we
         return None (graceful-degrade) without re-probing yfinance.
      3. yfinance fallback ONLY for non-SEC-shaped tickers (those
         that SEC's filer list won't have anyway): preferreds (-P*),
         warrants (W* or *W suffix), units (U* or *U / *UN / *R).
         For plain common-stock symbols, skip yfinance entirely if
         SEC didn't already populate (SEC is the authoritative path
         and re-probing yfinance for SEC misses just re-triggers
         the rate-limit loop).
      4. Persist outcome. A real name → stored verbatim. A rate-limit
         exception → store `__RATE_LIMITED__` + last_updated=now so
         the 24h retry kicks in. A genuine empty → store ''.

    Threading: uses tm_cache.get_connection() per-call (fresh
    connection, WAL mode + busy_timeout — same discipline as every
    other cache.db writer in tm_cache). Best-effort throughout —
    any failure returns None and lets the caller fall through to
    the graceful-degradation path (rules 3/4/5 only in
    `_is_entity_relevant`).
    """
    global _NAME_CACHE_LOCK
    if _NAME_CACHE_LOCK is None:
        import threading as _th
        _NAME_CACHE_LOCK = _th.Lock()
    t = (ticker or '').strip().upper()
    if not t:
        return None
    # ── Step 1: in-process memo (24h-respecting) ─────────────────
    import time as _time_gcn
    now_epoch = _time_gcn.time()
    with _NAME_CACHE_LOCK:
        cached = _NAME_CACHE.get(t)
    if cached is not None:
        cached_val, cached_ts = cached
        if cached_val is not None:
            # Real name cached — fast path.
            return cached_val
        # Negative cache: respect 24h before re-probing.
        if (now_epoch - cached_ts) < _NAME_RETRY_AFTER_SECONDS:
            return None
        # else fall through to re-probe.
    # ── Step 2: cache.db.tickers ─────────────────────────────────
    db_val = None
    db_last_updated = None
    try:
        import tm_cache as _tmc
        conn = _tmc.get_connection()
        try:
            row = conn.execute(
                "SELECT name, last_updated FROM tickers WHERE ticker=?",
                (t,)).fetchone()
            if row is not None:
                db_val = row[0]
                db_last_updated = row[1]
        finally:
            conn.close()
    except Exception:
        pass
    if _is_real_company_name(db_val):
        real = str(db_val).strip()
        with _NAME_CACHE_LOCK:
            _NAME_CACHE[t] = (real, now_epoch)
        return real
    # If DB says __RATE_LIMITED__ AND last_updated is fresh, don't
    # re-probe yfinance yet — return None (graceful degradation).
    if (db_val == _NAME_RATE_LIMITED_SENTINEL
            and db_last_updated):
        try:
            _dlu = datetime.fromisoformat(str(db_last_updated))
            _age = (datetime.now() - _dlu).total_seconds()
            if _age < _NAME_RETRY_AFTER_SECONDS:
                with _NAME_CACHE_LOCK:
                    _NAME_CACHE[t] = (None, now_epoch)
                return None
        except Exception:
            pass  # malformed timestamp → fall through to retry
    # ── Step 3: yfinance fallback (only for non-SEC-shape tickers) ─
    # SEC's filer list doesn't carry preferreds (-PD/-PE/-P*), warrants
    # (suffix W on units, e.g. AAONW; or -WT/-WS), or units
    # (suffix U/UN/R on SPAC tickers). For those, yfinance is still
    # the only path. For plain symbols, if SEC didn't already place
    # a name, re-probing yfinance just re-triggers the rate-limit
    # loop that left 89.5% of names empty pre-v4.14.6.25 — so skip.
    _is_non_sec_shape = False
    if ('-P' in t or '-WT' in t or '-WS' in t):
        _is_non_sec_shape = True
    elif len(t) >= 4 and t[-1] in ('W', 'U', 'R') and t[-2].isalpha():
        # SPAC unit/warrant suffix: AACBU, AACBW, AACBR, etc.
        _is_non_sec_shape = True
    if not _is_non_sec_shape:
        with _NAME_CACHE_LOCK:
            _NAME_CACHE[t] = (None, now_epoch)
        return None
    cand = ''
    rate_limited = False
    try:
        import yfinance as _yf
        info = _yf.Ticker(t).info or {}
        cand = info.get('longName') or info.get('shortName') or ''
        cand = str(cand).strip()
    except Exception as e:
        # Distinguish rate-limit from other errors so we can write the
        # right sentinel and retry later.
        _emsg = str(e).lower()
        if ('ratelimit' in _emsg or 'rate limit' in _emsg
                or 'too many requests' in _emsg
                or e.__class__.__name__.lower().endswith('ratelimiterror')):
            rate_limited = True
        cand = ''
    # ── Step 4: persist outcome ──────────────────────────────────
    persist_val = cand if cand else (
        _NAME_RATE_LIMITED_SENTINEL if rate_limited else '')
    try:
        import tm_cache as _tmc
        conn = _tmc.get_connection()
        now_iso = datetime.now().isoformat()
        try:
            with conn:
                cur = conn.execute(
                    "SELECT 1 FROM tickers WHERE ticker=?", (t,))
                if cur.fetchone() is not None:
                    conn.execute(
                        "UPDATE tickers SET name=?, last_updated=? "
                        "WHERE ticker=?",
                        (persist_val, now_iso, t))
                else:
                    conn.execute(
                        "INSERT INTO tickers (ticker, name, last_updated) "
                        "VALUES (?, ?, ?)",
                        (t, persist_val, now_iso))
        finally:
            conn.close()
    except Exception:
        pass
    # Memo: real name → real; sentinel/empty → None (graceful-degrade).
    resolved = cand if cand else None
    with _NAME_CACHE_LOCK:
        _NAME_CACHE[t] = (resolved, now_epoch)
    return resolved


def _is_entity_relevant(title: str, ticker: str,
                         company_name: str | None,
                         aliases: list[str] | None) -> bool:
    """STRICT-PLUS entity admit-decision. Applied ONLY to
    collision-prone RSS-firehose sources (callers must gate by source).

    Admit if ANY of:
      1. Normalized-core substring of normalized title
         (apostrophe-insensitive, suffix-stripped).
      2. First-2-token prefix of a ≥3-token normalized core
         (recovers "Two Harbors" when name is
         "Two Harbors Investment Corp").
      3. Cashtag `$TICKER` or paren `(TICKER)` in title.
      4. Word-boundary `\\bTICKER\\b` — ONLY if ticker is NOT in
         `_COMMON_WORD_TICKERS` (English-word tickers like NOW/GAP
         would otherwise wildcard-admit unrelated articles).
      5. Curated alias substring match (alias normalized the same way).

    Then apply `_GOSSIP_GUARD` as a reject-override: even if admitted,
    drop if a known gossip bigram appears (catches "X's baby mama
    shares Y" / "Lil Mama" / "Mama Mountain" that `\\bMAMA\\b` admits).

    Graceful degradation: when `company_name` is None (un-bootstrapped
    ticker — first scan ever, name still resolving, or orphan ticker
    like WORK), rules 1 + 2 are skipped and the function falls back to
    rules 3 + 4 + 5 only. The gossip-guard still applies. The wordlist
    is NOT used as fallback (retired this release; see the comment
    block at the top of this section). Net: a fresh public clone never
    silently drops real news — it filters a bit looser per-ticker for
    the first cycle, then self-tightens once the name caches.
    """
    if not title:
        return False
    title_low = title.lower()
    t = (ticker or '').strip().lower()
    t_upper = (ticker or '').strip().upper()

    title_norm = _normalize_name(title)
    admitted = False

    # Rule 1 + 2: company name (skip when None — graceful degradation).
    if company_name:
        core = _normalize_name(company_name)
        if len(core) >= 3 and core in title_norm:
            admitted = True
        elif not admitted and core:
            tokens = core.split()
            if len(tokens) >= 3:
                prefix = ' '.join(tokens[:2])
                if len(prefix) >= 6 and prefix in title_norm:
                    admitted = True

    # Rule 3: cashtag / parens — strong ticker-relevance signal.
    if not admitted and t:
        if f'${t}' in title_low or f'({t})' in title_low:
            admitted = True

    # Rule 4: ticker as word-boundary token — gated off for common-word
    # tickers. Applied to the RAW lowercase title (not the
    # punctuation-stripped normalized form) because the regex needs
    # word boundaries.
    if not admitted and t and t_upper not in _COMMON_WORD_TICKERS:
        import re as _re
        if _re.search(r'\b' + _re.escape(t) + r'\b', title_low):
            admitted = True

    # Rule 5: curated aliases (normalized).
    if not admitted and aliases:
        for a in aliases:
            an = _normalize_name(a)
            if an and len(an) >= 3 and an in title_norm:
                admitted = True
                break

    if not admitted:
        return False

    # Gossip-guard reject-override.
    for g in _GOSSIP_GUARD:
        if g in title_low:
            return False
    return True


def _pub_date_to_iso(s) -> str | None:
    """v4.14.6.21-news-identity: pub_date string → ISO 8601 UTC string.
    Uses the existing _parse_news_date_to_epoch which already handles
    both RFC 822 (RSS) and ISO 8601 (Finnhub/Yahoo adapters). Returns
    None for empty / unparseable input (Finviz scrape, malformed feeds)
    so the column persists as NULL and downstream code can detect
    "publisher date unknown" rather than guessing.
    """
    if not s:
        return None
    try:
        epoch = _parse_news_date_to_epoch(s)
        if not epoch or epoch <= 0:
            return None
        from datetime import timezone as _tz
        return datetime.fromtimestamp(epoch, _tz.utc).strftime(
            '%Y-%m-%dT%H:%M:%SZ')
    except Exception:
        return None


def _merge_news_articles(by_source: dict[str, list[dict]]) -> list[dict]:
    """v4.14.2 stage 2: merge articles from multiple sources.

    Dedup key is the canonical URL. Articles missing a URL stay as
    separate entries (no cross-source merge possible without a
    shared identifier — fuzzy title matching is a future
    enhancement).

    For multi-source articles:
      - title: longest title across sources (Finnhub tends to be
               concise; RSS feeds sometimes include publication
               name suffixes — longest preserves the most context)
      - summary: longest summary across sources
      - pub_date: first non-empty pub_date encountered
      - sources: union of all source ids that covered the article
      - sentiment: arithmetic mean of all source scores

    Returned list is sorted by pub_date descending (newest first),
    with URL-less items appended at the end in input order.
    """
    by_url: dict[str, dict] = {}
    titleless: list[dict] = []
    for source_id, articles in by_source.items():
        for art in articles or []:
            if not isinstance(art, dict) or not art.get('title'):
                continue
            url_key = _canon_news_url(art.get('url', ''))
            if not url_key:
                titleless.append({
                    'title':     art['title'],
                    'url':       '',
                    'pub_date':  art.get('pub_date', ''),
                    'summary':   art.get('summary', ''),
                    'sources':   [art.get('source', source_id)],
                    'sentiment': float(art.get('sentiment', 0.0)),
                })
                continue
            existing = by_url.get(url_key)
            if existing is None:
                by_url[url_key] = {
                    'title':      art['title'],
                    'url':        art['url'],
                    'pub_date':   art.get('pub_date', ''),
                    'summary':    art.get('summary', ''),
                    'sources':    {art.get('source', source_id)},
                    'sentiments': [float(art.get('sentiment', 0.0))],
                }
            else:
                if len(art['title']) > len(existing['title']):
                    existing['title'] = art['title']
                summary = art.get('summary', '')
                if summary and len(summary) > len(existing['summary']):
                    existing['summary'] = summary
                if not existing['pub_date'] and art.get('pub_date'):
                    existing['pub_date'] = art['pub_date']
                existing['sources'].add(art.get('source', source_id))
                existing['sentiments'].append(
                    float(art.get('sentiment', 0.0)))

    merged: list[dict] = []
    for rec in by_url.values():
        merged.append({
            'title':     rec['title'],
            'url':       rec['url'],
            'pub_date':  rec['pub_date'],
            'summary':   rec['summary'],
            'sources':   sorted(rec['sources']),
            'sentiment': (sum(rec['sentiments']) / len(rec['sentiments'])
                           if rec['sentiments'] else 0.0),
        })
    # Sort by pub_date desc with format-aware datetime parsing
    # (v4.14.2 stage 2 polish — string compare across mixed ISO
    # and RFC-822 formats put RSS above Finnhub regardless of
    # actual recency). Empty / unparseable pub_dates sink to
    # the bottom because _parse_news_date_to_epoch returns 0.0.
    merged.sort(
        key=lambda a: _parse_news_date_to_epoch(a.get('pub_date')),
        reverse=True)
    merged.extend(titleless)
    return merged


def deep_news_scan(ticker, db, enabled_sources=None):
    """Run a full news scan for a ticker, cache results in DB.

    v4.14.2 stage 2: parallel multi-source fetch + URL-based merge.

    Pre-stage-2 the function fetched RSS sequentially then made one
    router.fetch('news', ...) call which only ever picked the
    highest-priority provider (Finnhub when keyed, Yahoo when not —
    never both). The result was "primary or fallback," not "merge."

    Stage 2 fires every enabled news source in parallel — RSS bundle
    via _news_via_rss, Yahoo via direct adapter call, Finnhub via
    direct adapter call — bounded by a per-source timeout so one
    slow source doesn't block the merge. Results merge by canonical
    URL with sentiment averaged across sources for multi-covered
    articles.

    Source enablement: Finnhub and Yahoo are skipped if disabled in
    Data Providers. RSS always runs (no per-source toggle today).
    Adding a new source is one line in the `fetchers` list — the
    merge function and downstream code are source-agnostic.

    Future sources (FRED is N/A, Marketaux / NewsAPI / Twelve Data)
    plug in via the same pattern. v4.14.2 stage 3 added Google News
    RSS as a top-level fetcher (was a sub-source of the RSS bundle).
    """
    import concurrent.futures

    fetchers: list[tuple[str, callable]] = []
    fetchers.append(("rss",
                      lambda t=ticker, e=enabled_sources:
                          _news_via_rss(t, e)))
    fetchers.append(("yahoo",
                      lambda t=ticker: _news_via_yahoo(t)))
    fetchers.append(("finnhub",
                      lambda t=ticker: _news_via_finnhub(t)))
    # v4.14.2 stage 3: Google News RSS as keyless top-level source.
    # Always fires (no API key required, no enabled-check needed —
    # same as the existing RSS scrape).
    fetchers.append(("google_news",
                      lambda t=ticker: _news_via_google_news(t)))

    by_source: dict[str, list[dict]] = {}

    with concurrent.futures.ThreadPoolExecutor(
            max_workers=max(1, len(fetchers)),
            thread_name_prefix='news-fetch') as ex:
        future_to_source = {ex.submit(fn): src for (src, fn) in fetchers}
        try:
            for future in concurrent.futures.as_completed(
                    future_to_source,
                    timeout=_NEWS_PER_SOURCE_TIMEOUT_SEC):
                src = future_to_source[future]
                try:
                    by_source[src] = future.result() or []
                except Exception as e:
                    _log_data_fetch_error(
                        f"deep_news_scan future src={src} ticker={ticker}",
                        e)
                    by_source[src] = []
        except concurrent.futures.TimeoutError:
            # Global timeout fired. Record any sources still pending
            # as empty (their work continues in the daemon thread but
            # we don't read it). The caller treats empty-from-source
            # the same as "source had no headlines" — graceful degrade.
            for fut, src in future_to_source.items():
                if not fut.done():
                    _log_data_fetch_error(
                        f"deep_news_scan src={src} ticker={ticker} "
                        f"timeout",
                        TimeoutError(
                            f"source took longer than "
                            f"{_NEWS_PER_SOURCE_TIMEOUT_SEC}s"))
                    by_source.setdefault(src, [])
                else:
                    # Finished but we didn't pick up the result before
                    # the global timeout fired — read it now.
                    try:
                        by_source.setdefault(
                            src, fut.result(timeout=0) or [])
                    except Exception:
                        by_source.setdefault(src, [])

    # Merge across sources by canonical URL.
    merged = _merge_news_articles(by_source)

    # v4.14.6.21-news-identity: lenient finance-relevance filter.
    # Drop articles whose only source is a collision-prone RSS firehose
    # AND which carry no finance signal in the title. Multi-source
    # articles (covered by yahoo or finnhub in addition to RSS) pass
    # through unconditionally — those provider-curated paths are
    # trusted. Filter runs HERE so the dropped items don't pollute
    # news_cache rows, news_scans.total_headlines, or top_headlines
    # (the AI prompt's NEWS block).
    # v4.14.6.22-entity-filter: STRICT-PLUS entity match replaces the
    # retired v4.14.6.21 keyword wordlist. Resolve company_name + alias
    # ONCE per scan (not per article) — _get_company_name is itself
    # in-process memoized so this is a dict lookup after the first
    # call. The trusted-source bypass for yahoo/finnhub is unchanged.
    _company_name = _get_company_name(ticker)
    _aliases = _TICKER_ALIASES.get((ticker or '').strip().upper())
    def _keep(a):
        srcs = set(a.get('sources') or [])
        if srcs - _FINANCE_RELEVANCE_COLLISION_SOURCES:
            # At least one trusted source covers it.
            return True
        return _is_entity_relevant(
            a.get('title', ''), ticker, _company_name, _aliases)
    merged = [a for a in merged if _keep(a)]

    # Per-article rows — now 5-tuples with url + published_at_iso so
    # the detector can recognise headlines by identity and so the
    # prompt's NEWS block sees real publisher dates. save_news_batch
    # dedups on (ticker, url) so a re-scan of the same URL preserves
    # its original first-seen `timestamp`.
    legacy_tuples = [
        (a['title'],
         (a['sources'][0] if a.get('sources') else 'unknown'),
         a.get('sentiment', 0.0),
         a.get('url') or '',
         _pub_date_to_iso(a.get('pub_date')))
        for a in merged
    ]
    if legacy_tuples:
        db.save_news_batch(ticker, legacy_tuples)

    # Aggregate save — top_headlines is what the prompt block reads.
    scores = [a.get('sentiment', 0.0) for a in merged]
    # avg_sentiment in the news_scans table is documented as the
    # [-100, +100] _score_headline range. The merged sentiments are
    # in [-1, +1]; multiply by 100 so the on-disk value stays in the
    # documented range and get_news_features's existing /100
    # normalization continues to produce the [-1, +1] sentiment_score
    # the prompt block consumes.
    avg_sent = round(float(np.mean(scores) * 100), 1) if scores else 0
    top = [a['title'] for a in merged[:8]]
    db.save_news_scan(ticker, len(merged), avg_sent, top)

    # Activity-log surface so the user sees the multi-source merge
    # in action. Keeps the existing single-line summary shape.
    by_source_counts = {
        s: len(arts) for s, arts in by_source.items()}

    # v4.15.0: tap into cache.news_signals. Side-effect only; existing
    # callers see the same return value. Dedups against recent rows so
    # the scheduler's ~30-min refresh doesn't balloon the table.
    try:
        _v415_cache_write_news(ticker, merged)
    except Exception:
        # Cache writes must never break the data path.
        pass

    return {
        'total':          len(merged),
        'avg_sentiment':  avg_sent,
        'top_headlines':  top,
        # New in stage 2 — caller can introspect per-source counts
        # (used by the activity-log line in callers that want it).
        'by_source':      by_source_counts,
        'merged':         merged,
    }


def get_news_features(ticker, db):
    """Get news features for prediction — uses cached data.

    Existing aggregate signals (news_sentiment, news_headline_count,
    news_recent_sentiment, news_momentum, news_volume) are unchanged.

    v4.14.1 stage 5 follow-up: also returns three fields that
    Stage 1's tm_context_builder NEWS block expects, sourced from
    the news_scans table that deep_news_scan already writes to:

    - top_headlines: list[str], up to 10 entries, most-recent scan's
      cached headline list. Pre-fix the consumer side read this key
      (or the legacy 'headlines' fallback) but neither was populated
      and the NEWS block silently emitted nothing.

    - article_count: int, total headline count from the most recent
      scan for this ticker.

    - sentiment_score: float | None, aggregate sentiment normalized
      to [-1.0, +1.0]. The underlying news_scans.avg_sentiment is
      stored in [-100, +100] range (matches _score_headline's
      documented output); we divide by 100 here so consumers like
      tm_context_builder._news_block see the canonical [-1, +1]
      range its rendered label promises.

    Window: news_scans is keyed by ticker (PRIMARY KEY), INSERT OR
    REPLACE — there's exactly one row per ticker, holding the most
    recent scan's aggregates. No 7-day query is performed here; the
    "last 7 days" framing in the rendered NEWS header reflects
    deep_news_scan's default days_back=7 input window.

    Defensive on SQLite failure: if db.get_news_scan or
    db.get_recent_news raises, the affected fields fall back to
    safe defaults rather than propagating the exception.
    """
    try:
        scan = db.get_news_scan(ticker)
    except Exception:
        scan = None
    try:
        recent = db.get_recent_news(ticker, hours=24)
    except Exception:
        recent = None

    features = {}

    if scan:
        features['news_sentiment'] = scan['avg_sentiment'] or 0
        features['news_headline_count'] = scan['total_headlines'] or 0
    else:
        features['news_sentiment'] = 0
        features['news_headline_count'] = 0

    # Weight recent news more heavily
    if recent:
        # v4.14.2 stage 2: was n['score'] which never matched the
        # actual key produced by db.get_recent_news ('sentiment_score').
        # Pre-fix the KeyError got swallowed by the outer try/except in
        # _fetch_news_features and the entire features dict came back
        # None, BUT the news_cache table was also empty (Bug 2) so this
        # branch never actually fired in production. Both bugs fixed in
        # the same patch — verify together.
        recent_scores = [n['sentiment_score'] for n in recent]
        features['news_recent_sentiment'] = round(np.mean(recent_scores), 1)
        # Sentiment momentum: are recent articles more positive or negative?
        if len(recent_scores) >= 4:
            first_half = np.mean(recent_scores[:len(recent_scores)//2])
            second_half = np.mean(recent_scores[len(recent_scores)//2:])
            features['news_momentum'] = round(first_half - second_half, 1)
        else:
            features['news_momentum'] = 0
        # Headline volume — lots of news can mean volatility
        features['news_volume'] = len(recent)
    else:
        features['news_recent_sentiment'] = 0
        features['news_momentum'] = 0
        features['news_volume'] = 0

    # ── v4.14.1 stage 5 follow-up: surface headline text + counts +
    # normalized sentiment from the most recent scan, so consumers
    # like tm_context_builder._news_block can render real content.
    if scan:
        raw_headlines = scan.get('top_headlines') or []
        # Cap at 10 — the rendered NEWS block only shows up to 5
        # anyway, but a generous cap leaves room for future
        # consumers without bloating the cache payload.
        features['top_headlines'] = list(raw_headlines)[:10]
        features['article_count'] = scan.get('total_headlines') or 0
        avg = scan.get('avg_sentiment')
        # avg_sentiment is stored in [-100, +100] (per
        # _score_headline's documented output range). Normalize to
        # [-1, +1] so the consumer-side label "(-1=very bearish,
        # +1=very bullish)" matches the displayed value.
        if avg is None:
            features['sentiment_score'] = None
        else:
            try:
                features['sentiment_score'] = round(float(avg) / 100.0, 3)
            except (TypeError, ValueError):
                features['sentiment_score'] = None
    else:
        features['top_headlines'] = []
        features['article_count'] = 0
        features['sentiment_score'] = None

    # ── v4.14.2 stage 7: surface per-article (source, sentiment_score)
    # records over a 7-day window so tm_context_builder.
    # detect_news_disagreement can compute per-source sentiment
    # aggregates and decide whether to flag directional disagreement.
    #
    # Note on units: news_cache.sentiment_score is stored in the
    # [-1, +1] range (per-article scores written by deep_news_scan
    # via save_news_batch), even though news_scans.avg_sentiment is
    # in [-100, +100]. The two tables track different scales — don't
    # divide here. (This was confirmed by inspecting actual stored
    # values across multiple tickers; pre-stage-7 the doc-string in
    # this function claimed both were [-100, +100], which is wrong
    # for news_cache.) Detection thresholds are in [-1, +1] units
    # so the raw values pass through unchanged.
    try:
        articles_7d = db.get_recent_news(ticker, hours=168)
    except Exception:
        articles_7d = []
    norm_articles: list[dict] = []
    for a in articles_7d or []:
        src = (a.get('source') or '').strip()
        if not src:
            continue
        raw_score = a.get('sentiment_score')
        if raw_score is None:
            continue
        try:
            norm_articles.append({
                'source':          src,
                'sentiment_score': float(raw_score),
            })
        except (TypeError, ValueError):
            continue
    features['articles'] = norm_articles

    return features


# ═══════════════════════════════════════════════════════════════════════════
# DATA AGGREGATOR
# ═══════════════════════════════════════════════════════════════════════════

def compute_technicals(df):
    if df is None or df.empty or len(df) < 20:
        return None
    close = df['Close'].values.astype(float)
    high = df['High'].values.astype(float)
    low = df['Low'].values.astype(float)
    volume = df['Volume'].values.astype(float)
    opens = df['Open'].values.astype(float)
    n = len(close)
    ind = {}

    for p in [5, 10, 20, 50]:
        if n >= p:
            sma = np.convolve(close, np.ones(p)/p, mode='valid')
            ind[f'sma{p}'] = round(float(sma[-1]), 4)
            ind[f'price_vs_sma{p}'] = round((close[-1] - sma[-1]) / sma[-1] * 100, 4)

    if n >= 26:
        e12 = pd.Series(close).ewm(span=12, adjust=False).mean().values
        e26 = pd.Series(close).ewm(span=26, adjust=False).mean().values
        macd = e12 - e26
        sig = pd.Series(macd).ewm(span=9, adjust=False).mean().values
        ind['macd'] = round(float(macd[-1]), 4)
        ind['macd_signal'] = round(float(sig[-1]), 4)
        ind['macd_histogram'] = round(float(macd[-1] - sig[-1]), 4)
        ind['macd_crossover'] = (
            1 if macd[-1] > sig[-1] and macd[-2] <= sig[-2] else
            -1 if macd[-1] < sig[-1] and macd[-2] >= sig[-2] else 0)

    if n >= 15:
        delta = np.diff(close)
        g = np.where(delta > 0, delta, 0)
        l = np.where(delta < 0, -delta, 0)
        ag = np.convolve(g, np.ones(14)/14, mode='valid')
        al = np.convolve(l, np.ones(14)/14, mode='valid')
        rs = ag[-1] / al[-1] if al[-1] != 0 else 100
        ind['rsi'] = round(100 - (100 / (1 + rs)), 2)

    if n >= 20:
        s20 = np.convolve(close, np.ones(20)/20, mode='valid')[-1]
        std = np.std(close[-20:])
        ind['bb_upper'] = round(s20 + 2*std, 4)
        ind['bb_lower'] = round(s20 - 2*std, 4)
        r = ind['bb_upper'] - ind['bb_lower']
        ind['bb_position'] = round((close[-1] - ind['bb_lower']) / r * 100 if r > 0 else 50, 2)

    if n >= 14:
        l14 = min(low[-14:]); h14 = max(high[-14:])
        ind['stoch_k'] = round((close[-1]-l14)/(h14-l14)*100 if h14!=l14 else 50, 2)
        ind['williams_r'] = round((h14-close[-1])/(h14-l14)*-100 if h14!=l14 else -50, 2)

    if n >= 15:
        tr = np.maximum(high[1:]-low[1:], np.maximum(np.abs(high[1:]-close[:-1]),
                                                       np.abs(low[1:]-close[:-1])))
        atr = np.convolve(tr, np.ones(14)/14, mode='valid')
        ind['atr'] = round(float(atr[-1]), 4)
        ind['atr_pct'] = round(float(atr[-1])/close[-1]*100, 4)

    if n >= 10:
        va = np.mean(volume[-10:])
        ind['volume_ratio'] = round(volume[-1]/va, 4) if va > 0 else 1

    ind['current_price'] = round(float(close[-1]), 2)
    ind['daily_return'] = round((close[-1]/close[-2]-1)*100, 4) if n >= 2 else 0
    if n >= 5: ind['return_5d'] = round((close[-1]/close[-5]-1)*100, 4)
    if n >= 10: ind['momentum_10'] = round((close[-1]/close[-10]-1)*100, 4)
    if n >= 20:
        ind['return_20d'] = round((close[-1]/close[-20]-1)*100, 4)
        h20 = max(high[-20:]); l20 = min(low[-20:])
        ind['high_20d'] = round(float(h20), 2)
        ind['low_20d'] = round(float(l20), 2)
        ind['range_position'] = round((close[-1]-l20)/(h20-l20)*100 if h20!=l20 else 50, 2)
        rets = np.diff(close[-21:])/close[-21:-1]
        ind['volatility_20d'] = round(float(np.std(rets)*100), 4)

    # Pivot points / support / resistance
    if n >= 2:
        pivot = (high[-1] + low[-1] + close[-1]) / 3
        ind['pivot'] = round(pivot, 2)
        ind['resistance1'] = round(2 * pivot - low[-1], 2)
        ind['support1'] = round(2 * pivot - high[-1], 2)
        ind['resistance2'] = round(pivot + (high[-1] - low[-1]), 2)
        ind['support2'] = round(pivot - (high[-1] - low[-1]), 2)

    if n >= 20:
        tp = (high[-20:]+low[-20:]+close[-20:])/3
        tp_m = np.mean(tp); tp_mad = np.mean(np.abs(tp-tp_m))
        ind['cci'] = round((tp[-1]-tp_m)/(0.015*tp_mad) if tp_mad > 0 else 0, 2)

    # ADX — trend strength (0-100, >25 = trending)
    if n >= 28:
        try:
            tr = np.maximum(high[1:]-low[1:], np.maximum(
                np.abs(high[1:]-close[:-1]), np.abs(low[1:]-close[:-1])))
            plus_dm = np.where((high[1:]-high[:-1]) > (low[:-1]-low[1:]),
                              np.maximum(high[1:]-high[:-1], 0), 0)
            minus_dm = np.where((low[:-1]-low[1:]) > (high[1:]-high[:-1]),
                               np.maximum(low[:-1]-low[1:], 0), 0)
            atr14 = pd.Series(tr).ewm(span=14, adjust=False).mean().values
            plus_di = 100 * pd.Series(plus_dm).ewm(span=14, adjust=False).mean().values / np.maximum(atr14, 0.0001)
            minus_di = 100 * pd.Series(minus_dm).ewm(span=14, adjust=False).mean().values / np.maximum(atr14, 0.0001)
            dx = 100 * np.abs(plus_di - minus_di) / np.maximum(plus_di + minus_di, 0.0001)
            adx = pd.Series(dx).ewm(span=14, adjust=False).mean().values
            ind['adx'] = round(float(adx[-1]), 2)
            ind['plus_di'] = round(float(plus_di[-1]), 2)
            ind['minus_di'] = round(float(minus_di[-1]), 2)
        except Exception:
            ind['adx'] = 25

    # OBV — on-balance volume slope (volume confirming price moves)
    if n >= 20:
        obv = np.zeros(n)
        for i in range(1, n):
            if close[i] > close[i-1]:
                obv[i] = obv[i-1] + volume[i]
            elif close[i] < close[i-1]:
                obv[i] = obv[i-1] - volume[i]
            else:
                obv[i] = obv[i-1]
        # OBV slope over last 10 days (normalized)
        obv_recent = obv[-10:]
        if len(obv_recent) >= 2:
            obv_slope = (obv_recent[-1] - obv_recent[0]) / max(abs(obv_recent[0]), 1)
            ind['obv_slope'] = round(obv_slope * 100, 4)
        else:
            ind['obv_slope'] = 0

    # Mean reversion distance (z-score from 20-day mean)
    if n >= 20:
        sma20_val = np.mean(close[-20:])
        std20 = np.std(close[-20:])
        if std20 > 0:
            ind['mean_reversion_z'] = round((close[-1] - sma20_val) / std20, 4)
        else:
            ind['mean_reversion_z'] = 0

    # Bollinger Band width (squeeze detection — low width = breakout coming)
    if 'bb_upper' in ind and 'bb_lower' in ind:
        bb_width = (ind['bb_upper'] - ind['bb_lower']) / close[-1] * 100 if close[-1] > 0 else 0
        ind['bb_width'] = round(bb_width, 4)
        # Squeeze: BB width below 20-day average BB width
        if n >= 40:
            bb_widths = []
            for i in range(-20, 0):
                s = np.mean(close[i-19:i+1]) if abs(i) <= n-20 else sma20_val
                st = np.std(close[i-19:i+1]) if abs(i) <= n-20 else std20
                bb_widths.append((s + 2*st - (s - 2*st)) / max(close[i], 0.01) * 100)
            avg_width = np.mean(bb_widths) if bb_widths else bb_width
            ind['bb_squeeze'] = 1 if bb_width < avg_width * 0.7 else 0
        else:
            ind['bb_squeeze'] = 0

    # Volume trend — is volume increasing or decreasing over 5 days
    if n >= 10:
        vol_5d_recent = np.mean(volume[-5:])
        vol_5d_prior = np.mean(volume[-10:-5])
        ind['volume_trend'] = round(vol_5d_recent / max(vol_5d_prior, 1) - 1, 4)

    # Rate of change (ROC) — 12-day
    if n >= 13:
        ind['roc_12'] = round((close[-1] / close[-13] - 1) * 100, 4)

    if n >= 3:
        body = close[-1]-opens[-1]; pb = close[-2]-opens[-2]
        ind['candle_body'] = round(body, 4)
        ind['candle_bullish_engulf'] = 1 if body>0 and pb<0 and abs(body)>abs(pb)*1.2 else 0
        ind['candle_bearish_engulf'] = 1 if body<0 and pb>0 and abs(body)>abs(pb)*1.2 else 0

    return ind


# ═══════════════════════════════════════════════════════════════════════════
# TIME PREDICTION ENGINE — Estimates when prices will be reached
# ═══════════════════════════════════════════════════════════════════════════

def get_sector(ticker):
    return SECTOR_MAP.get(ticker, 'Other')

_sector_cache = {}

def sector_momentum(ticker, quotes):
    """Calculate sector-level momentum from available quotes."""
    sector = get_sector(ticker)
    if sector == 'Other':
        return 0
    same_sector = [t for t, s in SECTOR_MAP.items() if s == sector and t in quotes]
    if len(same_sector) < 2:
        return 0
    changes = [quotes[t].get('change_pct', 0) for t in same_sector if not quotes[t].get('error')]
    if not changes:
        return 0
    avg = sum(changes) / len(changes)
    return round(avg, 2)


# ═══════════════════════════════════════════════════════════════════════════
# MARKET HOURS — adjust behavior based on trading hours
# ═══════════════════════════════════════════════════════════════════════════
def is_market_hours():
    """Check if US stock market is currently open (9:30 AM - 4:00 PM ET)."""
    try:
        from datetime import timezone
        # US Eastern = UTC-5 (EST) or UTC-4 (EDT)
        utc_now = datetime.now(timezone.utc)
        # Approximate ET: UTC-4 during DST (Mar-Nov), UTC-5 otherwise
        month = utc_now.month
        offset = timedelta(hours=-4 if 3 <= month <= 11 else -5)
        et_now = utc_now + offset
        # Weekday check (0=Mon, 6=Sun)
        if et_now.weekday() >= 5:
            return False
        hour, minute = et_now.hour, et_now.minute
        market_open = (hour == 9 and minute >= 30) or hour >= 10
        market_close = hour < 16
        return market_open and market_close
    except Exception:
        return True  # Assume open if can't determine


def get_market_status():
    """Return market status string and whether to use extended interval."""
    try:
        from datetime import timezone
        utc_now = datetime.now(timezone.utc)
        month = utc_now.month
        offset = timedelta(hours=-4 if 3 <= month <= 11 else -5)
        et_now = utc_now + offset
        if et_now.weekday() >= 5:
            return "CLOSED (Weekend)", True
        hour, minute = et_now.hour, et_now.minute
        if hour < 4:
            return "CLOSED (Pre-market opens 4AM ET)", True
        elif hour < 9 or (hour == 9 and minute < 30):
            return f"PRE-MARKET ({hour}:{minute:02d} ET)", False
        elif hour < 16:
            return f"OPEN ({hour}:{minute:02d} ET)", False
        elif hour < 20:
            return f"AFTER-HOURS ({hour}:{minute:02d} ET)", False
        else:
            return "CLOSED", True
    except Exception:
        return "UNKNOWN", False


# ═══════════════════════════════════════════════════════════════════════════
# MULTI-TIMEFRAME — weekly trend confirmation
# ═══════════════════════════════════════════════════════════════════════════
_weekly_cache = {}

def get_weekly_trend(ticker):
    """Check the weekly trend direction. Returns 'UP', 'DOWN', or 'FLAT'."""
    now = time.time()
    if ticker in _weekly_cache:
        trend, ts = _weekly_cache[ticker]
        if now - ts < 3600:  # Cache 1 hour
            return trend
    try:
        df = yf.download(ticker, period="3mo", interval="1wk", progress=False)
        if df is None or len(df) < 4:
            return 'FLAT'
        close = df['Close'].values.astype(float)
        sma4 = sum(close[-4:]) / 4
        sma2 = sum(close[-2:]) / 2
        current = close[-1]
        if current > sma4 and sma2 > sma4:
            trend = 'UP'
        elif current < sma4 and sma2 < sma4:
            trend = 'DOWN'
        else:
            trend = 'FLAT'
        _weekly_cache[ticker] = (trend, now)
        return trend
    except Exception:
        return 'FLAT'


# ═══════════════════════════════════════════════════════════════════════════
# PRE-MARKET PRICE — detect overnight gaps
# ═══════════════════════════════════════════════════════════════════════════
def get_premarket_price(ticker):
    """Get pre/post-market price from yfinance if available."""
    try:
        t = _get_yf_ticker(ticker)
        info = t.info
        pre = info.get('preMarketPrice')
        post = info.get('postMarketPrice')
        prev_close = info.get('previousClose') or info.get('regularMarketPreviousClose')
        current = info.get('regularMarketPrice') or info.get('currentPrice')
        ext_price = pre or post
        if ext_price and prev_close and prev_close > 0:
            gap_pct = ((ext_price / prev_close) - 1) * 100
            return {'ext_price': ext_price, 'prev_close': prev_close,
                    'gap_pct': round(gap_pct, 2), 'type': 'pre' if pre else 'post'}
    except Exception:
        pass
    return None


# ═══════════════════════════════════════════════════════════════════════════
# POSITION SIZING — Kelly/risk-based sizing
# ═══════════════════════════════════════════════════════════════════════════
def calc_position_size(buy_price, stop_price, portfolio_value, risk_pct=2.0, prob_correct=50):
    """Calculate position size based on risk management.
    risk_pct: max % of portfolio to risk per trade (default 2%).
    Returns shares count and dollar amount."""
    if buy_price <= 0 or stop_price <= 0 or buy_price <= stop_price:
        return 0, 0
    risk_per_share = buy_price - stop_price
    if risk_per_share <= 0:
        return 0, 0
    # Max dollars to risk
    max_risk = portfolio_value * (risk_pct / 100)
    # Basic position size
    shares = int(max_risk / risk_per_share)
    # Kelly adjustment: scale by edge
    edge = (prob_correct / 100 - 0.5) * 2  # -1 to 1
    if edge > 0:
        kelly_fraction = min(edge, 0.25)  # Cap at 25% Kelly
        shares = max(1, int(shares * (0.5 + kelly_fraction)))
    else:
        shares = max(1, int(shares * 0.3))  # Reduce size when low confidence
    dollar_amount = round(shares * buy_price, 2)
    return shares, dollar_amount


# ═══════════════════════════════════════════════════════════════════════════
# TRADING COST CALCULATOR — ensures trades are profitable after fees
# ═══════════════════════════════════════════════════════════════════════════
def calc_trading_costs(buy_price, sell_price, shares, cfg=None):
    """Calculate all trading costs and determine if trade is profitable.
    
    Costs modeled:
    - Commission per trade (buy + sell)
    - SEC fee (sells only, ~$8 per $1M)
    - FINRA TAF (sells only, ~$0.000119 per share)
    - Estimated spread cost (bid-ask, ~0.05% each way)
    
    Returns dict with cost breakdown, net profit, and break-even price.
    """
    if buy_price <= 0 or sell_price <= 0 or shares <= 0:
        return {'total_cost': 0, 'net_profit': 0, 'profitable': False,
                'breakeven_price': buy_price, 'cost_pct': 0}

    # Get broker fees from config (defaults = commission-free broker like Robinhood)
    commission = (cfg or {}).get('commission_per_trade', 0.00)  # Per trade
    sec_rate = 0.000008    # SEC fee: $8 per $1,000,000 (sells only)
    finra_rate = 0.000119  # FINRA TAF: $0.000119 per share (sells only), min $0.01
    spread_pct = (cfg or {}).get('spread_cost_pct', 0.05)  # Estimated bid-ask spread %

    buy_total = buy_price * shares
    sell_total = sell_price * shares

    # Commission: buy + sell
    commission_cost = commission * 2

    # SEC fee (on sell proceeds only)
    sec_fee = round(sell_total * sec_rate, 4)

    # FINRA TAF (on sell shares only)
    finra_fee = max(0.01, round(shares * finra_rate, 4))

    # Spread cost: estimated slippage on both buy and sell
    spread_buy = round(buy_total * (spread_pct / 100), 2)
    spread_sell = round(sell_total * (spread_pct / 100), 2)
    spread_cost = spread_buy + spread_sell

    # Total costs
    total_cost = round(commission_cost + sec_fee + finra_fee + spread_cost, 2)

    # Gross and net profit
    gross_profit = round(sell_total - buy_total, 2)
    net_profit = round(gross_profit - total_cost, 2)

    # Break-even sell price (what price you need to sell at to cover costs)
    cost_per_share = total_cost / shares if shares > 0 else 0
    breakeven_price = round(buy_price + cost_per_share, 4)

    # Cost as % of trade value
    cost_pct = round((total_cost / buy_total) * 100, 3) if buy_total > 0 else 0

    return {
        'total_cost': total_cost,
        'commission': commission_cost,
        'sec_fee': sec_fee,
        'finra_fee': finra_fee,
        'spread_cost': spread_cost,
        'gross_profit': gross_profit,
        'net_profit': net_profit,
        'profitable': net_profit > 0,
        'breakeven_price': breakeven_price,
        'cost_pct': cost_pct,
        'cost_per_share': round(cost_per_share, 4),
    }


# ═══════════════════════════════════════════════════════════════════════════
# DESKTOP NOTIFICATIONS
# ═══════════════════════════════════════════════════════════════════════════
_notifications_enabled = True  # Global flag, updated by App

def send_notification(title, message):
    """Send a Windows toast notification — respects alert settings."""
    if not HAS_NOTIFY or not _notifications_enabled:
        return
    try:
        _notifier.notify(title=title, message=message,
                         app_name="Tired Market Analyzation", timeout=8)
    except Exception:
        pass


