# ═══════════════════════════════════════════════════════════════════════════
# YAHOO BATCH QUOTES — used by the cache layer for efficient multi-ticker
# ═══════════════════════════════════════════════════════════════════════════
def yahoo_batch_quotes(tickers):
    """Fetch quotes for multiple tickers in one yfinance call."""
    results = {}
    try:
        data = yf.download(tickers, period="1d", group_by='ticker',
                           progress=False, threads=True)
        for t in tickers:
            try:
                if len(tickers) == 1:
                    row = data
                else:
                    row = data[t] if t in data.columns.get_level_values(0) else None
                if row is not None and not row.empty:
                    close = float(row['Close'].iloc[-1])
                    opn = float(row['Open'].iloc[-1])
                    vol = float(row['Volume'].iloc[-1])
                    if close > 0:
                        change = ((close - opn) / opn * 100) if opn > 0 else 0
                        results[t] = {"source": "Yahoo", "ticker": t,
                                      "price": round(close, 2),
                                      "change_pct": round(change, 2),
                                      "volume": vol}
            except Exception:
                pass
    except Exception:
        pass
    for t in tickers:
        if t not in results:
            q = yahoo_quote(t)
            if q and q.get('price', 0) > 0:
                results[t] = q
    return results
class Tooltip:
    def __init__(self, widget, text):
        self.widget = widget; self.text = text; self.tip = None; self._after_id = None
        widget.bind('<Enter>', self._schedule_show)
        widget.bind('<Leave>', self._hide)
        widget.bind('<Button-1>', self._hide)
        widget.bind('<Destroy>', self._hide)
        widget.bind('<Motion>', self._on_motion)
        # Also hide when focus changes
        widget.bind('<FocusOut>', self._hide)

    def _on_motion(self, event=None):
        """Track mouse — if it leaves widget bounds, force hide."""
        try:
            if not self.widget.winfo_exists():
                self._hide()
                return
            w = self.widget.winfo_width()
            h = self.widget.winfo_height()
            if event and (event.x < 0 or event.y < 0 or event.x > w or event.y > h):
                self._hide()
        except Exception:
            self._hide()

    def _schedule_show(self, event=None):
        self._hide()
        self._after_id = self.widget.after(500, self._show)

    def _show(self, event=None):
        self._after_id = None
        try:
            if not self.widget.winfo_exists():
                return
            x = self.widget.winfo_rootx() + 20
            y = self.widget.winfo_rooty() + self.widget.winfo_height() + 4
            self.tip = tk.Toplevel(self.widget)
            self.tip.wm_overrideredirect(True)
            self.tip.wm_geometry(f"+{x}+{y}")
            self.tip.attributes('-topmost', True)
            lbl = tk.Label(self.tip, text=self.text, bg='#1e293b', fg='#f1f5f9',
                           font=('Segoe UI', 9), padx=10, pady=6, wraplength=300,
                           justify='left')
            lbl.pack()
            # Auto-hide after 3 seconds
            self.tip.after(3000, self._hide)
            # Also hide if mouse enters the tooltip itself
            self.tip.bind('<Enter>', self._hide)
        except Exception:
            self._hide()

    def _hide(self, event=None):
        if self._after_id:
            try:
                self.widget.after_cancel(self._after_id)
            except Exception:
                pass
            self._after_id = None
        if self.tip:
            try:
                self.tip.destroy()
            except Exception:
                pass
            self.tip = None

