# GUI APPLICATION — Phase 2A.5 cleanup edition
#
# What this does:
#   - Top bar with Settings, Help, Holdings buttons
#   - Live clock + market status
#   - Activity log on the right (running narrative of AI activity)
#   - Disclaimer modal on first launch (or after disclaimer text changes)
#
# What this DOESN'T do (deliberately removed in cleanup):
#   - Old ML prediction engine (Predictor, AIController, round timer)
#   - Discovery scanner / AI brain tick
#   - Old portfolio popup with "Founder tier" leakage
#   - Track Record / AI Journal views (tied to dead engine)
#   - Watchlist row at top (replaced by Holdings)
#   - Status row counters (PREDICTIONS/ACCURACY/AVG PNL/LEARNING/MODELS/SOURCES)
#   - "Next scan in 45s" progress bar
#   - All the AI self-repair / self-thinking / self-optimize machinery
#
# The actual analysis lives in tm_holdings.py (the Holdings window) and
# tm_ai_chat.py (the chat window). This file is now mostly the shell that
# launches them.
# ═══════════════════════════════════════════════════════════════════════════
class App:
    # v4.14.5.14-merge-and-unify-fix Fix 1 (2026-05-19): class-level
    # default for _activity_text so `self._log` calls from very early
    # in __init__ (before line ~5117 where the instance attribute is
    # first assigned) no longer raise AttributeError on the
    # `if self._activity_text is not None:` guard. Previously every
    # such early call silently lost both the UI write AND the disk
    # write because the AttributeError propagated out of `_log`
    # before reaching the disk-write at the end of the function, and
    # the call sites' outer try/except swallowed it. Class-level
    # default = None means the guard short-circuits cleanly and the
    # disk write at the end still fires, so early diagnostic lines
    # actually land in data/activity.log. See IDEAS.md "Discipline
    # patterns surfaced 2026-05-19" Pattern 3 and HANDOFF item 16.
    _activity_text = None

    def __init__(self, root):
        self.root = root
        self.root.title("Tired Market Analyzation")
        # v4.14.5.94-watch-phase1 (2026-06-11): Ctrl+W opens the
        # Watching list — WATCH'd picks per path with their stored
        # wait-rationale. Read-only, reuses signals.jsonl entries the
        # consensus runner already captures (v4.14.5.93 reader). Flag
        # use_watching_list default True; off → bind no-ops. Defensive
        # try/except so a Tk bind fault never wedges startup.
        try:
            self.root.bind('<Control-w>',
                            lambda _e: self._open_watching_window())
            self.root.bind('<Control-W>',
                            lambda _e: self._open_watching_window())
        except Exception:
            pass

        # Phase 2: register self with the Teacher AI intercept layer
        # so emit_system_event() calls from background workers (cache
        # layer, API layer, etc.) can route surfaces back to this app
        # without needing an explicit app handle threaded through.
        try:
            import tm_teacher_intercept as _tm_ic
            _tm_ic.register_app(self)
        except Exception:
            pass

        # ── Responsive window sizing ──
        screen_w = self.root.winfo_screenwidth()
        screen_h = self.root.winfo_screenheight()
        # Smaller default — old layout was 1600x950 because of all the
        # signal cards and watchlist. The new layout doesn't need all that.
        target_w = min(1100, max(900, int(screen_w * 0.65)))
        target_h = min(720, max(600, int(screen_h * 0.7)))
        x = (screen_w - target_w) // 2
        y = (screen_h - target_h) // 2
        self.root.geometry(f"{target_w}x{target_h}+{x}+{y}")
        self.root.minsize(800, 540)

        # ── Theme colors ──
        # Same palette as the rest of the app. Dark, easy on the eyes.
        self.c = {
            'bg':      '#080c14',
            'card':    '#0f1520',
            'card2':   '#161e2e',
            'border':  '#1c2536',
            'text':    '#cfd6e1',
            'muted':   '#7a8497',
            'dim':     '#4a5468',
            'accent':  '#7aa2f7',
            'green':   '#9ece6a',
            'amber':   '#e0af68',
            'red':     '#f7768e',
            'teal':    '#73daca',
            'purple':  '#bb9af7',
            'blue':    '#7dcfff',
        }
        # ────────────────────────────────────────────────────────────────
        # v4.10.4: DESIGN SYSTEM TOKENS
        # ────────────────────────────────────────────────────────────────
        # Typography scale — five sizes only. Replaces the 11 ad-hoc
        # font sizes scattered across the codebase. New windows should
        # use these tokens; old windows get migrated to them in v4.10.5+.
        self.fonts = {
            'caption':    ('Segoe UI', 8),           # tooltips, footnotes
            'body':       ('Segoe UI', 9),           # most text
            'body_bold':  ('Segoe UI', 9, 'bold'),   # buttons, labels
            'heading':    ('Segoe UI', 12, 'bold'),  # section headers
            'display':    ('Segoe UI', 18, 'bold'),  # window titles, big numbers
            'mono':       ('Consolas', 9),           # ticker tables, numbers
            'mono_bold':  ('Consolas', 9, 'bold'),   # emphasized monospace
        }
        # Spacing scale — 4-pixel grid. Replaces the 9 random padx/pady
        # values found across the codebase.
        self.space = {
            'xs': 4,    # tight inline
            'sm': 8,    # related elements
            'md': 12,   # sections within a card
            'lg': 16,   # between cards
            'xl': 24,   # page margins
        }
        # Button category colors — by role, not aesthetic.
        # Every button picks ONE of these based on what it does.
        self.btn = {
            'primary':   self.c['accent'],   # main action on the screen
            'secondary': self.c['teal'],     # supporting action
            'utility':   self.c['muted'],    # meta-actions (Settings, Help)
            'danger':    self.c['red'],      # destructive (Stop, Exit, Delete)
        }
        self.root.configure(bg=self.c['bg'])

        # v4.10.4: configure ttk styling so Combobox / Scrollbar etc.
        # match the dark theme instead of rendering as pale Windows
        # default widgets. Has to happen after root is created.
        try:
            self._apply_ttk_styling()
        except Exception as e:
            # Never fatal — fall back to default ttk look
            pass

        # ── State ──
        self.cfg = load_config()

        # v4.14.5.62-validated-accuracy: push the accuracy-attribution flag
        # into tm_source_accuracy's module gate once at startup. OFF (default)
        # leaves every accuracy surface byte-identical; ON makes them count
        # only tier-2-validated picks. Re-synced on Settings save.
        try:
            import tm_source_accuracy as _tsa_init
            _tsa_init.set_attributable_only(
                self.cfg.get('use_validated_accuracy', False))
        except Exception:
            pass
        # v4.14.5.62-analyst-facts: push the FACTS-block analyst gate into
        # tm_context_builder once at startup (re-synced on Settings save).
        try:
            import tm_context_builder as _tcb_init
            _tcb_init.set_surface_analyst_facts(
                self.cfg.get('surface_analyst_facts', True))
            _tcb_init.set_surface_8k_events(
                self.cfg.get('surface_8k_events', True))
            _tcb_init.set_surface_insider_flow(
                self.cfg.get('surface_insider_flow', True))
        except Exception:
            pass
        # v4.14.5.62-autoenable-multiprovider: one-time migration — the two
        # multi-provider perf flags (use_concurrent_scan_dispatch,
        # parallel_consensus) had NO UI, so a persisted `false` is the OLD
        # static default, not a deliberate choice. Convert a legacy `false`
        # to the new "auto" sentinel ONCE (marker-gated) so multi-provider
        # users auto-enable. A value the user sets AFTER this (true/false) is
        # honored thereafter. Persists so it sticks across launches.
        try:
            if not self.cfg.get('_autoenable_multiprovider_migrated'):
                _changed = False
                for _ak in ('use_concurrent_scan_dispatch',
                            'parallel_consensus'):
                    if self.cfg.get(_ak) is False:
                        self.cfg[_ak] = 'auto'
                        _changed = True
                self.cfg['_autoenable_multiprovider_migrated'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
        except Exception:
            pass
        # v4.14.5.62-lottery-fill-enable: one-time migration — Speculative
        # (lottery) fill was RE-ENABLED in the engine default (.55,
        # tm_queue_runner._FILL_DEFAULT_TARGETS=True), but a persisted
        # path_fill_targets carrying the stale pre-.55 lottery.fill_enabled=
        # false SHADOWS it (_get_path_fill_targets prefers cfg when present),
        # so _fill_needed skips lottery and Speculative never dispatches
        # (0 picks). Flip a legacy persisted `false` -> true ONCE (marker-
        # gated); a value the user sets AFTER this is honored. Mirrors the
        # autoenable migration above. Guards for absent/odd shapes.
        try:
            if not self.cfg.get('_lottery_fill_enabled_migrated'):
                try:
                    _pft = self.cfg.get('path_fill_targets')
                    if isinstance(_pft, dict):
                        _lot = _pft.get('lottery')
                        if isinstance(_lot, dict) and _lot.get('fill_enabled') is False:
                            _lot['fill_enabled'] = True
                except Exception:
                    pass
                self.cfg['_lottery_fill_enabled_migrated'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
        except Exception:
            pass
        # v4.14.5.62-layer3-replace-default: one-time migration — Layer-3
        # Replace (drops validation-contradicted BUYs) shipped DORMANT
        # (default False); it's now default True for everyone. A persisted
        # `false` is the OLD dormant default, not a deliberate opt-out, so flip
        # it to True ONCE (marker-gated). A deliberate `true` (Mike already has
        # it on) is left untouched by the `is False` guard, and a value the user
        # sets AFTER this migration is honored (the marker blocks re-flips).
        # Mirrors the lottery / autoenable migrations.
        try:
            if not self.cfg.get('_layer3_replace_default_migrated'):
                if self.cfg.get('use_layer3_replace') is False:
                    self.cfg['use_layer3_replace'] = True
                self.cfg['_layer3_replace_default_migrated'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
        except Exception:
            pass
        # v4.14.5.62-parallel-consensus + autoenable: push the consensus
        # dispatch-mode flag into tm_consensus once at startup (re-synced on
        # Settings save). The cfg value may be "auto" → effective ON when >=2
        # working providers; a real bool is an explicit override. Logged so the
        # AUTO/EXPLICIT decision + provider count is visible.
        try:
            import tm_consensus as _tmc_init
            import tm_teacher_intercept as _tmic_init
            _pc_val = self.cfg.get('parallel_consensus', 'auto')
            _pc_eff = _tmic_init.multiprovider_autoflag(_pc_val, self)
            _tmc_init.set_parallel_consensus(
                _pc_eff,
                self.cfg.get('parallel_consensus_max_workers', 5))
            try:
                _cs_val = self.cfg.get('use_concurrent_scan_dispatch', 'auto')
                self._log(
                    f"[startup] parallel consensus: "
                    f"{_tmic_init.multiprovider_autoflag_reason(_pc_val, self)}"
                    f"  |  concurrent scan: "
                    f"{_tmic_init.multiprovider_autoflag_reason(_cs_val, self)}",
                    'muted')
            except Exception:
                pass
        except Exception:
            pass
        # v4.14.5.62-autoenable-rotation: one-time migration — the model-
        # rotation trio (use_model_rotation_schema/router, use_per_model_cap_
        # tracking) defaulted False (advanced, dark flags with no UI), so a
        # persisted `false` is the OLD static default, not a deliberate choice.
        # Convert a legacy `false` → the new "auto" sentinel ONCE (marker-gated)
        # so a multi-model user auto-enables. A deliberate `true` (Mike already
        # has all three on) is LEFT ALONE — explicit on is honored. Persists.
        try:
            if not self.cfg.get('_model_rotation_autoenable_migrated'):
                for _rk in ('use_model_rotation_schema',
                            'use_model_rotation_router',
                            'use_per_model_cap_tracking'):
                    if self.cfg.get(_rk) is False:
                        self.cfg[_rk] = 'auto'
                self.cfg['_model_rotation_autoenable_migrated'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
        except Exception:
            pass
        # v4.14.5.62-autoenable-rotation: resolve the trio's "auto" sentinel
        # against the working-provider model counts and PUSH the effective
        # bools into tm_model_cursor (app-agnostic, can't count providers
        # itself), mirroring the consensus push above. Rotation needs BOTH
        # schema AND router, so AND their resolved values. Re-synced on Settings
        # save. self._model_rotation_auto_enabled records an AUTO-enable (vs an
        # explicit user bool) so the Teacher AI can surface a one-time
        # "I turned rotation on" coaching line.
        self._model_rotation_auto_enabled = False
        try:
            import tm_model_cursor as _mc_init
            import tm_teacher_intercept as _tmic_rot
            _sch_val = self.cfg.get('use_model_rotation_schema', 'auto')
            _rtr_val = self.cfg.get('use_model_rotation_router', 'auto')
            _pmc_val = self.cfg.get('use_per_model_cap_tracking', 'auto')
            _sch_eff = _tmic_rot.model_rotation_autoflag(_sch_val, self)
            _rtr_eff = _tmic_rot.model_rotation_autoflag(_rtr_val, self)
            _pmc_eff = _tmic_rot.model_rotation_autoflag(_pmc_val, self)
            _rot_eff = bool(_sch_eff and _rtr_eff)
            _mc_init.set_rotation_effective(_rot_eff)
            _mc_init.set_per_model_caps_effective(_pmc_eff)
            _auto = (_tmic_rot.model_rotation_is_auto(_sch_val)
                     or _tmic_rot.model_rotation_is_auto(_rtr_val))
            self._model_rotation_auto_enabled = bool(_rot_eff and _auto)
            try:
                self._log(
                    f"[startup] model rotation: "
                    f"{_tmic_rot.model_rotation_autoflag_reason(_sch_val, self)}"
                    f"  |  per-model caps: "
                    f"{_tmic_rot.model_rotation_autoflag_reason(_pmc_val, self)}",
                    'muted')
            except Exception:
                pass
        except Exception:
            pass
        # v4.14.5.62-tier2-validator-select: push the flexible-validator gate
        # into tm_layer2_validation once at startup (re-synced on Settings
        # save). OFF (default) → strict favorites selection, byte-identical.
        try:
            import tm_layer2_validation as _tl2_init
            _tl2_init.set_flexible_validators(
                self.cfg.get('tier2_flexible_validators', True),
                self.cfg.get('tier2_validator_wait_threshold_sec', 12))
        except Exception:
            pass

        # ── v4.14.0 stage 6d: one-shot provider-name migration ──
        # Drops "My"/"my" prefix, fixes "Minstral" → "Mistral",
        # normalizes "Github" → "GitHub" / "Sambanova" → "SambaNova"
        # in data/api_providers.json. Idempotent; cfg flag prevents
        # re-runs. Must run BEFORE any code path that reads provider
        # names for display (chip strip, AI Mode dialog, consensus
        # runner). Errors are silent — old names keep working.
        #
        # v4.14.0 stage 7: schema bump v1 → v2 adds last_discovered_at
        # per provider entry. Independent migration, runs alongside
        # the name migration. Both idempotent. Stage 7 must run AFTER
        # the name migration (the .bak safety net references the
        # v4.14.0 generation of the file post-name-fix).
        try:
            import tm_api_providers as _tmap6d
            _tmap6d.migrate_provider_names_v4140(self.cfg)
            _tmap6d.migrate_api_providers_v4140_stage7(self.cfg)
            # v4.14.5.14b-prov: relabel pre-card Custom entries
            # (Cerebras/GitHub/SambaNova) to first-class. Idempotent,
            # non-destructive (partial preset update only). Flag-gated.
            try:
                if bool(self.cfg.get('use_providers_dialog_v2', True)):
                    _mig = _tmap6d.migrate_custom_to_first_class_v414b(
                        self.cfg)
                    for _nm, _old, _new in (_mig or []):
                        try:
                            self._log(
                                f"[providers] relabeled '{_nm}' "
                                f"{_old} → {_new} (first-class)",
                                'muted')
                        except Exception:
                            pass
            except Exception:
                pass
            # v4.14.5.14-rot Patch 1: seed per-provider models[] from
            # the singular model. Flag-gated (default OFF) so the
            # flag-off path runs NO migration → byte-identical.
            # Non-destructive + idempotent; singular `model` kept.
            try:
                if bool(self.cfg.get(
                        'use_model_rotation_schema', False)):
                    _rm = _tmap6d.migrate_models_list_v414rot(self.cfg)
                    for _nm, _ml in (_rm or []):
                        try:
                            self._log(
                                f"[providers] '{_nm}': seeded "
                                f"models rotation list {_ml}",
                                'muted')
                        except Exception:
                            pass
            except Exception:
                pass
            try: save_config(self.cfg)
            except Exception: pass
        except Exception:
            pass

        # v4.14.5.14-merge-and-unify (2026-05-19): apply Mike's
        # articulated penny_lottery→lottery merge (IDEAS.md
        # 2026-05-19) across the path-aware modules + the local
        # Recommend dropdown / universe-mismatch dict. Flag default
        # True; one-shot log so Mike sees the merge is engaged. Each
        # module's apply_path_merge_v414514mu is idempotent and
        # returns True only on first apply this process — so a
        # single True from any is enough to emit the announcement.
        try:
            import tm_path_candidate_pools as _tmpcp_mu
            import tm_event_triggers as _tmet_mu
            _applied_any = False
            for _mod in (tm_holdings, _tmpcp_mu, _tmet_mu):
                try:
                    if _mod.apply_path_merge_v414514mu(self.cfg):
                        _applied_any = True
                except Exception as _emu:
                    try:
                        self._log(
                            f"[path-merge] {_mod.__name__} apply "
                            f"failed (ignored, legacy path active): "
                            f"{type(_emu).__name__}: {_emu}", 'amber')
                    except Exception:
                        pass
            # When merge active, also drop penny_lottery from the local
            # Recommend trading-style dropdown labels. (The path-universe-
            # mismatch hint dict was removed entirely in
            # v4.14.5.14-stale-cleanup.) Source literals are kept intact
            # above so flag-off rollback restores them on the next restart.
            if bool(self.cfg.get('use_path_merge', True)):
                _RECO_STYLE_LABELS.pop('penny_lottery', None)
            if _applied_any:
                # Fix 2 (2026-05-19): persist the user-override cfg
                # mutations that tm_path_candidate_pools.apply now
                # makes (lottery: min=0/max=5, drop penny_lottery
                # from path_candidate_pools + path_fill_targets). The
                # _CFG_DEFAULT mutation is in-memory; without this
                # save the next restart re-reads the stale user
                # override and re-stomps the merge.
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
                try:
                    self._log(
                        "[path-merge] active — penny_lottery folded "
                        "into lottery (lottery now means under $5 "
                        "cheap speculation; staleness window matches "
                        "moderate; historical penny_lottery picks "
                        "roll up into lottery in Track Record). See "
                        "IDEAS.md 2026-05-19 entry. "
                        "use_path_merge=false + restart reverts.",
                        'green')
                except Exception:
                    pass
        except Exception:
            pass

        # v4.14.5.14-merge-and-unify-fix Fixes 3/4/5a (2026-05-19):
        # three one-shot startup migrations that close the parallel-
        # state-store gaps the shipped merge-and-unify patch missed.
        # Each is gated on a durable marker key in cfg so it fires
        # exactly once per machine and is then inert on every
        # subsequent restart (same pattern as the persisted-cap
        # sanity wipe in v4.14.5.14-classify429-fix — see HANDOFF
        # item 17 for the reference shape). All three only do
        # anything when use_path_merge is True; flag off → markers
        # stay absent → if user later flips the flag on, migrations
        # run then. Fail-OPEN per migration (one's failure doesn't
        # block the others). save_config once at the end if any
        # migration changed something.
        _mu_cfg_dirty = False
        try:
            if bool(self.cfg.get('use_path_merge', True)):
                # ── Fix 3: use_unified_multi_path_prompts default-flip
                # migration. load_config is set-default-if-missing, so
                # a user (like Mike) who explicitly persisted False
                # from the c-p2 validation phase silently kept False
                # even after the patch flipped the default to True.
                # First run sets the flag to True AND drops the
                # marker. Subsequent restarts see the marker and
                # respect whatever Mike has the flag set to (so he can
                # explicitly turn it back off after the migration
                # without it being re-flipped).
                if not self.cfg.get(
                        '_v414514mu_unification_migrated'):
                    _was = self.cfg.get(
                        'use_unified_multi_path_prompts')
                    if _was is not True:
                        self.cfg[
                            'use_unified_multi_path_prompts'] = True
                        try:
                            self._log(
                                "[migration] use_unified_multi_path_"
                                f"prompts: {_was!r} -> True "
                                "(v4.14.5.14-merge-and-unify default "
                                "flip; one-shot, marker now set).",
                                'green')
                        except Exception:
                            pass
                    self.cfg[
                        '_v414514mu_unification_migrated'] = True
                    _mu_cfg_dirty = True

                # ── Fix 4: data/path_config.json migration. The
                # `Paths active:` startup log line reads via
                # tm_recommend.get_path_config_summary which reads
                # this separate file — never touched by the merge.
                # Remove the penny_lottery entry once. The file
                # writer is just json.dump (the reader caches in
                # _PATH_CONFIG_CACHE; restart re-reads, so the
                # post-write effect is visible on the next launch).
                if not self.cfg.get(
                        '_v414514mu_path_config_json_migrated'):
                    try:
                        _pc_path = (
                            DATA_DIR / 'path_config.json')
                        if _pc_path.exists():
                            with open(_pc_path,
                                       encoding='utf-8') as _fh:
                                _pc = json.load(_fh)
                            _paths_d = (_pc.get('paths')
                                        if isinstance(_pc, dict)
                                        else None)
                            if (isinstance(_paths_d, dict)
                                    and 'penny_lottery'
                                    in _paths_d):
                                _paths_d.pop('penny_lottery', None)
                                _tmp = _pc_path.with_suffix(
                                    '.json.tmp')
                                _tmp.write_text(
                                    json.dumps(_pc, indent=2),
                                    encoding='utf-8')
                                _tmp.replace(_pc_path)
                                # Invalidate tm_recommend's
                                # _PATH_CONFIG cache so the in-process
                                # `Paths active:` log line that runs
                                # later in this same startup reads
                                # the freshly-written file, not a
                                # stale cached copy. Without this,
                                # the effect is only visible on the
                                # NEXT restart.
                                try:
                                    import tm_recommend as _tmr_inv
                                    _tmr_inv._PATH_CONFIG_LOADED = (
                                        False)
                                    _tmr_inv._PATH_CONFIG_CACHE = (
                                        None)
                                except Exception:
                                    pass
                                try:
                                    self._log(
                                        "[migration] path_config."
                                        "json: removed penny_"
                                        "lottery entry (one-shot, "
                                        "marker now set).", 'green')
                                except Exception:
                                    pass
                    except Exception as _epc:
                        try:
                            self._log(
                                "[migration] path_config.json "
                                "migration failed (ignored, "
                                "marker NOT set — will retry "
                                f"next restart): {type(_epc).__name__}"
                                f": {_epc}", 'amber')
                        except Exception:
                            pass
                    else:
                        self.cfg[
                            '_v414514mu_path_config_json_migrated'
                        ] = True
                        _mu_cfg_dirty = True

                # v4.14.5.14-cadence-dampening-and-f5a-hygiene Part D
                # (2026-05-20): the v4.14.5.14-merge-and-unify-fix F5a
                # `recommend_cache` stale-path sweep block USED to live
                # here. It was inert — `self.db` was None at this point
                # in App.__init__ (the Database() call is ~70 lines
                # below) so the sweep silently no-op'd while STILL
                # setting the marker `_v414514mu_recommend_cache_swept`.
                # The eligibility-fix's R2 placement-after-Database()
                # lesson exposed the bug. F5a's corrected replay now
                # runs AFTER `self.db = Database()` alongside R2,
                # gated on a NEW marker `_v414514cdfh_f5a_replay`
                # (Mike's old marker is True from the broken run and
                # can't be reused). Block deleted here so the broken
                # template can't be copy-pasted into a future
                # migration; see the new block below the Database
                # construction.
        except Exception:
            pass
        if _mu_cfg_dirty:
            try:
                save_config(self.cfg)
            except Exception:
                pass

        self.portfolio = load_portfolio()
        self.db = Database()
        self.db.set_config_ref(self.cfg)
        tm_cache.get_connection()  # v4.15.0: ensure cache.db exists and schema is current

        # ── v4.14.5.14-recommend-eligibility-fix R2 (2026-05-20):
        # one-shot startup sweep of recommend_cache rows whose
        # ticker price is outside the path's current band. Reference
        # case this patch was written for: ALGM ($55) and ADT
        # ($8.50) were sitting in lottery rows from before the merge
        # changed lottery's band to $0-$5. The Layer-1 eligibility
        # gate was correctly rejecting them every dispatch cycle,
        # but the Recommend dialog still surfaced them as actionable
        # BUYs because nothing in the display pipeline applied the
        # band check. R1 (in _read_recommend_cache_picks) is the
        # always-on display filter; R2 cleans up existing stale rows
        # once at startup. Rows with a missing/unknown price are
        # SKIPPED (fail-safe — only delete what we can verify is out
        # of band). Marker gated on
        # `_v414514ref_recommend_cache_eligibility_swept`. Placed
        # after `self.db = Database()` because it needs a live
        # connection (lesson from the merge-and-unify-fix F5a sweep
        # which sat in the earlier migration block before self.db
        # existed and silently no-op'd on Mike's machine — see
        # HANDOFF item 18 / follow the call chain).
        if not self.cfg.get(
                '_v414514ref_recommend_cache_eligibility_swept'):
            try:
                _conn_r2 = getattr(self.db, 'conn', None)
                if _conn_r2 is not None:
                    import tm_path_candidate_pools as _tpcp_r2
                    import tm_queue_runner as _qr_r2
                    _rows_r2 = _conn_r2.execute(
                        "SELECT ticker, path "
                        "FROM recommend_cache").fetchall()
                    _to_delete_r2 = []
                    for _tk_r2, _pth_r2 in _rows_r2:
                        try:
                            _pcfg_r2 = _tpcp_r2._cfg(
                                self, _pth_r2) or {}
                        except Exception:
                            _pcfg_r2 = {}
                        _lo_r2 = _pcfg_r2.get('min_price_usd')
                        _hi_r2 = _pcfg_r2.get('max_price_usd')
                        if _lo_r2 is None and _hi_r2 is None:
                            continue
                        _price_r2 = _qr_r2._latest_close_for(_tk_r2)
                        if _price_r2 is None:
                            continue  # fail-safe: skip unknowable
                        if ((_lo_r2 is not None
                             and _price_r2 < float(_lo_r2))
                            or (_hi_r2 is not None
                                and _price_r2 > float(_hi_r2))):
                            _to_delete_r2.append(
                                (_tk_r2, _pth_r2))
                    if _to_delete_r2:
                        _conn_r2.executemany(
                            "DELETE FROM recommend_cache "
                            "WHERE ticker = ? AND path = ?",
                            _to_delete_r2)
                        _conn_r2.commit()
                    try:
                        self._log(
                            "[migration] recommend_cache "
                            "eligibility sweep: "
                            f"{len(_to_delete_r2)} stale-band "
                            "row(s) deleted.", 'green')
                    except Exception:
                        pass
                    self.cfg[
                        '_v414514ref_recommend_cache_eligibility_swept'
                    ] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
            except Exception as _ese_r2:
                try:
                    self._log(
                        "[migration] recommend_cache eligibility "
                        "sweep failed (ignored, marker NOT set — "
                        "will retry next restart): "
                        f"{type(_ese_r2).__name__}: {_ese_r2}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-cadence-dampening-and-f5a-hygiene Part D
        # (2026-05-20): F5a "stale-path recommend_cache row" sweep
        # replay after the placement bug fix. The original F5a block
        # sat at line ~5101 BEFORE `self.db = Database()` and silently
        # no-op'd while still setting its marker
        # (`_v414514mu_recommend_cache_swept`), so on Mike's machine
        # any pre-merge `penny_lottery` rows survived all subsequent
        # restarts. R2 doesn't catch these because the penny_lottery
        # path has no band entry post-merge ("no band → no gate" →
        # R2 skip). New marker `_v414514cdfh_f5a_replay` so Mike's
        # already-set old marker doesn't block this. Runtime works
        # exactly as F5a was supposed to: DELETE every row whose
        # `path` is no longer in `tm_holdings.PATHS` (penny_lottery
        # today, any future removed path tomorrow — self-sweeping).
        # Placed after `self.db = Database()` so `self.db.conn` is
        # real, not None. Fail-OPEN: on any error the marker stays
        # unset and the sweep retries on the next restart.
        if not self.cfg.get('_v414514cdfh_f5a_replay'):
            try:
                _conn_f5a = getattr(self.db, 'conn', None)
                if _conn_f5a is not None:
                    _valid_paths = tuple(
                        sorted(tm_holdings.PATHS.keys()))
                    if _valid_paths:
                        _ph = ",".join("?" * len(_valid_paths))
                        _cur_f5a = _conn_f5a.execute(
                            "DELETE FROM recommend_cache "
                            f"WHERE path NOT IN ({_ph})",
                            _valid_paths)
                        _n_f5a = _cur_f5a.rowcount
                        _conn_f5a.commit()
                        try:
                            self._log(
                                "[migration] F5a replay after "
                                f"placement fix: {_n_f5a} "
                                "stale-path row(s) cleaned "
                                f"(paths not in {list(_valid_paths)}).",
                                'green')
                        except Exception:
                            pass
                        self.cfg[
                            '_v414514cdfh_f5a_replay'] = True
                        try:
                            save_config(self.cfg)
                        except Exception:
                            pass
            except Exception as _ef5a:
                try:
                    self._log(
                        "[migration] F5a replay failed (ignored, "
                        "marker NOT set — will retry next "
                        "restart): "
                        f"{type(_ef5a).__name__}: {_ef5a}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.80-cache-metadata-hygiene: one-shot sanitize of
        # garbage have_to_date / have_from_date in cache_metadata.
        # Investigation (post v.79 ship) found ~18 daily_bars metadata
        # rows carrying literal HTML fragments (`('</script`,
        # `('(async()`) as date values — yfinance returned an HTML
        # error/landing page and `_v415_cache_write_bars`'s
        # `str(idx)[:10]` fallback captured the first 10 chars of the
        # JS body as a "date string." The v.79 resolver defensively
        # falls back to a full 2y pull on those rows, so they re-pay
        # the restart fill tax every time. This migration NULLs the
        # malformed date fields ONCE so those tickers re-fill cleanly
        # through the normal daily_bars path (full pull for them
        # ONCE) and then ride the cheap v.79 incremental path forever.
        # Bar rows in `daily_bars` itself are NOT touched — only the
        # metadata's date columns. Marker-gated:
        # `_v414580_cache_metadata_sanitized`. Placed after
        # `self.db = Database()` (F5a placement lesson). Bypassed
        # entirely when `cfg['use_cache_metadata_hygiene']=False`.
        if (bool(self.cfg.get('use_cache_metadata_hygiene', True))
                and not self.cfg.get(
                    '_v414580_cache_metadata_sanitized')):
            # v4.14.6.25-cache-metadata-wrong-db: pre-fix this used
            # self.db.conn (= tired_market.db) but `cache_metadata`
            # lives in cache.db — so it always raised
            # `no such table: cache_metadata`, the marker
            # `_v414580_cache_metadata_sanitized` never set, and the
            # cleanup (~18 malformed have_to/from_date rows + the
            # follow-on daily_bars dead-PK sweep below) HAS NEVER
            # RUN. Open the correct cache.db connection via tm_cache
            # (its WAL + busy_timeout discipline) and close in finally.
            _conn_cmh = None
            try:
                try:
                    import tm_cache as _tmc_cmh
                    _conn_cmh = _tmc_cmh.get_connection()
                except Exception:
                    _conn_cmh = None
                if _conn_cmh is not None:
                    from datetime import date as _date_cmh
                    # 1. Scan every row with a non-NULL date field and
                    # parse-validate each value individually. We
                    # deliberately do NOT pre-filter with `NOT LIKE
                    # '____-__-__%'` — values like '2026-13-99' MATCH
                    # that LIKE shape but FAIL date.fromisoformat,
                    # so a SQL pre-filter would miss them. The
                    # per-row parse check is microseconds × N rows,
                    # runs once at startup, and catches every
                    # malformed shape (HTML/JS fragments AND
                    # LIKE-passing-but-invalid dates).
                    _cur_cmh = _conn_cmh.execute(
                        "SELECT rowid, ticker, lane, "
                        "       have_from_date, have_to_date "
                        "FROM cache_metadata "
                        "WHERE have_from_date IS NOT NULL "
                        "   OR have_to_date IS NOT NULL"
                    )
                    _candidates = list(_cur_cmh.fetchall())
                    _bad_rowids: list = []
                    _bad_ht_count = 0
                    _bad_hf_count = 0
                    for _rid, _tk, _lane, _hf, _ht in _candidates:
                        _bad_hf = False
                        _bad_ht = False
                        if _hf is not None:
                            try:
                                _date_cmh.fromisoformat(str(_hf)[:10])
                            except (ValueError, TypeError):
                                _bad_hf = True
                        if _ht is not None:
                            try:
                                _date_cmh.fromisoformat(str(_ht)[:10])
                            except (ValueError, TypeError):
                                _bad_ht = True
                        if _bad_hf or _bad_ht:
                            _bad_rowids.append((_rid, _bad_hf, _bad_ht))
                            if _bad_hf:
                                _bad_hf_count += 1
                            if _bad_ht:
                                _bad_ht_count += 1
                    # 2. NULL the malformed fields one row at a time
                    # so we don't touch the valid sibling field on
                    # the same row.
                    for _rid, _bf, _bt in _bad_rowids:
                        _sets: list = []
                        if _bf:
                            _sets.append("have_from_date = NULL")
                        if _bt:
                            _sets.append("have_to_date = NULL")
                        if _sets:
                            _conn_cmh.execute(
                                f"UPDATE cache_metadata SET "
                                f"{', '.join(_sets)} WHERE rowid = ?",
                                (_rid,))
                    _conn_cmh.commit()
                    try:
                        self._log(
                            f"[migration] cache_metadata hygiene: "
                            f"nulled {_bad_ht_count} malformed "
                            f"have_to_date + {_bad_hf_count} "
                            f"have_from_date value(s) across "
                            f"{len(_bad_rowids)} row(s) — these "
                            f"tickers will re-fill once cleanly "
                            f"then ride incremental.",
                            'green' if (_bad_ht_count + _bad_hf_count)
                            else 'muted')
                    except Exception:
                        pass
                    self.cfg[
                        '_v414580_cache_metadata_sanitized'] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
            except Exception as _ecmh:
                try:
                    self._log(
                        "[migration] cache_metadata hygiene "
                        "failed (ignored, marker NOT set — will "
                        "retry next restart): "
                        f"{type(_ecmh).__name__}: {_ecmh}",
                        'amber')
                except Exception:
                    pass
            finally:
                if _conn_cmh is not None:
                    try:
                        _conn_cmh.close()
                    except Exception:
                        pass

        # ── v4.14.6.25-sec-name-bootstrap: bulk-populate
        # cache.db.tickers.name from SEC's company_tickers.json.
        # See _bulk_bootstrap_names_from_sec docstring for context —
        # pre-v4.14.6.25 the lazy yfinance-only bootstrap left ~89.5%
        # of universe names empty because yfinance rate-limited every
        # probe; the empty-name epidemic was the root cause of the
        # CARD-class entity-filter regression. SEC ships ~10,400
        # (ticker, title, cik) entries in one free request, covering
        # ~95% of the universe (everything except preferreds, warrants,
        # units, ETFs, and foreign listings — yfinance stays the
        # per-ticker fallback for those).
        #
        # Marker-gated: runs only if the marker is absent OR > 7 days
        # old. Set only on success — an offline / unreachable / non-200
        # SEC response logs once at amber and leaves the marker unset
        # so the next eligible startup retries. App continues normally
        # in all failure modes.
        # v4.14.6.26-seed-no-clobber: one-time marker reset. v4.14.6.25
        # shipped before the seed-clobber bug was understood, so the
        # SEC bootstrap ran once, set the 7-day marker, and then watched
        # the universe seed wipe the names ~20 s later. Now that
        # upsert_tickers is non-clobbering (Fix A), the names will
        # survive — but the marker is already set, so without this
        # reset the bootstrap won't re-fire for 7 days and most names
        # would stay NULL in the interim. Mechanism: a tiny idempotent
        # migration gated by its OWN one-shot marker
        # `_v414626_seed_clobber_marker_reset` clears the SEC marker
        # exactly once on the first v4.14.6.26 startup, then itself
        # latches so the SEC bootstrap resumes its normal 7-day cadence
        # afterward. No-op on a fresh install (the SEC marker is absent
        # anyway, so the reset is harmless and the latch just sets).
        try:
            if not self.cfg.get(
                    '_v414626_seed_clobber_marker_reset'):
                if self.cfg.get('_v414625_sec_names_last_run'):
                    self.cfg['_v414625_sec_names_last_run'] = None
                    try:
                        self._log(
                            "[migration] v4.14.6.26 seed-clobber "
                            "marker reset: cleared "
                            "_v414625_sec_names_last_run so SEC "
                            "bootstrap re-runs once to repopulate "
                            "names that the prior seed-clobber wiped. "
                            "Returns to normal 7-day cadence after "
                            "this run.",
                            'muted')
                    except Exception:
                        pass
                self.cfg[
                    '_v414626_seed_clobber_marker_reset'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
        except Exception:
            pass
        try:
            _sec_marker_iso = self.cfg.get(
                '_v414625_sec_names_last_run')
            _sec_run = True
            if _sec_marker_iso:
                try:
                    _sec_last = datetime.fromisoformat(str(_sec_marker_iso))
                    _sec_age_days = (
                        datetime.now() - _sec_last
                    ).total_seconds() / 86400.0
                    if _sec_age_days < 7.0:
                        _sec_run = False
                except Exception:
                    pass  # malformed marker → run
            if _sec_run:
                def _sec_log(_m, _t='muted'):
                    try:
                        self._log(_m, _t)
                    except Exception:
                        pass
                # Best-effort offline-safe call; never raises.
                _sec_stat = _bulk_bootstrap_names_from_sec(
                    self, log_fn=_sec_log)
                if (isinstance(_sec_stat, dict)
                        and not _sec_stat.get('error')
                        and _sec_stat.get('fetched', 0) > 0):
                    self.cfg[
                        '_v414625_sec_names_last_run'] = (
                        datetime.now().isoformat(timespec='seconds'))
                    try: save_config(self.cfg)
                    except Exception: pass
                    try:
                        self._log(
                            f"[sec-names] bootstrap complete: "
                            f"{_sec_stat.get('updated', 0)} name(s) "
                            f"updated, "
                            f"{_sec_stat.get('cik_updated', 0)} cik(s) "
                            f"filled "
                            f"(SEC supplied "
                            f"{_sec_stat.get('fetched', 0)}, "
                            f"{_sec_stat.get('matched', 0)} "
                            f"matched universe).",
                            'green' if _sec_stat.get('updated', 0)
                            else 'muted')
                    except Exception:
                        pass
        except Exception as _esec:
            try:
                self._log(
                    f"[sec-names] bootstrap launcher failed "
                    f"(ignored, marker NOT set — will retry next "
                    f"restart): {type(_esec).__name__}: {_esec}",
                    'amber')
            except Exception:
                pass

        # ── v4.14.5.84-fetch-boundary-validation Part B: one-shot
        # sweep of dead PK rows in daily_bars. v.80's metadata
        # hygiene NULL'd garbage have_to_date / have_from_date
        # values but couldn't touch the daily_bars rows themselves —
        # the `date` column is part of the PK and can't be NULL'd.
        # Investigation found ~2,376 rows across 1,188 tickers with
        # literal garbage (`('</script`, `('(async()`) in the date
        # column from the v.80-era HTML-mis-parse bug. Those rows
        # are excluded from any normal date-range query (lexicographic
        # compare against ISO dates fails) — harmless but bloat. v.84
        # ships the upstream validator (Part A) that prevents new
        # garbage from being written; this migration sweeps the
        # existing dead rows. Same `cache.db` connection the v.80
        # migration uses. Marker-gated, idempotent, placed after
        # `self.db = Database()`. Bypassed by
        # `cfg['use_fetch_boundary_validation']=False`.
        if (bool(self.cfg.get('use_fetch_boundary_validation', True))
                and not self.cfg.get(
                    '_v414584_daily_bars_dead_row_sweep')):
            try:
                import tm_cache as _tc_dr
                _cache_conn = _tc_dr.get_connection()
                try:
                    from datetime import date as _date_dr
                    # Mirror v.80's strict validator — pull every row
                    # whose date doesn't lexically prefix-match the
                    # YYYY-MM-DD shape (cheap SQL pre-filter that
                    # catches obvious garbage; we re-validate each
                    # candidate with fromisoformat so a row whose
                    # date matches `____-__-__` shape but isn't a
                    # real date — e.g. '2026-13-99' — also gets
                    # deleted).
                    _cur_dr = _cache_conn.execute(
                        "SELECT rowid, ticker, date FROM daily_bars "
                        "WHERE date NOT LIKE '____-__-__%'")
                    _bad_rowids: list = []
                    for _rid, _tk, _d in _cur_dr.fetchall():
                        _bad_rowids.append(_rid)
                    # Second pass: rows that DO match the shape but
                    # fail strict parse (e.g. impossible dates).
                    _cur_dr2 = _cache_conn.execute(
                        "SELECT rowid, ticker, date FROM daily_bars "
                        "WHERE date LIKE '____-__-__%'")
                    for _rid, _tk, _d in _cur_dr2.fetchall():
                        try:
                            _date_dr.fromisoformat(str(_d)[:10])
                        except (ValueError, TypeError):
                            _bad_rowids.append(_rid)
                    _n_deleted = 0
                    if _bad_rowids:
                        # Batch delete in chunks (sqlite has an
                        # expression-tree limit on huge IN lists).
                        for _i in range(0, len(_bad_rowids), 500):
                            _chunk = _bad_rowids[_i:_i + 500]
                            _ph = ','.join('?' * len(_chunk))
                            _cache_conn.execute(
                                f"DELETE FROM daily_bars "
                                f"WHERE rowid IN ({_ph})",
                                _chunk)
                            _n_deleted += len(_chunk)
                        _cache_conn.commit()
                    try:
                        self._log(
                            f"[migration] daily_bars dead-row "
                            f"sweep: {_n_deleted} garbage-date "
                            f"row(s) deleted.",
                            'green' if _n_deleted else 'muted')
                    except Exception:
                        pass
                    self.cfg[
                        '_v414584_daily_bars_dead_row_sweep'] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
                finally:
                    try:
                        _cache_conn.close()
                    except Exception:
                        pass
            except Exception as _edr:
                try:
                    self._log(
                        "[migration] daily_bars dead-row sweep "
                        "failed (ignored, marker NOT set — will "
                        "retry next restart): "
                        f"{type(_edr).__name__}: {_edr}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-layer2-decouple Part B (2026-05-20):
        # backfill cleanup of daemon-written consensus_fresh_buy
        # signals in `data/signals.jsonl`. Background: between
        # 2026-05-19 evening (when v4.14.5.14b-layer2-fix activated
        # the Layer 2 daemon) and this patch, the daemon wrote ~80+
        # `consensus_fresh_buy` rollup signals to signals.jsonl as
        # an unintended side effect of producing the
        # `recommend_cache_validation` row for the badge. Those
        # rollups feed `_consensus_says_buy` in the Recommend dialog
        # and were the mechanism that dropped 95% of picks. Part A
        # of this patch (ConsensusRunner write-gate) stops future
        # daemon writes. Part B removes the existing backlog so Mike
        # sees the fix immediately rather than waiting up to 5 days
        # for the staleness window to age them out.
        #
        # Discriminator: a `consensus_fresh_buy` entry is
        # daemon-written iff a `recommend_cache_validation` row
        # exists for the same ticker with `validated_at` within ±300
        # seconds of the signal's `ts`. The daemon writes both
        # within seconds; user-initiated Verify writes only the
        # signal (no recommend_cache_validation row). The tight
        # time window prevents false positives where Mike happened
        # to Verify a ticker the daemon also validated.
        #
        # Implementation: atomic rewrite (read all signals.jsonl
        # entries, filter, write to .tmp, os.replace). signals.jsonl
        # is append-only by convention so a rewrite is the cleanest
        # in-place edit. Backs up to `.pre_v4_14_5_14ld_purge.bak`
        # so Mike has a recovery path. Marker
        # `_v414514ld_daemon_signals_purged` set after success only.
        # F5a placement lesson — runs AFTER `self.db = Database()`.
        if not self.cfg.get('_v414514ld_daemon_signals_purged'):
            try:
                _sig_path = DATA_DIR / 'signals.jsonl'
                if _sig_path.exists():
                    from datetime import datetime as _dt_ld
                    # Build {ticker: [validated_at_epoch, ...]} from
                    # recommend_cache_validation for the discriminator.
                    _val_map: dict = {}
                    _conn_ld = getattr(self.db, 'conn', None)
                    if _conn_ld is not None:
                        try:
                            for _t, _va in _conn_ld.execute(
                                "SELECT ticker, validated_at FROM "
                                "recommend_cache_validation"):
                                _val_map.setdefault(
                                    str(_t).upper(), []).append(
                                        int(_va or 0))
                        except Exception:
                            _val_map = {}

                    def _signal_was_daemon_written(_entry):
                        if (_entry.get('kind')
                                != 'consensus_fresh_buy'):
                            return False
                        _tk = str(_entry.get('ticker')
                                   or '').upper()
                        _times = _val_map.get(_tk)
                        if not _times:
                            return False
                        _ts = _entry.get('ts') or ''
                        try:
                            _sig_epoch = int(_dt_ld.fromisoformat(
                                str(_ts).split('+')[0]
                                ).timestamp())
                        except Exception:
                            return False
                        return any(
                            abs(_sig_epoch - _va) <= 300
                            for _va in _times)

                    _kept: list[str] = []
                    _n_dropped = 0
                    with open(_sig_path, encoding='utf-8') as _fh:
                        for _line in _fh:
                            _s = _line.rstrip('\n')
                            if not _s.strip():
                                _kept.append(_s)
                                continue
                            try:
                                _e = json.loads(_s)
                            except Exception:
                                _kept.append(_s)
                                continue
                            if _signal_was_daemon_written(_e):
                                _n_dropped += 1
                                continue
                            _kept.append(_s)

                    if _n_dropped:
                        # Backup then atomic rewrite.
                        _bak = _sig_path.with_suffix(
                            '.jsonl.pre_v4_14_5_14ld_purge.bak')
                        try:
                            if not _bak.exists():
                                _bak.write_text(
                                    _sig_path.read_text(
                                        encoding='utf-8'),
                                    encoding='utf-8')
                        except Exception:
                            pass
                        _tmp = _sig_path.with_suffix('.jsonl.tmp')
                        _tmp.write_text(
                            '\n'.join(_kept) + '\n',
                            encoding='utf-8')
                        os.replace(str(_tmp), str(_sig_path))
                    try:
                        self._log(
                            "[migration] signals.jsonl: purged "
                            f"{_n_dropped} daemon-written "
                            "consensus_fresh_buy entries from the "
                            "v4.14.5.14b-layer2-fix era. Layer 2 "
                            "diagnostic still surfaces via the "
                            "Recommend badge (recommend_cache_"
                            "validation). User-Verify-clicked "
                            "signals preserved.", 'green')
                    except Exception:
                        pass
                    self.cfg[
                        '_v414514ld_daemon_signals_purged'] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
            except Exception as _eld:
                try:
                    self._log(
                        "[migration] Layer 2 daemon signal purge "
                        "failed (ignored, marker NOT set — will "
                        "retry next restart): "
                        f"{type(_eld).__name__}: {_eld}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-displayed-picks-recovery Part C1 (2026-05-20):
        # one-shot penny_lottery cleanup. The v4.14.5.14-merge-and-
        # unify-fix F5a sweep + the cadence-dampening F5a-replay BOTH
        # were supposed to delete penny_lottery rows from
        # recommend_cache. F5a-replay actually ran (marker
        # _v414514cdfh_f5a_replay=True in Mike's config) and DID
        # delete the row at restart-time. The row keeps reappearing
        # because `tm_recommend_cache._PATHS` is a stale literal that
        # still includes 'penny_lottery'; every refresh tick iterates
        # it and re-writes the row from the 3 historical penny_lottery
        # BUYs still in predictions.jsonl. Part C2 of this patch (in
        # tm_recommend_cache.py) replaces that literal with a call-
        # time read from tm_holdings.PATHS — preventing future
        # recurrence. Part C1 (this block) cleans up the current row
        # one more time. New marker `_v414514dpr_penny_lottery_cleanup`
        # so the old F5a-replay marker doesn't block. Placed AFTER
        # `self.db = Database()` (F5a placement lesson).
        if not self.cfg.get(
                '_v414514dpr_penny_lottery_cleanup'):
            try:
                _conn_dpr = getattr(self.db, 'conn', None)
                if _conn_dpr is not None:
                    _valid_dpr = tuple(
                        sorted(tm_holdings.PATHS.keys()))
                    if _valid_dpr:
                        _ph_dpr = ",".join("?" * len(_valid_dpr))
                        _cur_dpr = _conn_dpr.execute(
                            "DELETE FROM recommend_cache "
                            f"WHERE path NOT IN ({_ph_dpr})",
                            _valid_dpr)
                        _n_dpr = _cur_dpr.rowcount
                        _conn_dpr.commit()
                        try:
                            self._log(
                                "[migration] penny_lottery "
                                f"cleanup: {_n_dpr} stale-path "
                                "row(s) deleted "
                                "(tm_recommend_cache writer now "
                                "reads PATHS at call time so the "
                                "row won't recur).", 'green')
                        except Exception:
                            pass
                        self.cfg[
                            '_v414514dpr_penny_lottery_cleanup'
                        ] = True
                        try:
                            save_config(self.cfg)
                        except Exception:
                            pass
            except Exception as _edpr:
                try:
                    self._log(
                        "[migration] penny_lottery cleanup "
                        "failed (ignored, marker NOT set — will "
                        "retry next restart): "
                        f"{type(_edpr).__name__}: {_edpr}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-layer3-replace (2026-05-23): create the Layer 3
        # drop-cooldown table. Runs REGARDLESS of use_layer3_replace so
        # the cooldown query in
        # tm_queue_runner._build_candidate_shortlist never blows up when
        # Mike flips the flag later. Marker `_v414514l3r_drop_log_table`.
        # Placed AFTER `self.db = Database()` (F5a placement lesson).
        if not self.cfg.get('_v414514l3r_drop_log_table'):
            try:
                _conn_l3 = getattr(self.db, 'conn', None)
                if _conn_l3 is not None:
                    _conn_l3.execute(
                        "CREATE TABLE IF NOT EXISTS layer3_drop_log ("
                        " ticker TEXT NOT NULL, path TEXT NOT NULL, "
                        " dropped_at REAL NOT NULL, "
                        " l1_signature TEXT NOT NULL, "
                        " PRIMARY KEY (ticker, path, dropped_at))")
                    _conn_l3.execute(
                        "CREATE INDEX IF NOT EXISTS "
                        "ix_layer3_drop_recent "
                        "ON layer3_drop_log(dropped_at)")
                    _conn_l3.commit()
                    self.cfg['_v414514l3r_drop_log_table'] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
                    try:
                        self._log(
                            "[migration] layer3_drop_log table created "
                            "(Layer 3 daemon dormant pending "
                            "use_layer3_replace=true).", 'green')
                    except Exception:
                        pass
            except Exception as _el3:
                try:
                    self._log(
                        "[migration] layer3_drop_log creation failed "
                        "(ignored, marker NOT set — will retry next "
                        f"restart): {type(_el3).__name__}: {_el3}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-layer2-revalidate-and-heartbeat Part A
        # (2026-05-20): force Layer 2 to re-validate rows that
        # predate the v4.14.5.14-layer2-thesis-validation patch.
        # Background: the thesis-validation patch changed WHAT
        # question the daemon asks each cloud model (from
        # "would you BUY from scratch?" to "is Layer 1's thesis
        # defensible?"), but the daemon's `_select_next_pick`
        # skips any row whose validation is within the 7-day
        # recency window. Existing rows were validated with the
        # OLD prompt yesterday/today — they're all "fresh" and
        # block re-validation for ~6 days. Without this
        # migration, Mike won't see the prompt change's effect
        # on the bulk of his cache until ~2026-05-26.
        # Delete only rows that predate the thesis-validation
        # ship time (2026-05-20 ~15:30 local). Rows written by
        # the new prompt — GOOGL/moderate at 16:15 today, plus
        # anything that lands between this patch shipping and
        # Mike restarting — are preserved. The daemon catches
        # up over ~3 hours (one pick per 180s × ~57 deleted
        # rows). Marker `_v414514lrh_validation_revalidation`.
        # Placed AFTER `self.db = Database()` (F5a placement
        # lesson).
        if not self.cfg.get(
                '_v414514lrh_validation_revalidation'):
            try:
                _conn_lrh = getattr(self.db, 'conn', None)
                if _conn_lrh is not None:
                    from datetime import datetime as _dt_lrh
                    # Cutoff = 2026-05-20 15:30:00 LOCAL,
                    # converted to UTC epoch (validated_at is
                    # stored as int(time.time()), UTC epoch).
                    # The thesis-validation patch shipped
                    # around 15:30 local — anything before is
                    # old-prompt, anything after (incl. GOOGL
                    # at 16:15) is new-prompt.
                    _cutoff_lrh = int(_dt_lrh(
                        2026, 5, 20, 15, 30, 0).timestamp())
                    _cur_lrh = _conn_lrh.execute(
                        "DELETE FROM recommend_cache_validation "
                        "WHERE validated_at < ?",
                        (_cutoff_lrh,))
                    _n_lrh = _cur_lrh.rowcount
                    _conn_lrh.commit()
                    try:
                        self._log(
                            "[migration] recommend_cache_"
                            f"validation: deleted {_n_lrh} "
                            "rows predating thesis-validation "
                            "patch (daemon will re-validate "
                            "with new prompt over next ~3 "
                            "hours).", 'green')
                    except Exception:
                        pass
                    self.cfg[
                        '_v414514lrh_validation_revalidation'
                    ] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
            except Exception as _elrh:
                try:
                    self._log(
                        "[migration] recommend_cache_validation "
                        "revalidation purge failed (ignored, "
                        "marker NOT set — will retry next "
                        "restart): "
                        f"{type(_elrh).__name__}: {_elrh}",
                        'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-layer2-gemini-flash (2026-05-23): one-shot
        # rewrite of any existing Layer 2 preference entry that still
        # names Gemini 2.5 PRO over to Gemini 2.5 FLASH. Background:
        # Pro's free tier has a very low requests-per-minute ceiling,
        # so on Layer 2's back-to-back validation calls it 429'd and
        # was silently dropped from the consensus (live logs showed
        # "2/2 BUY" — only Groq + Mistral actually answered). The
        # shipped default above is now Flash, but a user who already
        # has config.json on disk keeps their saved list — this brings
        # them onto Flash too. Non-destructive: ONLY the model string
        # of a pro entry is rewritten; every other preference entry
        # and all of its ordering is preserved. Idempotent via marker
        # `_v414514l2gf_gemini_flash` AND by the fact that after the
        # rewrite there is no pro entry left to match. Fail-open: any
        # error leaves config untouched and the marker UNSET so it
        # retries next restart. Config-only, but placed in the
        # post-Database() migration block for consistency.
        if not self.cfg.get('_v414514l2gf_gemini_flash'):
            try:
                _l2gf_changed = False
                _l2gf_list = self.cfg.get('layer2_validation_models')
                if isinstance(_l2gf_list, list):
                    for _l2gf_e in _l2gf_list:
                        if (isinstance(_l2gf_e, (list, tuple))
                                and len(_l2gf_e) >= 2
                                and isinstance(_l2gf_e[1], str)
                                and _l2gf_e[1].strip().lower()
                                == 'gemini-2.5-pro'):
                            _l2gf_e[1] = 'gemini-2.5-flash'
                            _l2gf_changed = True
                        elif (isinstance(_l2gf_e, dict)
                                and str(_l2gf_e.get('model', ''))
                                .strip().lower() == 'gemini-2.5-pro'):
                            _l2gf_e['model'] = 'gemini-2.5-flash'
                            _l2gf_changed = True
                self.cfg['_v414514l2gf_gemini_flash'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
                if _l2gf_changed:
                    try:
                        self._log(
                            "[migration] Layer 2 validator updated: "
                            "gemini-2.5-pro -> gemini-2.5-flash "
                            "(Pro's low RPM cap kept dropping it from "
                            "consensus; Flash answers reliably).",
                            'green')
                    except Exception:
                        pass
            except Exception as _el2gf:
                try:
                    self._log(
                        "[migration] gemini-flash preference rewrite "
                        "failed (ignored, marker NOT set — will retry "
                        f"next restart): {type(_el2gf).__name__}: "
                        f"{_el2gf}", 'amber')
                except Exception:
                    pass

        # ── v4.14.5.14-soft-gate-and-cap-hygiene Part B (2026-05-20):
        # archaeological cleanup of stale `_default` records in
        # data/provider_learning.json. Background: rot-p3b flipped
        # cap-tracking from family-level `_default` to per-(family,
        # model). Since that ship (~2026-05-18) all writes route to
        # per-model records, leaving `_default` rows frozen with
        # whatever counters they had on the day the flag flipped —
        # `today_iso='2026-05-18'`, `today_calls=2538` for Mistral,
        # 818 for Cerebras, etc. These rows are INERT at runtime when
        # `use_per_model_cap_tracking=True` (every cap check resolves
        # to the per-model slot), but they look alarmingly like "Mike
        # burned 2538 Mistral calls today!" when read cold. The
        # 2026-05-20 cap-discrepancy investigation report tripped on
        # exactly this and produced a false-alarm "Cerebras over cap"
        # finding. Reset the today-counters (today_iso → today UTC,
        # today_calls/today_429s → 0) so future investigations see
        # honest values. **Preserve `daily_cap`**, `last_updated`,
        # `source` — Phase 0 confirmed `_default.daily_cap` IS still
        # consulted by `_resolve_provider_cap` when no canonical_model
        # is passed (legacy paths), so we don't want to lose the
        # learned cap. Atomic write (tmp + os.replace). Marker
        # `_v414514sgch_default_records_cleaned` gates one-shot fire.
        # Placed AFTER `self.db = Database()` — same placement
        # lesson as the eligibility-fix R2 (F5a sat before Database()
        # and silently no-op'd).
        if not self.cfg.get(
                '_v414514sgch_default_records_cleaned'):
            try:
                _pl_path = DATA_DIR / 'provider_learning.json'
                if _pl_path.exists():
                    from datetime import timezone as _tz_sgch
                    with open(_pl_path, encoding='utf-8') as _fh:
                        _pl_data = json.load(_fh)
                    _today_utc = datetime.now(
                        _tz_sgch.utc).strftime('%Y-%m-%d')
                    _n_cleaned = 0
                    _provs = _pl_data.get('providers') or {}
                    for _fam, _models in _provs.items():
                        if not isinstance(_models, dict):
                            continue
                        _rec = _models.get('_default')
                        if not isinstance(_rec, dict):
                            continue
                        _iso = _rec.get('today_iso')
                        if _iso != _today_utc:
                            _rec['today_iso'] = _today_utc
                            _rec['today_calls'] = 0
                            _rec['today_429s'] = 0
                            _n_cleaned += 1
                    if _n_cleaned:
                        _tmp = _pl_path.with_suffix(
                            '.json.tmp')
                        _tmp.write_text(
                            json.dumps(_pl_data, indent=2),
                            encoding='utf-8')
                        os.replace(str(_tmp), str(_pl_path))
                    try:
                        self._log(
                            "[migration] provider_learning.json: "
                            f"cleaned {_n_cleaned} stale _default "
                            "record(s).", 'green')
                    except Exception:
                        pass
                    self.cfg[
                        '_v414514sgch_default_records_cleaned'
                    ] = True
                    try:
                        save_config(self.cfg)
                    except Exception:
                        pass
            except Exception as _esgch:
                try:
                    self._log(
                        "[migration] provider_learning.json _default "
                        "cleanup failed (ignored, marker NOT set — "
                        "will retry next restart): "
                        f"{type(_esgch).__name__}: {_esgch}",
                        'amber')
                except Exception:
                    pass

        try:
            _lane_promos = _v415_bootstrap_lane_config(
                selfheal=bool(self.cfg.get('use_lane_selfheal', True)))
            for _ln, _chg in (_lane_promos or []):
                try:
                    self._log(
                        f"[lane] {_ln}: promoted {_chg} "
                        f"(key now present)", 'muted')
                except Exception:
                    pass
        except Exception:
            # Bootstrap must never break App init.
            _v415_bootstrap_lane_config(selfheal=False)
        try:
            import tm_data_adapter_edgar as _tedg
            _tedg.set_edgar_retry_safe(
                bool(self.cfg.get('use_edgar_retry_safe', True)))
            # v4.14.5.13: dual-class/delisted symbol-format fallback
            # (BRKB → BRK-B etc.) + per-ticker session dedup.
            _tedg.set_edgar_variant_fallback(
                bool(self.cfg.get('use_edgar_variant_fallback', True)))
        except Exception:
            pass
        try:
            # v4.14.5.14a: demote the momentum filter from population
            # gate to sort key (default True). Component B reads its
            # own cfg flag directly in tm_recommend_cache.
            import tm_recommend_filter as _trf
            _trf.set_filter_as_sort_key(
                bool(self.cfg.get('use_filter_as_sort_key', True)))
        except Exception:
            pass
        try:
            # v4.14.5.14a.2 Component A: when no provider is available,
            # don't write a fake NO_CALL / advance the cursor. Flag
            # default False = new behaviour on; True = legacy write.
            # (Component B reads use_fill_mode_pause_on_exhaustion
            # directly in tm_queue_runner.)
            import tm_api_providers as _tapi
            _tapi.set_no_call_on_provider_exhaustion(
                bool(self.cfg.get(
                    'use_no_call_on_provider_exhaustion', False)))
        except Exception:
            pass
        try:
            # v4.14.5.14-scan-canonical-fallback: on full exhaustion of the
            # rotation-picked canonical model, fall over to the next
            # eligible model instead of skipping the ticker. Default True;
            # False = legacy single-model-then-skip.
            import tm_api_providers as _tapi_scf
            _tapi_scf.set_scan_canonical_fallback(
                bool(self.cfg.get('use_scan_canonical_fallback', True)))
        except Exception:
            pass
        try:
            # v4.14.5.14-retry-and-cleanup-bundle Fix A: apply the
            # transient-503 retry budget override (default 3). The setter
            # clamps to [0,8] and pads the backoff schedule so the retry
            # loop's index can never go out of range.
            import tm_api_providers as _tapi_trc
            _tapi_trc.set_transient_retry_count(
                self.cfg.get('transient_retry_count', 3))
        except Exception:
            pass
        # v4.14.5.14a Component C: per-path fill targets. setdefault so
        # it persists to config.json (tunable) without overwriting any
        # value Mike has already customized. lottery/penny_lottery
        # fill_enabled=False — they populate organically from triggers
        # only (consensus is structurally weak on sparse-data paths).
        self.cfg.setdefault('path_fill_targets', {
            'slow_safe':     {'displayed_target': 10,
                              'bench_floor': 10, 'fill_enabled': True},
            'moderate':      {'displayed_target': 10,
                              'bench_floor': 10, 'fill_enabled': True},
            'aggressive':    {'displayed_target': 10,
                              'bench_floor': 10, 'fill_enabled': True},
            # v4.14.5.62-lottery-fill-enable: lottery fill_enabled=True to match
            # the engine default (tm_queue_runner._FILL_DEFAULT_TARGETS, re-enabled
            # in .55). The old False here meant even a FRESH install wrote a
            # shadowing `false` into cfg, so _fill_needed skipped Speculative and
            # it never dispatched (0 picks). Pool is ample; it fills last by yield.
            'lottery':       {'displayed_target': 10,
                              'bench_floor': 10, 'fill_enabled': True},
            'penny_lottery': {'displayed_target': 10,
                              'bench_floor': 10, 'fill_enabled': False},
        })
        # v4.14.5.14a.6: per-path candidate pools (Option 3 hybrid —
        # slow_safe/moderate seed lists, others dynamic). setdefault
        # persists the tunable structure to config.json without
        # clobbering a user override; the module owns the canonical
        # defaults so there's a single source of truth.
        try:
            import tm_path_candidate_pools as _tpcp
            self.cfg.setdefault('path_candidate_pools',
                                _tpcp._CFG_DEFAULT)
        except Exception:
            pass
        self._v415_init_network_detector()  # v4.15.0 Step 12: register transition callback + start tick
        # Teacher AI MVP Session 4: first-launch flow flags. setdefault is
        # safe on existing installs — missing key resolves to False which
        # is the right "fresh user" baseline.
        self.cfg.setdefault('teacher_ai_disclaimer_acknowledged', False)
        self.cfg.setdefault('teacher_ai_first_launch_complete', False)
        # Teacher AI MVP Session 5: tutorial mode is session-only — never
        # persisted to cfg. Resets to off on every launch. Toggled by
        # Ctrl+Shift+` (and Ctrl+~ on shifted keyboard layouts). When on,
        # tm_teacher_intercept.is_suppressed() returns False for every
        # key so suppressed intercepts re-fire.
        self._teacher_ai_tutorial_mode_on = False
        # Handle for the corner-indicator canvas item (set in _build()).
        self._teacher_ai_corner_item = None
        self._teacher_ai_corner_frame = None
        # v4.14.5.14a.7: Choices dialog removed — no longer seed
        # v415_price_ranges/v415_style into cfg (keys retired; the
        # universe/fill picker's _v415_get_choices() safely defaults
        # when they're absent). Attributes kept = None so any inert
        # leftover reference is harmless.
        self._choices_window = None
        self._v415_choices_label = None
        # v4.15.0 Step 22a-cleanup: silently apply sensible defaults on first
        # launch so the app is immediately usable — no setup wall. The picker
        # (_open_fill_mode_picker) remains callable for future Teacher AI use
        # or a Settings hook, but no longer auto-fires. _v415_check_first_launch_picker
        # is kept defined for the same reason.
        self._fill_picker_window = None
        self.root.after(500, self._v415_apply_silent_defaults_if_needed)
        # v4.14.5.16-sec-contact-prompt: first-run prompt asking the
        # operator for the email SEC should use to warn-before-block on
        # EDGAR over-requests. Disclaimer-gated, self-rescheduling.
        # No-ops silently when TIREDMARKET_SEC_CONTACT is already set
        # (Mike's machine) or the cfg field is already populated. Slots
        # alongside the other startup hooks; it self-gates.
        self.root.after(750, self._check_sec_contact_prompt)
        # v4.15.0 Step 20: auto-start slow fill on launch when any bulk-
        # fillable lane is in incremental mode. Deferred 3s so the silent-
        # defaults bootstrap (at +500ms) finishes first; fresh-install users
        # get their lane_config rows set before this check reads them.
        self.root.after(3000, self._v415_check_auto_start_slow_fill)
        # v4.14.5.14-stale-cleanup: the one-shot path-vs-universe mismatch
        # popup was removed (obsolete post path-merge; its "Change universe"
        # action pointed at a picker no longer in the UI). Whole chain gone.
        self._holdings_window = None
        self._holdings_state = None
        # v4.14.3.6 (2026-05-14): construction lock so the queue runner
        # thread and a user click can't both try to build the window
        # at the same time. _ensure_holdings_window acquires this
        # before any state/window write.
        import threading as _threading_for_lock
        self._holdings_build_lock = _threading_for_lock.Lock()
        # v4.14.3.7 (2026-05-14): translate any legacy cfg
        # ['top_ai_override'] value to the canonical registry id
        # form. Pre-v4.14.3.7 cfg values were preset names ('groq')
        # or display names ('Cerebras'); the new picker still
        # accepts both as backward-compat fallbacks, but writing
        # the resolved UUID back on first launch keeps the canonical
        # cfg shape clean for future contributors. Migration is
        # idempotent: if the cfg value already IS a registry id,
        # the helper returns it unchanged and nothing gets written.
        try:
            self._v4143_7_migrate_override()
        except Exception as e:
            try:
                self._log(
                    f"[migration] top_ai_override migration raised: "
                    f"{type(e).__name__}: {e}",
                    'amber')
            except Exception:
                pass
        # v4.14.3.8 (2026-05-14): one-time warning if the user's
        # cfg pins a tight-burst provider (e.g. Groq) for the
        # queue runner's burst pattern. Fires after migration so
        # the override is in canonical UUID form before we resolve.
        try:
            import tm_top_ai_picker as _picker_for_warn
            _picker_for_warn.warn_pinned_tight_burst_once(self)
        except Exception:
            pass
        self._activity_lines = []  # for the right-side log
        self._activity_text = None
        self._settings_win = None
        self._recommend_win = None  # v4.8.8
        # v4.10.2: auto-refresh stop event (set on shutdown)
        self._auto_refresh_stop = None
        # v4.14.5.62-remove-stop-resume: the toolbar Stop/Resume toggle was
        # removed — it never stopped the continuous queue runner (the real
        # AI scanner kept calling cloud providers after "Stop"), so its label
        # misled. The continuous-queue architecture has no manual start/stop;
        # provider quota is handled by pacing and per-AI enable/disable in
        # Settings. cfg['auto_refresh_enabled'] stays as the Settings-only
        # on/off for the holdings auto-refresh loop.
        # v4.10.2: cached freshness label for header indicator
        self._freshness_var = None
        # v4.13.61: startup state flag. False during heavy background
        # init (predictions log load, model classifications, etc.),
        # True once the app is ready to use. Toolbar button click
        # handlers check this and refuse early clicks with a tooltip
        # message instead of blocking. The header status indicator
        # shows "Loading..." while False.
        self._startup_complete = False

        # v4.14.5.14-gui-cleanup-c / RESTORED v4.14.5.56: startup phase-progress
        # state. Per-path "initial fill pass done" flags (sticky for the session
        # once True); the announce timestamp; the collapse latch; the phase-dot
        # labels; and the last activity-log message/age (captured in _log).
        # v4.14.5.56: lottery included — Speculative now fills (last) and gets a
        # dot.
        # v4.14.6.2-dropdown-fix: four band keys (sticky-completion flags).
        self._path_initial_fill_complete = {
            'lottery': False, 'band_5_10': False,
            'band_10_50': False, 'band_50_up': False}
        self._phase_announce_at = None     # epoch all phases first completed
        self._status_bar_collapsed = False  # True once the phase row collapses
        self._last_activity_msg = ''
        self._last_activity_at = 0.0
        self._phase_dot_lbls = {}
        # v4.14.5.59-statusbar-all-flash: per-path render state for ALL FOUR
        # slots — NO active-path picker. Each slot decides its own state from its
        # OWN count (below target → flash Name⇄N/M; at target → solid green).
        # _pulse_phase parity (even/odd) drives the Name⇄N/M flash of every
        # below-target slot; the ~600ms pulse is cosmetic (no DB, zero reflow).
        self._phase_render_state = {'paths': {}}
        self._pulse_phase = 0
        self._pulse_after_id = None

        # v4.14.0 stage 7: shared stop event for the two discovery
        # threads (startup-catchup + weekly refresh). Initialized
        # lazily by whichever thread starter fires first; set on
        # shutdown alongside _auto_refresh_stop.
        self._discovery_refresh_stop = None

        # ── v4.14.0 stage 6c: in-process state-query API ──
        # Read-only window into app state for the embedded assistant
        # that lands in v4.14.x+. Per the 2026-05-08 assistant-as-
        # primary-layer decision in DECISIONS.md, the hook ships now
        # so the assistant can plug in cleanly later. Nothing reads
        # `self.state` yet — every existing flow keeps working if the
        # import or constructor fails.
        self.state = None
        try:
            import tm_app_state as _tmstate6c
            self.state = _tmstate6c.AppStateQuery(self)
        except Exception:
            self.state = None

        # ── Phase 2B: background scheduler state ──
        self._scheduler = None
        self._game_tracker = None
        self._ai_busy = False  # set True while we're actively running AI
        self._scheduler_mode = (tm_scheduler.MODE_IDLE
                                 if _SCHEDULER_ENABLED else 'idle')

        # ── v4.8.6: UPS / battery monitoring state ──
        # Power monitor watches the UPS via Windows Win32_Battery API.
        # On power loss: pause AI, show banner, optionally schedule
        # graceful shutdown if user has opted in.
        self._power_monitor = None
        self._power_banner = None  # tk.Label that shows on battery
        self._power_banner_var = None  # StringVar for banner text
        self._shutdown_pending = False  # True when shutdown scheduled
        self._power_state = 'unknown'  # 'online' / 'on_battery' / 'unknown'
        self._power_last_info = None  # last BatteryInfo

        # v4.14.5.14-ollama-purge-3c: tm_ai (Ollama) logging removed — the
        # Ollama client is gone (cloud-only). Cloud calls log via their own
        # provider paths.

        # v4.8.11: Configure pre-filter cache persistence + diagnostic logging.
        # Persist cache to data/prefilter_cache.json so app restart keeps the
        # candidate list (avoids the rate-limit spiral that previously hit
        # whenever a restart happened mid-session). Wire the cache's hit/miss
        # diagnostic line into the activity log so we can see when scans
        # reuse cached data and how stale it is.
        if _DISCOVER_ENABLED:
            try:
                tm_discover.set_prefilter_cache_path(
                    DATA_DIR / "prefilter_cache.json")
            except Exception:
                pass
            try:
                # Use 'muted' tone — this is diagnostic, not user-visible action
                tm_discover.set_prefilter_log_fn(
                    lambda msg: self._log(msg, 'muted'))
            except Exception:
                pass
            # v4.8.12: Configure rate-limit cooldown state. Same pattern
            # as the prefilter cache. Tracks rate-limit events, learns
            # cooldown duration from history, refuses scans during cooldown.
            try:
                tm_discover.set_rate_limit_state_path(
                    DATA_DIR / "rate_limit_state.json")
            except Exception:
                pass
            try:
                # Cooldown messages are more important than cache diagnostics
                # — surface them in amber so they catch the eye.
                tm_discover.set_rate_limit_log_fn(
                    lambda msg: self._log(msg, 'amber'))
            except Exception:
                pass

            # v4.10.0: install the scan snapshot writer. Snapshots get saved
            # to data/snapshots/scan_*.json on every successful Discover or
            # Consensus scan. Foundation for v4.10.1 unified-scan that re-uses
            # snapshots without re-fetching. Failure here is silent — scans
            # work fine without snapshots being saved.
            try:
                tm_discover.set_scan_snapshot_path(DATA_DIR / "snapshots")
            except Exception:
                pass

        # ── Sync runtime portfolio with prefill if user agreed ──
        # If portfolio.json next to the script has more entries than the
        # runtime one in data/, copy them in. Lets the v4 prefill take effect
        # for users whose runtime portfolio was already populated.
        self._maybe_merge_prefill_portfolio()

        # ── v4.13.63.3: build everything while root is withdrawn ──
        # main() calls root.withdraw() immediately after creating it and
        # root.deiconify() after App.__init__ returns. That means every
        # widget we create here goes onto an INVISIBLE window — no paint
        # events fire during construction. When deiconify() runs, Tk
        # does ONE paint pass that shows the final state directly:
        # overlay covering the main UI. No flicker, no double-paint, no
        # "main window flashes through then overlay slams on" sequence.
        #
        # Order matters for Z-stacking: create overlay first, then main
        # UI. Both are children of root with default stacking by
        # creation order, so main UI defaults above overlay. lift() the
        # overlay once at the end to restore the cover.
        # Teacher AI MVP Session 4: legacy loading overlay replaced by
        # tm_teacher_splash. The splash is a Toplevel that floats above
        # the main window naturally; no Z-order lift dance required.
        # Session 4 fix: defer splash creation until after root.deiconify()
        # runs at end of main(). Creating a transient Toplevel while root
        # is withdrawn leaves it in an unmapped invisible state.
        self._splash = None
        # Session 6 polish: returning users (disclaimer marker present)
        # skip the splash entirely and go straight to the main app. The
        # splash exists to carry the first-launch disclaimer flow; once
        # the marker is written it has no further role. _teacher_ai_splash_branch
        # handles the splash-is-None case by deiconifying root cleanly.
        if not _has_accepted_disclaimer():
            self.root.after(0, self._teacher_ai_show_splash)

        # ── Build UI ──
        self._build()

        # ── Wire up close handler ──
        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

        # Refresh the portfolio summary whenever the main window regains
        # focus — this catches sells/changes that happened while the
        # Holdings window was open. Cheap (just re-reads JSON) and avoids
        # needing complex callback wiring between windows.
        self.root.bind('<FocusIn>',
                        lambda e: self._on_main_focus(e) if e.widget is self.root else None)

        # ── Live clock ticker ──
        self._tick_clock()

        # ── Disclaimer modal (first launch / after version bump) ──
        # Teacher AI MVP Session 4: disclaimer delivery moved into the
        # splash window. _show_disclaimer_if_needed remains as dead code
        # for now (post-MVP cleanup).
        # self.root.after(200, self._show_disclaimer_if_needed)

        # ── Welcome message in activity log ──
        # v4.13.62.8: cut the two "Click Holdings / Click AI Chat"
        # instructional lines. Mike has used the app for months — he
        # knows what the buttons do. Goal is ~3 lines on launch.
        self._log("Tired Market Analyzation ready.", 'header')

        # ── v4.13.39: path enable/disable summary ──
        # v4.13.62.8: dropped the trailing "None paused." trailer when
        # nothing's paused (it's redundant with "Paths active: …"). The
        # paused branch keeps its own dedicated message.
        try:
            import tm_recommend as _tmr39
            cfg = _tmr39.get_path_config_summary()
            if cfg:
                enabled = sorted(n for n, info in cfg.items()
                                  if info.get('enabled', True))
                disabled = sorted(n for n, info in cfg.items()
                                   if not info.get('enabled', True))
                if disabled:
                    self._log(
                        f"Paths paused: {', '.join(disabled)}. "
                        f"Active: {', '.join(enabled) or 'none'}. "
                        f"Edit data/path_config.json to change.",
                        'amber')
                else:
                    self._log(
                        f"Paths active: {', '.join(enabled)}.",
                        'muted')
        except Exception:
            pass

        # ── v4.13.5: one-time startup reminder ──
        # Fires every launch until: (a) the user removes the
        # abliterated model from their consensus list, OR (b) the
        # user dismisses by setting v4135_reminder_seen=True in
        # config.json. Self-clearing once condition (a) holds.
        try:
            _models = list(self.cfg.get('consensus_models') or [])
            _has_abl = any('abliterated' in m.lower()
                            for m in _models)
            _seen = self.cfg.get('v4135_reminder_seen', False)
            if _has_abl and not _seen:
                self._log(
                    "\u26a0 v4.13.5 reminder: "
                    "'richardyoung/qwen3-14b-abliterated' has "
                    "a 0/5 target hit / 5/5 stop hit record on "
                    "closed predictions. Consider removing it from "
                    "Settings \u2192 AI \u2192 Consensus models. "
                    "This reminder will stop once you do.",
                    'amber')
            elif not _has_abl and not _seen:
                # User already removed it — record dismissal so
                # this code path becomes a no-op going forward.
                self.cfg['v4135_reminder_seen'] = True
                try:
                    save_config(self.cfg)
                except Exception:
                    pass
        except Exception:
            pass

        # ── v4.8.7: power-loss marker detection ──
        # If the previous session ended via auto-save-and-close due to
        # critical battery, drop a banner so the user knows what happened
        # and can verify nothing was lost.
        self._check_power_loss_marker()

        # ── v4.9.2: auto-cleanup of backups, prediction backups, snapshots, logs ──
        # v4.13.63.1: was scheduled at 1500ms via root.after — that delay
        # was protective against UI paint contention but cleanup runs
        # entirely on a background thread and never touches widgets. Fire
        # at 0 so it overlaps with the disclaimer modal and other startup
        # work instead of sitting idle.
        self.root.after(0, self._launch_startup_cleanup)

        # ── v4.13.61: background preload of heavy state ────────────
        # Predictions log (potentially thousands of entries), holdings
        # manager, prompt builder, watchlist, universe — these are all
        # lazy-loaded on first use, which makes the first click on any
        # AI-related toolbar button feel slow (35+ seconds for Track
        # Record on a populated install). Pre-load them in a background
        # thread now so the user doesn't have to wait when they click.
        # The header status indicator shows "⏳ Loading..." while this
        # runs; toolbar handlers can check self._startup_complete to
        # gate early clicks.
        # v4.13.62: Track Record stats cache. Populated by the startup
        # preload thread once the predictions log is in memory; consumed
        # by HoldingsWindow._show_track_record so first-click is instant.
        # Invalidated by checking len(predictions_log.get_all()) at click
        # time — if it changed since cache was built, recompute.
        self._track_record_cache = None

        def _preload_holdings_state():
            # v4.13.61: This thread does the predictions-log + holdings
            # state preload. It does NOT flip _startup_complete — that
            # gets flipped by _startup_close_outcomes when the closer
            # finishes (which is the LAST thing that runs at startup).
            # If we flipped here, the user would see "Idle" before the
            # 30-second closer fires and then experience UI freezes
            # when they click during the closer's run.
            try:
                if self._holdings_state is None:
                    self._holdings_state = self._build_holdings_state()
            except Exception as e:
                try:
                    self.root.after(0, lambda: self._log(
                        f"Background preload failed: {type(e).__name__}. "
                        "Buttons will still work, just slower on first "
                        "click.", 'amber'))
                except Exception:
                    pass

            # v4.14.5.14-sold-prediction-tracking (Fix C): one-shot
            # backfill of PAST sales. The Holdings 'closed' list stores
            # the exact sell price + date for every sale you've recorded
            # (e.g. RIG bought 6.90, sold 7.40). For each, mark any still-
            # OPEN BUY predictions for that ticker 'sold' at the recorded
            # price/date — making historical wins like RIG count in Track
            # Record. Uses real stored prices (no market approximation).
            # Marker-gated + idempotent; runs here (after the state is
            # built, before the stats precompute below) so the cached
            # stats already reflect it. Skipped if the flag is off.
            try:
                if (self._holdings_state is not None
                        and bool(self.cfg.get(
                            'use_sold_prediction_tracking', True))
                        and not self.cfg.get(
                            '_v414514spt_sold_backfill')):
                    _mgr = self._holdings_state.get('mgr')
                    _plog = self._holdings_state.get('predictions_log')
                    if _mgr is not None and _plog is not None:
                        _nt, _nm = _plog.backfill_sold_from_closed(
                            _mgr.get_closed())
                        self.cfg['_v414514spt_sold_backfill'] = True
                        try:
                            save_config(self.cfg)
                        except Exception:
                            pass
                        if _nm:
                            self.root.after(0, lambda nt=_nt, nm=_nm:
                                self._log(
                                    f"[migration] sold-prediction "
                                    f"backfill: marked {nm} open "
                                    f"prediction(s) across {nt} past "
                                    f"sale(s) as 'sold' (incl. RIG). "
                                    f"Track Record now reflects them.",
                                    'green'))
            except Exception:
                # Backfill is best-effort; marker NOT set on error so it
                # retries next launch.
                pass
            # v4.13.62: pre-compute Track Record stats too. Adds maybe
            # 1-2 seconds to the background preload but makes the first
            # Track Record click feel instant. All wrapped in try/except
            # since this is a pure optimization — failure means the
            # dialog falls back to on-demand compute, same as before.
            try:
                if (self._holdings_state is not None
                        and _DISCOVER_ENABLED
                        and tm_discover is not None):
                    plog = self._holdings_state.get('predictions_log')
                    if plog is not None:
                        cache = {}
                        try:
                            cache['all_stats'] = plog.compute_all_stats()
                        except Exception:
                            cache['all_stats'] = None
                        try:
                            cache['per_model_stats'] = (
                                tm_discover.compute_per_model_stats(
                                    plog, hours=168))
                        except Exception:
                            cache['per_model_stats'] = None
                        try:
                            cache['consensus'] = (
                                tm_discover.compute_consensus(
                                    plog, hours=48, min_models=2,
                                    scan_id=None))
                        except Exception:
                            cache['consensus'] = None
                        try:
                            cache['scan_ids'] = (
                                tm_discover.list_consensus_scan_ids(
                                    plog, hours=168))
                        except Exception:
                            cache['scan_ids'] = None
                        try:
                            cache['pred_count'] = len(plog.get_all())
                        except Exception:
                            cache['pred_count'] = -1
                        self._track_record_cache = cache
            except Exception:
                pass

            # v4.13.63: chain the startup closer off the END of the
            # preload thread instead of firing on a 30-second wall-clock
            # timer. Old design held the loading overlay visible for at
            # LEAST 30 seconds on every launch, even when everything
            # heavy finished in 5. New design: closer fires the moment
            # holdings_state is ready. The closer function itself spawns
            # its own daemon thread (it doesn't touch Tk widgets), so we
            # schedule it via root.after(0,...) to keep scheduling on
            # the main thread for consistency with the rest of startup.
            # _startup_close_outcomes flips _startup_complete=True when
            # done, which dismisses the loading overlay.
            try:
                if getattr(self, '_should_run_startup_closer', False):
                    self.root.after(0, self._startup_close_outcomes)
            except Exception:
                pass

        # v4.13.63.1: fire at 0 instead of 300ms. The "let disclaimer
        # paint first" rationale was overly cautious — the preload
        # thread doesn't touch Tk widgets directly (only via after(0)
        # for log writes), so it runs cleanly while the disclaimer modal
        # is up. Removing the artificial wait shaves 300ms and lets the
        # keystone thread overlap with disclaimer interaction.
        def _kick_preload():
            import threading
            threading.Thread(
                target=_preload_holdings_state,
                daemon=True,
                name='startup-preload').start()
        self.root.after(0, _kick_preload)
        # ── end v4.13.61 background preload ────────────────────────

        # v4.13.63.1: removed the launch-time auto-scan after() schedule.
        # _launch_auto_scan has been a no-op stub since v4.11.0 (consensus
        # is manual-only via per-holding Run consensus button). The 5-sec
        # after() was firing every launch and immediately returning. The
        # method itself is kept for any callers still referencing it.

        # ── Phase 2B: start background scheduler ──
        # v4.13.63.1: fire at 0 instead of 8000ms. _start_scheduler polls
        # internally for disclaimer acceptance and self-defers if not
        # ready (root.after(15000, self._start_scheduler) inside the
        # method), so no need for an artificial wall-clock wait here.
        if _SCHEDULER_ENABLED and _AI_ENABLED \
                and self.cfg.get('background_scheduler_enabled', True):
            self.root.after(0, self._start_scheduler)

        # ── v4.8.6: start power monitor ──
        # v4.13.63.1: fire at 0 instead of 2000ms. The UPS probe is a
        # quick WMI query and its polling thread idles until state
        # changes — no contention with anything else at startup.
        if _POWER_ENABLED and self.cfg.get('ups_monitoring_enabled', True):
            self.root.after(0, self._start_power_monitor)

        # v4.14.5.12: version banner — first thing in the startup
        # sequence so "what version is actually running" is answerable
        # straight from the activity log. The 2026-05-17 investigation
        # could not confirm the running version from logs (old error
        # formats appeared that exist in no live source file). Disk
        # persistence in _log works even this early (it does not need
        # the activity widget), so this lands in data/activity.log.
        try:
            self._log(
                f"[startup] Tired Market v{APP_VERSION} — "
                f"APP_VERSION confirmed (PID {os.getpid()})", 'muted')
        except Exception:
            pass

        # ── v4.10.2: start auto-refresh background loop ──
        # Honors auto_refresh_enabled in config. The loop polls every
        # 30 minutes and refreshes when interval has elapsed.
        # v4.13.63: capture closer-eligibility as an instance flag so
        # the preload thread (which now chains the closer at its end)
        # can check it without re-evaluating the same conditions. The
        # standalone 30-second after() that used to fire the closer is
        # removed — the chain-from-preload approach replaces it.
        self._should_run_startup_closer = (
            _AI_ENABLED and _DISCOVER_ENABLED
            and self.cfg.get('auto_refresh_enabled', True))

        # v4.13.63.1: fire at 0 instead of 10000ms. _launch_auto_refresh
        # spawns a daemon thread that polls _has_accepted_disclaimer()
        # internally before doing any real work, so the wall-clock wait
        # was redundant.
        if self._should_run_startup_closer:
            self.root.after(0, self._launch_auto_refresh)
        else:
            # Initialize the stop event anyway so _on_close doesn't crash
            # checking for it
            self._auto_refresh_stop = None

        # v4.13.61: Fallback for the startup-complete flag. The closer
        # flips it after running, but if the user's config disables
        # auto-refresh / AI / discover, the closer never fires and the
        # flag would stay False forever. Schedule a fallback so the
        # indicator clears regardless.
        # v4.13.63: shortened from 40s to 10s. The chain-from-preload
        # closer (see _preload_holdings_state) typically finishes in
        # ~3-5 seconds; 10s gives plenty of margin while keeping the
        # overlay from sitting visible far longer than necessary on
        # configurations that skip the closer entirely. If the closer
        # is still running after 10s on a heavily-populated install,
        # this fallback fires early and the overlay clears — the
        # closer continues working in the background harmlessly
        # (its finally block re-flips the same flag, no-op).
        def _fallback_startup_complete():
            if not self._startup_complete:
                self._startup_complete = True
                try:
                    self._update_freshness_label()
                except Exception:
                    pass
                # Teacher AI MVP Session 4: splash closure is driven by
                # the end of _build(), not the bg_closer / fallback timer.
        self.root.after(10000, _fallback_startup_complete)

        # v4.14.5.62-autoenable-rotation: if rotation AUTO-enabled this launch,
        # surface the one-time Teacher-AI coaching line ("I turned rotation
        # on…"). Scheduled with a delay so the UI settles first; the method
        # self-gates on the auto flag + disclaimer-accepted + the once-ever
        # suppression marker, so it no-ops when rotation was off / explicit /
        # already introduced.
        try:
            self.root.after(3500, self._fire_model_rotation_feature_intro)
        except Exception:
            pass

        # v4.14.5.56-restore-statusbar: start the phase-progress poll (~2.5s,
        # self-rescheduling, guarded) driving the dot row → "✓ All set" announce
        # → collapse. The _state_icon_lbl (Idle/Running/Paused/Cooldown) stays
        # owned by _update_freshness_label — the restored bar never writes it
        # (Option A: the phase dots and the state indicator coexist).
        self.root.after(3000, self._tick_status_bar)
        # v4.14.5.59: the all-slot flash (cosmetic, no DB) runs faster (~600ms)
        # on its own self-rescheduling loop — flips every below-target slot
        # Name⇄N/M; done slots stay solid green.
        self.root.after(3200, self._pulse_phase_labels)

        # v4.10.10: cache persistence loop. Saves the quote cache every
        # 2 minutes if there are unsaved changes. Decoupled from
        # auto-refresh so it runs even when auto-refresh is disabled.
        # v4.13.63.1: fire at 0 instead of 15000ms. The thread's first
        # action is wait(120) — so the first save attempt still happens
        # 2 minutes in; firing earlier just removes idle wall-clock time.
        # The save also checks _holdings_state is non-None internally,
        # so it's safe even if preload is still running at first tick.
        self.root.after(0, self._start_cache_persistence)

        # v4.15.0 continuous-queue Phase 1: background queue runner.
        # Same lifecycle pattern as _launch_auto_refresh — daemon
        # thread, signaled by _queue_runner_stop Event. Phase 1 ships
        # infrastructure only; the queue accumulates silently. Phase 2
        # wires the Recommend window to read from it.
        self._queue_runner_stop = None
        self._queue_runner_thread = None
        if self.cfg.get('queue_runner_enabled', True):
            self.root.after(0, self._launch_queue_runner)

        # v4.14.5.62-lookup-backoff: thread-safe "a user lookup is in flight"
        # indicator. A COUNTER (not a bool) so overlapping lookups compose
        # (fill backs off while count > 0). The lock makes it visible to the
        # background fill loop (other thread). `_last_begin` is the failsafe
        # timestamp: even if a clear is somehow missed (async cancel/leak),
        # the fill loop ignores a stale active flag after the bounded window,
        # so fill can NEVER be paused forever. Flag-gated at read time, so
        # this is inert when lookup_priority_backoff is off.
        self._lookup_backoff_lock = threading.Lock()
        self._lookup_backoff_count = 0
        self._lookup_backoff_last_begin = 0.0

        # v4.14.0 stage 7: model-discovery threads. startup-catchup
        # runs once for any provider with last_discovered_at null
        # or > 7 days, after disclaimer acceptance. weekly-refresh
        # polls hourly and re-runs per-provider when the 7-day window
        # has elapsed. Both share _discovery_refresh_stop for clean
        # shutdown. Non-blocking — startup is unaffected.
        self.root.after(0, self._start_startup_discovery)
        self.root.after(0, self._start_weekly_discovery_refresh)

        # v4.14.5.12: Arc B daemon startup wiring. Closes the
        # integration gap found in the 2026-05-17 overnight
        # investigation: the recommend-cache / news / fundfile daemons
        # were code-complete in v4.14.5.4-.11 but ONLY launched by the
        # since-removed toolbar Resume handler (v4.14.5.62 removed the
        # Stop/Resume button), never at startup. On a normal launch all
        # three stayed dormant; the visible "healthy" behaviour came from
        # the legacy slow-fill, not Arc B. THIS startup launch is now the
        # sole launcher; the launchers are idempotent (v4.14.5.12), and it
        # is deferred
        # via root.after(0,...) like every other daemon launch so it
        # runs after init/schema/router are in place. Last in the
        # sequence to be safe.
        self.root.after(0, self._v45012_launch_arc_b_daemons)

        # v4.14.5.14-portfolio-watching-timing-fix (Fix B): report the TRUE
        # active-watching state once, ~25s in — AFTER the deferred scheduler
        # (root.after(0, self._start_scheduler) above) has started. The old
        # emission inside _build_holdings_state ran during early startup,
        # before the scheduler thread existed, and therefore ALWAYS logged a
        # false "OFF". 25s clears the common ~1-3s scheduler start with huge
        # margin; the method itself re-arms once for the rare 30s holdings-
        # build defer before committing to an OFF verdict.
        self.root.after(25000, self._log_active_watching_status)

    # ═══════════════════════════════════════════════════════════════════════
    # v4.10.2 — AUTO-REFRESH BACKGROUND LOOP
    # ═══════════════════════════════════════════════════════════════════════
    # Runs in a daemon thread. Wakes up every 30 minutes, checks if the
    # snapshot is stale (older than auto_refresh_interval_hours), and if
    # so does:
    #   1. Refresh the universe (IWV) if needed
    #   2. Run the configured single auto-refresh model against fresh data
    #      (or skip the AI run if model is "(none)")
    # Honors yfinance cooldown — never tries to fetch during cooldown.

    def _launch_auto_refresh(self):
        """Start the auto-refresh background thread. Called from app startup
        after disclaimer + universe + scheduler init are all in place."""
        if not _AI_ENABLED or not _DISCOVER_ENABLED:
            return
        if not self.cfg.get('auto_refresh_enabled', True):
            self._log("Auto-refresh disabled in Settings.", 'muted')
            return

        # Cancellation flag — set on app close so the loop exits cleanly
        self._auto_refresh_stop = threading.Event()

        def _loop():
            # Wait for disclaimer acceptance before starting
            while not _has_accepted_disclaimer():
                if self._auto_refresh_stop.wait(15):
                    return  # app closing

            self.root.after(0, lambda: self._log(
                "Auto-refresh: started (background data refresh + "
                "optional model run).", 'muted'))

            while not self._auto_refresh_stop.is_set():
                try:
                    self._auto_refresh_tick()
                except Exception as e:
                    # Never let auto-refresh crash kill the loop
                    try:
                        self.root.after(0, lambda e=e: self._log(
                            f"Auto-refresh error: {e}", 'amber'))
                    except Exception:
                        pass
                # Sleep 30 minutes between checks. The actual refresh
                # interval is checked inside _auto_refresh_tick — this
                # is just polling cadence.
                if self._auto_refresh_stop.wait(30 * 60):
                    return

        threading.Thread(target=_loop, daemon=True,
                          name='auto-refresh').start()

    def _launch_recommend_cache_refresh(self):
        """v4.14.5.4 (Step 2): daemon thread that keeps recommend_cache
        fresh. Same daemon+Event pattern as _launch_auto_refresh.
        Startup one-shot (skipped if the persisted cache is <5 min
        old), then every RECOMMEND_CACHE_REFRESH_INTERVAL_SECONDS.
        Pause-aware (skips while AI is paused). Pure cache reads —
        cheap, no AI calls."""
        if not bool(self.cfg.get('use_filter_recommend', True)):
            return
        # v4.14.5.12: idempotent — startup wiring and the toolbar
        # Stop->Resume handler can both call this; never run two
        # recommend-cache daemons at once.
        existing = getattr(self, '_recommend_cache_thread', None)
        if existing is not None and existing.is_alive():
            return
        try:
            import tm_recommend_cache as _trc
        except Exception as e:
            self._log(f"recommend-cache: module import failed: {e}",
                       'amber')
            return
        self._recommend_cache_stop = threading.Event()

        def _do_refresh(tag):
            try:
                import tm_holdings as _tmh
                if _tmh.is_ai_paused():
                    return
            except Exception:
                pass
            try:
                res = _trc.refresh_recommend_cache(self)
                msg = (res or {}).get('message')
                st = (res or {}).get('status')
                if st and st != 'ok':
                    self.root.after(0, lambda: self._log(
                        f"[recommend-cache] {tag}: {st} "
                        f"({msg})", 'muted'))
                elif msg and msg != 'ok':
                    self.root.after(0, lambda: self._log(
                        f"[recommend-cache] {tag}: {msg}", 'muted'))
                # v4.14.5.51-recs-gatekeeping: fire the once-ever 'ready, want
                # to look?' moment only when the helper's >=2-populated-paths
                # gate is met (the panel shows one style at a time, so a single
                # populated style would open to an empty panel for the others).
                # The helper re-checks per-path counts + AI-present + once-ever.
                self.root.after(
                    0, self._fire_recs_ready_feature_intro)
            except Exception as e:
                try:
                    self.root.after(0, lambda e=e: self._log(
                        f"recommend-cache {tag} error: {e}", 'amber'))
                except Exception:
                    pass

        def _loop():
            while not _has_accepted_disclaimer():
                if self._recommend_cache_stop.wait(15):
                    return
            # Startup one-shot — skip if cache is already fresh.
            try:
                db = getattr(self, 'db', None)
                conn = getattr(db, 'conn', None) if db else None
                fresh = False
                if conn is not None:
                    row = conn.execute(
                        "SELECT MAX(last_refresh_at) "
                        "FROM recommend_cache").fetchone()
                    if row and row[0]:
                        fresh = (time.time() - float(row[0])) < (
                            _trc.RECOMMEND_CACHE_REFRESH_INTERVAL_SECONDS)
                if not fresh:
                    _do_refresh('startup')
            except Exception:
                _do_refresh('startup')
            while not self._recommend_cache_stop.is_set():
                if self._recommend_cache_stop.wait(
                        _trc.RECOMMEND_CACHE_REFRESH_INTERVAL_SECONDS):
                    return
                _do_refresh('tick')

        t = threading.Thread(target=_loop, daemon=True,
                              name='recommend-cache')
        self._recommend_cache_thread = t
        t.start()

    def _refresh_recommend_cache_now(self, reason='choices'):
        """Synchronous immediate refresh (used on Choices-strip change).
        Cheap — pure cache reads. Best-effort; never raises."""
        if not bool(self.cfg.get('use_filter_recommend', True)):
            return
        try:
            import tm_recommend_cache as _trc
            _trc.refresh_recommend_cache(self)
        except Exception as e:
            try:
                self._log(f"recommend-cache {reason} refresh "
                           f"skipped: {e}", 'amber')
            except Exception:
                pass

    def _v45012_launch_arc_b_daemons(self):
        """v4.14.5.12: launch the three Arc B daemons at startup.

        Uses the same launcher calls + flag guards the since-removed
        Resume button used (v4.14.5.62 removed Stop/Resume). Before
        v4.14.5.12 these were ONLY started by the Resume button, so on
        a normal launch Arc B (recommend-cache refresh, news
        incremental, and the fundamentals / filings / earnings /
        universe maintenance daemon) never ran — the 8h overnight test
        on 2026-05-17 had all three dormant the whole session.

        Each launcher is idempotent as of v4.14.5.12 (thread-alive
        guard), so if the user presses Resume after startup the second
        call is a no-op for an already-running daemon.

        Failures are surfaced (amber log), not swallowed — the daemon
        layer is load-bearing; a silent failure here is exactly the
        class of bug this patch exists to fix. The per-daemon
        "started" line is what Mike reads to confirm the integration
        works (he reads the activity log, not the code)."""
        # v4.14.5.62-model-routing Part 3: self-maintaining rotation lists.
        # On a background thread (so it never blocks startup), probe each
        # installed provider's live model list and prune dead rotation models
        # (e.g. a deprecated Groq mixtral, a never-real glm-4.7-flash). A
        # failed/empty probe never prunes. Logged per prune.
        try:
            import threading as _th_mscan

            def _model_scan_bg():
                try:
                    import tm_provider_discovery as _tpd_scan
                    n = _tpd_scan.validate_and_prune_models(
                        log_fn=lambda m, c='amber': self.root.after(
                            0, lambda: self._log(m, c)))
                    if n:
                        self.root.after(0, lambda: self._log(
                            f"[model-scan] startup: pruned {n} dead model(s) "
                            f"from rotation lists.", 'muted'))
                except Exception:
                    pass
            _th_mscan.Thread(target=_model_scan_bg, daemon=True,
                             name='model-scan-startup').start()
        except Exception:
            pass

        # recommend_cache refresh daemon — flag: use_filter_recommend.
        if bool(self.cfg.get('use_filter_recommend', True)):
            try:
                self._launch_recommend_cache_refresh()
                self._log(
                    "[recommend_cache] daemon started (refresh every "
                    "5 min + on Choices change)", 'muted')
            except Exception as e:
                self._log(
                    f"[recommend_cache] failed to start daemon: {e}",
                    'amber')
        # news incremental daemon — flag: use_news_incremental.
        if bool(self.cfg.get('use_news_incremental', True)):
            try:
                import tm_news_fetcher as _tnf
                _tnf.launch_news_refresh(self)
                self._log(
                    "[news] daemon started (tier-1 every 5 min, "
                    "tier-2 every 30 min, tier-3 every 60 min)",
                    'muted')
            except Exception as e:
                self._log(
                    f"[news] failed to start daemon: {e}", 'amber')
        # fundamentals / filings / earnings / universe daemon. The
        # launcher itself starts if ANY of its four independent flags
        # is enabled (v4.14.5.11), so gate the call the same way.
        if (bool(self.cfg.get('use_fundamentals_incremental', True))
                or bool(self.cfg.get('use_filings_incremental', True))
                or bool(self.cfg.get('use_earnings_daily_refresh', True))
                or bool(self.cfg.get(
                    'use_universe_maintenance', True))):
            try:
                import tm_fundfile_fetcher as _tff
                _tff.launch_fundfile_refresh(self)
                self._log(
                    "[fundfile] daemon started (fundamentals + "
                    "filings + earnings + universe; every 30 min)",
                    'muted')
            except Exception as e:
                self._log(
                    f"[fundfile] failed to start daemon: {e}", 'amber')

        # v4.14.5.14b: Layer 2 — background multi-AI consensus
        # validation of recommend_cache picks. Independent of Layer 1
        # fill (it never blocks or rewrites Layer 1); flag-gated;
        # fully fail-open (a Layer 2 fault must not drag any other
        # daemon down).
        if bool(self.cfg.get('use_layer2_validation', True)):
            try:
                import tm_layer2_validation as _tl2
                _t = _tl2.launch_layer2_validation(self)
                if _t is not None:
                    _iv = int(self.cfg.get(
                        'layer2_validation_interval_seconds', 180))
                    self._log(
                        f"[layer2] daemon started (background "
                        f"consensus-validation, 1 pick / "
                        f"{_iv}s; flag use_layer2_validation)",
                        'muted')
            except Exception as e:
                self._log(
                    f"[layer2] failed to start daemon: {e}", 'amber')

        # v4.14.5.14-layer3-replace (2026-05-23): Layer 3 — drops
        # CONTRADICTED picks from recommend_cache (the cadence runner
        # refills the slot). Ships DORMANT — flag use_layer3_replace
        # default False, so this is a no-op until Mike flips it.
        # persist_cfg lets the daemon durably stamp layer3_armed_at
        # without importing this GUI module. Fully fail-open.
        if bool(self.cfg.get('use_layer3_replace', False)):
            try:
                import tm_layer3_replace as _tl3
                _t3 = _tl3.launch_layer3_replace(
                    self, persist_cfg=lambda: save_config(self.cfg))
                if _t3 is not None:
                    _iv3 = int(self.cfg.get(
                        'layer3_interval_seconds', 180))
                    self._log(
                        f"[layer3_replace] daemon started "
                        f"(Fill-Validate-Replace Layer 3, 1 scan / "
                        f"{_iv3}s; flag use_layer3_replace)", 'muted')
            except Exception as e:
                self._log(
                    f"[layer3] failed to start daemon: {e}", 'amber')

    def _launch_queue_runner(self):
        """v4.15.0 continuous-queue Phase 1: start the background
        queue runner. Daemon thread that maintains the recommend_queue
        SQLite table. Phase 1 = infrastructure only; nothing reads
        from the queue yet."""
        if not _AI_ENABLED:
            return
        if not self.cfg.get('queue_runner_enabled', True):
            self._log("Queue runner disabled in cfg.", 'muted')
            return
        try:
            import tm_queue_runner
            tm_queue_runner.start_queue_runner(self)
        except Exception as e:
            try:
                self._log(
                    f"Queue runner failed to start: {e}", 'amber')
            except Exception:
                pass

    def _start_cache_persistence(self):
        """v4.10.10: Periodic save of the quote cache to disk so that an
        unexpected crash doesn't lose what we've fetched. Runs in its own
        small daemon thread, saves every 2 minutes if there are unsaved
        changes."""
        def _persist_loop():
            while True:
                if self._auto_refresh_stop is not None and \
                        self._auto_refresh_stop.wait(120):
                    return  # app closing
                if self._auto_refresh_stop is None:
                    # auto-refresh disabled: still want periodic save,
                    # use a plain sleep
                    time.sleep(120)
                try:
                    if (self._holdings_state is not None
                            and self._holdings_state.get('cache') is not None):
                        cache = self._holdings_state['cache']
                        if hasattr(cache, 'save_disk'):
                            cache.save_disk()
                except Exception:
                    pass

        threading.Thread(target=_persist_loop, daemon=True,
                          name='cache-persist').start()

    def _startup_close_outcomes(self):
        """v4.13.25: One-shot closer run shortly after app launch.
        Resolves any predictions whose target/stop/expiry hit while
        the app was closed.

        v4.13.36: also runs check_supersessions().

        v4.13.37: adds diagnostic logging to data/v4.13.37_closer.log
        for both check_outcomes and check_supersessions, so we can see
        whether persistence is sticking. The "222 resolved by price"
        activity log message has been misleading -- the disk file
        often shows fewer closures than the message claims, suggesting
        check_outcomes' _persist_full() is failing on some installs.
        Logging captures the symptom so we can chase the cause.

        v4.13.61: This routine fires from root.after() which runs on
        the main thread. With many open predictions and Yahoo latency,
        check_outcomes can take 60+ seconds — freezing the entire UI
        for that duration. Now we just kick off a background thread
        from here and do the heavy lifting there. UI stays responsive.
        Activity log writes are routed through root.after(0, ...) to
        keep them on the main thread.
        """
        def _bg_closer():
            try:
                if self._holdings_state is None:
                    try:
                        self._holdings_state = self._build_holdings_state()
                    except Exception:
                        return
                if (self._holdings_state is not None
                        and self._holdings_state.get('predictions_log')):
                    pl = self._holdings_state['predictions_log']

                    # v4.13.37: diagnostic log header
                    try:
                        from pathlib import Path as _P37
                        log_path = _P37(pl.path).parent / "v4.13.37_closer.log"
                        with open(log_path, 'a', encoding='utf-8') as lf:
                            lf.write(f"\n=== Startup closer run at {datetime.now().isoformat()} ===\n")
                            lf.write(f"  predictions.jsonl size: "
                                     f"{pl.path.stat().st_size if pl.path.exists() else 0} bytes\n")
                            lf.write(f"  cache size: {len(pl._cache)} entries\n")
                            # Count statuses in cache
                            from collections import Counter as _C
                            cache_status = _C(p.get('status') for p in pl._cache)
                            lf.write(f"  cache status counts: {dict(cache_status)}\n")
                    except Exception:
                        pass

                    before = len(pl.get_open())
                    pl.check_outcomes(
                        self._holdings_state['cache'].quote,
                        history_fn=tm_holdings.HoldingsWindow._build_history_fn())
                    after_outcomes = len(pl.get_open())
                    resolved_outcomes = before - after_outcomes

                    # v4.13.37: verify check_outcomes' persistence
                    try:
                        log_path = _P37(pl.path).parent / "v4.13.37_closer.log"
                        disk_status = {}
                        try:
                            with open(pl.path, 'r', encoding='utf-8') as df:
                                for line in df:
                                    try:
                                        e = json.loads(line)
                                        s = e.get('status', 'open')
                                        disk_status[s] = disk_status.get(s, 0) + 1
                                    except Exception:
                                        pass
                        except Exception:
                            pass
                        with open(log_path, 'a', encoding='utf-8') as lf:
                            lf.write(f"  check_outcomes: {resolved_outcomes} resolved "
                                     f"(before={before}, after={after_outcomes})\n")
                            lf.write(f"  disk read-back after check_outcomes: {disk_status}\n")
                            cache_open = sum(1 for p in pl._cache
                                              if p.get('status') == 'open')
                            disk_open = disk_status.get('open', 0)
                            if cache_open != disk_open:
                                lf.write(f"  *** WARNING: cache has {cache_open} open, "
                                         f"disk has {disk_open} open. "
                                         f"Persistence not in sync. ***\n")
                    except Exception:
                        pass

                    if resolved_outcomes > 0:
                        # v4.13.61: route activity log writes through
                        # root.after(0,...) since we're on a bg thread
                        self.root.after(0, lambda r=resolved_outcomes: self._log(
                            f"Startup closer: resolved {r} "
                            f"prediction{'s' if r != 1 else ''} "
                            f"by price.",
                            'green'))

                    # v4.13.36: supersession check (now with v4.13.37 logging)
                    try:
                        superseded = pl.check_supersessions(
                        stable=bool(self.cfg.get(
                            'use_stable_recommend', True)))
                        n_super = sum(1 for p in superseded
                                       if p.get('status') == 'superseded')
                        n_contra = sum(1 for p in superseded
                                        if p.get('status') == 'contradicted')
                        # v4.13.62.8: only log supersession results when
                        # something actually happened. The "no predictions
                        # resolved" + always-fire "Diagnostic" lines were
                        # pure noise on a healthy launch — silent on
                        # success now. Errors still surface via the
                        # except branch below.
                        if n_super or n_contra:
                            self.root.after(0, lambda ns=n_super, nc=n_contra: self._log(
                                f"Startup closer: closed {ns} as "
                                f"superseded (self-retracted) and "
                                f"{nc} as contradicted "
                                f"(cross-model AVOID/SELL in same path).",
                                'green'))
                    except Exception as _se:
                        self.root.after(0, lambda e=_se: self._log(
                            f"Supersession check error: {e}", 'amber'))

                    # v4.14.3: accuracy → source-weight bridge.
                    # Reads closed predictions, computes per-model
                    # accuracy, UPSERTs into source_weights. Silent on
                    # success; visible on failure. Cooldown-guarded.
                    try:
                        import tm_source_accuracy
                        # v4.14.5.14-db-concurrency: serialize this bridge
                        # call against ALL other direct app.db.conn users
                        # (queue runner / event triggers / shutdown). Without
                        # this, the bridge's SELECT/UPDATE/INSERT loop races
                        # those threads on the same Connection (which was
                        # opened check_same_thread=False) → SQLITE_MISUSE.
                        # RLock is reentrant so any nested helper that also
                        # acquires the lock is safe.
                        with self.db.lock:
                            result = (
                                tm_source_accuracy
                                .update_source_weights_from_accuracy(
                                    self.db.conn, pl,
                                )
                            )
                        n_changed = (result['rows_updated']
                                     + result['rows_inserted'])
                        if n_changed > 0:
                            self.root.after(0, lambda n=n_changed:
                                self._log(
                                    f"Source-weight bridge: updated "
                                    f"{n} model accuracy row"
                                    f"{'s' if n != 1 else ''}.",
                                    'green'))
                    except Exception as _ae:
                        self.root.after(0, lambda e=_ae: self._log(
                            f"Source-weight bridge error: {e}", 'amber'))
            except Exception as e:
                try:
                    self.root.after(0, lambda e=e: self._log(
                        f"Startup closer error: {e}", 'amber'))
                except Exception:
                    pass
            finally:
                # v4.13.61: only NOW is startup truly complete. The
                # closer ran (or failed cleanly), the predictions log
                # is fully resolved, and any other concurrent work
                # has had time to settle. Flip the flag and refresh
                # the header indicator.
                self._startup_complete = True
                try:
                    self.root.after(0, self._update_freshness_label)
                except Exception:
                    pass
                # Teacher AI MVP Session 4: splash closure runs at the
                # end of _build() (per-state branching), not from the
                # bg_closer. Leaving this comment so the next reader
                # knows where the splash close path moved to.

        import threading
        threading.Thread(target=_bg_closer, daemon=True,
                          name='startup-closer').start()

    def _run_predictions_cleanup(self, dry_run=None):
        """v4.14.5.14-predictions-cleanup: run tiered cleanup on
        predictions.jsonl (BUYs kept forever; NO_CALL 1d; WATCH/AVOID/HOLD
        30d), honoring the dry-run flag, and log a one-line summary.
        Stamps the daily-gate timestamp. Never raises."""
        try:
            if dry_run is None:
                dry_run = bool(self.cfg.get(
                    'predictions_cleanup_dry_run', True))
            state = self._holdings_state
            if state is None:
                try:
                    state = self._holdings_state = self._build_holdings_state()
                except Exception:
                    return
            pl = (state or {}).get('predictions_log')
            if pl is None or not hasattr(pl, 'cleanup_tiered'):
                self._log("[predictions-cleanup] skipped — predictions log "
                          "not available.", 'amber')
                return
            counts = pl.cleanup_tiered(dry_run=dry_run)
            dropped = (counts.get('dropped_no_call_old', 0)
                       + counts.get('dropped_other_old', 0))
            if counts.get('aborted'):
                self._log("[predictions-cleanup] ABORTED — backup or write "
                          "failed; NO records deleted, file intact.", 'red')
            else:
                mode = "DRY RUN: would" if dry_run else "RAN:"
                self._log(
                    f"[predictions-cleanup] {mode} keep "
                    f"{counts.get('total_after')}, drop {dropped} "
                    f"(BUY kept {counts.get('kept_buy')}; NO_CALL dropped-old "
                    f"{counts.get('dropped_no_call_old')}; WATCH/AVOID/HOLD "
                    f"dropped-old {counts.get('dropped_other_old')}; "
                    f"kept-fresh NO_CALL {counts.get('kept_no_call_fresh')} / "
                    f"other {counts.get('kept_other_fresh')})",
                    'muted' if dry_run else 'green')
            # Stamp the daily gate (dry OR real) so a flag-on dry-run
            # doesn't re-log on every ~4h tick.
            try:
                self.cfg['predictions_cleanup_last_run'] = (
                    datetime.now().isoformat())
                save_config(self.cfg)
            except Exception:
                pass
        except Exception as e:
            try:
                self._log(f"[predictions-cleanup] error: {e}", 'amber')
            except Exception:
                pass

    def _maybe_run_predictions_cleanup(self):
        """Daily gate, called from the auto-refresh tick. No-op unless
        enable_predictions_cleanup is on AND the last run was >24h ago.
        File maintenance — independent of AI pause / scan state."""
        try:
            if not bool(self.cfg.get('enable_predictions_cleanup', False)):
                return
            last = self.cfg.get('predictions_cleanup_last_run')
            if last:
                try:
                    if (datetime.now()
                            - datetime.fromisoformat(last)
                            ).total_seconds() < 86400:
                        return
                except Exception:
                    pass
            self._run_predictions_cleanup()
        except Exception:
            pass

    def run_predictions_cleanup_now(self, dry_run=True):
        """Manual trigger (REPL / testing). Honors dry_run explicitly;
        bypasses the daily gate and the enable flag."""
        self._run_predictions_cleanup(dry_run=dry_run)

    def _auto_refresh_tick(self):
        """One iteration of the auto-refresh loop. Called from the daemon
        thread, must NOT touch tkinter widgets directly — schedule UI
        updates with self.root.after(0, ...).

        Returns True if a refresh happened, False if skipped.
        """
        # v4.14.5.14-predictions-cleanup: daily file-maintenance gate.
        # Runs BEFORE the AI-state bails — cleanup is independent of
        # whether AI is paused or a scan is running.
        try:
            self._maybe_run_predictions_cleanup()
        except Exception:
            pass

        # Bail if AI is paused
        try:
            if tm_holdings.is_ai_paused():
                return False
        except Exception:
            pass

        # Bail if a scan is already running
        if (self._holdings_window is not None
                and getattr(self._holdings_window,
                             '_discover_running', False)):
            return False
        if (self._holdings_window is not None
                and getattr(self._holdings_window,
                             '_consensus_running', False)):
            return False
        # v4.13.12: also bail during a Scan All Paths sweep,
        # which toggles _discover_running True/False between
        # paths and would otherwise let auto-refresh sneak in
        # during the gap and skip a path in the sweep.
        if (self._holdings_window is not None
                and getattr(self._holdings_window,
                             '_all_paths_running', False)):
            return False

        # v4.13.15: opportunistic outcome evaluation. Cheap if no
        # predictions are open; valuable if some have hit target/stop
        # since the user last opened Discover/Track Record. Errors
        # are non-fatal — the auto-refresh tick continues regardless.
        # v4.13.25: closer runs whenever predictions_log is
        # available, regardless of whether Holdings window is open.
        # Builds holdings_state on demand if it doesn't yet exist.
        try:
            if self._holdings_state is None:
                try:
                    self._holdings_state = self._build_holdings_state()
                except Exception:
                    self._holdings_state = None
            if (self._holdings_state is not None
                    and self._holdings_state.get('predictions_log')):
                pl = self._holdings_state['predictions_log']
                pl.check_outcomes(
                    self._holdings_state['cache'].quote,
                    history_fn=tm_holdings.HoldingsWindow._build_history_fn())
                # v4.14.5.62-stop-recovery: ADDITIVE maturity sweep (flagged,
                # default OFF; at most ONCE per calendar day via the last-run
                # cfg key). Revisits matured stop_hit records and stamps
                # whether price recovered within the prediction's own horizon.
                # Changes NO verdict, touches NO open prediction. Runs AFTER
                # live grading; fully guarded + best-effort so it can never
                # block or interfere with the closer.
                try:
                    if self.cfg.get('use_stop_recovery_sweep', False):
                        _sr_today = datetime.now().strftime('%Y-%m-%d')
                        if (self.cfg.get('stop_recovery_sweep_last_run')
                                != _sr_today):
                            pl.sweep_stop_recovery(
                                history_fn=(tm_holdings.HoldingsWindow
                                            ._build_history_fn()))
                            self.cfg['stop_recovery_sweep_last_run'] = _sr_today
                            try:
                                save_config(self.cfg)
                            except Exception:
                                pass
                except Exception:
                    pass
                # v4.13.36: also run supersession check on each tick
                # so newly-written reversals close their predecessors
                # without waiting for app restart.
                try:
                    pl.check_supersessions(
                        stable=bool(self.cfg.get(
                            'use_stable_recommend', True)))
                except Exception:
                    pass
                # v4.14.3: accuracy → source-weight bridge. Internal
                # 5-min cooldown prevents redundant work on rapid
                # ticks. Silent on success.
                try:
                    import tm_source_accuracy
                    # v4.14.5.14-db-concurrency: serialize (see startup
                    # closer site above — same SQLITE_MISUSE race fix).
                    with self.db.lock:
                        tm_source_accuracy.update_source_weights_from_accuracy(
                            self.db.conn, pl,
                        )
                except Exception:
                    pass
        except Exception:
            pass

        # Bail if yfinance cooldown is active
        try:
            cd = tm_discover.get_cooldown_status()
            if cd.get('active'):
                return False
        except Exception:
            pass

        # Check staleness — when did we last refresh?
        interval_hours = float(self.cfg.get(
            'auto_refresh_interval_hours', 4))
        last_run_str = self.cfg.get('auto_refresh_last_run', '')
        last_dt = None
        if last_run_str:
            try:
                last_dt = datetime.fromisoformat(last_run_str)
            except Exception:
                last_dt = None

        if last_dt is not None:
            age_hours = (datetime.now() - last_dt).total_seconds() / 3600.0
            if age_hours < interval_hours:
                return False  # too soon

        # Time to refresh. Build holdings_state if needed.
        if self._holdings_state is None:
            try:
                self._holdings_state = self._build_holdings_state()
            except Exception:
                return False

        # Stamp the run BEFORE the actual fetch so we don't
        # re-trigger if it's slow
        self.cfg['auto_refresh_last_run'] = datetime.now().isoformat(
            timespec='seconds')
        try: save_config(self.cfg)
        except Exception: pass

        self.root.after(0, lambda: self._log(
            "Auto-refresh: refreshing data...", 'muted'))

        # Refresh the universe (this is the cheap part — just iShares CSVs)
        universe = self._holdings_state.get('universe')
        if universe is not None:
            try:
                universe.refresh(
                    log_fn=lambda m: self.root.after(
                        0, lambda m=m: self._log(f"  {m}", 'muted')))
            except Exception as e:
                self.root.after(0, lambda e=e: self._log(
                    f"  Universe refresh failed: {e}", 'amber'))
                return False

        # v4.14.5.50-cleanup: the auto-refresh "run a model" branch is a dead
        # Ollama-era vestige (local model scans were retired in the cloud-only
        # purge; auto_refresh_model is always '(none)' now). Data still refreshes
        # above; we just log that cleanly and return — the legacy model-run code
        # below is unreachable (kept inert; a future pass can excise it).
        auto_model = self.cfg.get('auto_refresh_model', '(none)')
        if auto_model == '(none)' or not auto_model:
            self.root.after(0, lambda: self._log(
                "Auto-refresh: data refreshed.",
                'green'))
            return True

        # Verify the configured model is still installed
        # v4.14.5.14-ollama-purge-3c: Ollama retired (cloud-only) — no local
        # model list. A configured local analysis_model (legacy) won't be found,
        # so the model-run below is skipped; data still refreshes.
        installed = []
        if auto_model not in installed:
            self.root.after(0, lambda: self._log(
                f"Auto-refresh: model '{auto_model}' is not installed. "
                f"Skipping model run. Pick a different model in Settings.",
                'amber'))
            return False

        # Build a HoldingsWindow proxy if we don't have one (same pattern
        # the main-page Scan button uses)
        if self._holdings_window is None:
            try:
                state = self._holdings_state
                self._holdings_window = tm_holdings.HoldingsWindow(
                    parent=self.root,
                    holdings_mgr=state['mgr'],
                    cache=state['cache'],
                    signals_log=state['log'],
                    prompt_builder=state['builder'],
                    get_path_fn=lambda: state['path'],
                    set_path_fn=state['save_path'],
                    predictions_log=state.get('predictions_log'),
                    watchlist=state.get('watchlist'),
                    universe=state.get('universe'),
                    log_callback=lambda msg, color='muted': self._log(
                        msg, color),
                    save_universe_source=lambda src: self._save_universe_source(src),
                    sync_main_universe=lambda label: self._sync_main_universe(label),
                    get_configured_model=lambda: self._get_configured_model(),
                    cfg=self.cfg,
                    app=self,  # v4.10.6: design tokens + popup helpers
                )
            except Exception as e:
                self.root.after(0, lambda e=e: self._log(
                    f"Auto-refresh: could not build holdings window: {e}",
                    'amber'))
                return False

        self.root.after(0, lambda m=auto_model: self._log(
            f"Auto-refresh: running model '{m}' against fresh data...",
            'green'))

        # Run a one-model Discover scan headlessly. The on_done callback
        # logs completion. This blocks the auto-refresh thread until
        # the scan finishes — that's fine, we sleep 30 min between
        # ticks anyway.
        scan_done = threading.Event()
        def _on_done():
            scan_done.set()
        try:
            self._holdings_window.run_discover_scan_headless(
                model=auto_model, on_done=_on_done)
            # Wait up to 30 minutes for completion
            if scan_done.wait(timeout=30 * 60):
                self.root.after(0, lambda: self._log(
                    "Auto-refresh: model run complete.", 'green'))
            else:
                self.root.after(0, lambda: self._log(
                    "Auto-refresh: model run timed out at 30min "
                    "(may still be writing predictions).", 'amber'))
        except Exception as e:
            self.root.after(0, lambda e=e: self._log(
                f"Auto-refresh: model run failed: {e}", 'amber'))
            return False

        return True

    def _launch_startup_cleanup(self):
        """v4.9.2: run auto-cleanup at startup, in a background thread so it
        never blocks the UI. Reports to the activity feed only if something
        was actually cleaned (otherwise stays silent)."""
        def _do():
            try:
                report = self._run_cleanup(triggered_by='startup')
                total = (report['backups_removed']
                         + report['pred_backups_removed']
                         + report['snapshots_removed']
                         + report['logs_rolled'])
                # v4.13.62.8: cleanup is internal housekeeping — no log
                # line on success. The cleanup report still gets written
                # to data/cleanup.log for diagnostic purposes; failures
                # still get caught silently by the except branch.
                _ = total  # keep var to satisfy code shape, no-op
            except Exception:
                # Cleanup failures should NEVER break the app
                pass
        threading.Thread(target=_do, daemon=True).start()

    def _launch_auto_scan(self):
        """v4.11.0: launch-time auto-scan is DISABLED.

        Reason: the auto-scan path was the source of the hang we chased
        across v4.10.9 through v4.10.16. With the new unified layout,
        consensus is manual-only (per-holding Run consensus button), so
        there's no need for this path anymore.

        We keep the method as a stub so existing callers (root.after
        scheduling in __init__, the disclaimer flow) don't crash.

        If a future build wants automatic scans on launch (e.g., only
        for holdings older than some threshold), that logic goes here."""
        return

    def _launch_auto_discover(self):
        """v4.9.3: Run a Discover scan when there are no tradable holdings,
        so the user gets fresh ideas on launch instead of a "nothing to do"
        message. Throttled by discover_min_interval_hours (default 4) so
        repeated app launches don't re-scan.

        Honors the same AI-paused / cooldown / disclaimer rules as a manual
        Discover scan — those checks happen inside HoldingsWindow's
        run_discover_scan_headless. We just decide whether to call it.
        """
        if not _AI_ENABLED or not _DISCOVER_ENABLED:
            self._log("No tradable positions — Discover not available.", 'muted')
            return
        try:
            state = self._holdings_state
            if state is None:
                return
            preds_log = state.get('predictions_log')

            # Find the most recent prediction timestamp (any kind — Discover
            # or Consensus both count as "we scanned recently").
            min_hours = float(self.cfg.get('discover_min_interval_hours', 4))
            last_scan_dt = None
            if preds_log is not None:
                try:
                    all_preds = preds_log.get_all()
                    for p in all_preds:
                        ts = p.get('timestamp')
                        if not ts:
                            continue
                        try:
                            dt = datetime.fromisoformat(ts)
                        except Exception:
                            continue
                        if last_scan_dt is None or dt > last_scan_dt:
                            last_scan_dt = dt
                except Exception:
                    last_scan_dt = None

            if last_scan_dt is not None:
                age = datetime.now() - last_scan_dt
                age_hours = age.total_seconds() / 3600.0
                if age_hours < min_hours:
                    # Recent enough — don't re-scan. Just tell user we
                    # already have fresh ideas, so they don't think the
                    # app is broken.
                    if age_hours < 1.0:
                        ago_str = f"{int(age.total_seconds() / 60)}m ago"
                    else:
                        ago_str = f"{age_hours:.1f}h ago"
                    self._log(
                        f"No tradable positions — last scan was {ago_str}, "
                        f"ideas are fresh. Click Discover to view.",
                        'muted')
                    return

            # No recent scan (or no predictions yet at all) — run Discover.
            self._log(
                "No tradable positions — running Discover for fresh ideas...",
                'green')

            # Need a HoldingsWindow instance to call run_discover_scan_headless.
            # Construct it without showing the actual window — same pattern
            # the main-page Discover button uses.
            if self._holdings_window is None:
                try:
                    self._holdings_window = tm_holdings.HoldingsWindow(
                        parent=self.root,
                        holdings_mgr=state['mgr'],
                        cache=state['cache'],
                        signals_log=state['log'],
                        prompt_builder=state['builder'],
                        get_path_fn=lambda: state['path'],
                        set_path_fn=state['save_path'],
                        predictions_log=state.get('predictions_log'),
                        watchlist=state.get('watchlist'),
                        universe=state.get('universe'),
                        log_callback=lambda msg, color='muted': self._log(msg, color),
                        save_universe_source=lambda src: self._save_universe_source(src),
                        sync_main_universe=lambda label: self._sync_main_universe(label),
                        get_configured_model=lambda: self._get_configured_model(),
                        cfg=self.cfg,
                        app=self,  # v4.10.6: design tokens + popup helpers
                    )
                except Exception:
                    self._log(
                        "Could not start Discover (init failed). "
                        "Click Discover manually if you want fresh ideas.",
                        'amber')
                    return

            def _on_discover_done():
                try:
                    # After scan completes, log a friendly nudge so user
                    # knows the work finished and where to look.
                    self.root.after(0, lambda: self._log(
                        "Discover complete. Click Discover to see candidates.",
                        'green'))
                except Exception:
                    pass

            try:
                self._holdings_window.run_discover_scan_headless(
                    on_done=_on_discover_done)
            except Exception:
                self._log(
                    "Could not start Discover scan. Click Discover manually "
                    "if you want fresh ideas.",
                    'amber')
        except Exception:
            # Never let auto-discover failures break startup
            pass

    def _is_background_scheduler_running(self) -> bool:
        """v4.14.5.14-portfolio-watching-visibility (Fix B): True only when
        the background scheduler thread is actually alive — the daemon that
        fires owned-position events into the cloud on-event scan. Active-
        watching needs BOTH use_cloud_on_event_scan AND this. Read-only,
        fail-safe (any uncertainty → False so the badge can't falsely claim
        'watching' when nothing is firing)."""
        try:
            sched = getattr(self, '_scheduler', None)
            if sched is None:
                return False
            t = getattr(sched, '_thread', None)
            if t is None or not t.is_alive():
                return False
            stop_ev = getattr(sched, '_stop_event', None)
            if stop_ev is not None and stop_ev.is_set():
                return False
            return True
        except Exception:
            return False

    def _refresh_portfolio_panel_live(self):
        """v4.14.5.14-portfolio-watching-visibility (Fix A): re-render the
        Portfolio panel so a cloud on-event scan's result (updated SELL
        TRIGGERS, fresh scan-age, freshness dot) shows WITHOUT the user
        reopening Portfolio. Called via root.after from the scheduler's
        background thread, so it runs on the Tk main thread. Fail-safe:
        a render hiccup never propagates into the scan loop."""
        try:
            panel = getattr(self, '_portfolio_panel', None)
            if panel is not None:
                panel.render()
        except Exception:
            pass

    def _portfolio_watching_inactive_reason(self):
        """v4.14.5.14-portfolio-watching-honesty: short reason string when
        AUTOMATIC owned-position re-analysis is NOT happening, else None.

        v4.14.5.21-ideas-hygiene: docstring corrected — the cloud on-event
        pipeline IS wired (shipped 2026-05-24, v4.14.5.14-portfolio-watching-
        cloud-wiring). It is ACTIVE when inference_mode=='api' AND
        use_cloud_on_event_scan is on AND the background scheduler is running;
        in that case this returns None (= actively watching). It reports an
        inactive REASON only when:
          - inference_mode == 'api' but use_cloud_on_event_scan is off → tell
            the user to set it true;
          - the flag is on but the background scheduler isn't running → tell
            the user no events can fire;
          - (non-api/legacy) event_driven_refresh == False → legacy cadence.
        When inactive, owned positions re-analyze ONLY via the manual
        per-holding 'Refresh triggers' button (that path works on cloud —
        it uses the owned_position ConsensusRunner directly, the same one the
        on-event path reuses). Honest signalling so a lost flag / stopped
        scheduler can't silently leave Portfolio reactive-only without the
        user knowing."""
        try:
            _infmode = str((self._get_inference_settings()
                            or ('api',))[0]).strip().lower()
        except Exception:
            _infmode = 'api'
        # v4.14.5.14-portfolio-watching-indicator-text-fix: return a CLEAN,
        # complete, display-ready message (or None when actively watching).
        # Both surfaces render it verbatim after "Active-watching OFF — "
        # (single source of truth). The prior version returned a short
        # fragment that the badge jammed into parens mid-sentence
        # ("...click 'Refresh triggers' (cloud on-event analysis is off…)"),
        # which read as garbled run-on. Now it's two proper sentences:
        # what works NOW, then how to turn on automatic monitoring.
        _action = ("owned positions update only when you click "
                   "'Refresh triggers' on each holding. To turn on "
                   "automatic monitoring of price/news/earnings events, "
                   "set ")
        if _infmode == 'api':
            # v4.14.5.14-portfolio-watching-cloud-wiring: the cloud on-event
            # path EXISTS; it's active only when its flag is on. When on,
            # owned positions ARE auto-watched (the scheduler fires events
            # → _run_cloud_on_event_scan) and we return None (badge clears,
            # actively watching).
            # v4.14.5.61-active-watching-default-on: active-watching defaults ON
            # now. It's only OFF here if the user explicitly disabled it — so
            # DON'T tell them to edit config to ENABLE; explain it's been
            # turned off.
            if not self.cfg.get('use_cloud_on_event_scan', True):
                return ("owned positions update only when you click "
                        "'Refresh triggers' on each holding — automatic "
                        "monitoring of price/news/earnings events is on by "
                        "default but has been turned off "
                        "(use_cloud_on_event_scan is set to false).")
            # v4.14.5.14-portfolio-watching-visibility (Fix B): the flag
            # alone isn't enough — the background scheduler must actually be
            # running for events to fire. If it's off (e.g. "Run background
            # AI scheduler" unchecked, or a startup failure), be honest that
            # nothing is watching rather than falsely claiming it is.
            if not self._is_background_scheduler_running():
                return ("the background AI scheduler is off, so no events "
                        "fire. Turn 'Run background AI scheduler' back on in "
                        "Settings (or restart the app).")
            return None  # cloud on-event scan wired + on → actively watching
        if not self.cfg.get('event_driven_refresh', False):
            return _action + "event_driven_refresh: true in config."
        return None

    def _log_active_watching_status(self, _retry=True):
        """v4.14.5.14-portfolio-watching-timing-fix (Fix B): log the TRUE
        active-watching state once at startup, AFTER the deferred background
        scheduler has had time to start. This REPLACES the old emission inside
        _build_holdings_state, which fired during early startup — before the
        scheduler thread existed — and therefore ALWAYS reported a false 'OFF'
        (the 2026-05-24 investigation traced the phantom 'Active-watching OFF'
        log line to exactly this premature check).

        If the only reason we'd report OFF is 'the scheduler isn't running
        yet' WHILE it's configured to be on (cloud flag + background scheduler
        both enabled), that's most likely the rare 30s holdings-build defer in
        _start_scheduler, not a real failure — so re-arm ONCE (another 15s)
        before committing to an OFF verdict. Fully fail-safe."""
        try:
            if not self.cfg.get('show_portfolio_watching_indicator', True):
                return
            reason = self._portfolio_watching_inactive_reason()
            if reason is None:
                self._log(
                    "[portfolio] Active-watching ON — auto-watching owned "
                    "positions on price / news / earnings events.", 'muted')
                return
            # Looks like a not-yet-started scheduler race? Give it one more
            # window before declaring OFF.
            if (_retry
                    and self.cfg.get('use_cloud_on_event_scan', True)
                    and self.cfg.get('background_scheduler_enabled', True)
                    and not self._is_background_scheduler_running()):
                self.root.after(
                    15000,
                    lambda: self._log_active_watching_status(_retry=False))
                return
            self._log(f"[portfolio] Active-watching OFF — {reason}", 'amber')
        except Exception:
            pass

    def _run_cloud_on_event_scan(self, holdings, state):
        """v4.14.5.14-portfolio-watching-cloud-wiring: cloud on-event
        owned-position re-analysis. For each scheduler-flagged holding,
        run the SAME owned_position consensus the manual 'Refresh
        triggers' button uses — sequentially (one at a time, blocking
        per holding via a done-Event, mirroring Layer 2's
        _run_consensus_blocking) and recency-gated. Runs on the
        scheduler's background thread, so blocking per-holding never ties
        up the UI. Burn discipline: event-only (the scheduler already
        only fires on real price/news/earnings events), one model-run per
        holding per sweep, and the recency gate skips a holding analyzed
        within cloud_on_event_recency_min minutes."""
        import threading as _th
        from datetime import datetime as _dt, timedelta as _td
        # Re-entrancy guard — never run two sweeps at once.
        if getattr(self, '_cloud_on_event_active', False):
            return
        self._cloud_on_event_active = True
        try:
            mgr = state.get('mgr')
            builder = state.get('builder')
            slog = state.get('log')
            plog = state.get('predictions_log')
            # v4.14.5.62-per-holding-tier: the global path is no longer used to
            # frame owned-position analysis — each holding is framed by its OWN
            # tier inside the loop below (h.get('path') or the moderate
            # default). state['path'] (the global analysis path) is kept only
            # for the empty-events early-out / diagnostics, not the prompt.
            path = state.get('path')
            if mgr is None or builder is None:
                return
            cfg = self.cfg or {}
            # v4.14.5.63-tier-timeframe: the recency gate is now per-holding
            # (tier-driven, resolved inside the loop). This cfg value is the
            # FALLBACK default used when a tier row has no recheck_min.
            recency_default = int(cfg.get('cloud_on_event_recency_min', 30) or 0)
            timeout = int(cfg.get('cloud_on_event_timeout_sec', 180) or 180)
            models = list(cfg.get('consensus_models') or [])  # []→cloud fanout
            try:
                providers = (self._load_enabled_api_providers()
                             if hasattr(self, '_load_enabled_api_providers')
                             else [])
                infmode, game_procs = self._get_inference_settings()
            except Exception:
                providers, infmode, game_procs = [], 'api', []

            try:
                import tm_consensus
            except Exception as e:
                self.root.after(0, lambda e=e: self._log(
                    f"[cloud-on-event] consensus module unavailable: "
                    f"{type(e).__name__}", 'amber'))
                return

            def _mk_done(d, b):
                def _cb(res):
                    b['res'] = res
                    d.set()
                return _cb

            n_run = 0
            n_skip = 0
            for h in (holdings or []):
                if tm_holdings.is_ai_paused():
                    break
                ticker = (h.get('ticker') or '?').upper()
                # v4.14.5.62-per-holding-tier: frame THIS holding by its own
                # stored tier, not the global analysis path. Fall back to the
                # safe default tier (moderate) when unset — NEVER the global
                # path (which could be 'lottery'/Speculative and mis-frame a
                # large-cap). Mirrors the per-holding precedence already used
                # by Check Now (_analyze_holding) and Refresh triggers.
                h_path = (str(h.get('path') or '').strip()
                          or getattr(tm_holdings, 'DEFAULT_PATH', 'moderate'))
                # v4.14.5.63-tier-timeframe: per-tier recency gate — aggressive
                # re-checks soonest, speculative least often. Falls back to the
                # cfg default if the tier row lacks a recheck_min.
                try:
                    import tm_watch_tiers as _wt
                    recency_min = int(_wt.tier_params(h_path).get(
                        'recheck_min', recency_default) or recency_default)
                except Exception:
                    recency_min = recency_default
                # Recency gate — skip if analyzed within the window.
                if recency_min > 0:
                    la = h.get('last_analyzed')
                    if la:
                        try:
                            if (_dt.now() - _dt.fromisoformat(la)) < \
                                    _td(minutes=recency_min):
                                n_skip += 1
                                continue
                        except Exception:
                            pass
                done = _th.Event()
                box: dict = {}
                try:
                    runner = tm_consensus.ConsensusRunner(
                        ticker=ticker,
                        holding=h,
                        models=models,
                        path=h_path,                      # per-holding tier
                        prompt_builder=builder,
                        signals_log=slog,
                        predictions_log=plog,
                        prompt_kind='owned_position',     # sell-oriented
                        providers=providers,
                        inference_mode=infmode,
                        game_processes=game_procs,
                        call_type='holdings_consensus',   # full cap (1.0)
                        on_all_done=_mk_done(done, box),
                        log_callback=lambda m, t='muted': self.root.after(
                            0, lambda mm=m, tt=t: self._log(mm, tt)),
                        **self._consensus_weight_kwargs(models),
                    )
                    runner.start()
                except Exception as e:
                    self.root.after(0, lambda tk=ticker, e=e: self._log(
                        f"[cloud-on-event] {tk}: consensus start failed "
                        f"({type(e).__name__}).", 'amber'))
                    continue
                if not done.wait(timeout=timeout):
                    self.root.after(0, lambda tk=ticker: self._log(
                        f"[cloud-on-event] {tk}: consensus timed out "
                        f"(>{timeout}s) — moving on.", 'amber'))
                    continue
                try:
                    mgr.mark_analyzed(ticker)
                    mgr.save()
                except Exception:
                    pass
                n_run += 1
                _res = box.get('res') or {}
                _votes_list = (_res or {}).get('votes') or []
                _votes = len(_votes_list)
                # v4.14.5.64-owned-position-surfacing: classify the
                # just-computed verdict and surface it through the
                # right channels for its severity. Until this build the
                # watcher detected, analyzed, formed a verdict — and
                # died silently (send_notification was defined but
                # never called from anywhere). This is the wire that
                # closes the loop. Program decides, AI explains.
                try:
                    import tm_owned_alert as _oa
                    _winner = _oa.winner_from_result(_res)
                    _prior_verdict = h.get('_last_verdict') or ''
                    _prior_alert = h.get('_owned_alert')
                    _alert = _oa.classify(
                        _prior_verdict, _winner,
                        vote_count=_votes,
                        prior_alert=_prior_alert,
                    )
                    _sev = _alert.get('severity')
                    # Persist last verdict so the NEXT pass can detect
                    # a change. Always written when a verdict was
                    # extracted, regardless of severity.
                    if _winner:
                        try:
                            mgr.set_last_verdict(ticker, _winner)
                        except Exception:
                            pass
                    if _sev == _oa.ROUTINE:
                        # Routine re-check: clear any stale alert badge.
                        # Mike has been quietly told "still the same."
                        try:
                            mgr.clear_owned_alert(ticker)
                        except Exception:
                            pass
                    else:
                        # ACTIONABLE or NOTABLE: persist the alert dict
                        # so the Portfolio panel can render a durable
                        # badge until acknowledged.
                        try:
                            mgr.set_owned_alert(ticker, _alert)
                        except Exception:
                            pass
                        if _sev == _oa.ACTIONABLE:
                            # Windows toast — send_notification is gated
                            # internally on HAS_NOTIFY (plyer present)
                            # AND cfg notifications_enabled. When toasts
                            # are off the badge above is still set, so
                            # Mike still sees it next time he opens
                            # Portfolio — silent-but-durable fallback.
                            try:
                                _title, _msg = _oa.toast_text(ticker, _alert)
                                self.root.after(
                                    0,
                                    lambda t=_title, m=_msg:
                                        send_notification(t, m))
                            except Exception:
                                pass
                            # Loud activity-log line so even users with
                            # toasts disabled get a non-transient signal.
                            self.root.after(
                                0,
                                lambda tk=ticker, v=_winner, pv=(
                                    _prior_verdict):
                                    self._log(
                                        f"[cloud-on-event] {tk}: ALERT — "
                                        f"watcher consensus "
                                        f"{(pv + ' → ' + v) if (pv and pv != v) else v}.",
                                        'red'))
                    try:
                        mgr.save()
                    except Exception:
                        pass
                except Exception:
                    # The surfacing layer must NEVER break the watcher
                    # loop — any classifier/notifier fault degrades to
                    # the pre-build silent behaviour.
                    pass
                self.root.after(0, lambda tk=ticker, v=_votes: self._log(
                    f"[cloud-on-event] {tk}: owned-position consensus "
                    f"done ({v} vote(s)) — SELL TRIGGERS updated.",
                    'green'))
                # v4.14.5.14-portfolio-watching-visibility (Fix A): re-render
                # the Portfolio panel now so this holding's card (SELL
                # TRIGGERS, scan-age, freshness dot, alert badge) updates
                # live — without the user reopening Portfolio.
                self.root.after(0, self._refresh_portfolio_panel_live)
            self.root.after(0, lambda nr=n_run, ns=n_skip: self._log(
                f"[cloud-on-event] sweep complete — {nr} re-analyzed, "
                f"{ns} skipped (recency gate).", 'muted'))
        finally:
            self._cloud_on_event_active = False

    def _run_silent_scan(self, tradable_holdings):
        """Run Check Now without opening the Holdings UI. Spins up the
        analysis in the background using the same prompt builder + AI
        request pipeline the Holdings window uses, but writes results
        only to signals.jsonl + the activity log on the main window.
        """
        # v4.15.0: gate on the unified AI-availability check (cloud OR
        # local). Pre-v4.15.0 this only checked local Ollama models,
        # which silently refused for cloud-only users. Background work
        # — single amber log, no Teacher AI surface (would be noisy
        # for an event the user didn't initiate).
        try:
            import tm_top_ai_picker
            if not tm_top_ai_picker.has_any_ai_available(self):
                self._log(
                    "Background scan skipped: no AI available "
                    "(no provider configured, all disabled, or all "
                    "out of quota).",
                    'amber')
                return
        except Exception:
            # Defensive: if the picker import fails, fall through to
            # the legacy local-Ollama check below so we don't block
            # background work entirely.
            pass

        state = self._holdings_state
        if state is None:
            return
        path = state['path']
        builder = state['builder']
        log = state['log']
        mgr = state['mgr']

        # Cloud-only (Ollama retired). Owned-position events route through the
        # cloud owned_position consensus path (the same path the manual "Refresh
        # triggers" button uses) when use_cloud_on_event_scan is on; otherwise
        # we log an honest skip. (v4.14.5.14-mode-detection-collapse-2b removed
        # the inference_mode gate; v4.14.5.14-ollama-purge-3c deleted the dead
        # local-Ollama scan pipeline that used to follow the skip return below.)
        if bool(self.cfg.get('use_cloud_on_event_scan', True)):
            try:
                self._run_cloud_on_event_scan(tradable_holdings, state)
            except Exception as e:
                self._log(
                    f"[cloud-on-event] dispatch failed "
                    f"({type(e).__name__}: {e}); skipping this sweep.",
                    'amber')
            return
        self._log("[silent-scan] skipped — cloud on-event analysis has been "
                  "turned off (use_cloud_on_event_scan=false; it is on by "
                  "default).",
                  'amber')
        return


    def _start_scheduler(self):
        """Start the Phase 2B background scheduler. Runs in a thread,
        ticks based on market-hours-aware cadence, dispatches events to
        the AI when something actually changed.

        Has to wait until disclaimer is accepted (otherwise we'd start
        analyzing before the user has agreed to anything). Polls every
        15s until ready.
        """
        if self._scheduler is not None:
            return  # already running
        if not _SCHEDULER_ENABLED or not _AI_ENABLED:
            return
        if not _has_accepted_disclaimer():
            # Try again later
            self.root.after(15000, self._start_scheduler)
            return
        if self._holdings_state is None:
            try:
                self._holdings_state = self._build_holdings_state()
            except Exception:
                self.root.after(30000, self._start_scheduler)
                return

        state = self._holdings_state

        # Game tracker: knows about extra game executables from config,
        # uses our AI-busy flag so it doesn't false-trigger.
        self._game_tracker = tm_scheduler.GameStateTracker(
            ai_busy_callback=lambda: self._ai_busy,
            extra_procs_callback=lambda: set(self.cfg.get('game_executables', []))
        )

        scheduler_state_path = DATA_DIR / "scheduler_state.json"
        self._scheduler = tm_scheduler.Scheduler(
            holdings_mgr=state['mgr'],
            cache=state['cache'],
            signals_log=state['log'],
            scan_callback=self._handle_scheduled_events,
            game_check_callback=lambda: (
                self._game_tracker.is_gaming()
                if self.cfg.get('auto_pause_gaming', True)
                else False
            ),
            paused_check_callback=tm_holdings.is_ai_paused,
            mode_change_callback=self._on_scheduler_mode_change,
            db=self.db,
            state_path=scheduler_state_path,
            event_detector_log_fn=lambda msg: self._log(msg, 'amber'),
        )
        # v4.14.5.76-adaptive-lane-pacing: surface controller adjustments
        # in the activity log. Marshal onto the Tk thread because the
        # scheduler's tick runs in its own daemon thread.
        try:
            def _lp_log(msg, color='muted'):
                try:
                    self.root.after(
                        0, lambda m=msg, c=color: self._log(m, c))
                except Exception:
                    pass
            self._scheduler._lane_pacing_log_fn = _lp_log
        except Exception:
            pass

        self._scheduler.start()
        # v4.13.62.8: dropped the "Background scheduler started" log
        # line — internal startup detail, not user-facing value.
        # v4.14.5.14-portfolio-watching-timing-fix (Fix A): RESTORED — that
        # silence was the root of the false "Active-watching OFF" badge. With
        # no start line, a running scheduler was indistinguishable from one
        # that never came up, and nothing told an already-open Portfolio panel
        # to re-check. Now: (1) log the start so the state is visible/auditable
        # (this was the missing evidence in the 2026-05-24 investigation), and
        # (2) push a Portfolio-panel refresh so an already-open badge flips
        # from the startup-time "OFF" to green "ON" the instant events can
        # fire. _is_background_scheduler_running() reads True the moment
        # start() returns (thread is alive even during its 15s first-tick
        # wait), so the refreshed badge reads correctly. Both guarded — a log
        # or render hiccup must never crash scheduler startup.
        try:
            self._log("[scheduler] Background scheduler started — "
                      "owned-position events are now being watched.", 'muted')
        except Exception:
            pass
        try:
            self.root.after(0, self._refresh_portfolio_panel_live)
        except Exception:
            pass

    # ─── v4.8.6: UPS / power monitoring ───────────────────────────────

    def _start_power_monitor(self):
        """Initialize and start the UPS battery monitor. Polls Windows
        for battery state every 10 seconds. On power loss: pauses AI,
        shows banner, optionally schedules graceful shutdown.
        """
        if not _POWER_ENABLED or self._power_monitor is not None:
            return

        # First do a probe — if no UPS detected, don't bother starting
        # the polling thread.
        try:
            probe = tm_power.query_battery()
        except Exception:
            probe = None

        if probe is None or not probe.is_valid:
            # No UPS detected. Don't poll. v4.13.62.8: silent — no log
            # line. The user already knows whether their machine has a
            # UPS; nothing for them to do here.
            return

        # UPS detected. v4.13.62.8: only surface a launch log line when
        # there's something the user might want to act on — i.e. the
        # machine is running on battery, or charge is below 20%. Plugged
        # in and healthy = silent. The PowerMonitor still polls and will
        # fire its own log lines on state transitions either way.
        try:
            on_battery = (probe.state_label or '').lower() == 'on_battery'
            low_charge = (probe.charge_pct is not None
                           and probe.charge_pct < 20)
        except Exception:
            on_battery = False
            low_charge = False
        if on_battery or low_charge:
            self._log(
                f"UPS: {probe.name} · {probe.charge_pct}% charged · "
                f"{probe.runtime_minutes} min runtime estimate "
                f"({'on battery' if on_battery else 'low charge'})",
                'amber')
        self._power_state = probe.state_label
        self._power_last_info = probe

        self._power_monitor = tm_power.PowerMonitor(
            on_state_change=self._on_power_state_change,
            on_low_battery=self._on_power_low_battery,
            on_critical=self._on_power_critical,
            poll_interval=10.0,
            low_battery_minutes=int(self.cfg.get('ups_low_minutes', 5)),
            low_battery_pct=int(self.cfg.get('ups_low_pct', 20)),
            critical_battery_minutes=int(self.cfg.get('ups_critical_minutes', 2)),
            critical_battery_pct=int(self.cfg.get('ups_critical_pct', 10)),
        )
        self._power_monitor.start()

    def _on_power_state_change(self, old_state, new_state, info):
        """Fired by PowerMonitor on AC<->Battery transitions. Runs on
        the polling thread; marshal UI updates to the main thread."""
        self._power_state = new_state
        self._power_last_info = info
        self.root.after(0, self._handle_power_state_change_ui,
                          old_state, new_state, info)

    def _handle_power_state_change_ui(self, old_state, new_state, info):
        """Main-thread UI work for power state transitions."""
        if new_state == 'on_battery':
            # Pause AI immediately to conserve battery — every minute of
            # GPU-bound AI inference is a minute of runtime burned.
            try:
                if not tm_holdings.is_ai_paused():
                    tm_holdings.set_ai_paused(True, 'ups')
            except Exception:
                pass

            # Cancel any in-progress Discover scan
            try:
                if self._holdings_window is not None:
                    self._holdings_window._discover_running = False
            except Exception:
                pass

            self._log(
                f"⚡ POWER LOST — running on UPS battery. AI paused. "
                f"{info.charge_pct}% charge, ~{info.runtime_minutes}min "
                f"estimated runtime.",
                'red')
            self._show_power_banner(info)

        elif new_state == 'online' and old_state == 'on_battery':
            # Power restored
            self._log(
                f"✓ Power restored. AC online. Battery at {info.charge_pct}%.",
                'green')
            self._hide_power_banner()
            # Clear shutdown-pending flag (no Windows shutdown to cancel
            # any more — v4.8.7 dropped that risky behavior)
            self._shutdown_pending = False
            # Resume AI (only if WE were the ones who paused it for UPS;
            # if user manually paused it for other reasons, leave it)
            try:
                if tm_holdings.get_ai_pause_reason() == 'ups':
                    tm_holdings.set_ai_paused(False)
                    self._log("AI resumed.", 'muted')
            except Exception:
                pass

        elif new_state == 'unknown':
            # USB disconnected or similar. Don't panic — just log.
            self._log("UPS connection lost (USB unplugged?). "
                       "Power state unknown.", 'amber')

    def _on_power_low_battery(self, info):
        """First low-battery warning crossed."""
        self.root.after(0, lambda: self._log(
            f"⚠ UPS battery low: {info.charge_pct}%, "
            f"~{info.runtime_minutes}min remaining. Save your work.",
            'amber'))

    def _on_power_critical(self, info):
        """Critical battery threshold — save data and close the app
        cleanly. v4.8.7: replaces the earlier "shutdown Windows" approach.
        Just protect our own data; let the OS do its own thing."""
        def _ui():
            self._log(
                f"⚠ UPS battery CRITICAL: {info.charge_pct}%, "
                f"~{info.runtime_minutes}min remaining.",
                'red')
            if self.cfg.get('ups_auto_save_close', True):
                self._save_and_close_for_power(info)
            else:
                self._log(
                    "Auto-save-and-close is disabled in Settings. Save "
                    "your work manually before battery dies.", 'amber')
        self.root.after(0, _ui)

    def _save_and_close_for_power(self, info):
        """Power critical → drop a marker file so we know on next launch
        why the app closed, then run the normal close sequence.

        The marker is read in __init__ to surface a banner: 'power loss
        detected, app closed itself at HH:MM, X% battery remaining.'
        """
        if self._shutdown_pending:
            return  # Already in progress
        self._shutdown_pending = True

        # Write the marker file FIRST so even if close hangs, we know
        # what happened on next launch
        try:
            marker = {
                'closed_at': datetime.now().isoformat(),
                'reason': 'power_critical',
                'battery_charge_pct': info.charge_pct,
                'battery_runtime_min': info.runtime_minutes,
                'ups_name': info.name,
                'discover_was_running': bool(
                    self._holdings_window is not None
                    and getattr(self._holdings_window, '_discover_running', False)
                ),
            }
            marker_path = USER_DATA_DIR / "power_loss_marker.json"
            marker_path.parent.mkdir(parents=True, exist_ok=True)
            with open(marker_path, 'w') as f:
                json.dump(marker, f, indent=2)
        except Exception:
            pass

        self._log(
            "⚠ Auto-saving and closing to preserve your data. "
            "Next launch will show what happened.", 'red')

        # Tiny delay so the activity log message is visible before we
        # destroy the window
        self.root.after(500, self._on_close)

    def _show_power_banner(self, info):
        """Show a persistent banner at the top of the main window."""
        try:
            if self._power_banner is None:
                # Build banner above the existing body
                banner = tk.Label(self.root, text="",
                                   bg=self.c['red'], fg=self.c['bg'],
                                   font=('Segoe UI', 10, 'bold'),
                                   pady=6)
                # Pack just under the title bar — needs to be top-most.
                # We'll insert it before all other body content by
                # using pack_configure with before=
                banner.pack(side='top', fill='x',
                             before=self.root.winfo_children()[0]
                             if self.root.winfo_children() else None)
                self._power_banner = banner
            self._power_banner.config(
                text=(f"  ⚡  RUNNING ON UPS BATTERY  ·  "
                      f"{info.charge_pct}% · ~{info.runtime_minutes} min "
                      f"runtime · AI paused to conserve power  "))
            self._power_banner.pack(side='top', fill='x')
        except Exception:
            pass

    def _hide_power_banner(self):
        try:
            if self._power_banner is not None:
                self._power_banner.pack_forget()
        except Exception:
            pass

    # ─── v4.8.7: power-loss marker (post-event banner) ───

    def _check_power_loss_marker(self):
        """Check for a power_loss_marker.json from a previous session.
        If present, the previous session ended via auto-save-and-close
        because battery hit critical. Show an amber warning banner so
        the user knows what happened.
        """
        marker_path = USER_DATA_DIR / "power_loss_marker.json"
        if not marker_path.exists():
            return

        try:
            with open(marker_path) as f:
                marker = json.load(f)
        except Exception:
            # Couldn't read marker — best effort, just delete it
            try: marker_path.unlink()
            except Exception: pass
            return

        # Schedule the banner so it appears after main window has built
        self.root.after(300, lambda: self._show_power_loss_warning(marker))

    def _show_power_loss_warning(self, marker: dict):
        """Render an amber banner at top of main window with details
        about the previous power-loss-induced close. User dismisses to
        clear the marker file."""
        try:
            ts_str = marker.get('closed_at', '')
            try:
                ts = datetime.fromisoformat(ts_str)
                ts_pretty = ts.strftime('%-I:%M %p on %b %-d')
            except Exception:
                # Windows strftime doesn't support %-I; fall back to %I
                try:
                    ts = datetime.fromisoformat(ts_str)
                    ts_pretty = ts.strftime('%I:%M %p on %b %d').lstrip('0')
                except Exception:
                    ts_pretty = ts_str or 'unknown time'

            charge = marker.get('battery_charge_pct', '?')
            runtime = marker.get('battery_runtime_min', '?')
            scan_was_running = marker.get('discover_was_running', False)

            scan_note = (" Discover scan was in progress and was cancelled."
                          if scan_was_running else "")

            banner_text = (
                f"  ⚠  Power loss recovery: app auto-saved and closed at "
                f"{ts_pretty} (battery was at {charge}%, ~{runtime}min "
                f"remaining).{scan_note} Verify nothing was lost.  "
            )

            warning = tk.Frame(self.root, bg=self.c['amber'])

            label = tk.Label(warning, text=banner_text,
                              bg=self.c['amber'], fg=self.c['bg'],
                              font=('Segoe UI', 9, 'bold'),
                              pady=4, padx=12, anchor='w')
            label.pack(side='left', fill='x', expand=True)

            def _dismiss():
                try:
                    marker_path = USER_DATA_DIR / "power_loss_marker.json"
                    if marker_path.exists():
                        marker_path.unlink()
                except Exception:
                    pass
                try: warning.destroy()
                except Exception: pass

            tk.Button(warning, text="Dismiss",
                      bg=self.c['bg'], fg=self.c['amber'],
                      relief='flat', padx=10, pady=2,
                      font=('Segoe UI', 8, 'bold'), cursor='hand2',
                      command=_dismiss).pack(side='right', padx=8, pady=4)

            # Insert at top, before the existing body
            children = self.root.winfo_children()
            warning.pack(side='top', fill='x',
                          before=children[0] if children else None)

            # Also log to activity for the record
            self._log(
                f"⚠ Power loss closure detected from previous session "
                f"({ts_pretty}). Banner shown at top.", 'amber')
        except Exception:
            pass

    def _handle_scheduled_events(self, events: list[dict]):
        """Called by the scheduler when events fire. We dedupe by ticker
        (don't analyze the same ticker twice in one batch even if it has
        multiple events fired) and run AI analyses sequentially.

        Events are dispatched on the same thread the scheduler called us
        from (a background thread), so we can do the AI work inline
        without blocking the UI.
        """
        if not events:
            return
        if tm_holdings.is_ai_paused():
            return
        state = self._holdings_state
        if state is None:
            return

        # Dedupe by ticker — keep highest severity per ticker
        severity_rank = {'minor': 0, 'major': 1, 'critical': 2}
        per_ticker: dict[str, dict] = {}
        for ev in events:
            t = ev.get('ticker', '?').upper()
            existing = per_ticker.get(t)
            if existing is None:
                per_ticker[t] = ev
            else:
                if (severity_rank.get(ev.get('severity'), 0) >
                        severity_rank.get(existing.get('severity'), 0)):
                    per_ticker[t] = ev

        # Build the holdings list from these events
        mgr = state['mgr']
        holdings_to_scan = []
        reasons = []
        for ticker, ev in per_ticker.items():
            for h in mgr.holdings:
                if h.get('ticker', '').upper() == ticker:
                    holdings_to_scan.append(h)
                    reasons.append(f"{ticker}: {ev.get('reason', '?')}")
                    break

        if not holdings_to_scan:
            return

        # Log on the UI thread
        msg = f"Background AI: {len(holdings_to_scan)} event(s) — " + \
              "; ".join(reasons[:3])
        if len(reasons) > 3:
            msg += f" + {len(reasons) - 3} more"
        self.root.after(0, lambda: self._log(msg, 'green'))

        # The silent-scan helper does all the heavy lifting (prompt build,
        # AI request, signals log, mgr.mark_analyzed). We just hand it
        # the list of holdings to scan.
        self._run_silent_scan(holdings_to_scan)

        # Mark them analyzed on the detector so they cool down
        if self._scheduler is not None:
            for h in holdings_to_scan:
                try:
                    self._scheduler.detector.mark_analyzed(h.get('ticker', '?'))
                except Exception:
                    pass

    def _on_scheduler_mode_change(self, new_mode: str):
        """Called by the scheduler when its mode changes (active/reduced/
        idle/paused/gaming/brief). Updates the badge to reflect it."""
        self._scheduler_mode = new_mode
        # Schedule UI update on main thread
        try:
            self.root.after(0, self._refresh_ai_badge)
        except Exception:
            pass

    def _maybe_merge_prefill_portfolio(self):
        """Seed the runtime portfolio from a prefill file on FIRST launch only.

        Why "first launch only" matters: if we ran this every launch, then
        when the user sells a holding, the prefill would happily re-add it
        on next launch (it sees "prefill has HUMA, runtime doesn't, so add").
        That's wrong — once the user has touched their portfolio (sold
        anything, removed anything, added anything), the prefill is no
        longer the source of truth.

        Behavior:
        - If runtime has zero active holdings AND zero closed trades →
          this is genuinely the first launch, seed from prefill.
        - Otherwise, prefill is ignored. The user has already made changes;
          we don't second-guess them.

        Skips a prefill ticker if it appears in the closed list (already
        sold) — that shouldn't trigger anyway given the above check, but
        it's a belt-and-suspenders safety net.
        """
        try:
            prefill_path = SCRIPT_DIR / "portfolio.json"
            if not prefill_path.exists():
                return
            # Only seed on first launch. If user has any active holdings
            # OR any closed trades, the runtime is the source of truth.
            holdings_count = len(self.portfolio.get('holdings', []))
            closed_count = len(self.portfolio.get('closed', []))
            if holdings_count > 0 or closed_count > 0:
                return  # User has touched their portfolio; leave it alone

            with open(prefill_path) as f:
                prefill = json.load(f)
            prefill_holdings = prefill.get('holdings', [])
            if not prefill_holdings:
                return

            # Belt-and-suspenders: skip any prefill ticker that's in closed.
            # (Shouldn't trigger given the above check, but doesn't hurt.)
            closed_tickers = {
                c.get('ticker', '').upper()
                for c in self.portfolio.get('closed', [])
            }
            added = 0
            for h in prefill_holdings:
                t = h.get('ticker', '').upper()
                if t and t not in closed_tickers:
                    self.portfolio.setdefault('holdings', []).append(h)
                    added += 1
            if added > 0:
                total = sum(
                    h.get('total_cost', h.get('shares', 0) * h.get('buy_price', 0))
                    for h in self.portfolio.get('holdings', [])
                )
                self.portfolio['total_invested'] = float(total)
                save_portfolio(self.portfolio)
        except Exception:
            pass  # never block startup on prefill issues

    def _build(self):
        c = self.c

        # ── Header bar ──
        header = tk.Frame(self.root, bg=c['card'], height=56)
        header.pack(side='top', fill='x')
        header.pack_propagate(False)

        # App title (left)
        title_frame = tk.Frame(header, bg=c['card'])
        title_frame.pack(side='left', padx=12, pady=8)
        tk.Label(title_frame, text="Tired Market", bg=c['card'], fg=c['accent'],
                 font=('Segoe UI', 14, 'bold')).pack(side='top', anchor='w')
        tk.Label(title_frame, text="AI-driven stock analysis", bg=c['card'],
                 fg=c['dim'], font=('Segoe UI', 8)).pack(side='top', anchor='w')

        # Header buttons (right side)
        btn_frame = tk.Frame(header, bg=c['card'])
        btn_frame.pack(side='right', padx=10, pady=10)

        # ════════════════════════════════════════════════════════════════
        # v4.10.4: HEADER REWORK — design system applied
        # ════════════════════════════════════════════════════════════════
        # The right side of the header used to cram 9 buttons + 3 status
        # widgets into one row, which truncated buttons at narrow widths.
        # Now:
        #   - Status area (clock, freshness, AI badge): rightmost, dim
        #   - Action buttons: centered weight, secondary teal color
        #   - Stop: danger red, pulled out for emergency clarity
        #   - Help / Settings / Exit: collapsed into one '≡' utility menu
        # All buttons use design-system spacing (padx=8, pady=3) and
        # body_bold font (9pt) — ~30% horizontal saving over the old
        # padx=12 buttons.

        # ── STATUS AREA (rightmost) ──
        # v4.10.4: clock + freshness now live in a single status widget
        # area with consistent spacing. State icon prepends the
        # freshness label so user can tell at a glance what's happening.

        # Clock: lives at the very right edge.
        self._status_lbl = tk.Label(btn_frame, text="",
                                     bg=c['card'], fg=c['muted'],
                                     font=self.fonts['body'])
        self._status_lbl.pack(side='right', padx=(0, self.space['md']))

        # Freshness/state indicator: combines the auto-refresh state
        # (idle / refreshing / running model / paused / cooldown) with
        # the data age. Two-element row so state + age both visible.
        freshness_frame = tk.Frame(btn_frame, bg=c['card'])
        freshness_frame.pack(side='right', padx=(0, self.space['sm']))
        self._state_icon_lbl = tk.Label(freshness_frame, text="",
                                          bg=c['card'], fg=c['muted'],
                                          font=self.fonts['body'])
        self._state_icon_lbl.pack(side='top', anchor='e')
        # v4.14.5.14-gui-cleanup-a: the "data: Xm old" age label
        # (_freshness_lbl) was removed. With slow-start streaming + verdict-
        # recency gating + event-driven re-checks, data freshness isn't one
        # number (different tickers, different freshness, all the time). The
        # Idle/state indicator (_state_icon_lbl, above) stays.

        # ── v4.14.5.56-restore-statusbar: startup phase-progress row ──────
        # [○ Startup][○ Conservative][○ Moderate][○ Aggressive][○ Speculative]
        # — dots turn green as each phase's initial fill completes (Speculative
        # greens LAST, by yield). When all complete, a brief "✓ All set" shows,
        # then the row collapses. Option A: this row COEXISTS with _state_icon_lbl
        # (packed above) — the bar never writes the state icon; _update_freshness_
        # label keeps sole ownership of Idle/Running/Paused/Cooldown.
        # _tick_status_bar drives it; logic lives in the pure gui_* helpers.
        self._phase_frame = tk.Frame(freshness_frame, bg=c['card'])
        self._phase_frame.pack(side='top', anchor='e')
        for _plabel, _ppath in _GUI_PHASE_DOTS:
            # v4.14.5.58: FIXED-WIDTH centered slot so the active label can pulse
            # name→working→N/M, and paths can transition dim/green/accent, with
            # ZERO reflow of anything to the right. width sized to the longest
            # name ("Conservative"=12) + margin. Colour (not a glyph) conveys
            # state: dim=waiting, green=done, accent=active.
            _dl = tk.Label(self._phase_frame,
                           text=_plabel, width=13, anchor='center',
                           bg=c['card'], fg=c['dim'],
                           font=self.fonts['caption'])
            _dl.pack(side='left', padx=(0, 4))
            self._phase_dot_lbls[_plabel] = _dl
            try:
                _tip = (f"{_plabel} — startup phase"
                        if _ppath is None else
                        f"{_plabel} — green once its candidate pool has all "
                        f"been analyzed once")
                Tooltip(_dl, _tip)
            except Exception:
                pass
        # Announcement label (shown briefly when all phases complete; managed
        # by _set_status_mode, so not packed here).
        self._phase_announce_lbl = tk.Label(
            freshness_frame, text="", bg=c['card'], fg=c['green'],
            font=self.fonts['caption'])

        # AI pause/resume badge — clickable Button. Reflects the global
        # pause state from tm_holdings. v4.10.4: tightened padding
        # using design tokens.
        if _AI_ENABLED:
            self._ai_badge = tk.Button(btn_frame, text="",
                                        bg=c['card'], fg=c['green'],
                                        activebackground=c['card2'],
                                        activeforeground=c['green'],
                                        font=self.fonts['body_bold'],
                                        cursor='hand2',
                                        padx=self.space['sm'],
                                        pady=self.space['xs'],
                                        relief='flat', borderwidth=0,
                                        command=self._toggle_ai_paused)
            self._ai_badge.pack(side='right', padx=(0, self.space['sm']))
            try:
                Tooltip(self._ai_badge,
                        "Click to pause / resume the AI. When paused, "
                        "Check Now and Re-check do nothing until resumed.")
            except Exception:
                pass
            initial_paused = bool(self.cfg.get('ai_paused', False))
            tm_holdings.set_ai_paused(initial_paused)
            self._refresh_ai_badge()

            # ── v4.14.0 stage 6d: AI Mode pill ────────────────────
            # Small text-only colored pill showing current AI Mode
            # (Local / API / Hybrid). Sits left of the AI badge so
            # the order reads:
            #   [ ... action buttons | Pill | AI badge | Freshness | Clock ]
            # Color-coded per Decision 1 of the locked spec, picked
            # to be visually distinct from the chip strip's green so
            # the heartbeat semantic and the mode indicator don't
            # cross-talk. Clickable hook for the embedded assistant
            # (no-op today).
            self._ai_mode_pill = tk.Label(btn_frame, text="",
                                            bg=c['card2'],
                                            fg=c['muted'],
                                            font=self.fonts['caption'],
                                            padx=self.space['sm'],
                                            pady=self.space['xs'],
                                            cursor='hand2')
            self._ai_mode_pill.pack(side='right',
                                     padx=(0, self.space['sm']))
            try:
                # v4.14.5.14-mode-detection-collapse-2d: cloud-only — the
                # pill is a static "API" status tag now (local/hybrid modes
                # are gone). Tooltip reworded to drop the dead modes + the
                # removed "AI Mode" menu reference.
                Tooltip(self._ai_mode_pill,
                        "Tired Market runs on cloud AI providers "
                        "(no local install needed).")
            except Exception:
                pass

            def _ai_mode_pill_click(_event=None):
                # Stage 6d hook for the assistant (lands v4.14.x+).
                # No-op today.
                pass

            try:
                self._ai_mode_pill.bind(
                    '<Button-1>', _ai_mode_pill_click)
            except Exception:
                pass
            self._refresh_ai_mode_pill()
        else:
            self._ai_badge = None
            self._ai_mode_pill = None

        # ── ACTION BUTTONS ──
        # v4.10.4: All action buttons use the SECONDARY teal color since
        # they're peer-level workflow buttons (no single one is the
        # "primary" action — they all do different things). Stop uses
        # DANGER red since it's an emergency control. Utility buttons
        # (Help / Settings / Exit) collapse into a single '≡' menu on
        # the far right of the action group.
        # Buttons pack right-to-left, so the FIRST item appended ends
        # up RIGHTMOST visually. We want the visual order from left to
        # right: Recommend · Scan · Track Record · Holdings · Stop · ≡
        # That means we append in REVERSE order.

        action_buttons = []  # list of (label, cmd, color, tooltip)

        # v4.14.5.14-gui-cleanup-e: the ≡ hamburger menu was removed. Its only
        # still-needed destination — Settings — is now a direct gear (⚙) button
        # in the same (rightmost) slot, opening the Settings dialog on a single
        # click (no menu). AI Providers / Data Providers moved INTO Settings as
        # link-out sections; Help (Teacher AI will own it) and Exit (the window
        # X already runs the same graceful _on_close) were dropped. Appended
        # FIRST so it ends up rightmost.
        action_buttons.append(
            ("⚙", self._show_settings, self.btn['utility'],
             "Settings — power, display, AI & data providers")
        )

        # v4.14.6.27: in-app Maintenance / cleanup tool. Dry-run-first
        # tool that pauses the daemons, cleans (gossip removal, oplog
        # rolling, backup pile, etc.), VACUUMs the affected DBs, and
        # resumes — no app restart required. NOT bolted onto startup or
        # shutdown (those are already slow). Tooltip carries the live
        # "due" indicator computed cheaply on demand so the button is
        # honest about whether there's anything to clean.
        try:
            _maint_tip = self._maintenance_tooltip_text()
        except Exception:
            _maint_tip = ("Maintenance — review and clean accumulated "
                           "data. Dry-run first; nothing deletes "
                           "without explicit confirm.")
        action_buttons.append(
            ("🧹", self._open_maintenance_window, self.btn['utility'],
             _maint_tip)
        )

        if _AI_ENABLED and _DISCOVER_ENABLED:
            # v4.14.5.62-remove-stop-resume: the Stop/Resume toggle button was
            # removed from this block (it didn't stop the continuous queue
            # runner — the real AI scanner kept calling cloud providers after
            # "Stop", so its label misled). The continuous-queue architecture
            # has no manual start/stop; provider quota is handled by pacing +
            # per-AI enable/disable in Settings, and auto_refresh_enabled is a
            # Settings-only on/off. The "Watch" button below stays.

            # v4.14.5.14-gui-cleanup-h: "Watch" opens the dedicated Watch
            # window (the watchlist moved out of the left column into its own
            # window — same pattern as Track Record -> Performance).
            action_buttons.append(
                ("Watch", self._show_watch_window, self.btn['secondary'],
                 "Open your Watchlist — stocks you're keeping an eye on.\n"
                 "Add tickers, see each one's latest AI verdict, and expand "
                 "a card for consensus detail.")
            )

        # v4.15.0 Step 15b: Choices toolbar button removed. The "Looking for:
        # ..." summary strip below the header is the single path to the modal
        # (the whole strip is clickable). Teacher AI onboarding will reinforce
        # the click-the-strip pattern at first launch.

        if _AI_ENABLED:
            # v4.13.17: Look Up - quick AI analysis on any ticker
            action_buttons.append(
                ("Look Up", self._show_stock_lookup,
                 self.btn['secondary'],
                 "Look up any stock and get an AI analysis.\n"
                 "Type a ticker, pick a path, get a quick read.\n"
                 "Optional: run full consensus for the deep dive.")
            )
            # v4.13.22: Refresh All moved out of header. Now only
            # accessible via the ≡ menu (less prominent placement for
            # an action you take maybe once a day). The method itself
            # (_refresh_all_holdings) is still defined and callable.
            # v4.14.5.14-ai-chat-removal: the "AI Chat" toolbar button was
            # removed here (Ollama-only surface, Ollama exit Phase 2 step 1).
            # Free-form questions are served by Ctrl+` "Ask Tired Market AI".
            # v4.13.58: Holdings toolbar button HIDDEN.
            # Everything formerly in the Holdings window is now in:
            #   - Portfolio panel (main window) - holdings list, buy/sell,
            #     consensus, refresh triggers, view reasoning
            #   - Trade History button (toolbar) - closed positions + P&L
            #   - Track Record button (toolbar) - AI prediction accuracy
            #   - Scan / Scan All / Recommend / Look Up buttons
            # The HoldingsWindow code is preserved internally (still
            # callable via _show_holdings) so anything we missed can
            # easily be brought back. Once we're confident nothing's
            # missing, v4.13.59 deletes the file.
            # Uncomment the next 3 lines to restore the button:
            # action_buttons.append(
            #     ("Holdings", self._show_holdings, self.btn['secondary'],
            #      "Holdings + Signals - AI analysis of your positions"))

        if _AI_ENABLED and _DISCOVER_ENABLED:
            action_buttons.append(
                ("Track Record", self._show_track_record,
                 self.btn['secondary'],
                 "How accurate the AI's predictions have been")
            )
            # v4.13.64: Trade Log toolbar button removed. Two contextual
            # entry points replace it: the PORTFOLIO card's dollar total
            # (tm_portfolio_panel) and Track Record's REAL TRADES card
            # (tm_holdings._show_track_record) both open the same dialog
            # via self._show_trade_history. Frees a chip-strip slot.
            # v4.14.5.14-gui-cleanup-a: the "Scan" and "Scan All" toolbar
            # buttons were removed. The system is continuous-queue now
            # (Recommend daemon + event-driven sweeps), so user-initiated
            # batch scans are obsolete. The backing methods
            # (_consensus_quick_scan / _scan_all_paths) remain defined but
            # are no longer reachable from the UI; their cancel/refuse
            # state-flags are read elsewhere via getattr-safe checks, so
            # leaving them dormant is harmless.
            if _RECOMMEND_ENABLED:
                action_buttons.append(
                    ("Recommend", self._show_recommendations,
                     self.btn['secondary'],
                     "Given a budget, what should you buy?\n"
                     "Three options: ALL IN, A FEW, DIVERSIFY.\n"
                     "Built from current open BUY predictions.")
                )

        # DEV button only if marker file exists
        try:
            if (USER_DATA_DIR / ".dev_mode").exists():
                action_buttons.append(
                    ("DEV", self._show_dev_panel, self.c['purple'],
                     "Dev tools"))
        except Exception:
            pass

        # Pack with design-token sizing. v4.13.22: even tighter
        # to fit all action buttons cleanly without clipping.
        # Teacher AI MVP Session 3: capture per-label button refs so
        # tm_teacher_intercept.register_intercept can wrap their commands
        # after the loop.
        self._toolbar_buttons = {}
        for label, cmd, color, tooltip in action_buttons:
            b = tk.Button(btn_frame, text=label, bg=color, fg=c['bg'],
                          relief='flat',
                          padx=6,  # was self.space['sm'] (~8px)
                          pady=2,  # was 3px
                          font=('Segoe UI', 9, 'bold'),  # was body_bold
                          cursor='hand2',
                          command=cmd)
            b.pack(side='right', padx=1)  # was 2
            self._toolbar_buttons[label] = b
            # v4.14.5.14-ollama-purge-3b2: the right-click-Scan → Discover
            # window opener was removed. The Discover window was local-Ollama
            # only and is retired; cloud Scan (left-click) + Recommend replace
            # it. Left-click "Scan" (_consensus_quick_scan) is unchanged.
            tip_obj = None
            try:
                tip_obj = Tooltip(b, tooltip)
            except Exception:
                pass
            # v4.14.5.62-remove-stop-resume: the Stop/Resume widget-capture
            # was removed here (no Stop/Resume button exists anymore).

        # ── Teacher AI MVP Session 3: wire click intercepts ──
        # Each intercepted button gets its command wrapped to check
        # prereqs against error_recovery_playbook.json first. Failing
        # prereqs surface a contextual AI message instead of running
        # the action. Discover reuses scan's playbook entry — same
        # prereqs (AI provider + trading style).
        try:
            import tm_teacher_intercept as _tm_intercept
            _intercept_map = [
                ('Look Up', 'look_up'),
                # v4.14.5.14-gui-cleanup-a: 'Scan'/'scan' removed with the
                # Scan toolbar button (the .get() lookup below already no-ops
                # on a missing label, but drop the entry for cleanliness).
                # v4.14.5.14-ai-chat-removal: 'AI Chat'/'ai_chat' removed.
                ('Recommend', 'recommend'),
            ]
            for _btn_label, _action_id in _intercept_map:
                _btn = self._toolbar_buttons.get(_btn_label)
                if _btn is not None:
                    _tm_intercept.register_intercept(
                        _btn, _action_id, self)
            # v4.14.5.14-ollama-purge-3b2: the former 5th intercept (Discover,
            # via right-click on Scan) is gone — the Discover window was
            # retired with the Ollama exit. Only Look Up / Scan / Recommend
            # are intercepted now.
        except Exception as _e:
            try: self._log(
                f"Teacher AI intercept wiring failed: {_e}", 'amber')
            except Exception: pass

        # v4.8.3: universe source dropdown right next to Discover button.
        # Lets you pick what universe to scan WITHOUT opening Discover first.
        # Packed side='right' AFTER all buttons, so it ends up immediately
        # to the LEFT of the Discover button (rightward-packing inverts
        # v4.10.2: Universe dropdown removed. We always scan IWV (Russell
        # 3000 — the iShares holdings export currently ships ~7,200
        # positions, broader than the 3,000-name nominal index) — the
        # broadest list. The path dropdown still lets you
        # tune signal selectivity. Universe-as-filter is now a future
        # post-scan feature (e.g., "show only S&P 500 picks in Track
        # Record").
        #
        # We still run a one-time migration of old configs that had qqq
        # or vti selected so the underlying Universe object doesn't see
        # an unknown source key. After this, current_source is iwv for
        # everyone.
        if _AI_ENABLED and _DISCOVER_ENABLED:
            try:
                src_keys = list(tm_discover.Universe.SOURCES.keys())
                current_key = self.cfg.get(
                    'universe_source', tm_discover.Universe.DEFAULT_SOURCE)
                if current_key not in src_keys:
                    self._log(
                        f"Universe '{current_key}' no longer exists; "
                        f"switching to {tm_discover.Universe.DEFAULT_SOURCE}.",
                        'muted')
                    current_key = tm_discover.Universe.DEFAULT_SOURCE
                    self.cfg['universe_source'] = current_key
                    try: save_config(self.cfg)
                    except Exception: pass
                # v4.10.2: force everyone to IWV. Subset universes will
                # come back later as Track Record post-filters, not as
                # scan-time selectors. Saves the user from having to
                # care about this.
                if current_key != tm_discover.Universe.PRIMARY_SOURCE:
                    self.cfg['universe_source'] = tm_discover.Universe.PRIMARY_SOURCE
                    try: save_config(self.cfg)
                    except Exception: pass
            except Exception as e:
                self._log(f"Universe migration init failed: {e}", 'amber')

        # v4.10.3: Path dropdown removed from main header. Settings owns
        # the path choice now (radio buttons in the AI section). Removing
        # the redundant header dropdown declutters the row and removes a
        # ttk.Combobox that may have been rendering invisibly against the
        # dark theme on Windows anyway.
        # Keep the migration / config validation logic so old configs
        # don't end up with broken path values.
        if _AI_ENABLED:
            try:
                # v4.14.6.2-dropdown-fix: post-band-cleanup the valid
                # path keys are the four bands; legacy keys remap on
                # read via tm_holdings.remap_legacy_path so a persisted
                # 'aggressive' analysis_path still resolves — only
                # truly-unknown keys reset to DEFAULT_PATH.
                path_keys = ['lottery', 'band_5_10',
                             'band_10_50', 'band_50_up']
                current_path = self.cfg.get(
                    'analysis_path', tm_holdings.DEFAULT_PATH)
                _remapped = tm_holdings.remap_legacy_path(current_path)
                if _remapped != current_path and _remapped in path_keys:
                    self.cfg['analysis_path'] = _remapped
                    try: save_config(self.cfg)
                    except Exception: pass
                elif current_path not in path_keys:
                    self.cfg['analysis_path'] = tm_holdings.DEFAULT_PATH
                    try: save_config(self.cfg)
                    except Exception: pass
            except Exception as e:
                self._log(f"Path validation failed: {e}", 'amber')

        # ── v4.14.5.14a.7: Choices summary strip REMOVED ──
        # The Choices dialog is gone; user price/style intent now lives
        # in Portfolio Recommendations (trading-style + price-tier
        # filters). No strip is built.

        # ── Portfolio Ticker bar (v4.13.14) ──
        # Thin strip showing per-share price + day change for every
        # tradable holding. Refreshes every 60 seconds.
        try:
            self._build_portfolio_ticker(self.root)
        except Exception as _e:
            try: self._log(f"Ticker build failed: {_e}", 'amber')
            except Exception: pass

        # ── Main body — Canvas-wrapped DRAGGABLE PanedWindow ──
        # v4.15.0 Teacher AI MVP Session 1: the content area below the
        # ticker bar is now a tk.Canvas hosting the PanedWindow as a
        # single canvas item. The canvas is the unified drawing surface
        # Teacher AI will render on in later sessions (intercept bubbles,
        # reserved-zone surfaces, corner indicator). Today it hosts only
        # the PanedWindow — visually identical to pre-migration.
        #
        # Why a Canvas: lets AI surfaces share the same drawing area as
        # the regular UI without an overlay window or transparency hack.
        # See design/teacher_ai_mvp.md "Canvas as main window".
        self.content_canvas = tk.Canvas(
            self.root, bg=c['bg'],
            highlightthickness=0, borderwidth=0)
        self.content_canvas.pack(side='top', fill='both', expand=True,
                                  padx=10, pady=10)
        # Teacher AI MVP: attach the App so tm_teacher_ai can read the live
        # theme (self.c) + fonts instead of falling back to defaults.
        self.content_canvas._teacher_ai_app = self

        # PanedWindow parented to the canvas. It becomes a canvas item
        # via create_window below.
        body = tk.PanedWindow(self.content_canvas, orient='horizontal',
                                sashrelief='raised', sashwidth=6,
                                bg=c['bg'], borderwidth=0)

        # Left panel: portfolio. v4.14.5.14-gui-cleanup-h: the WATCHLIST moved
        # OUT of the left column into a dedicated Watch window (the "Watch"
        # toolbar button), so the left column is back to just the Portfolio
        # panel (no holder split). PortfolioPanel owns this `left` frame again.
        left = tk.Frame(body, bg=c['card'])
        body.add(left, minsize=380)
        self._build_portfolio_summary(left)

        # Right panel: activity log
        right = tk.Frame(body, bg=c['card'])
        body.add(right, minsize=300)
        self._build_activity_log(right)

        # Embed the PanedWindow as a canvas item. Initial size of (1, 1)
        # gets corrected by the first <Configure> event the canvas fires
        # once it has its real packed dimensions; we also fire the handler
        # once manually below after update_idletasks() to avoid a brief
        # zero-width flash during startup.
        self._body_canvas_item = self.content_canvas.create_window(
            0, 0, anchor='nw', window=body, width=1, height=1)

        # Save reference for the sash position handler
        self._main_paned = body

        # Teacher AI MVP Session 5: persistent corner indicator pinned to
        # the top-right of the content canvas. Always visible, clickable
        # to summon AI (same effect as Ctrl+`). Built BEFORE binding
        # <Configure> so the handler can reposition both the body item
        # and the corner indicator on every resize.
        _CORNER_PAD = 16
        try:
            corner = tk.Frame(self.content_canvas, bg=c['bg'])
            corner_lbl = tk.Label(
                corner,
                text="Ask Tired Market AI",
                bg=c['bg'], fg=c['accent'],
                font=self.fonts.get('caption', ('Segoe UI', 8)),
                cursor='hand2',
                padx=6, pady=2,
            )
            corner_lbl.pack(side='right')
            corner.bind('<Button-1>',
                        lambda _e: self._summon_teacher_ai())
            corner_lbl.bind('<Button-1>',
                            lambda _e: self._summon_teacher_ai())
            # Created AFTER _body_canvas_item so it draws on top of the
            # PanedWindow's top-right corner. Initial x uses current
            # canvas width; the Configure handler keeps it pinned on resize.
            self._teacher_ai_corner_frame = corner
            self._teacher_ai_corner_item = self.content_canvas.create_window(
                _CORNER_PAD, _CORNER_PAD, anchor='ne', window=corner)
        except Exception:
            self._teacher_ai_corner_item = None
            self._teacher_ai_corner_frame = None

        # Resize the embedded PanedWindow whenever the canvas resizes;
        # also reposition the corner indicator to stay in the top-right,
        # and pin scrollregion to the visible viewport so embedded
        # focusable widgets (like the show_input Entry) don't trigger
        # auto-scroll-to-focus and drag surfaces off-screen.
        def _on_content_canvas_configure(event):
            try:
                if getattr(self, '_body_canvas_item', None) is not None:
                    self.content_canvas.itemconfig(
                        self._body_canvas_item,
                        width=event.width, height=event.height)
            except Exception:
                pass
            try:
                item = getattr(self, '_teacher_ai_corner_item', None)
                if item is not None:
                    self.content_canvas.coords(
                        item, event.width - _CORNER_PAD, _CORNER_PAD)
            except Exception:
                pass
            try:
                self.content_canvas.configure(
                    scrollregion=(0, 0, event.width, event.height))
            except Exception:
                pass
        self.content_canvas.bind(
            '<Configure>', _on_content_canvas_configure)

        # Teacher AI MVP Session 5: global keyboard shortcuts.
        #   Ctrl+Shift+` / Ctrl+~ → toggle tutorial mode
        # bind_all so they fire from anywhere in the app; the handler
        # internally skips if focus is in a text widget so it doesn't
        # interfere with users typing tickers.
        #
        # v4.14.5.30-frontdoor-fixes: the Ctrl+` SUMMON binding was REMOVED —
        # it wasn't firing on Mike's hardware, and the front door is now the
        # visible "Ask Tired Market AI" corner link (more discoverable for a
        # beginner than a hotkey). The link calls _summon_teacher_ai directly.
        try:
            self.root.bind_all(
                '<Control-Shift-grave>',
                self._toggle_tutorial_mode, add='+')
            # Some keyboard layouts report the shifted backtick as the
            # tilde keysym instead. Bind both so the toggle works
            # regardless of which form Tk emits on Mike's hardware.
            self.root.bind_all(
                '<Control-asciitilde>',
                self._toggle_tutorial_mode, add='+')
        except Exception:
            pass

        # Fire one initial sizing pass so the PanedWindow gets a real
        # width before _restore_sash() runs in +100ms. Without this the
        # canvas item stays at 1x1 until Tk's first natural Configure,
        # and the sash-restore math reads winfo_width()=1.
        try:
            self.content_canvas.update_idletasks()
            cw = self.content_canvas.winfo_width()
            ch = self.content_canvas.winfo_height()
            if cw > 1 and ch > 1:
                self.content_canvas.itemconfig(
                    self._body_canvas_item, width=cw, height=ch)
                if self._teacher_ai_corner_item is not None:
                    self.content_canvas.coords(
                        self._teacher_ai_corner_item,
                        cw - _CORNER_PAD, _CORNER_PAD)
                self.content_canvas.configure(
                    scrollregion=(0, 0, cw, ch))
        except Exception:
            pass

        # Restore sash position from config (default ~55% portfolio)
        def _restore_sash():
            try:
                saved = self.cfg.get('main_sash_position')
                if saved and saved > 50:
                    body.sash_place(0, int(saved), 0)
                else:
                    # Default: ~55% to portfolio
                    width = body.winfo_width()
                    if width > 100:
                        body.sash_place(0, int(width * 0.55), 0)
            except Exception:
                pass
        # Wait for the window to actually have a width
        self.root.after(100, _restore_sash)

        # Save sash position when user drags it
        def _on_sash_release(_e=None):
            try:
                pos = body.sash_coord(0)[0]
                if pos > 50:
                    self.cfg['main_sash_position'] = int(pos)
                    # Persist to disk
                    if hasattr(self, '_save_config'):
                        try: self._save_config()
                        except Exception: pass
            except Exception:
                pass
        body.bind('<ButtonRelease-1>', _on_sash_release)

        # ── Bottom bar: short disclaimer + version ──
        bottom = tk.Frame(self.root, bg=c['bg'], height=24)
        bottom.pack(side='bottom', fill='x')
        bottom.pack_propagate(False)
        tk.Label(bottom,
                 text="For educational and personal use. AI analysis is not financial advice.",
                 bg=c['bg'], fg=c['dim'], font=('Segoe UI', 8)
                 ).pack(side='left', padx=10)
        tk.Label(bottom, text=f"v{APP_VERSION}", bg=c['bg'], fg=c['dim'],
                 font=('Segoe UI', 8)).pack(side='right', padx=10)

        # v4.13.62: center-screen loading overlay covers the whole
        # window during startup, blocks accidental clicks, and clears
        # when _startup_complete flips. Disclaimer Toplevel still
        # appears above because Toplevels stack above place()-managed
        # frames in their parent. Tiny header indicator stays as backup.
        # v4.13.63.2: overlay is now built BEFORE _build() runs (see
        # the comment block in __init__) so the user sees it first
        # instead of watching the main UI paint widget-by-widget.
        # Nothing is constructed here anymore — leaving the comment
        # only so the next reader knows where to look.

        # ── Teacher AI MVP Session 4: post-build splash branching ──
        # Three states:
        #   (1) Returning user (first_launch_complete=True) — close splash silently.
        #   (2) Disclaimer done but wizard interrupted — close splash, fire wizard.
        #   (3) Fresh user — transition splash to disclaimer; on ack, close + fire wizard.
        # Session 4 fix: deferred to give the splash (itself deferred via
        # root.after(0) from __init__) time to map + paint before we
        # decide whether to transition, close, or fire the wizard. 300ms
        # is the safe minimum on Tk for a transient Toplevel to actually
        # appear on screen post-deiconify.
        def _deferred_branch():
            try:
                self._teacher_ai_splash_branch()
            except Exception as _e:
                try: self._log(
                    f"Teacher AI splash branch failed: {_e}", 'amber')
                except Exception: pass
                # Defensive: ensure the splash doesn't strand the user.
                try:
                    import tm_teacher_splash as _tm_splash
                    _tm_splash.close_splash(getattr(self, '_splash', None))
                except Exception:
                    pass
                # And reveal the main window — root has been withdrawn
                # since main() and the splash flow normally owns the
                # deiconify call.
                try: self.root.deiconify()
                except Exception: pass
        try:
            self.root.after(300, _deferred_branch)
        except Exception:
            pass

    def _teacher_ai_show_splash(self):
        """Create the Teacher AI splash window. Scheduled via root.after(0)
        from __init__ so it runs after main() calls root.deiconify(). A
        transient Toplevel created while root is withdrawn never gets
        mapped to the screen — Tk holds it in an unmapped state and
        deiconify on root doesn't propagate. Deferring fixes it."""
        try:
            import tm_teacher_splash as _tm_splash
            self._splash = _tm_splash.show_splash(self.root)
        except Exception as e:
            self._splash = None
            try:
                self._log(
                    f"Teacher AI splash failed to load: {e}", 'amber')
            except Exception:
                pass

    def _teacher_ai_splash_branch(self):
        """End-of-_build() decision: close splash silently, fire wizard,
        or hand off to disclaimer. See Session 4 design doc.

        Session 4 fix: this method is deferred via root.after(300, ...)
        from the end of _build() so the splash (also deferred) has time
        to map + paint before we decide what to do with it."""
        import tm_teacher_splash as _tm_splash
        splash = getattr(self, '_splash', None)

        if splash is None:
            # Two reasons splash can be None here:
            #   (a) returning user — __init__ deliberately skipped it
            #       (Session 6 polish; disclaimer marker already present).
            #   (b) splash construction raised — recovery path.
            # Reveal the main window either way.
            try: self.root.deiconify()
            except Exception: pass
            # v4.14.5.40-live-gate: even a returning, disclaimer-accepted user
            # must pass the LIVE gate. __init__ skips the splash once the
            # disclaimer marker exists, so this is the OTHER bypass the flag
            # path had. If there's no working AI provider, route straight to
            # the connect wizard (disclaimer already done) rather than dropping
            # them into an app that can't actually analyse anything.
            if _has_accepted_disclaimer():
                try:
                    import tm_teacher_intercept as _tm_ic_gate
                    _no_working = not _tm_ic_gate.has_working_provider(self)
                except Exception:
                    _no_working = False
                if _no_working:
                    try:
                        self._log(
                            "Teacher AI: returning user with no working AI — "
                            "opening setup wizard", 'accent')
                    except Exception:
                        pass
                    try:
                        self.root.after(500, self._start_setup_wizard)
                    except Exception:
                        pass
                return
            # case (b): splash failed AND no disclaimer yet — can't run the
            # splash-borne disclaimer flow; reveal app (next launch re-asks).
            try:
                self._log(
                    "Teacher AI splash not available; "
                    "skipping disclaimer/wizard flow",
                    'amber')
            except Exception:
                pass
            return

        # v4.14.5.40-live-gate: the entry gate is now the LIVE working-provider
        # check, NOT the one-time teacher_ai_first_launch_complete flag (a
        # restart bypassed that flag — it only ever meant "saw the wizard").
        # >=1 working provider (enabled + health-usable) -> straight into the
        # app; otherwise fall through to setup, every launch, no bypass.
        import tm_teacher_intercept as _tm_ic_gate
        # v4.14.5.62-scheduler-disclaimer-gate: a working provider lets us skip
        # the setup wizard, but it must NOT skip the DISCLAIMER. The disclaimer
        # marker (.disclaimer_accepted) is what `_start_scheduler` gates on, and
        # it's written ONLY when the disclaimer is shown + accepted (on_ack
        # below). Previously this branch silent-closed and returned whenever a
        # provider was present — so a new/copied folder (working provider, no
        # marker) skipped the disclaimer, never wrote the marker, and the
        # background scheduler stayed permanently gated ("Active-watching OFF").
        # Now we only silent-close when the marker is ALSO present; a missing
        # marker falls through to the disclaimer flow regardless of provider
        # state (preserving the copied-folder re-acceptance design + consent).
        if _tm_ic_gate.has_working_provider(self) and _has_accepted_disclaimer():
            try:
                self._log(
                    "Teacher AI: working AI provider present, "
                    "closing splash silently", 'muted')
            except Exception:
                pass
            _tm_splash.close_splash(splash)
            try: self.root.deiconify()
            except Exception: pass
            return

        # Disclaimer marker file is the canonical "user has acknowledged"
        # signal — 6 background workers poll it. We respect it here too.
        if _has_accepted_disclaimer():
            try:
                self._log(
                    "Teacher AI: disclaimer acknowledged, "
                    "firing setup wizard", 'accent')
            except Exception:
                pass
            self.cfg['teacher_ai_disclaimer_acknowledged'] = True
            try: save_config(self.cfg)
            except Exception: pass
            _tm_splash.close_splash(splash)
            try: self.root.deiconify()
            except Exception: pass
            try:
                self.root.after(500, self._start_setup_wizard)
            except Exception:
                pass
            return

        # Fresh user — transition splash to disclaimer.
        try:
            self._log(
                "Teacher AI: fresh user, transitioning splash "
                "to disclaimer", 'accent')
        except Exception:
            pass
        disclaimer_text = (
            "I'm a tool that points you toward stocks I think are "
            "likely to go up. I'll show you my reasoning. But I'm wrong "
            "sometimes — every analysis tool is.\n\n"
            "Use my analysis as one input among several. Do your own "
            "research. Make your own decisions. I'll help you think; "
            "I won't think for you."
        )

        def on_ack():
            # Write the legacy marker file so the 6 background pollers
            # don't stall.
            try:
                _record_disclaimer_acceptance()
            except Exception:
                pass
            try:
                self.cfg['teacher_ai_disclaimer_acknowledged'] = True
                save_config(self.cfg)
            except Exception:
                pass
            try:
                _tm_splash.close_splash(splash)
            except Exception:
                pass
            # Reveal the main window now that the user has acknowledged
            # the disclaimer. root has been withdrawn since main().
            try:
                self.root.deiconify()
            except Exception:
                pass
            # v4.14.5.62-scheduler-disclaimer-gate: only run the first-launch
            # setup wizard when there's NO working provider yet. A user who
            # already has a working provider (e.g. a new/copied folder shipped
            # with keys) reached the disclaimer via the gate above and just
            # accepted it — send them straight into the app, not the "set up
            # your first AI" wizard they don't need. The normal fresh user
            # (no provider) still gets the wizard unchanged.
            try:
                if not _tm_ic_gate.has_working_provider(self):
                    self.root.after(500, self._start_setup_wizard)
            except Exception:
                pass

        try:
            _tm_splash.transition_splash_to_disclaimer(
                splash, disclaimer_text, on_ack)
        except Exception as e:
            # If transition fails, log the cause + close the splash
            # defensively so the user isn't trapped. The legacy marker
            # file stays absent; next launch will re-ask.
            try:
                self._log(
                    f"Teacher AI disclaimer transition failed: {e}",
                    'amber')
            except Exception:
                pass
            try:
                _tm_splash.close_splash(splash)
            except Exception:
                pass
            # Reveal the main window — the user can't acknowledge a
            # disclaimer that never appeared, so don't trap them with
            # an invisible app.
            try: self.root.deiconify()
            except Exception: pass

    def _start_setup_wizard(self):
        """Teacher AI MVP Session 4: three-step first-launch wizard.
        Each step is a tm_teacher_ai.show_center surface on the main
        canvas. Final step sets teacher_ai_first_launch_complete=True."""
        import tm_teacher_ai as _tm_ai

        canvas = getattr(self, 'content_canvas', None)
        if canvas is None:
            return

        def _has_working():
            # v4.14.5.40-live-gate: the wizard's own truth source. STRICT on
            # error (treat as not-working) so setup can never complete empty.
            try:
                import tm_teacher_intercept as _ic
                return _ic.has_working_provider(self)
            except Exception:
                return False

        def _finish():
            # v4.14.5.40-live-gate: setup completes ONLY with a working
            # provider. _step2 is reached only once connected, but guard here
            # too — the user could delete the key between connect and "Got it".
            # Without a working AI there is nothing to enter the app for.
            if not _has_working():
                _step1()
                return
            # Legacy flag kept for back-compat/telemetry; it no longer GATES
            # entry (the live working-provider check does). Harmless to set.
            try:
                self.cfg['teacher_ai_first_launch_complete'] = True
                save_config(self.cfg)
            except Exception:
                pass
            # v4.14.5.36-proactive-guidance: setup is handled — now run the
            # first proactive guidance moment: introduce the always-available
            # "Ask Tired Market AI" control by pointing at it. Delayed so the
            # step-2 surface finishes sliding out first (one surface/canvas).
            try:
                self.root.after(700, self._fire_ask_ai_feature_intro)
            except Exception:
                pass

        # v4.14.5.33-firstrun-honesty: the wizard is now TWO honest steps.
        #  - The old fill-mode offer step (slow / all-at-once / donor) is
        #    REMOVED: those modes are retired; the app just auto-fills fast
        #    with a status indicator and is usable after startup. No picker.
        #  - Step 2 is now honest about the background fill + analyzing-once-
        #    connected (it previously claimed no setup was needed, which
        #    contradicted Step 1 and was false in the no-AI state).
        #  - Step 1 LEADS instead of asking, removes the old skip option (a
        #    provider is the required minimum to enter), and offers Exit so
        #    the user is never trapped.

        def _step2():
            # Reached ONLY once a working provider exists (v4.14.5.40-live-
            # gate), so the copy is honest about being connected — no longer
            # "while you connect".
            msg = (
                "You're connected — nice. I'm already loading market data in "
                "the background (you'll see the progress up top), and I'll "
                "start analyzing as soon as it's ready."
            )
            _tm_ai.show_center(
                canvas, msg,
                actions=[
                    {"label": "Got it", "callback": _finish},
                ])

        def _step1():
            msg = (
                "Let me get you connected — I need at least one AI provider "
                "to work (and I run better with a few). Groq is the quickest: "
                "free, about a minute, just an email. Let's set up your first "
                "one."
            )

            def _await_connect():
                # v4.14.5.40-live-gate: advance ONLY when a working provider
                # actually exists — never on a blind timer. While the
                # providers window is open we keep waiting; if it closes with
                # still no working provider, return to this required step (the
                # user cannot "Got it" their way in empty).
                if _has_working():
                    _step2()
                    return
                win = getattr(self, '_apw_window', None)
                try:
                    still_open = bool(win is not None and win.winfo_exists())
                except Exception:
                    still_open = False
                if still_open:
                    try:
                        self.root.after(600, _await_connect)
                    except Exception:
                        pass
                else:
                    # window closed, still no working provider -> re-steer
                    _step1()

            def _open_providers():
                try:
                    self._show_api_providers()
                except Exception:
                    pass
                try:
                    self.root.after(600, _await_connect)
                except Exception:
                    _await_connect()

            def _exit_app():
                # Never trap the user: connecting a provider is required to
                # enter, but Exit always closes the app cleanly (the normal
                # WM_DELETE_WINDOW path). It is the ONLY way past setup without
                # a working provider — and it quits rather than entering a
                # broken app.
                try:
                    self._on_close()
                except Exception:
                    try:
                        self.root.quit()
                    except Exception:
                        pass

            _tm_ai.show_center(
                canvas, msg,
                actions=[
                    {"label": "Set up my first AI",
                     "callback": _open_providers},
                    {"label": "Exit app", "callback": _exit_app},
                ])

        _step1()

    def _fire_ask_ai_feature_intro(self):
        """v4.14.5.36-proactive-guidance (slice 1): the first proactive
        guidance moment. Introduce the "Ask Tired Market AI" corner control
        by docking a one-line intro NEXT TO it (arrow points at it, via the
        now-wired show_near path). Fires once ever — the persistent
        teacher_ai_suppressions marker 'feature_intro:ask_ai' gates it, so
        subsequent launches stay silent; tutorial mode re-fires it. All the
        once-ever / cooldown / dedupe / tutorial-bypass logic lives in
        tm_teacher_intercept.emit_feature_intro — this just names the moment
        and hands it the control to point at."""
        try:
            target = getattr(self, '_teacher_ai_corner_frame', None)
            import tm_teacher_intercept as _tm_ic
            _tm_ic.emit_feature_intro(
                'feature_intro_ask_ai', 'feature_intro:ask_ai',
                app=self, target_widget=target)
        except Exception:
            pass

    def _fire_model_rotation_feature_intro(self):
        """v4.14.5.62-autoenable-rotation: one-time coaching line, surfaced via
        the existing emit_feature_intro seam, telling the user the program
        auto-enabled model rotation (the program decided + acted; the AI only
        EXPLAINS — 'program knows, AI gates'). Self-gates: fires only when
        rotation AUTO-enabled this launch (not when off / explicitly set), only
        after the disclaimer is accepted, and only once ever (the
        'feature_intro:model_rotation' suppression marker in emit_feature_intro).
        Tutorial mode re-fires it like the other intros."""
        try:
            if not getattr(self, '_model_rotation_auto_enabled', False):
                return
            if not _has_accepted_disclaimer():
                return
            import tm_teacher_intercept as _tm_ic
            _tm_ic.emit_feature_intro(
                'feature_intro_model_rotation',
                'feature_intro:model_rotation', app=self)
        except Exception:
            pass

    def _fire_layer3_drop_feature_intro(self):
        """v4.14.5.62-layer3-replace-default: one-time plain-language note,
        surfaced via the existing emit_feature_intro seam, the first time the
        Layer-3 daemon DROPS a validation-contradicted pick — so a pick
        disappearing isn't confusing. The program (Layer-3) made the drop; the
        AI only EXPLAINS it ('program decides, AI explains'). Called from the
        daemon thread on a drop; emit_feature_intro is thread-safe (marshals to
        the Tk main thread) and once-ever (the 'feature_intro:layer3_drop'
        suppression marker), so subsequent drops stay silent. The specific
        ticker is in the activity log ('[layer3] dropped …')."""
        try:
            if not _has_accepted_disclaimer():
                return
            import tm_teacher_intercept as _tm_ic
            _tm_ic.emit_feature_intro(
                'feature_intro_layer3_drop',
                'feature_intro:layer3_drop', app=self)
        except Exception:
            pass

    # ── v4.14.5.51-recs-gatekeeping: per-path "displayable picks" predicate ──
    # The Recommend panel shows ONE trading style (path) at a time. So both the
    # 'recommendations ready' notification AND the access gates key off PER-PATH
    # displayable picks (a path with >=1 recommend_cache displayed-tier row =
    # the panel would render content for it), NOT the global total — that's what
    # made the notification fire while the user's panel style was empty.
    def _recs_populated_paths(self) -> set:
        """Set of paths whose recommend_cache displayed tier has >=1 row (the
        panel would render content for them). Cheap; never raises."""
        try:
            import tm_queue_runner as _qr
            counts = _qr._recommend_cache_counts(self) or {}
        except Exception:
            return set()
        out = set()
        for p, dv in counts.items():
            try:
                d = dv[0] if isinstance(dv, (tuple, list)) else 0
                if d and int(d) > 0:
                    out.add(p)
            except Exception:
                continue
        return out

    def _recs_path_has_picks(self, path) -> bool:
        try:
            return path in self._recs_populated_paths()
        except Exception:
            return False

    def _recs_best_populated_path(self):
        """Highest-yield populated path (the A2 priority order), else any
        populated path, else None."""
        try:
            pop = self._recs_populated_paths()
        except Exception:
            return None
        # v4.14.6.16-dead-path-purge (2026-06-12): legacy priority
        # tuple trimmed from the 5 pre-v4.14.6.1 time-paths to the 4
        # live price bands. Order is highest-priced -> speculative,
        # matching the Trading-style dropdown's ordering. The legacy
        # keys (aggressive/moderate/slow_safe/penny_lottery) never
        # appear in `pop` post-purge (the stale recommend_cache rows
        # under those keys were deleted), so the old tuple would
        # have just iterated dead values anyway.
        for p in ('band_50_up', 'band_10_50', 'band_5_10', 'lottery'):
            if p in pop:
                return p
        return next(iter(pop), None) if pop else None

    # ── v4.14.5.53-recs-gate-filteraware: FILTER-AWARE gate predicate ──
    # The rows-based _recs_populated_paths above answers "does the path have
    # recommend_cache rows?". The gates ALSO need "would the panel RENDER >=1
    # pick for this path under the user's CURRENT price/conviction filter?" —
    # otherwise a style with rows that the user's filter hides looks populated
    # to the gate but renders empty. These read the SAME persisted per-path
    # filter (cfg['recommend_filters'][path]) and the SAME shared predicate
    # (_reco_pick_user_filter_reason) the panel's _hard_filter uses, so the gate
    # and the rendered "X of N survive filters" can't drift. (Consensus is the
    # system gate — render-only — so the gate intentionally covers only the
    # USER-clearable filters: it must never block the user's own filter choice,
    # only stop misrepresenting a filtered-empty style as populated.)
    def _recs_active_cash(self):
        """v4.14.5.54-recs-gate-budgetaware: the budget the GATES judge against —
        the user's last Recommend cash, or None ("Any") if they've never set
        one. None == no budget constraint, so a brand-new user is never blocked
        against a number they never chose. Stored as the literal 'Any' (or
        absent) for new users; a real number once they set one."""
        try:
            v = self.cfg.get('recommend_last_cash', None)
            if v is None:
                return None
            if isinstance(v, str) and v.strip().lower() in ('', 'any'):
                return None
            return float(v)
        except Exception:
            return None

    def _recs_path_visible_pick_count(self, path, apply_budget=True) -> int:
        """# of `path`'s recommend_cache picks surviving the user's current
        price/conviction filter AND (when apply_budget) the active budget.
        Fail-OPEN (unfiltered count) on any fault so a glitch never wrongly
        blocks the user. apply_budget=False isolates the price/conviction
        result so callers can tell budget-hidden from filter-hidden."""
        try:
            picks = self._read_recommend_cache_picks(path)
        except Exception:
            return 0
        if not picks:
            return 0
        try:
            flt = (self.cfg.get('recommend_filters', {}) or {}).get(path, {}) or {}
            pmin = flt.get('price_min', 0)
            pmax = flt.get('price_max', 0)
            conv = flt.get('conviction', 'all')
            cash = self._recs_active_cash() if apply_budget else None
            return sum(1 for p in picks
                       if _reco_pick_user_filter_reason(
                           p, pmin, pmax, conv, cash) is None)
        except Exception:
            return len(picks)  # fail-open: a filter fault must not block

    def _recs_path_has_visible_picks(self, path) -> bool:
        try:
            return self._recs_path_visible_pick_count(path) > 0
        except Exception:
            return self._recs_path_has_picks(path)

    def _recs_visible_tickers(self, apply_budget=True):
        """v4.14.5.54: the SET of DISTINCT tickers that survive the active
        price/conviction filter (and, when apply_budget, the budget) across all
        populated styles. Deduped by ticker so one BUY smeared across two styles
        (e.g. the same pick on aggressive AND moderate) counts ONCE, not twice —
        the false-fire the popup gate hit. Returns None to signal a fault (the
        caller should fail-open to the older populated-paths check)."""
        try:
            cash = self._recs_active_cash() if apply_budget else None
            filters = self.cfg.get('recommend_filters', {}) or {}
            out = set()
            for path in self._recs_populated_paths():
                flt = filters.get(path, {}) or {}
                pmin = flt.get('price_min', 0)
                pmax = flt.get('price_max', 0)
                conv = flt.get('conviction', 'all')
                for p in (self._read_recommend_cache_picks(path) or []):
                    if _reco_pick_user_filter_reason(
                            p, pmin, pmax, conv, cash) is None:
                        tkr = (p.get('ticker') or '').upper()
                        if tkr:
                            out.add(tkr)
            return out
        except Exception:
            return None

    def _recs_cheapest_visible_pick(self):
        """v4.14.5.54: (ticker, price) of the CHEAPEST pick that passes the
        price/conviction filter (ignoring budget) across styles, or None. Used
        to name the move in the budget-block message ("the cheapest BUY I have
        is X at $N") so the steer points somewhere concrete. Never raises."""
        try:
            filters = self.cfg.get('recommend_filters', {}) or {}
            best = None
            for path in self._recs_populated_paths():
                flt = filters.get(path, {}) or {}
                pmin = flt.get('price_min', 0)
                pmax = flt.get('price_max', 0)
                conv = flt.get('conviction', 'all')
                for p in (self._read_recommend_cache_picks(path) or []):
                    if _reco_pick_user_filter_reason(
                            p, pmin, pmax, conv, None) is not None:
                        continue
                    # v4.14.5.54a: raw plog recs carry no 'entry' — resolve the
                    # real price the same way the predicate does.
                    price = _reco_resolve_entry_price(p)
                    tkr = (p.get('ticker') or '').upper()
                    if price > 0 and tkr and (best is None or price < best[1]):
                        best = (tkr, price)
            return best
        except Exception:
            return None

    def _emit_recs_budget_block(self):
        """v4.14.5.54: block-and-explain when the user's set budget fits NO pick.
        Names the cheapest actual BUY + its price and the move (raise to about
        that, or switch to Any). In-voice via the playbook entry; context fills
        the numbers. Dedupe key varies by budget so a re-attempt at a DIFFERENT
        budget re-shows. Never raises."""
        try:
            import tm_teacher_intercept as _tm_ic
            cheapest = self._recs_cheapest_visible_pick()
            cash = self._recs_active_cash()
            ctx = {
                # the popup dedupe is keyed on 'provider'; reuse it to carry the
                # budget so a new budget re-shows the steer (same budget = shown
                # once, which is fine — they just saw it).
                'provider': (f"{cash:.0f}" if cash is not None else 'any'),
                'budget': (f"{cash:.0f}" if cash is not None else 'Any'),
            }
            if cheapest:
                ctx['cheapest_ticker'] = cheapest[0]
                ctx['cheapest_price'] = f"{cheapest[1]:.2f}"
            else:
                ctx['cheapest_ticker'] = 'the cheapest pick'
                ctx['cheapest_price'] = '—'
            _tm_ic.emit_system_event(
                'recs_gate_budget_blocks_all', app=self, context=ctx)
        except Exception:
            pass

    def _recs_visible_paths(self) -> set:
        try:
            return {p for p in self._recs_populated_paths()
                    if self._recs_path_has_visible_picks(p)}
        except Exception:
            return set()

    def _recs_best_visible_path(self):
        try:
            # v4.14.6.16-dead-path-purge: same legacy-tuple trim as
            # _recs_best_populated_path. Live band keys only.
            for p in ('band_50_up', 'band_10_50', 'band_5_10', 'lottery'):
                if self._recs_path_has_visible_picks(p):
                    return p
            vis = self._recs_visible_paths()
            return next(iter(vis), None) if vis else None
        except Exception:
            return None

    def _fire_recs_ready_feature_intro(self, *_ignored):
        """v4.14.5.37-recs-ready / v4.14.5.51 / v4.14.5.54: the first
        STATE-TRANSITION moment. Fires once-ever when recommendations are
        genuinely ready to LOOK AT — i.e. at least TWO DISTINCT picks survive
        the user's active filters AND budget — and an AI is connected. Docks a
        'ready, want to look?' bubble by the Recommend button (Show me / Not
        now). Main-thread only.

        v4.14.5.54-recs-gate-budgetaware: gate on >=2 distinct SURVIVING TICKERS,
        not >=2 populated styles. The old populated-styles count false-fired
        because a single BUY (e.g. ADBE@$265) lands on two styles (shared pool)
        and read as "2". Counting distinct tickers that pass the active filters
        + budget (deduped) means a lone pick the user can't act on — or can't
        afford — no longer trips the popup. At "Any" budget (new user) every
        priced BUY still counts, so the popup fires the moment there's a real
        spread to look at."""
        # v4.14.5.54: >=2 distinct filter+budget survivors (deduped by ticker),
        # not >=2 populated styles. Fail-open to the prior populated-paths check.
        try:
            _vis = self._recs_visible_tickers(apply_budget=True)
            if _vis is None:
                if len(self._recs_populated_paths()) < 2:
                    return
            elif len(_vis) < 2:
                return  # not >=2 distinct actionable picks yet
        except Exception:
            return
        # Require an AI: don't announce 'ready' when nothing analyzed it.
        try:
            if not self._load_enabled_api_providers():
                return
        except Exception:
            return
        try:
            target = None
            tb = getattr(self, '_toolbar_buttons', None)
            if isinstance(tb, dict):
                target = tb.get('Recommend')
            import tm_teacher_intercept as _tm_ic
            _tm_ic.emit_feature_intro(
                'feature_intro_recs_ready', 'feature_intro:recs_ready',
                app=self, target_widget=target,
                actions=[
                    {'label': 'Show me', 'action': 'open_recommendations'},
                    {'label': 'Not now', 'action': 'dismiss'},
                ])
        except Exception:
            pass

    # ── Teacher AI guided-add (v4.14.5.39): first-key how-to + connect confirm ──

    def _fire_groq_howto_guide(self) -> bool:
        """Show the first-run Groq how-to on the MAIN screen (the providers
        screen is a separate Toplevel the overlay can't draw on — Option B:
        deliver the steps on the main canvas as reference). Fires only when
        the user has NO provider yet (the setup case) and only once ever
        (persistent marker; tutorial mode re-fires). Returns True if a
        surface was emitted (so the caller can let it show before opening
        the providers window)."""
        try:
            if self._load_enabled_api_providers():
                return False  # already has a provider — not the setup case
        except Exception:
            return False
        try:
            import tm_teacher_intercept as _tm_ic
            # Respect the once-ever marker (is_suppressed bypasses it under
            # tutorial mode, so tutorial mode re-fires).
            if _tm_ic.is_suppressed('feature_intro:groq_howto', self):
                return False
            _tm_ic.emit_feature_intro(
                'feature_intro_groq_howto', 'feature_intro:groq_howto',
                app=self, target_widget=None)  # center on the main canvas
            return True
        except Exception:
            return False

    def _open_providers_with_guide(self):
        """Demand-steer / 'Set up my first AI' entry point: deliver the Groq
        how-to on the main screen first (no-provider, once), then open the
        AI Providers window. When the how-to actually shows, briefly delay
        the window so the user reads it before it's covered; otherwise open
        immediately."""
        guided = False
        try:
            guided = self._fire_groq_howto_guide()
        except Exception:
            guided = False
        delay = 900 if guided else 0
        try:
            self.root.after(delay, self._show_api_providers)
        except Exception:
            try:
                self._show_api_providers()
            except Exception:
                pass

    def _maybe_fire_connected_confirm(self):
        """Fire the 'you're connected, now I can work' payoff once, when the
        user connects their FIRST provider during a providers-window session
        that started with zero enabled providers (the 0->>=1 transition).
        Renders on the main canvas near the Recommend button (visible when
        they return). Once ever; tutorial mode re-fires. Honest: at 1
        provider the app works (single-voice) — the copy never claims
        'consensus' and never claims faster data fill."""
        try:
            if not getattr(self, '_apw_started_empty', False):
                return  # window opened with a provider already — not a first-connect
        except Exception:
            return
        try:
            if not self._load_enabled_api_providers():
                return  # still no enabled provider — nothing connected yet
        except Exception:
            return
        try:
            target = None
            tb = getattr(self, '_toolbar_buttons', None)
            if isinstance(tb, dict):
                target = tb.get('Recommend')
            import tm_teacher_intercept as _tm_ic
            _tm_ic.emit_feature_intro(
                'feature_intro_connected', 'feature_intro:connected',
                app=self, target_widget=target)
        except Exception:
            pass

    # ── Teacher AI MVP Session 5: summon + tutorial-mode toggle ──

    def _teacher_ai_focus_in_text_widget(self) -> bool:
        """True if the keyboard focus is currently inside a text-input
        widget (Entry / Text / Spinbox / ttk.Entry / ttk.Combobox edit
        field). Used by the keyboard-shortcut handlers to avoid stealing
        keystrokes from someone typing a ticker.
        """
        try:
            import tkinter.ttk as _ttk
            focused = self.root.focus_get()
        except Exception:
            return False
        if focused is None:
            return False
        try:
            if isinstance(focused, (tk.Entry, tk.Text, tk.Spinbox)):
                return True
            if isinstance(focused, _ttk.Entry):
                return True
            if isinstance(focused, _ttk.Combobox):
                return True
        except Exception:
            pass
        return False

    def _summon_teacher_ai(self, _event=None):
        """Open Teacher AI for a free-form question. Triggered by the
        "Ask Tired Market AI" corner link (the Ctrl+` hotkey was removed in
        v4.14.5.30 — it wasn't firing; the visible link is more discoverable).
        Skips if focus is in a text widget when called from a keystroke.
        """
        if _event is not None and self._teacher_ai_focus_in_text_widget():
            return  # let the keystroke pass through to the Entry
        canvas = getattr(self, 'content_canvas', None)
        if canvas is None:
            return
        try:
            import tm_teacher_ai as _tm_ai
        except Exception:
            return

        # v4.15.0-ask-ai-frontdoor: this is the FIRST live wiring of the
        # Ctrl+` box to the real brain (slices 1-7). It ONLY connects
        # input -> brain -> output; it does NOT change any lane logic. The
        # brain (tm_teacher_retrieval.answer_question) routes through the
        # proven classifier + lanes (advice/accuracy canned, program/general
        # local-grounded, open-world research -> cloud, offline/no-provider
        # caught) and never raises — it always returns {'text': ...}.
        def _render(msg):
            try:
                _tm_ai.show_center(canvas, msg)
            except Exception:
                pass

        def _on_submit(text):
            text = (text or '').strip()
            if not text:
                return
            # NEVER LOOK FROZEN: show thinking instantly, compute the real
            # answer OFF the UI thread, swap it in when ready. A real answer
            # is ~10-17s local / a network round-trip cloud; running it on the
            # Tk thread would freeze the whole app. (A static "Thinking…" over
            # a RESPONSIVE window is the substance — the off-thread dispatch is
            # what actually prevents the freeze.)
            _render("Thinking…")

            def _work():
                try:
                    import tm_teacher_retrieval as _brain
                    out = _brain.answer_question(text)
                    msg = (out.get('text') or '').strip()
                except Exception:
                    msg = ""
                if not msg:
                    msg = "Something went wrong — try asking again in a moment."
                try:
                    self.root.after(0, lambda m=msg: _render(m))
                except Exception:
                    _render(msg)

            try:
                import threading as _th
                _th.Thread(target=_work, daemon=True,
                           name='ask-ai-brain').start()
            except Exception:
                # No threads available — answer inline (blocks briefly) rather
                # than leave the box stuck on "Thinking…".
                _work()

        # slice 10: a persistent, hot-editable disclaimer line on the ASK
        # screen (shown before submit). Replaces the old per-answer footer —
        # framing is established up front so factual answers stay clean. The
        # text lives in data/internal/teacher_ask_disclaimer.txt (edit live,
        # like the identity sheet); falls back to a built-in line if missing.
        _disclaimer = ("This is not a financial advisor and doesn't tell you "
                       "what to buy — every decision is your own.")
        try:
            import os as _os
            _dp = _os.path.join(_os.path.dirname(_os.path.abspath(__file__)),
                                'data', 'internal',
                                'teacher_ask_disclaimer.txt')
            with open(_dp, 'r', encoding='utf-8') as _f:
                _txt = _f.read().strip()
            if _txt:
                _disclaimer = _txt
        except Exception:
            pass

        try:
            _tm_ai.show_input(
                canvas,
                prompt="Ask AI — type any question:",
                on_submit=_on_submit,
                disclaimer=_disclaimer,
            )
        except Exception:
            pass

    def _toggle_tutorial_mode(self, _event=None):
        """Flip the session-only tutorial-mode flag. Bound to Ctrl+Shift+`
        AND Ctrl+~ (the shifted form some keyboard layouts report).
        Shows a brief auto-dismiss confirmation surface.
        """
        if _event is not None and self._teacher_ai_focus_in_text_widget():
            return
        canvas = getattr(self, 'content_canvas', None)
        if canvas is None:
            return
        try:
            import tm_teacher_ai as _tm_ai
        except Exception:
            return

        self._teacher_ai_tutorial_mode_on = (
            not self._teacher_ai_tutorial_mode_on)

        if self._teacher_ai_tutorial_mode_on:
            msg = ("Tutorial mode on — I'll walk you through features more "
                   "proactively, even ones you've previously dismissed. "
                   "Press Ctrl+Shift+` again to turn off.")
        else:
            msg = "Tutorial mode off."

        try:
            handle = _tm_ai.show_center(canvas, msg, actions=[])
        except Exception:
            handle = None

        # Auto-dismiss after 2.5s. Guard against None (surface was
        # replaced mid-build — the replacement displaces it anyway).
        if handle is not None:
            def _auto_dismiss():
                try:
                    _tm_ai.dismiss_surface(handle)
                except Exception:
                    pass
            try:
                self.root.after(2500, _auto_dismiss)
            except Exception:
                pass

    def _build_loading_overlay(self):
        """Create the center-screen loading overlay. Hidden when
        _startup_complete is already True, otherwise shown immediately.
        v4.13.62.1: animated icon (hourglass flips ⏳↔⌛) and pulsing
        dots in the title so it's obvious the app isn't stuck."""
        c = self.c
        try:
            self._loading_overlay = tk.Frame(self.root, bg=c['bg'])
            inner = tk.Frame(self._loading_overlay, bg=c['card'],
                              highlightthickness=1,
                              highlightbackground=c['border'])
            inner.place(relx=0.5, rely=0.5, anchor='center')
            # Save references so the animation tick can update them.
            self._loading_icon_lbl = tk.Label(
                inner, text="⏳",
                bg=c['card'], fg=c['amber'],
                font=('Segoe UI', 48))
            self._loading_icon_lbl.pack(side='top', padx=40, pady=(28, 8))
            self._loading_title_lbl = tk.Label(
                inner, text="Loading Tired Market",
                bg=c['card'], fg=c['text'],
                font=('Segoe UI', 18, 'bold'))
            self._loading_title_lbl.pack(side='top', padx=40, pady=(0, 4))
            tk.Label(inner,
                      text="Loading predictions log, models, "
                           "and provider state. Toolbar buttons "
                           "are paused until this finishes.",
                      bg=c['card'], fg=c['muted'],
                      font=('Segoe UI', 10),
                      wraplength=420, justify='center'
                      ).pack(side='top', padx=40, pady=(0, 12))
            # Marching-dot row underneath. Three dots that take turns
            # being highlighted — gives an unmistakable "alive" pulse
            # even if the emoji font happens to render the hourglass
            # the same way for both frames.
            dot_row = tk.Frame(inner, bg=c['card'])
            dot_row.pack(side='top', padx=40, pady=(0, 28))
            self._loading_dots = []
            for _i in range(3):
                d = tk.Label(dot_row, text="●",
                              bg=c['card'], fg=c['dim'],
                              font=('Segoe UI', 16, 'bold'))
                d.pack(side='left', padx=4)
                self._loading_dots.append(d)
            # Click-blocker: any mouse event on the overlay is swallowed
            # so accidental clicks during launch don't queue up.
            for ev in ('<Button-1>', '<Button-3>',
                       '<Double-Button-1>'):
                self._loading_overlay.bind(ev, lambda e: 'break')
            if not getattr(self, '_startup_complete', False):
                # Cover the full window. Place above everything.
                self._loading_overlay.place(
                    relx=0, rely=0, relwidth=1, relheight=1)
                self._loading_overlay.lift()
                # Kick off the animation
                self._loading_anim_step = 0
                self._loading_anim_id = None
                self._tick_loading_animation()
        except Exception:
            self._loading_overlay = None

    def _tick_loading_animation(self):
        """Cycle the loading overlay's icon, title dots, and marching
        dot row. Reschedules itself every 250ms until the overlay goes
        away. Each tick is cheap: text updates only, no layout changes."""
        try:
            if getattr(self, '_loading_overlay', None) is None:
                return  # overlay was hidden — stop animating
            step = getattr(self, '_loading_anim_step', 0)
            # Icon flip every other tick (500ms cadence)
            try:
                icon_char = "⏳" if (step // 2) % 2 == 0 else "⌛"
                self._loading_icon_lbl.config(text=icon_char)
            except Exception:
                pass
            # Title with growing ellipsis (0..3 dots)
            try:
                ellipsis = "." * (step % 4)
                self._loading_title_lbl.config(
                    text=f"Loading Tired Market{ellipsis}")
            except Exception:
                pass
            # Marching dots: highlight one at a time, others dim
            try:
                c = self.c
                hot = step % 3
                for i, lbl in enumerate(self._loading_dots):
                    lbl.config(fg=c['amber'] if i == hot else c['dim'])
            except Exception:
                pass
            self._loading_anim_step = step + 1
            try:
                self._loading_anim_id = self.root.after(
                    250, self._tick_loading_animation)
            except Exception:
                pass
        except Exception:
            pass

    def _hide_loading_overlay(self):
        """Tear down the loading overlay. Idempotent."""
        try:
            anim_id = getattr(self, '_loading_anim_id', None)
            if anim_id is not None:
                try:
                    self.root.after_cancel(anim_id)
                except Exception:
                    pass
                self._loading_anim_id = None
        except Exception:
            pass
        try:
            ov = getattr(self, '_loading_overlay', None)
            if ov is not None:
                ov.place_forget()
                ov.destroy()
                self._loading_overlay = None
        except Exception:
            pass

    def _build_portfolio_summary(self, parent):
        # Save parent reference so we can rebuild after sells/etc.
        self._summary_parent = parent
        self._render_portfolio_summary()

    def _render_portfolio_summary(self):
        """v4.11.0: (Re)build the portfolio panel. Replaces the old
        summary+open-Holdings two-step UI with the unified PortfolioPanel
        that includes per-holding consensus cards inline."""
        parent = getattr(self, '_summary_parent', None)
        if parent is None:
            return
        # Make sure the holdings state is built — the panel reads from it
        # for the data layer (HoldingsManager, DataCacheLayer, SignalsLog).
        if getattr(self, '_holdings_state', None) is None:
            try:
                self._holdings_state = self._build_holdings_state()
            except Exception as e:
                self._log(f"Holdings state build failed: {e}", 'red')
                return
        # Lazily create the panel object (it caches form state across
        # rebuilds). Tear-down/rebuild of the *visual* tree happens inside
        # render().
        if getattr(self, '_portfolio_panel', None) is None:
            try:
                self._portfolio_panel = tm_portfolio_panel.PortfolioPanel(
                    parent, self)
            except Exception as e:
                self._log(f"PortfolioPanel init failed: {e}", 'red')
                return
        try:
            self._portfolio_panel.render()
        except Exception as e:
            import traceback
            self._log(f"PortfolioPanel render failed: {e}", 'red')
            try:
                with open(USER_DATA_DIR / "panel_render_errors.log",
                          'a', encoding='utf-8') as f:
                    f.write(f"\n=== {datetime.now().isoformat()} ===\n")
                    f.write(traceback.format_exc())
            except Exception:
                pass

