    def _build_portfolio_ticker(self, parent):
        """Build the per-share price/change strip below the action
        button row. Stays mounted for the life of the window; the
        cells inside it are re-rendered every 60 seconds.
        """
        c = self.c
        # Outer frame: full-width, thin
        self._ticker_frame = tk.Frame(parent, bg=c['card'], height=32)
        self._ticker_frame.pack(side='top', fill='x', padx=10,
                                  pady=(0, 6))
        self._ticker_frame.pack_propagate(False)

        # Left side: market session label
        self._ticker_session_lbl = tk.Label(
            self._ticker_frame, text="",
            bg=c['card'], fg=c['muted'],
            font=('Segoe UI', 9, 'bold'))
        self._ticker_session_lbl.pack(side='left', padx=(8, 12))

        # Right side: cells container (we rebuild children of THIS,
        # not the outer frame, so the session label stays put).
        self._ticker_cells_frame = tk.Frame(self._ticker_frame,
                                              bg=c['card'])
        self._ticker_cells_frame.pack(side='left', fill='x',
                                        expand=True)

        # Initial render + schedule refresh loop
        self._render_portfolio_ticker()
        self._schedule_ticker_refresh()

        # Also kick off the revival watcher (different cadence)
        self._schedule_revival_check()

    def _render_portfolio_ticker(self):
        """(Re)build the cells inside the ticker. Called on initial
        draw and every refresh tick. Keeps the outer frame intact so
        we don't visually flash."""
        c = self.c
        if not hasattr(self, '_ticker_cells_frame') or \
                self._ticker_cells_frame is None:
            return
        # Wipe existing cells
        try:
            for child in self._ticker_cells_frame.winfo_children():
                try: child.destroy()
                except Exception: pass
        except Exception:
            return

        # Update market-session label
        try:
            session_text, _ = get_market_status()
            # Shorten for display
            session_short = session_text.split('(')[0].strip()
            color = c['green'] if session_short == 'OPEN' else c['muted']
            if session_short.startswith('CLOSED'):
                color = c['dim']
            elif session_short in ('PRE-MARKET', 'AFTER-HOURS'):
                color = c['amber']
            self._ticker_session_lbl.config(text=session_short, fg=color)
        except Exception:
            pass

        # Get the holdings list
        try:
            if getattr(self, '_holdings_state', None) is None:
                self._holdings_state = self._build_holdings_state()
            mgr = self._holdings_state['mgr']
            cache = self._holdings_state['cache']
            holdings = list(mgr.holdings)
        except Exception:
            holdings = []
            cache = None

        # Filter to tradable only (skip written_off)
        tradable = [h for h in holdings
                     if h.get('status', 'tradable') != 'written_off']
        portfolio_tickers = [h.get('ticker', '?').upper() for h in tradable]

        # v4.14.5.14-gui-cleanup-d: watchlist tickers, read from the same
        # _holdings_state['watchlist'] the Look Up "Add to watchlist" button
        # writes to. Small list (Mike's manual picks) — no scroll, just
        # appended after a WATCHED divider.
        watch_tickers = []
        try:
            wl = (self._holdings_state or {}).get('watchlist')
            if wl is not None:
                watch_tickers = [e.get('ticker', '').upper()
                                 for e in wl.tickers if e.get('ticker')]
        except Exception:
            watch_tickers = []

        # PORTFOLIO always shown (even when empty); WATCHED only when the
        # watchlist has entries (gui_ticker_strip_sections enforces this).
        for label, tickers in gui_ticker_strip_sections(
                portfolio_tickers, watch_tickers):
            tk.Label(self._ticker_cells_frame, text=label,
                     bg=c['card'], fg=c['dim'],
                     font=('Segoe UI', 8, 'bold')
                     ).pack(side='left', padx=(0, 10))
            if not tickers:
                tk.Label(self._ticker_cells_frame,
                         text="(no tradable positions)",
                         bg=c['card'], fg=c['dim'],
                         font=('Segoe UI', 9, 'italic')
                         ).pack(side='left', padx=(0, 14))
                continue
            for ticker in tickers:
                self._build_ticker_cell(self._ticker_cells_frame,
                                         ticker, cache)

    def _build_ticker_cell(self, parent, ticker, cache):
        """Build one price/change cell in the top ticker strip (shared by the
        PORTFOLIO and WATCHED sections). Dot = quote freshness (green when a
        price is cached, amber when a stale quote exists, red when none).
        Click re-renders the Portfolio panel (harmless for watched tickers)."""
        c = self.c
        ticker = (ticker or '?').upper()
        cell = tk.Frame(parent, bg=c['card'])
        cell.pack(side='left', padx=(0, 18))

        quote = None
        if cache is not None:
            try:
                quote = cache.quote(ticker)
            except Exception:
                quote = None

        price = (quote or {}).get('price') if quote else None
        change_pct = (quote or {}).get('change_pct') if quote else None

        dot_color = c['red']
        if quote is not None and price is not None:
            dot_color = c['green']
        elif quote is not None:
            dot_color = c['amber']

        chg_color = c['muted']
        if change_pct is not None:
            if change_pct > 0:
                chg_color = c['green']
            elif change_pct < 0:
                chg_color = c['red']

        tk.Label(cell, text=ticker,
                 bg=c['card'], fg=c['text'],
                 font=('Segoe UI', 10, 'bold')
                 ).pack(side='left', padx=(0, 6))

        price_str = f"${price:.2f}" if price is not None else "$--.--"
        tk.Label(cell, text=price_str,
                 bg=c['card'], fg=c['text'],
                 font=('Consolas', 10)
                 ).pack(side='left', padx=(0, 4))

        if change_pct is not None:
            sign = "+" if change_pct >= 0 else ""
            chg_str = f"({sign}{change_pct:.2f}%)"
        else:
            chg_str = "(--%)"
        tk.Label(cell, text=chg_str,
                 bg=c['card'], fg=chg_color,
                 font=('Consolas', 9)
                 ).pack(side='left', padx=(0, 4))

        tk.Label(cell, text="●",
                 bg=c['card'], fg=dot_color,
                 font=('Segoe UI', 8)
                 ).pack(side='left', padx=(0, 0))

        def _click(_evt=None):
            try:
                self._render_portfolio_summary()
            except Exception:
                pass
        cell.bind('<Button-1>', _click)
        for child in cell.winfo_children():
            child.bind('<Button-1>', _click)

    # ── v4.14.5.14-gui-cleanup-d: WATCHLIST panel ────────────────────────
    # ── v4.14.5.14-gui-cleanup-h: dedicated Watch window ─────────────────
    # The watchlist moved out of the left column into its own window (the
    # "Watch" toolbar button), mirroring Track Record -> Performance. Cards
    # are collapsible (default collapsed), styled like Portfolio holding
    # cards. The backend tm_discover.Watchlist is unchanged.
    def _show_watch_window(self):
        """Open the Watch window. Single-instance: re-clicking lifts the
        existing window and keeps each card's expand state."""
        existing = getattr(self, '_watch_win', None)
        if existing is not None:
            try:
                if existing.winfo_exists():
                    existing.lift()
                    existing.focus_force()
                    return
            except Exception:
                pass
        c = self.c
        s = self.space

        def _on_close():
            self._watch_win = None
            self._watch_cards_frame = None
            self._watch_status_lbl = None
            self._watch_add_entry = None

        tl = self._make_styled_toplevel(
            title="Watch",
            subtitle="Stocks you're keeping an eye on.",
            width=560, height=560, min_width=460, min_height=360,
            close_callback=_on_close)
        win = tl['win']
        body = tl['body']
        self._watch_win = win

        # ── Add-ticker input row ──
        add_row = tk.Frame(body, bg=c['bg'])
        add_row.pack(side='top', fill='x', padx=s['md'], pady=(s['sm'], s['xs']))
        tk.Label(add_row, text="Add ticker:", bg=c['bg'], fg=c['text'],
                 font=('Segoe UI', 10)).pack(side='left')
        entry = tk.Entry(add_row, width=10, bg=c['card2'], fg=c['text'],
                         insertbackground=c['text'], font=('Consolas', 11))
        entry.pack(side='left', padx=(6, 6))
        self._watch_add_entry = entry
        tk.Button(add_row, text="Add", command=self._on_watch_add,
                  bg=c['accent'], fg=c['bg'], font=('Segoe UI', 9, 'bold'),
                  relief='flat', padx=12, pady=3, cursor='hand2').pack(side='left')
        entry.bind('<Return>', lambda _e: self._on_watch_add())

        self._watch_status_lbl = tk.Label(
            body, text="", bg=c['bg'], fg=c['muted'],
            font=('Segoe UI', 8, 'italic'), anchor='w')
        self._watch_status_lbl.pack(side='top', fill='x',
                                    padx=s['md'], pady=(0, s['xs']))

        # ── Scrollable card list ──
        outer = tk.Frame(body, bg=c['bg'])
        outer.pack(side='top', fill='both', expand=True,
                   padx=s['md'], pady=(0, s['md']))
        canvas = tk.Canvas(outer, bg=c['bg'], highlightthickness=0)
        sb = ttk.Scrollbar(outer, orient='vertical', command=canvas.yview)
        cards = tk.Frame(canvas, bg=c['bg'])
        cards.bind('<Configure>',
                   lambda e: canvas.configure(scrollregion=canvas.bbox('all')))
        cwin = canvas.create_window((0, 0), window=cards, anchor='nw')
        canvas.bind('<Configure>',
                    lambda e: canvas.itemconfig(cwin, width=e.width))
        canvas.configure(yscrollcommand=sb.set)
        sb.pack(side='right', fill='y')
        canvas.pack(side='left', fill='both', expand=True)

        def _wheel(e):
            try:
                canvas.yview_scroll(-1 if e.delta > 0 else 1, 'units')
            except Exception:
                pass
        canvas.bind('<Enter>', lambda e: canvas.bind_all('<MouseWheel>', _wheel))
        canvas.bind('<Leave>', lambda e: canvas.unbind_all('<MouseWheel>'))
        self._watch_cards_frame = cards

        self._populate_watch_window()
        try:
            self._log("Opened Watch", 'muted')
        except Exception:
            pass

    def _refresh_watch_window(self):
        """Re-populate the Watch window IF it's open. Safe no-op when closed
        (the watchlist has no other live surface now — nothing to draw)."""
        win = getattr(self, '_watch_win', None)
        if win is None:
            return
        try:
            if not win.winfo_exists():
                self._watch_win = None
                return
        except Exception:
            return
        try:
            self._populate_watch_window()
        except Exception:
            pass

    def _populate_watch_window(self):
        """(Re)build the cards in the Watch window. No-op if closed. Framed
        empty-state block when the watchlist is empty."""
        cards = getattr(self, '_watch_cards_frame', None)
        if cards is None:
            return
        try:
            if not cards.winfo_exists():
                return
            for ch in cards.winfo_children():
                try: ch.destroy()
                except Exception: pass
        except Exception:
            return
        c = self.c
        s = self.space
        watchlist = cache = preds = None
        try:
            if getattr(self, '_holdings_state', None) is None:
                self._holdings_state = self._build_holdings_state()
            watchlist = self._holdings_state.get('watchlist')
            cache = self._holdings_state.get('cache')
            preds = self._holdings_state.get('predictions_log')
        except Exception:
            pass
        entries = []
        try:
            if watchlist is not None:
                entries = [e for e in watchlist.tickers if e.get('ticker')]
        except Exception:
            entries = []
        if not entries:
            block = tk.Frame(cards, bg=c['card'], padx=s['md'], pady=s['md'],
                             highlightbackground=c['border'],
                             highlightthickness=1)
            block.pack(fill='x', padx=s['sm'], pady=(0, s['sm']))
            tk.Label(block,
                     text=("No stocks watched yet.\nUse Look Up -> "
                           "“Add to watchlist”, or type a ticker "
                           "above to add one."),
                     bg=c['card'], fg=c['dim'], justify='left', anchor='w',
                     wraplength=460, font=('Segoe UI', 9, 'italic')
                     ).pack(side='top', fill='x', anchor='w')
            return
        for entry in entries:
            tkr = entry.get('ticker', '').upper()
            recent = []
            try:
                if preds is not None:
                    recent = preds.get_recent_for_ticker(tkr, limit=30) or []
            except Exception:
                recent = []
            self._build_watch_card(cards, tkr, recent, cache)

    def _build_watch_card(self, parent, ticker, recent, cache):
        """One collapsible Watch card. Header (always visible): chevron +
        verdict dot + ticker + TRADABLE pill + price + change% + age + AI
        verdict + Remove. Body (collapsed by default): aggregate consensus +
        plan + action buttons. Built in the Portfolio holding-card style
        (parallel implementation; tm_portfolio_panel.py untouched)."""
        c = self.c
        s = self.space
        exp = getattr(self, '_watch_card_expanded', None)
        if exp is None:
            exp = self._watch_card_expanded = {}
        is_expanded = bool(exp.get(ticker, False))

        card = tk.Frame(parent, bg=c['card'], padx=s['md'], pady=s['sm'],
                        highlightbackground=c['border'], highlightthickness=1)
        card.pack(fill='x', padx=s['sm'], pady=(0, s['sm']))

        latest = recent[0] if recent else None
        direction = (latest or {}).get('direction')
        verdict_ts = (latest or {}).get('timestamp')
        dot_kind = gui_watchlist_dot(direction)
        vcolor = {'buy': c['green'], 'watch': c['amber'],
                  'avoid': c['red']}.get(dot_kind, c['dim'])

        quote = None
        if cache is not None:
            try:
                quote = cache.quote(ticker)
            except Exception:
                quote = None
        price = (quote or {}).get('price') if quote else None
        change_pct = (quote or {}).get('change_pct') if quote else None

        # ── Header line ──
        hdr = tk.Frame(card, bg=c['card'])
        hdr.pack(fill='x')
        chev = tk.Label(hdr, text=('▼' if is_expanded else '▶'),
                        bg=c['card'], fg=c['muted'], font=('Segoe UI', 8),
                        cursor='hand2')
        chev.pack(side='left', padx=(0, s['xs']))
        tk.Label(hdr, text="●", bg=c['card'], fg=vcolor,
                 font=('Segoe UI', 8)).pack(side='left')
        tk.Label(hdr, text=ticker, bg=c['card'], fg=c['accent'],
                 font=('Segoe UI', 10, 'bold')
                 ).pack(side='left', padx=(s['xs'], s['sm']))
        tk.Label(hdr, text="TRADABLE", bg=c['card2'], fg=c['green'],
                 font=('Segoe UI', 7, 'bold'), padx=6, pady=1).pack(side='left')
        price_str = f"${price:.2f}" if price is not None else "$--.--"
        tk.Label(hdr, text=price_str, bg=c['card'], fg=c['text'],
                 font=('Consolas', 10)).pack(side='left', padx=(s['sm'], 4))
        chg_color = c['muted']
        if change_pct is not None:
            chg_color = (c['green'] if change_pct > 0
                         else c['red'] if change_pct < 0 else c['muted'])
            sign = "+" if change_pct >= 0 else ""
            chg_str = f"({sign}{change_pct:.2f}%)"
        else:
            chg_str = "(--%)"
        tk.Label(hdr, text=chg_str, bg=c['card'], fg=chg_color,
                 font=('Consolas', 9)).pack(side='left')
        # Remove — right-packed first so it never clips.
        tk.Button(hdr, text="Remove",
                  command=lambda t=ticker: self._on_watchlist_remove(t),
                  bg=c['card'], fg=c['muted'], activebackground=c['card2'],
                  activeforeground=c['text'], font=('Segoe UI', 8),
                  relief='flat', borderwidth=0, cursor='hand2',
                  padx=6, pady=0).pack(side='right')
        vw = (direction or '').strip().upper()
        vtext = f"AI: {vw}" if vw else "AI: not yet analyzed"
        tk.Label(hdr, text=vtext, bg=c['card'],
                 fg=(vcolor if vw else c['dim']),
                 font=('Segoe UI', 8, 'bold')
                 ).pack(side='right', padx=(0, s['sm']))
        age = gui_short_age(verdict_ts)
        if age:
            tk.Label(hdr, text=age, bg=c['card'], fg=c['dim'],
                     font=('Segoe UI', 8)).pack(side='right', padx=(0, s['sm']))

        # ── Collapsible body — aggregate consensus + plan + actions ──
        bodyf = tk.Frame(card, bg=c['card'])
        summ = gui_watch_consensus(recent)
        last_age = gui_short_age(summ['latest_ts'])
        cons = (f"Consensus: {summ['buy']} BUY · {summ['watch']} WATCH "
                f"· {summ['avoid']} AVOID  ({summ['models']} model"
                f"{'' if summ['models'] == 1 else 's'}"
                + (f", last analyzed {last_age} ago" if last_age else "")
                + ")")
        tk.Label(bodyf, text=cons, bg=c['card'], fg=c['muted'],
                 font=('Segoe UI', 8), anchor='w', justify='left',
                 wraplength=480).pack(side='top', anchor='w', pady=(4, 0))
        if summ['target'] is not None or summ['stop'] is not None:
            plan_bits = []
            if summ['target'] is not None:
                plan_bits.append(f"target ${summ['target']:g}")
            if summ['stop'] is not None:
                plan_bits.append(f"stop ${summ['stop']:g}")
            tk.Label(bodyf, text="Plan: " + " / ".join(plan_bits),
                     bg=c['card'], fg=c['muted'], font=('Segoe UI', 8),
                     anchor='w').pack(side='top', anchor='w', pady=(2, 0))
        elif not recent:
            tk.Label(bodyf, text="No AI analysis on record yet.",
                     bg=c['card'], fg=c['dim'],
                     font=('Segoe UI', 8, 'italic'), anchor='w'
                     ).pack(side='top', anchor='w', pady=(2, 0))
        # NOTE: per-model breakdown is intentionally NOT shown here — it lives
        # in Track Record -> Per-Model Matrix. This is the aggregate only.
        btns = tk.Frame(bodyf, bg=c['card'])
        btns.pack(side='top', fill='x', pady=(6, 0))
        tk.Button(btns, text="Look Up fresh",
                  command=lambda t=ticker: self._watch_lookup_fresh(t),
                  bg=c['card2'], fg=c['text'], font=('Segoe UI', 8),
                  relief='flat', padx=8, pady=2, cursor='hand2'
                  ).pack(side='left', padx=(0, 6))
        tk.Button(btns, text="Add to Holdings",
                  command=lambda t=ticker: self._watch_add_to_holdings(t),
                  bg=c['card2'], fg=c['text'], font=('Segoe UI', 8),
                  relief='flat', padx=8, pady=2, cursor='hand2').pack(side='left')

        body_kwargs = {'fill': 'x', 'pady': (s['xs'], 0)}
        if is_expanded:
            bodyf.pack(**body_kwargs)

        def _toggle(_e=None, t=ticker, b=bodyf, ch=chev, bk=body_kwargs):
            self._toggle_watch_card(t, b, ch, bk)
        chev.bind('<Button-1>', _toggle)

    def _toggle_watch_card(self, ticker, body, chevron, body_kwargs):
        """Flip a Watch card's expanded/collapsed state in place (pack /
        pack_forget the body; update the chevron). Session-only state."""
        exp = getattr(self, '_watch_card_expanded', None)
        if exp is None:
            exp = self._watch_card_expanded = {}
        new_state = not exp.get(ticker, False)
        exp[ticker] = new_state
        try:
            if new_state:
                body.pack(**(body_kwargs or {'fill': 'x'}))
                chevron.config(text='▼')
            else:
                body.pack_forget()
                chevron.config(text='▶')
        except Exception:
            pass

    def _on_watch_add(self):
        """Add-ticker input handler (the Watch window's Add button / Enter).
        Same backend path as Look Up's Add-to-watchlist."""
        entry = getattr(self, '_watch_add_entry', None)
        sl = getattr(self, '_watch_status_lbl', None)
        c = self.c

        def _say(txt, col):
            try:
                if sl is not None and sl.winfo_exists():
                    sl.config(text=txt, fg=c.get(col, c['muted']))
            except Exception:
                pass

        if entry is None:
            return
        try:
            sym = (entry.get() or '').strip().upper()
        except Exception:
            sym = ''
        if not sym:
            _say("Type a ticker first.", 'amber')
            return
        wl = (self._holdings_state or {}).get('watchlist')
        if wl is None:
            _say("No watchlist configured.", 'amber')
            return
        try:
            added = wl.add(
                sym, notes=f"Watched {datetime.now().strftime('%Y-%m-%d')}")
        except Exception as e:
            _say(f"Could not add {sym}: {e}", 'red')
            return
        if added:
            _say(f"Added {sym}.", 'green')
            try: entry.delete(0, 'end')
            except Exception: pass
        else:
            _say(f"{sym} is already on the watchlist.", 'muted')
        try: self._populate_watch_window()
        except Exception: pass
        try: self._render_portfolio_ticker()
        except Exception: pass

    def _watch_lookup_fresh(self, ticker):
        """'Look Up fresh' — open the Look Up window prefilled with this
        ticker (the user fires the consensus from there)."""
        try:
            self._watch_lookup_prefill = (ticker or '').strip().upper()
        except Exception:
            pass
        try:
            self._show_stock_lookup()
        except Exception:
            pass

    def _watch_add_to_holdings(self, ticker):
        """'Add to Holdings' — prefill the (always-visible) left-column Add
        Holding form's ticker via the Portfolio panel's existing _form_ticker
        StringVar. Uses the existing object; does NOT modify tm_portfolio_panel."""
        sym = (ticker or '').strip().upper()
        done = False
        try:
            panel = getattr(self, '_portfolio_panel', None)
            var = getattr(panel, '_form_ticker', None) if panel else None
            if var is not None:
                var.set(sym)
                done = True
        except Exception:
            done = False
        sl = getattr(self, '_watch_status_lbl', None)
        try:
            if sl is not None and sl.winfo_exists():
                if done:
                    sl.config(
                        text=(f"{sym} filled into Add Holding (main window) "
                              "— set shares/price and click Add."),
                        fg=self.c['green'])
                else:
                    sl.config(
                        text=(f"To buy {sym}: enter it in the Add Holding "
                              "form on the main window."),
                        fg=self.c['muted'])
        except Exception:
            pass

    def _on_watchlist_remove(self, ticker):
        """Remove a ticker from the watchlist and refresh the Watch window
        (if open) + the ticker strip. Fail-safe."""
        try:
            wl = (self._holdings_state or {}).get('watchlist')
            if wl is not None and wl.remove(ticker):
                self._log(f"Removed {ticker} from the watchlist.", 'muted')
        except Exception as e:
            try: self._log(f"Watchlist remove failed: {e}", 'amber')
            except Exception: pass
        try:
            if getattr(self, '_watch_card_expanded', None):
                self._watch_card_expanded.pop(ticker, None)
        except Exception:
            pass
        try: self._refresh_watch_window()
        except Exception: pass
        try: self._render_portfolio_ticker()
        except Exception: pass

    def _schedule_ticker_refresh(self):
        """Re-render the ticker every 60 seconds via root.after.
        v4.13.22: also triggers portfolio cards re-render so their
        displayed prices stay in sync with the ticker bar (was a bug
        where ticker showed live price but portfolio card showed
        stale price).
        Cancels itself cleanly when the window closes."""
        try:
            self._render_portfolio_ticker()
        except Exception:
            pass
        # v4.14.5.14-gui-cleanup-h: refresh the Watch window (if open) on the
        # same cadence so watched-ticker prices / verdict ages stay live.
        # No-op when the window is closed.
        try:
            self._refresh_watch_window()
        except Exception:
            pass
        # v4.13.27: do NOT call portfolio_panel.render() here.
        # That tore down and rebuilt every card every 60s, which
        # threw scroll position back to top. Cards stay put now;
        # they refresh on their own when the user re-runs
        # consensus or when auto-refresh ticks. Live ticker
        # prices still update via the cells in this bar.
        try:
            # v4.13.27: 15_000 ms = 15 seconds. Faster visual
            # refresh so the ticker feels live. Underlying quote
            # cache TTL is unchanged, so no extra network hits.
            self.root.after(15_000, self._schedule_ticker_refresh)
        except Exception:
            # Window probably closed
            pass

    # v4.13.14: Revival watcher for written-off positions
    def _schedule_revival_check(self):
        """Every 5 minutes, peek at written-off positions and log an
        alert to activity if any are showing unusual price/volume
        action. Background-only -- doesn't auto-promote."""
        try:
            self._check_revival_alerts()
        except Exception:
            pass
        try:
            # 5 min = 300_000 ms. Slow cadence is fine; this is just
            # a sanity check, not a real-time signal.
            self.root.after(300_000, self._schedule_revival_check)
        except Exception:
            pass

    def _check_revival_alerts(self):
        """Inspect written-off positions for unusual activity. Logs
        an alert if price is up significantly on elevated volume."""
        try:
            if getattr(self, '_holdings_state', None) is None:
                return
            mgr = self._holdings_state['mgr']
            cache = self._holdings_state['cache']
            holdings = list(mgr.holdings)
        except Exception:
            return

        # Throttle alerts: don't re-alert on the same ticker within
        # 6 hours, even if condition still holds.
        if not hasattr(self, '_revival_alert_last'):
            self._revival_alert_last = {}  # ticker -> timestamp
        now_ts = time.time()

        written_off = [h for h in holdings
                        if h.get('status') == 'written_off']

        for h in written_off:
            ticker = h.get('ticker', '?').upper()
            # Throttle
            last = self._revival_alert_last.get(ticker, 0)
            if now_ts - last < 6 * 3600:
                continue

            try:
                quote = cache.quote(ticker) if cache else None
            except Exception:
                quote = None
            if not quote:
                continue
            change_pct = quote.get('change_pct')
            volume = quote.get('volume')
            if change_pct is None or volume is None:
                continue

            # Try to get average volume for comparison
            try:
                tech = cache.technicals(ticker) if cache else None
                avg_volume = (tech or {}).get('avg_volume_30')
            except Exception:
                avg_volume = None

            # Trigger condition: up >50% AND volume >5x average (if
            # we have avg). If we don't have avg, fall back to just
            # the price condition with a higher bar (>100% move).
            triggered = False
            reason = ""
            if avg_volume and avg_volume > 0:
                vol_mult = volume / avg_volume
                if change_pct > 50 and vol_mult > 5:
                    triggered = True
                    reason = (f"up {change_pct:.0f}% on "
                              f"{vol_mult:.1f}x avg volume")
            elif change_pct > 100:
                # No avg volume data -- use a stricter price-only bar
                triggered = True
                reason = f"up {change_pct:.0f}% (volume baseline unknown)"

            if triggered:
                self._log(
                    f"⚠ {ticker} (written off) {reason}. "
                    f"Review in Portfolio if interested.",
                    'amber')
                self._revival_alert_last[ticker] = now_ts

    def _provider_status_tick(self):
        """v4.13.59: periodic refresh of the provider status bar.
        Re-schedules itself every 3 seconds via root.after()."""
        try:
            self._refresh_provider_status_bar()
        except Exception:
            pass
        try:
            self.root.after(3000, self._provider_status_tick)
        except Exception:
            pass

    def _provider_chip_is_green(self, provider) -> bool:
        """v4.14.0 stage 6d: heartbeat eligibility for one AI provider.

        GREEN if at least one canonical model on this provider has:
          - provider enabled
          - api_key present (except for Ollama which doesn't need one)
          - not in cooldown
          - learned/declared cap not exhausted
        Otherwise GREY.

        Per Q8 of the locked spec: "any" semantics — a provider goes
        GREEN as soon as ONE of its canonical models is usable, even
        if other models on the same provider are over cap or cooling
        down. The router can still failover within the provider.
        """
        try:
            if not provider.get('enabled'):
                return False
            preset = (provider.get('preset') or '').lower()
            api_key = (provider.get('api_key') or '').strip()
            if not api_key and preset != 'ollama':
                return False

            # If router/health unavailable, default to GREEN (no data
            # to say otherwise — treat as "alive, never been called").
            if not _AI_ROUTER_ENABLED or tm_ai_router is None:
                return True
            if tm_provider_health is None:
                return True
            state = tm_provider_health.get_state()
            if state is None:
                return True

            prov_id = provider.get('id') or provider.get('name') or '?'
            # v4.14.5.14-status-dot-meaning: if this provider's LAST call
            # this session failed (auth/transient/other), it's not green
            # even though it's enabled + keyed + not in cooldown — the
            # SambaNova-401 case the heartbeat used to show green. Cooldown
            # (amber/grey) is already handled by the per-record check below.
            # Flag-gated so rollback restores the pre-patch heartbeat.
            if bool(self.cfg.get('use_status_dot_health', True)):
                try:
                    _lcs = state.get_last_call_state(prov_id)
                    if isinstance(_lcs, str) and _lcs.startswith('failed'):
                        return False
                except Exception:
                    pass
            records = [r for r in state.all() if r.provider_id == prov_id]
            if not records:
                # No health records yet — provider is fresh today,
                # treat as GREEN (we haven't burned anything).
                return True

            # Resolve the declared cap fallback for "cap not exhausted"
            # check. Per-record observed_max_per_day is preferred when
            # set; otherwise we fall back to the preset's
            # default_max_per_day so a fresh provider with no observed
            # ceiling still has a sane cap to compare against.
            base_cap = None
            try:
                import tm_api_providers as _tmap6d4
                preset_def = _tmap6d4.PRESETS.get(preset, {})
                base_cap = preset_def.get('default_max_per_day')
            except Exception:
                pass

            import time as _t
            now = _t.time()
            for rec in records:
                if rec.in_cooldown(now):
                    continue
                cap = rec.observed_max_per_day or base_cap
                if (cap is not None and cap > 0
                        and rec.calls_today >= cap):
                    continue
                # Found at least one healthy model
                return True
            return False
        except Exception:
            # Paranoid fallback — heartbeat should not crash the app
            return True

    def _refresh_provider_status_bar(self):
        """v4.14.0 stage 6d: heartbeat-style chip strip.

        One chip per provider (AI: grouped by canonical_id via
        tm_ai_router.provider_canonical_id, so duplicate registry
        entries pointing at the same provider collapse into one chip;
        Data: one chip per registered DataProviderProfile). Two states
        only — GREEN (eligible) / GREY (unavailable). No per-call
        counts, no cap text, no per-canonical-model duplication.

        Tick: 3 seconds (unchanged). G9 caching: per-canonical state
        is recomputed every tick, but the widget tree only repaints
        when at least one chip's GREEN/GREY state transitions —
        calls_today changing from 14 to 15 does not trigger a paint.
        """
        if not hasattr(self, '_provider_status_inner'):
            return
        if self._provider_status_inner is None:
            return
        c = self.c
        try:
            # Measure available width up front (same pattern as before
            # so the row-flow logic doesn't read a stale collapsed
            # value mid-rebuild).
            try:
                self._provider_status_bar.update_idletasks()
                _avail_pre = self._provider_status_bar.winfo_width()
                if _avail_pre < 50:
                    _avail_pre = self._provider_status_inner.winfo_width()
                if _avail_pre < 50:
                    _avail_pre = 600
                self._provider_status_avail = max(50, _avail_pre - 24)
            except Exception:
                self._provider_status_avail = 600

            # ── Compute new chip data ───────────────────────────────
            # ai_chips and data_chips are ordered lists of:
            #   {'cid': canonical_id, 'name': display, 'state': 'green'|'grey'}
            # cid is the dedup key (Decision G3) — for AI providers it
            # comes from tm_ai_router.provider_canonical_id which
            # resolves preset='custom' entries by endpoint URL pattern.
            try:
                import tm_api_providers as _tmap6d4
            except Exception:
                _tmap6d4 = None

            ai_chips = []
            try:
                enabled = (self._load_enabled_api_providers()
                            if hasattr(self, '_load_enabled_api_providers')
                            else [])
                # Group by canonical_id; first encountered name wins;
                # state is GREEN if any provider in the group is green.
                seen_cids = {}  # cid -> {'name': str, 'state': 'green'|'grey'}
                seen_order = []  # preserve first-seen order for stable layout
                for prov in enabled:
                    if not prov.get('enabled'):
                        continue
                    cid = None
                    if (_AI_ROUTER_ENABLED and tm_ai_router is not None):
                        try:
                            cid = tm_ai_router.provider_canonical_id(prov)
                        except Exception:
                            cid = None
                    # Fall back to provider id when canonical resolution
                    # fails — keeps the chip visible rather than dropped.
                    if not cid:
                        cid = prov.get('id') or prov.get('preset') or '?'

                    is_green = self._provider_chip_is_green(prov)
                    if cid in seen_cids:
                        if is_green:
                            seen_cids[cid]['state'] = 'green'
                    else:
                        # Display name: canonicalize whatever the
                        # provider's stored name is, or fall back to
                        # the preset's display name, or the canonical id.
                        name = (prov.get('name') or '').strip()
                        if not name and _tmap6d4 is not None:
                            preset_def = _tmap6d4.PRESETS.get(
                                (prov.get('preset') or '').lower(), {})
                            name = preset_def.get('name') or cid
                        if _tmap6d4 is not None:
                            name = _tmap6d4.canonicalize_model_label(name)
                        seen_cids[cid] = {
                            'name': name or cid,
                            'state': 'green' if is_green else 'grey',
                        }
                        seen_order.append(cid)
                for cid in seen_order:
                    rec = seen_cids[cid]
                    ai_chips.append({
                        'cid': cid,
                        'name': rec['name'],
                        'state': rec['state'],
                    })
            except Exception:
                pass

            data_chips = []
            try:
                if _DATA_LAYER_ENABLED and tm_data_providers is not None:
                    reg = tm_data_providers.get_registry()
                    if reg is not None:
                        for prof in reg.all():
                            if not prof.enabled:
                                continue
                            # GREEN if usable AND health is not red.
                            # is_usable() covers enabled + key-present.
                            try:
                                usable = prof.is_usable()
                            except Exception:
                                usable = bool(prof.enabled)
                            healthy = (prof.health != 'red')
                            state = ('green' if (usable and healthy)
                                     else 'grey')
                            data_chips.append({
                                'cid': f"data:{prof.id}",
                                'name': prof.display_name,
                                'state': state,
                            })
            except Exception:
                pass

            # ── G9: signature compare against last paint ────────────
            # Signature is just (cid, state) per chip. Calls/cap aren't
            # in the signature anymore (they're not displayed), so a
            # 14→15 calls increment never triggers a repaint. Only
            # state transitions (green↔grey) do.
            avail = getattr(self, '_provider_status_avail', 600)
            new_states = {}
            for cd in ai_chips:
                new_states[cd['cid']] = cd['state']
            for cd in data_chips:
                new_states[cd['cid']] = cd['state']

            last_states = getattr(self, '_last_chip_states', None)
            existing = self._provider_status_inner.winfo_children()
            if (last_states is not None
                    and last_states == new_states
                    and len(existing) > 0
                    and getattr(self, '_last_chip_avail', None) == avail):
                return  # No state changed — leave the widget tree alone
            self._last_chip_states = dict(new_states)
            self._last_chip_avail = avail

            # ── Rebuild ─────────────────────────────────────────────
            for w in existing:
                try:
                    w.destroy()
                except Exception:
                    pass

            if not ai_chips and not data_chips:
                tk.Label(self._provider_status_inner,
                         text="(no providers active yet)",
                         bg=c['card2'], fg=c['dim'],
                         font=('Segoe UI', 8, 'italic')
                         ).pack(side='left')
                return

            # Two-state palette per Decision 3. No yellow tier, no
            # red-cooldown distinction surfaced in the heartbeat —
            # those nuances live in the activity log instead.
            def _color_for_state(state):
                return c['green'] if state == 'green' else c['dim']

            def _make_label(text, fg, font_, tooltip_text=None):
                def _f(parent):
                    lbl = tk.Label(parent, text=text,
                                    bg=c['card2'], fg=fg, font=font_)
                    if tooltip_text:
                        try:
                            Tooltip(lbl, tooltip_text)
                        except Exception:
                            pass
                    return lbl
                return _f

            def _on_chip_click(_event=None):
                # v4.14.0 stage 6d: clickable hook for the embedded
                # assistant (lands in v4.14.x+). No-op today.
                pass

            def _make_chip(name, state, tooltip_text=None):
                def _f(parent):
                    chip_frame = tk.Frame(parent, bg=c['card2'],
                                            cursor='hand2')
                    dot = tk.Label(chip_frame, text='●',
                                     bg=c['card2'],
                                     fg=_color_for_state(state),
                                     font=('Segoe UI', 10))
                    dot.pack(side='left')
                    txt = tk.Label(chip_frame, text=f" {name}",
                                     bg=c['card2'], fg=c['text'],
                                     font=('Segoe UI', 8),
                                     cursor='hand2')
                    txt.pack(side='left')
                    # Click hook on the frame and both labels so the
                    # whole chip is clickable, not just the text.
                    for w in (chip_frame, dot, txt):
                        try:
                            w.bind('<Button-1>', _on_chip_click)
                        except Exception:
                            pass
                    if tooltip_text:
                        try:
                            Tooltip(chip_frame, tooltip_text)
                        except Exception:
                            pass
                    return chip_frame
                return _f

            # Row-flow helper — chips wrap into a new row when the
            # current row would overflow `avail`. Identical mechanism
            # to the v4.13.62.6 implementation, just with the new chip
            # factory.
            def _flow_into(section, items):
                cur = [None]
                def _new_row():
                    cur[0] = tk.Frame(section, bg=c['card2'])
                    cur[0].pack(side='top', fill='x', anchor='w')
                for factory, padx in items:
                    if cur[0] is None:
                        _new_row()
                    widget = factory(cur[0])
                    widget.pack(side='left', padx=padx)
                    try:
                        cur[0].update_idletasks()
                        req = cur[0].winfo_reqwidth()
                    except Exception:
                        req = 0
                    if (req > avail
                            and len(cur[0].pack_slaves()) > 1):
                        try:
                            widget.destroy()
                        except Exception:
                            pass
                        _new_row()
                        widget = factory(cur[0])
                        widget.pack(side='left', padx=padx)

            # Tooltip text (Decision 3 — heartbeat semantics)
            _heartbeat_tip = (
                "Provider is currently available for AI calls. "
                "Grey means unavailable (out of capacity, in cooldown, "
                "or no API key). The assistant will explain in detail "
                "when it lands.")
            _data_heartbeat_tip = (
                "Data source is currently usable. Grey means unavailable "
                "(disabled, no key, or repeated failures).")

            # AI section
            if ai_chips:
                ai_section = tk.Frame(
                    self._provider_status_inner, bg=c['card2'])
                ai_section.pack(side='top', fill='x', anchor='w')
                items = [(_make_label("AI:", c['muted'],
                                        ('Segoe UI', 8, 'bold'),
                                        tooltip_text=_heartbeat_tip),
                          (0, 4))]
                for chip in ai_chips:
                    items.append((_make_chip(
                        chip['name'], chip['state'],
                        tooltip_text=_heartbeat_tip),
                        (0, 8)))
                _flow_into(ai_section, items)

            # Data section — separate line below AI
            if data_chips:
                data_section = tk.Frame(
                    self._provider_status_inner, bg=c['card2'])
                data_section.pack(side='top', fill='x', anchor='w',
                                    pady=(2, 0))
                items = [(_make_label("Data:", c['muted'],
                                        ('Segoe UI', 8, 'bold'),
                                        tooltip_text=_data_heartbeat_tip),
                          (0, 4))]
                for chip in data_chips:
                    items.append((_make_chip(
                        chip['name'], chip['state'],
                        tooltip_text=_data_heartbeat_tip),
                        (0, 8)))
                _flow_into(data_section, items)
        except Exception:
            # Bar refresh should never crash the app
            pass

    def _build_activity_log(self, parent):
        c = self.c

        hdr = tk.Frame(parent, bg=c['card'], padx=12, pady=10)
        hdr.pack(side='top', fill='x')
        tk.Label(hdr, text="ACTIVITY", bg=c['card'], fg=c['green'],
                 font=('Segoe UI', 11, 'bold')).pack(side='left')

        # Clear button — v4.14.3.9: wrapped in confirmation dialog
        # because the activity buffer is the only sink for queue runner
        # / AI dispatch messages (they don't reach data/activity.log).
        tk.Button(hdr, text="Clear", bg=c['card2'], fg=c['muted'],
                  relief='flat', padx=8, pady=2,
                  font=('Segoe UI', 8), cursor='hand2',
                  command=self._confirm_clear_activity).pack(side='right')

        # v4.14.3.9: Copy All button, peer to Clear. side='right' packs
        # right-to-left, so Clear (packed first) sits at the right edge
        # and Copy All sits just to its left, reading "Copy All  Clear".
        tk.Button(hdr, text="Copy All", bg=c['card2'], fg=c['muted'],
                  relief='flat', padx=8, pady=2,
                  font=('Segoe UI', 8), cursor='hand2',
                  command=self._copy_activity_all).pack(
                      side='right', padx=(0, 4))

        # ── v4.13.59: Live provider status bar (AI: / Data: rows) ───
        # v4.14.5.14-retry-and-cleanup-bundle Fix C — DEPRECATED, dev-only.
        # These heartbeat rows were development-visibility scaffolding.
        # Provider health now lives in the AI Providers dialog health dot
        # (the surviving half of the status-dot patch). The rows + their
        # 3s refresh tick + _provider_chip_is_green are GATED OFF by
        # default: cfg['show_dev_toolbar_rows'] (default False) must be
        # True to build them. When off, _provider_status_inner stays None
        # so _refresh_provider_status_bar()/_provider_status_tick() (kept
        # for the escape hatch) are inert no-ops. To fully retire the rows
        # later, delete this block + those three methods.
        self._provider_status_bar = None
        self._provider_status_inner = None
        self._status_bar_resize_after = None
        self._status_bar_last_width = None
        if self.cfg.get('show_dev_toolbar_rows', False):
            # Shows live AI + Data provider state without spamming the log.
            # Each provider chip: dot color + name + count/cap. Updates
            # every 3s via _refresh_provider_status_bar().
            self._provider_status_bar = tk.Frame(
                parent, bg=c['card2'], padx=10, pady=5)
            self._provider_status_bar.pack(side='top', fill='x',
                                              padx=4, pady=(0, 2))
            # Inner frame holds the chips — cleared/rebuilt on refresh.
            self._provider_status_inner = tk.Frame(
                self._provider_status_bar, bg=c['card2'])
            self._provider_status_inner.pack(
                side='left', fill='x', expand=True)
            # First render
            try:
                self._refresh_provider_status_bar()
            except Exception:
                pass
            # v4.13.62.2/.5: re-flow chips on resize, width-change-guarded
            # + 100ms-debounced so a drag doesn't rebuild every pixel and
            # a height-only wrap doesn't feed back into a flashing rebuild.
            def _on_status_bar_configure(_event=None):
                try:
                    new_w = self._provider_status_bar.winfo_width()
                except Exception:
                    return
                last_w = self._status_bar_last_width
                if last_w is not None and abs(new_w - last_w) < 5:
                    return  # height-only change or trivial jitter — ignore
                self._status_bar_last_width = new_w
                try:
                    if self._status_bar_resize_after is not None:
                        self.root.after_cancel(
                            self._status_bar_resize_after)
                except Exception:
                    pass
                try:
                    self._status_bar_resize_after = self.root.after(
                        100, self._refresh_provider_status_bar)
                except Exception:
                    pass
            try:
                self._provider_status_bar.bind(
                    '<Configure>', _on_status_bar_configure)
            except Exception:
                pass
            # Schedule periodic refresh
            try:
                self.root.after(3000, self._provider_status_tick)
            except Exception:
                pass

        # Scrollable text area
        body = tk.Frame(parent, bg=c['card'])
        body.pack(side='top', fill='both', expand=True, padx=4, pady=(0, 6))

        self._activity_text = tk.Text(body, bg=c['card'], fg=c['text'],
                                       font=('Consolas', 9), wrap='word',
                                       relief='flat', padx=10, pady=8,
                                       highlightthickness=0,
                                       state='disabled', cursor='arrow')
        sb = ttk.Scrollbar(body, orient='vertical', command=self._activity_text.yview)
        self._activity_text.configure(yscrollcommand=sb.set)
        sb.pack(side='right', fill='y')
        self._activity_text.pack(side='left', fill='both', expand=True)

        # Mousewheel
        def _wheel(e):
            delta = -3 if e.delta > 0 else 3
            self._activity_text.yview_scroll(delta, 'units')
            return 'break'
        # v4.10.6: REMOVED focus_set on Enter. That call was raising the
        # main window above any open popup (Settings/Recommend/Help) any
        # time the mouse moved over the activity feed. The MouseWheel
        # binding works fine without focus on Windows since it's bound
        # directly to the widget.
        self._activity_text.bind('<MouseWheel>', _wheel)

        # v4.14.3.9: copy affordance. Right-click opens a context menu
        # (Copy / Copy All / Clear); Ctrl+C copies the current selection.
        # The widget stays state='disabled' — selection still works via
        # the default Tk mechanism, and the copy handlers read via
        # widget.get() without flipping state. cursor='xterm' on the
        # text content gives the visual hint that selection is now
        # meaningful (was 'arrow' before, which signalled non-interactive).
        try:
            self._activity_text.configure(cursor='xterm')
        except Exception:
            pass
        self._attach_copy_context_menu(
            self._activity_text,
            on_clear=self._confirm_clear_activity)

        # Tags
        self._activity_text.tag_configure('header', foreground=c['accent'],
                                           font=('Segoe UI', 9, 'bold'))
        self._activity_text.tag_configure('muted', foreground=c['muted'],
                                           font=('Segoe UI', 9))
        self._activity_text.tag_configure('green', foreground=c['green'],
                                           font=('Segoe UI', 9))
        self._activity_text.tag_configure('amber', foreground=c['amber'],
                                           font=('Segoe UI', 9))
        self._activity_text.tag_configure('red', foreground=c['red'],
                                           font=('Segoe UI', 9))

    def _apply_ttk_styling(self):
        """v4.10.4: Configure ttk widgets to match the dark theme.

        Without this, ttk.Combobox / ttk.Scrollbar / ttk.Treeview render
        in Windows default colors (pale gray) and look terrible against
        our dark background. ttk theming is finicky — different base
        themes (clam/vista/alt/default) expose different style options,
        so we use 'clam' which has the most flexibility on Windows.
        """
        from tkinter import ttk
        c = self.c
        style = ttk.Style(self.root)
        # 'clam' is the most flexible theme on Windows for color
        # overrides. 'vista' looks more native but ignores most of
        # our background settings.
        try:
            style.theme_use('clam')
        except Exception:
            pass

        # Combobox — the dropdown widget. Make the field, arrow, and
        # popdown match dark theme.
        style.configure('TCombobox',
                        fieldbackground=c['card2'],
                        background=c['card2'],
                        foreground=c['text'],
                        arrowcolor=c['text'],
                        bordercolor=c['border'],
                        lightcolor=c['border'],
                        darkcolor=c['border'],
                        selectbackground=c['accent'],
                        selectforeground=c['bg'])
        style.map('TCombobox',
                  fieldbackground=[('readonly', c['card2'])],
                  foreground=[('readonly', c['text'])],
                  selectbackground=[('readonly', c['accent'])],
                  selectforeground=[('readonly', c['bg'])])
        # The popdown listbox is a separate widget — color it via
        # an option_add on the root.
        self.root.option_add('*TCombobox*Listbox.background', c['card2'])
        self.root.option_add('*TCombobox*Listbox.foreground', c['text'])
        self.root.option_add('*TCombobox*Listbox.selectBackground',
                              c['accent'])
        self.root.option_add('*TCombobox*Listbox.selectForeground',
                              c['bg'])

        # Scrollbar — replaces the pale default with a thin dark style.
        style.configure('Vertical.TScrollbar',
                        background=c['card2'],
                        troughcolor=c['bg'],
                        bordercolor=c['border'],
                        arrowcolor=c['muted'],
                        gripcount=0)
        style.map('Vertical.TScrollbar',
                  background=[('active', c['card2']),
                              ('!active', c['card'])])
        style.configure('Horizontal.TScrollbar',
                        background=c['card2'],
                        troughcolor=c['bg'],
                        bordercolor=c['border'],
                        arrowcolor=c['muted'],
                        gripcount=0)

        # Treeview — used in some popups for tabular data.
        style.configure('Treeview',
                        background=c['card'],
                        fieldbackground=c['card'],
                        foreground=c['text'],
                        bordercolor=c['border'])
        style.configure('Treeview.Heading',
                        background=c['card2'],
                        foreground=c['accent'],
                        bordercolor=c['border'],
                        font=self.fonts['body_bold'])
        style.map('Treeview',
                  background=[('selected', c['accent'])],
                  foreground=[('selected', c['bg'])])

        # Notebook (tabs) — used in Settings.
        style.configure('TNotebook',
                        background=c['bg'],
                        bordercolor=c['border'])
        style.configure('TNotebook.Tab',
                        background=c['card'],
                        foreground=c['muted'],
                        padding=[12, 4],
                        font=self.fonts['body'])
        style.map('TNotebook.Tab',
                  background=[('selected', c['card2'])],
                  foreground=[('selected', c['accent'])])

    def _make_styled_toplevel(self, title: str,
                                subtitle: str = "",
                                width: int = 800,
                                height: int = 600,
                                min_width: int | None = None,
                                min_height: int | None = None,
                                close_callback=None):
        """v4.10.5: Build a standardized Toplevel popup window with the
        design-system look: dark theme, consistent header bar with title
        and optional subtitle, standard outer padding.

        Returns a dict with these keys:
          - 'win': the tk.Toplevel itself
          - 'body': a tk.Frame inside the window where caller adds content
          - 'footer': a tk.Frame at the bottom for action buttons
          - 'close': the WM_DELETE_WINDOW handler that's been wired up

        Caller is responsible for adding content widgets to body and
        action buttons to footer. Close behavior calls close_callback
        (if provided) then destroys the window.

        Why this helper exists: every popup (Settings, Recommend,
        Track Record, Holdings, AI Chat) used to build its own ad-hoc
        Toplevel with slightly different padding, font sizes, header
        styling. This unifies them so they look like siblings.
        """
        c = self.c
        win = tk.Toplevel(self.root)
        win.title(f"{title} — Tired Market")
        win.configure(bg=c['bg'])
        win.geometry(f"{width}x{height}")
        if min_width and min_height:
            win.minsize(min_width, min_height)
        elif min_width:
            win.minsize(min_width, height)
        # v4.10.6: transient(parent) makes the popup a child of the main
        # window in z-order. Means it stays above main even when main
        # gets focus events. Fixes the bug where popups disappeared
        # behind main when the mouse hovered over main.
        try:
            win.transient(self.root)
        except Exception:
            pass

        # Close handler — calls user callback then destroys
        def _on_close():
            try:
                if close_callback:
                    close_callback()
            finally:
                try: win.destroy()
                except Exception: pass
        win.protocol("WM_DELETE_WINDOW", _on_close)

        # ── Header bar ──
        # Single visual element at the top of every popup. Dark card
        # bg, padded with design tokens. Title in display font, optional
        # subtitle below in muted body font.
        header = tk.Frame(win, bg=c['card'])
        header.pack(side='top', fill='x')
        header_inner = tk.Frame(header, bg=c['card'])
        header_inner.pack(side='top', fill='x',
                           padx=self.space['lg'], pady=self.space['md'])
        tk.Label(header_inner, text=title,
                 bg=c['card'], fg=c['accent'],
                 font=self.fonts['display']
                 ).pack(side='top', anchor='w')
        if subtitle:
            tk.Label(header_inner, text=subtitle,
                     bg=c['card'], fg=c['muted'],
                     font=self.fonts['body']
                     ).pack(side='top', anchor='w', pady=(2, 0))

        # ── Footer (action buttons go here) ──
        # Reserve a fixed-height footer at the bottom BEFORE packing the
        # body, so when body fills the middle it can't push the footer
        # off-screen at narrow window heights. This was a bug in
        # several pre-v4.10.5 popups.
        footer = tk.Frame(win, bg=c['bg'], height=60)
        footer.pack(side='bottom', fill='x',
                     padx=self.space['lg'],
                     pady=(self.space['md'], self.space['lg']))
        footer.pack_propagate(False)

        # ── Body (the main content area) ──
        body = tk.Frame(win, bg=c['bg'])
        body.pack(side='top', fill='both', expand=True,
                   padx=self.space['lg'],
                   pady=(self.space['md'], 0))

        return {
            'win': win,
            'body': body,
            'footer': footer,
            'close': _on_close,
        }

    def _make_close_button(self, parent, callback=None, text="Close"):
        """v4.10.5: Standard close button for popups. Utility-gray
        category, lives in the bottom-right of the footer. Caller
        passes the parent (typically the footer frame from
        _make_styled_toplevel) and an optional callback that runs
        before close (defaults to just closing).
        """
        c = self.c
        return tk.Button(parent, text=text,
                          bg=self.c['card2'], fg=c['text'],
                          activebackground=c['border'],
                          activeforeground=c['text'],
                          relief='flat',
                          padx=self.space['md'],
                          pady=self.space['xs'],
                          font=self.fonts['body_bold'],
                          cursor='hand2',
                          command=callback or (lambda: None))

    def _log(self, message, tag='muted'):
        """Append a line to the activity log (UI buffer + disk).

        v4.13.59: Dedup repeat 'AI router [...] skipped X — reason' lines.
        Within a 30-second window, an identical "skipped {provider} —
        {reason}" message only fires once. After the window expires (or
        on app restart) it can fire again. This stops the activity log
        from drowning in identical skip messages during big batch scans
        while preserving the FIRST instance so you still know what
        happened.

        v4.14.3.15 (2026-05-15): every log line also persists to
        data/activity.log so Clear stops being destructive. The disk
        write happens AFTER the UI write — if disk fails (disk full,
        AV lock, permission), the UI write has already succeeded and
        the disk failure is printed to stderr without disrupting the
        UI. Disk persistence fires even when self._activity_text is
        None (early-startup, before _build_activity_log runs); early-
        init errors are the diagnostics most worth capturing.

        The 30-second AI-router dedup fires BEFORE both writes — that's
        correct, dedup is about both UI noise AND disk record
        completeness. The first instance of any deduped line goes to
        both UI and disk.
        """
        # Dedup check: only applies to AI router skip lines. Fires
        # BEFORE both UI and disk writes — dedup applies to both.
        if 'AI router' in message and 'skipped' in message:
            try:
                # Strip ticker-specific or count-specific bits to get the
                # reusable signature: "AI router [scan]: skipped Mistral"
                # is the same across many tickers, so we dedupe on that.
                # The reason text often contains the cap counter
                # ("15/15") which IS interesting to see change, but the
                # router emits the same reason within a single batch
                # so we just dedupe on the whole line for simplicity.
                signature = message.split(' (')[0]  # drop "(N/N)" suffix
                if not hasattr(self, '_skip_log_dedup'):
                    self._skip_log_dedup = {}
                last_time = self._skip_log_dedup.get(signature, 0.0)
                now = time.time()
                if now - last_time < 30.0:
                    return  # suppress
                self._skip_log_dedup[signature] = now
            except Exception:
                pass  # fail open — better to over-log than under-log

        # v4.14.5.25-activity-log-tiering: ROUTINE-tier filter. Lines tagged
        # 'routine' are repetitive per-tick steady-state breadcrumbs (fill-mode
        # idle, the owned-ticker event skip, the per-ticker earnings-no-data
        # wall, the unified-scan gated line) — all correct, all useless when
        # repeated. They are collapsed by `activity_log_verbosity`:
        #   'verbose' → emit every one (today's firehose; the safety valve)
        #   'normal'  → emit once per signature per ROUTINE_DEDUP_WINDOW, then
        #               suppress identical repeats (signature strips digits AND
        #               ticker-like ALL-CAPS tokens so per-ticker / per-count
        #               variants collapse to one line)
        #   'quiet'   → suppress routine entirely (signal + errors only)
        # SIGNAL lines (any other tag — green/amber/red/header/muted) are NEVER
        # filtered here; this branch only touches tag=='routine'. Mirrors the
        # AI-router dedup pattern above. Behaviour-free: this only decides
        # whether TEXT is emitted; no control flow / dispatch is affected.
        if tag == 'routine':
            try:
                _verb = (self.cfg or {}).get('activity_log_verbosity',
                                             'normal')
            except Exception:
                _verb = 'normal'
            if _verb == 'quiet':
                return  # routine fully suppressed
            if _verb != 'verbose':  # 'normal' (default) → window-dedup
                try:
                    sig = re.sub(r'\d+', '',
                                 re.sub(r'\b[A-Z]{1,6}\b', '', message))
                    now = time.time()
                    if not hasattr(self, '_routine_log_dedup'):
                        self._routine_log_dedup = {}
                    if (now - self._routine_log_dedup.get(sig, 0.0)
                            < ROUTINE_DEDUP_WINDOW):
                        return  # suppress identical routine within the window
                    self._routine_log_dedup[sig] = now
                except Exception:
                    pass  # fail open — over-log rather than swallow
            tag = 'muted'  # render the surviving routine line as muted

        # v4.14.5.14-gui-cleanup-c: record the last (non-suppressed) message
        # so the persistent activity indicator can derive a short status from
        # it (read-only — no new tracking infrastructure, per the patch).
        try:
            self._last_activity_msg = message
            # v4.14.5.14-indicator-honesty: stamp the time so the indicator
            # can age this line out (a >10s-old line is a finished echo).
            self._last_activity_at = time.time()
        except Exception:
            pass

        # UI write — only if the widget exists. Pre-_build_activity_log
        # this is a no-op and we fall through to the disk write.
        if self._activity_text is not None:
            try:
                ts = datetime.now().strftime(
                    '%I:%M%p').lower().lstrip('0')
                self._activity_text.config(state='normal')
                self._activity_text.insert('end', f"[{ts}] ", 'muted')
                self._activity_text.insert('end', f"{message}\n", tag)
                self._activity_text.see('end')
                self._activity_text.config(state='disabled')
            except Exception:
                pass

        # v4.14.3.15: persist to data/activity.log. Matches the
        # cleanup-events format at line ~20356 ('[<iso>] <msg>\n')
        # so cleanup events and runtime events coexist cleanly in
        # one file. Synchronous open-append-close per call — atomic
        # at the OS level for append mode, safe across threads.
        # Tag is NOT written to disk (UI uses color tags; disk file
        # is for human reading where wording conveys severity).
        try:
            iso_ts = datetime.now().isoformat(timespec='seconds')
            with open(LOG_PATH, 'a', encoding='utf-8') as f:
                f.write(f"[{iso_ts}] {message}\n")
        except Exception as e:
            # Don't recurse into _log; print to stderr. Same pattern
            # v4.14.3.13 / v4.14.3.14 established for persistence
            # failures — log amber + continue, never let a write
            # failure crash the calling code.
            try:
                print(
                    f"[activity.log] persistence write failed: "
                    f"{type(e).__name__}: {e}",
                    file=sys.stderr)
            except Exception:
                pass

    def log(self, msg, tag=''):
        """Public log() for compat with anything still calling self.log()."""
        # Map old tag names to new ones
        tag_map = {'info': 'muted', 'ok': 'green', 'warn': 'amber',
                   'error': 'red', 'header': 'header', '': 'muted'}
        self._log(msg, tag_map.get(tag, 'muted'))

    def _clear_activity(self):
        if self._activity_text is None:
            return
        try:
            self._activity_text.config(state='normal')
            self._activity_text.delete('1.0', 'end')
            self._activity_text.config(state='disabled')
        except Exception:
            pass

    def _confirm_clear_activity(self):
        """v4.14.3.9: Clear-button wrapper.

        v4.14.3.15 (2026-05-15): dialog copy softened. Pre-v4.14.3.15
        Clear was genuinely destructive because data/activity.log
        only caught cleanup summaries. Now app._log Tees to disk on
        every call, so clearing the view leaves the on-disk record
        intact. The dialog still confirms because clearing the view
        IS still mildly surprising (Mike's at-a-glance buffer just
        vanishes), but the dire-warning framing is no longer
        accurate. NOTE: this dialog text MUST still mention
        'data/activity.log' so the v4.14.3.9 audit B7 check stays
        green — the literal is here, just used to explain why
        clearing is now SAFE rather than destructive."""
        if self._activity_text is None:
            return
        try:
            ok = messagebox.askyesno(
                "Clear activity log view?",
                "This clears the activity messages from the current "
                "view. Diagnostic events are still saved to "
                "data/activity.log on disk for later reference, so "
                "clearing the view does NOT delete that record.\n\n"
                "Clear the view?",
                default='no', parent=self.root)
        except Exception:
            # If the dialog itself fails, fall through to clearing —
            # better than wedging the Clear button.
            ok = True
        if ok:
            self._clear_activity()

    def _copy_activity_all(self):
        """v4.14.3.9: header 'Copy All' button handler. Wraps
        _copy_text_widget_all so the button click and the context
        menu's 'Copy All' entry share a single code path."""
        if self._activity_text is None:
            return
        self._copy_text_widget_all(self._activity_text)

    def _copy_text_widget_selection(self, widget):
        """v4.14.3.9: copy current selection from a tk.Text widget to
        the clipboard. No-op if nothing is selected. The trailing
        update() call is required on Windows or the clipboard contents
        disappear when the Tk loop yields back."""
        try:
            text = widget.get('sel.first', 'sel.last')
        except tk.TclError:
            # No selection — fall back to Copy All semantics? No.
            # Keep selection-only semantics so Ctrl+C with no selection
            # is a deliberate no-op (matches every other text widget).
            return
        if not text:
            return
        try:
            widget.clipboard_clear()
            widget.clipboard_append(text)
            widget.update()
        except Exception as e:
            try:
                self._log(f"Copy failed: {type(e).__name__}: {e}",
                          'amber')
            except Exception:
                pass

    def _copy_text_widget_all(self, widget):
        """v4.14.3.9: copy the entire buffer from a tk.Text widget.
        Uses 'end-1c' to drop the trailing newline Tk appends to every
        Text widget. The trailing update() is required (see
        _copy_text_widget_selection note)."""
        try:
            text = widget.get('1.0', 'end-1c')
        except Exception as e:
            try:
                self._log(
                    f"Copy All failed: {type(e).__name__}: {e}",
                    'amber')
            except Exception:
                pass
            return
        if not text:
            return
        try:
            widget.clipboard_clear()
            widget.clipboard_append(text)
            widget.update()
        except Exception as e:
            try:
                self._log(
                    f"Copy All failed: {type(e).__name__}: {e}",
                    'amber')
            except Exception:
                pass

    def _attach_copy_context_menu(self, widget, on_clear=None):
        """v4.14.3.9: attach a right-click context menu + Ctrl+C binding
        to a tk.Text widget. Menu entries:
          - Copy        (active when there's a selection; copies it)
          - Copy All    (always active; copies entire buffer)
          - Clear       (only if on_clear is supplied)

        on_clear is a callable; the helper itself does not gate it with
        a confirmation dialog — that's the caller's responsibility. For
        the Activity log, on_clear is _confirm_clear_activity which
        already wraps the action in askyesno.

        Works on state='disabled' widgets — selection still works via
        the default Tk mechanism, and Copy reads via widget.get()."""
        c = self.c
        try:
            menu = tk.Menu(widget, tearoff=0,
                            bg=c['card2'], fg=c['text'],
                            activebackground=c['accent'],
                            activeforeground=c['bg'],
                            borderwidth=0)
            menu.add_command(
                label='Copy',
                command=lambda: self._copy_text_widget_selection(widget))
            menu.add_command(
                label='Copy All',
                command=lambda: self._copy_text_widget_all(widget))
            if on_clear is not None:
                menu.add_separator()
                menu.add_command(label='Clear', command=on_clear)
        except Exception as e:
            try:
                self._log(
                    f"Context menu attach failed: "
                    f"{type(e).__name__}: {e}",
                    'amber')
            except Exception:
                pass
            return

        def _popup(event):
            try:
                menu.tk_popup(event.x_root, event.y_root)
            finally:
                # tk_popup grabs the menu — release it so the next
                # event dispatches normally.
                try:
                    menu.grab_release()
                except Exception:
                    pass
            return 'break'

        try:
            widget.bind('<Button-3>', _popup)
            widget.bind(
                '<Control-c>',
                lambda e: (self._copy_text_widget_selection(widget),
                           'break')[1])
            widget.bind(
                '<Control-C>',
                lambda e: (self._copy_text_widget_selection(widget),
                           'break')[1])
        except Exception as e:
            try:
                self._log(
                    f"Context menu bind failed: "
                    f"{type(e).__name__}: {e}",
                    'amber')
            except Exception:
                pass

    def _on_main_focus(self, _event=None):
        """Called when the main window regains focus. Refreshes the
        portfolio summary in case the Holdings window made changes
        (sold, removed, added, edited) while it was active.

        IMPORTANT: only rebuilds the summary if the portfolio actually
        changed. Otherwise the rebuild can race with button clicks —
        clicking "Open Holdings →" right as focus changes destroys the
        button mid-click and the click registers as nothing.
        """
        try:
            # Read fresh from disk
            new_portfolio = load_portfolio()
            # Cheap signature for change detection: (count active, count
            # closed, sum of total_costs)
            def _sig(pf):
                holdings = pf.get('holdings', [])
                closed = pf.get('closed', [])
                cost = sum(h.get('total_cost', 0) for h in holdings)
                return (len(holdings), len(closed), round(cost, 2))
            old_sig = _sig(self.portfolio)
            new_sig = _sig(new_portfolio)
            self.portfolio = new_portfolio
            if old_sig != new_sig:
                self._render_portfolio_summary()
        except Exception:
            pass

    def _format_scheduler_state(self) -> str:
        """One-line summary of scheduler state for the Settings display."""
        if not _SCHEDULER_ENABLED:
            return "    Scheduler module not available."
        if self._scheduler is None:
            return "    Not running. Will start when this is enabled + saved."
        mode = self._scheduler_mode
        label = tm_scheduler.MODE_LABELS.get(mode, mode)
        cadence = tm_scheduler.cadence_for(mode)
        cad_str = f"{cadence}s" if cadence < 60 else f"{cadence // 60}min"
        # Get last brief / locked check timestamps
        last_brief = "never"
        last_locked = "never"
        try:
            sched_state_path = DATA_DIR / "scheduler_state.json"
            if sched_state_path.exists():
                with open(sched_state_path) as f:
                    s = json.load(f)
                lb = s.get('last_morning_brief')
                if lb:
                    try:
                        d = datetime.fromisoformat(lb)
                        last_brief = d.strftime('%b %d, %I:%M%p').lstrip('0')
                    except Exception:
                        last_brief = lb[:16]
                ll = s.get('last_locked_check')
                if ll:
                    try:
                        d = datetime.fromisoformat(ll)
                        last_locked = d.strftime('%b %d, %I:%M%p').lstrip('0')
                    except Exception:
                        last_locked = ll[:16]
        except Exception:
            pass
        return (f"    Current mode: {label} (ticks every {cad_str})\n"
                f"    Last morning brief: {last_brief}\n"
                f"    Last locked-position check: {last_locked}")

    def _toggle_ai_paused(self):
        """Flip the AI pause state. Saves to config and updates the badge."""
        if not _AI_ENABLED:
            return
        new_state = not tm_holdings.is_ai_paused()
        tm_holdings.set_ai_paused(new_state)
        self.cfg['ai_paused'] = new_state
        try:
            save_config(self.cfg)
        except Exception:
            pass
        self._refresh_ai_badge()
        self._log(f"AI {'paused' if new_state else 'resumed'}",
                   'amber' if new_state else 'green')

    def _refresh_ai_mode_pill(self):
        """v4.14.0 stage 6d: paint the AI Mode pill from the current
        inference_mode setting. Color-coded:
          Local  → blue   (cyan; Ollama-only)
          API    → accent (light blue/lavender; cloud-only)
          Hybrid → purple (cloud primary, Ollama fallback)

        The colors are deliberately chosen to be visually distinct
        from the chip strip's green so a "green chip" reading and a
        "Local mode" reading don't cross-talk.

        Called once at end of _build() for the initial paint, and
        again from the AI Mode dialog's save handler whenever the
        user flips inference_mode.
        """
        try:
            pill = getattr(self, '_ai_mode_pill', None)
            if pill is None:
                return
            c = self.c
            mode, _ = self._get_inference_settings()
            if mode == 'local':
                text = "Local"
                color = c['blue']
            elif mode == 'hybrid':
                text = "Hybrid"
                color = c['purple']
            else:  # 'api' default
                text = "API"
                color = c['accent']
            pill.config(text=text, fg=color)
        except Exception:
            pass

    def _refresh_ai_badge(self):
        """Update the badge text/color to match the current AI state.
        Shows the scheduler mode if scheduler is running, otherwise just
        on/paused. Click toggles pause/resume.
        """
        if self._ai_badge is None:
            return
        c = self.c
        try:
            if tm_holdings.is_ai_paused():
                # Paused: amber on darker bg
                self._ai_badge.config(text="⏸ AI Paused",
                                       fg=c['amber'],
                                       bg=c['card2'],
                                       activebackground=c['card2'],
                                       activeforeground=c['amber'])
                return

            # If scheduler is running, show its mode
            if _SCHEDULER_ENABLED and self._scheduler is not None:
                mode = self._scheduler_mode
                # Map mode to label + color
                # Active (market open) = green, Reduced = teal/blue,
                # Brief = amber, Idle = muted, Gaming = purple
                mode_styles = {
                    tm_scheduler.MODE_ACTIVE:  ("● AI Active", c['green']),
                    tm_scheduler.MODE_REDUCED: ("◐ AI Reduced", c['blue']),
                    tm_scheduler.MODE_BRIEF:   ("☀ Morning Brief", c['amber']),
                    tm_scheduler.MODE_IDLE:    ("○ AI Idle", c['muted']),
                    tm_scheduler.MODE_GAMING:  ("🎮 Gaming", c['purple']),
                    tm_scheduler.MODE_WORKING: ("● AI Working", c['green']),
                }
                text, color = mode_styles.get(mode, ("● AI On", c['green']))
                self._ai_badge.config(text=text,
                                       fg=color,
                                       bg=c['card'],
                                       activebackground=c['card2'],
                                       activeforeground=color)
            else:
                # Scheduler not running; just show on
                self._ai_badge.config(text="● AI On",
                                       fg=c['green'],
                                       bg=c['card'],
                                       activebackground=c['card2'],
                                       activeforeground=c['green'])
        except Exception:
            pass

    def _tick_clock(self):
        """Update the status label with time + market status. Runs every 30s.
        v4.10.2: also updates the data-freshness indicator next to it."""
        try:
            now = datetime.now()
            ts = now.strftime('%I:%M%p ET').lower().lstrip('0')
            try:
                ms = get_market_status()
                if isinstance(ms, str):
                    market = ms
                elif isinstance(ms, dict):
                    market = ms.get('status', '')
                else:
                    market = ''
            except Exception:
                market = ''
            text = f"{ts}  ·  {market}" if market else ts
            if self._status_lbl is not None:
                self._status_lbl.config(text=text)
        except Exception:
            pass

        # v4.10.2: update freshness label
        try:
            self._update_freshness_label()
        except Exception:
            pass

        try:
            self.root.after(30000, self._tick_clock)
        except Exception:
            pass

    def _v415_init_network_detector(self):
        """v4.15.0 Step 12: register the activity-log transition callback and
        kick off the periodic network probe tick. Called once from __init__.
        """
        def _on_transition(was_online: bool, now_online: bool,
                            _self=self):
            # Probe runs on a worker thread; marshal log writes back to Tk.
            try:
                if now_online:
                    _self.root.after(0, lambda: _self._log(
                        "[network] back online", 'muted'))
                else:
                    _self.root.after(0, lambda: _self._log(
                        "[network] offline — working from cache",
                        'amber'))
            except Exception:
                pass

        try:
            import tm_network as _tmn
            _tmn.register_transition_callback(_on_transition)
        except Exception:
            pass

        try:
            self.root.after(30000, self._v415_network_tick)
        except Exception:
            pass

    def _v415_network_tick(self):
        """v4.15.0 Step 12: probe network state every 30s on a worker thread.

        The probe itself blocks up to ~6s when offline, so it must NOT run on
        the Tk thread. tm_network.periodic_tick fires transition callbacks
        if the state flipped; those callbacks marshal their UI writes via
        root.after(0, ...).
        """
        try:
            import tm_network as _tmn
            threading.Thread(
                target=_tmn.periodic_tick,
                daemon=True,
                name='v415-network-tick',
            ).start()
        except Exception:
            pass
        try:
            self.root.after(30000, self._v415_network_tick)
        except Exception:
            pass

    # ── v4.15.0 Step 15: Choices UI ──────────────────────────────────────
