        tk.Checkbutton(disp_frame, text="Desktop notifications",
                       variable=notif_var,
                       bg=c['card'], fg=c['text'],
                       selectcolor=c['bg'],
                       activebackground=c['card'], activeforeground=c['text'],
                       font=('Segoe UI', 9), borderwidth=0
                       ).pack(side='top', anchor='w', pady=(4, 0))

        # Sound toggle
        sound_var = tk.BooleanVar(value=self.cfg.get('sound_enabled', True))
        tk.Checkbutton(disp_frame, text="Sound alerts",
                       variable=sound_var,
                       bg=c['card'], fg=c['text'],
                       selectcolor=c['bg'],
                       activebackground=c['card'], activeforeground=c['text'],
                       font=('Segoe UI', 9), borderwidth=0
                       ).pack(side='top', anchor='w', pady=(4, 0))

        # ── "Auto-scan holdings when app launches" REMOVED
        #    (v4.14.5.14-settings-dialog-cleanup) ──
        # Orphaned toggle — auto_scan_on_launch had no live consumer.
        # cfg key left untouched (harmless orphan).

        # ── AI Providers (link-out) — v4.14.5.14-gui-cleanup-e ──
